INSERT INTO `article_tbl` VALUES (3,1,NULL,'01091280586','2019-12-27','2021-05-29','0000-00-00','0000-00-00','공인중개사법률소비조합을 소개합니다. &#91;조항준&#93;','0','올해로 꼬박 창립 3년차인 공인중개사 법률소비조합은 전국의 수많은 공인중개사 일동이 지닌 힘과 가치를 더욱 든든하게 키우기 위해 노력할 것입니다. ',NULL,'공인중개사 법률소비조합은 \r\n\r\n드러나지 않아도 ‘공인중개사’의 이름을 잇는 수려한 바탕이 되며, 전국의 수많은 공인중개사 일동이 지닌 힘과 가치를 한데 모아 든든하게 키워내는 양지로 자리매김할 것입니다.\r\n\r\n이것이 창립 3년차, 공인중개사 법률소비조합의 2021년도 사명입니다.\r\n\r\n조합은 나, 너 우리가 함께 평등하면서도 단순 모임 이상의 의미를 가지는 ‘조직’이어야 하며, 조합원들이 현실에서 그 도움을 구체적으로 구할 수 있는 ‘힘’이 있어야 했으며, 나아가 이를 통해 공인중개사의 법익을 회복하고 법의 주권자로서 자리매김할 ‘단체’여야 했습니다. \r\n\r\n공인중개사 법률소비조합은 분양권 중개과정에서의 초과보수를 원인으로 한 행정처분의 정당성을 다투는 과정에서, 이전의 단편적이고 파편화된 개인 차원의 문제 접근 방식을 넘어 좀 더 거시적으로 접근할 수 있는, 체계화된 조직의 존재가 필요하다는 공감을 얻어 2018년 4월 28일 문을 열었습니다. \r\n\r\n2018년 5월 11일 밴드 개설을 시작으로 첫 무대에 오른 공인중개사 법률소비조합은 네이버 카페까지 확장하는 등 내실 있게 규모를 키워갔으며, 2018년 12월 2일 마포구청에서 제1회 공인중개사 법률소비조합 컨퍼런스 개최 이후에도 매년 정기 컨퍼런스를 진행하는 등 우리 업계가 고민하는 다양한 이슈를 본격적으로 담아내며 새로운 담론의 공간을 구축해왔습니다.\r\n\r\n지난 과정을 뒤돌아보면, 중개보수청구소송에서 행정구제 소송까지 공인중개사 법률소비조합은 하루도 진행 중인 소송이 없던 날이 없었을 만큼 다사다난한 순간을 보냈지만, 여러 구성원이 보여준 감사한 노력에 힘입어 각각의 사례에서 분명한 성과를 낼 수 있었습니다.\r\n\r\n이 홈페이지(http://www.reuni.kr)는 공인중개사 법률소비조합이 이룬 그동안의 성과를 더 많은 공인중개사들과 함께 나누기 위해 개설한 공간입니다. 2018년도에 처음 문을 연 네이버 공인중개사 법률소비조합 카페(https://cafe.naver.com/reisis)와 더불어, 2021년도에 첫 삽을 뗀 이 공간을 통해 전국각지의 업계 관계자들이 각자 처한 현실에서 더욱 구체적이고 분명한 성공을 경험하며 그 스스로가 지닌 본연의 권익을 자각하는 계기가 되고 각자 사업 분야에서 더욱 전문성 있고 분명한 성과를 거둘 수 있기를 희망합니다.\r\n\r\n\r\n마포 성산 신대림 개업공인중개사 대표 조항준\r\n\r\n<H3>공인중개사 법률소비조합과 함께 하는 방법</H3>\r\n네이버카페 공인중개사법률소비조합 회원가입 후\r\n① 신한은행 218-12-036791 조항준으로 100,000원을 입금해 주세요<br>\r\n② 닉네임을 실명으로 변경해 주세요<br>\r\n③ \"사업장 소개\" 게시판에 사업장 소개해 주세요<br>\r\n④ \"등업 게시판\"에 등업글을 올려주세요',0);
INSERT INTO `article_tbl` VALUES (6,1,18,'01091280586','2020-01-07','2021-04-30','0000-00-00','0000-00-00','중개보조원(소속공인중개사포함)계약시 ','1','중개보조원중개계약시 반드시 확인해주세요 ',NULL,'중개보조원 또는 소속공인중개사의 이직시 정산관련된 분쟁이 많이 발생하고 있습니다. \r\n\r\n보통 수익에 대한 배분까지는 말해놓는데 그 분배의 기준이 계약을 기준으로 하는지 잔금을 기준으로하는지에 대한 거론이 없어 분쟁을 만들고 있습니다. \r\n\r\n당연히 대표자 입장에서는 잔금시가 유리하고 떠나시는 분 입장에는 계약시로 하는게 유리하겠죠 상황에 따라 상당한 금액이 되기도 하고요 \r\n\r\n꼭 확인해주시기 바랍니다.  ',0);
INSERT INTO `article_tbl` VALUES (10,1,32,'01091280586','2020-01-15','2021-04-30','2020-05-01','2020-05-30','소득세법에 따른 사업자등록과 민간임대주택에 ','0','소득세법에 따른 사업자등록과 민간임대주택에 관한 특별법에 따른 임대사업자등록의 차',NULL,'<H3>1. 소득세법에 따른 사업자등록과 민간임대주택에 관한 특별법에 따른 임대사업자등록</H3>\r\n모든 사업자는 사업소득에 대한 소득세를 납부하여야 하고 주택과 비주택으로 나워 주택의 경우에는 부가가치세에 있어서 면세적용을 받고 주택이 아닌 경우에는 부가가치세를 납부하여야 한다.  그러다 보니 주택이 아닌 상가등은 부가가치세법의 적용되나 주택의 임대에는 부가가치세법 시행령 제41제서 면세로 규정하고 있으며 소득세법에서는 제12조에 의한 *비과세 소득에 해당하지 않는다면 소득세를 과세한다.  \r\n\r\n<blockquote>*소득세법 제12조(비과세소득)2. 사업소득 중 다음 각 목의 어느 하나에 해당하는 소득\r\n\r\n나. 1개의 주택을 소유하는 자의 주택임대소득(제99조에 따른 <strong>기준시가가 9억원을 초과하는 주택</strong> 및 국외에 소재하는 주택의 임대소득은 제외한다) 또는 해당 과세기간에 대통령령으로 정하는 총수입금액의 합계액이 <strong>2천만원 이하인 자의 *주택임대소득(2018년 12월 31일 이전에 끝나는 과세기간까지 발생하는 소득으로 한정한다).</strong> 이 경우 주택 수의 계산 및 주택임대소득의 산정 등 필요한 사항은 대통령령으로 정한다</blockquote>\r\n<blockquote>*주택임대소득의 계산방법 연간총수입금액-필요경비</blockquote>\r\n\r\n부동산을 임대하는 임대사업자는 부가가치세법에의 의한 사업자 등록 소득세법에 따른 사업자등록과 민간임대주택에 관한 특별법에 따른 임대사업자등록으로 구분된다.  그중 최근 이슈가 되는 부분은 소득세법에 따른 사업바 등록과 민간임대주택에에 관한 특별법에 따른 임대사업자등록이며 이에 대해 살펴보기로 한다. \r\n. \r\n<blockquote>부가가치세법 시행령 [시행 2020. 2. 18.] [대통령령 제30423호, 2020. 2. 18., 타법개정] 제41조(주택과 이에 부수되는 토지의 임대 용역으로서 면세하는 것의 범위) ① 법 제26조제1항제12호에 따른 주택과 이에 부수되는 토지의 임대는 상시주거용(사업을 위한 주거용의 경우는 제외한다)으로 사용하는 건물(이하 \"주택\"이라 한다)과 이에 부수되는 토지로서 다음 각 호의 면적 중 넓은 면적을 초과하지 아니하는 토지의 임대로 하며, 이를 초과하는 부분은 토지의 임대로 본다.\r\n\r\n1. 주택의 연면적(지하층의 면적, 지상층의 주차용으로 사용되는 면적 및 「주택건설기준 등에 관한 규정」 제2조제3호에 따른 주민공동시설의 면적은 제외한다)\r\n\r\n2. 건물이 정착된 면적에 5배(「국토의 계획 및 이용에 관한 법률」 제6조에 따른 도시지역 밖의 토지의 경우에는 10배)를 곱하여 산정한 면적\r\n\r\n② 임대주택에 부가가치세가 과세되는 사업용 건물(이하 \"사업용건물\"이라 한다)이 함께 설치되어 있는 경우에는 주택과 이에 부수되는 토지의 임대의 범위는 다음 각 호에 따른다.\r\n\r\n1. 주택 부분의 면적이 사업용 건물 부분의 면적보다 큰 경우에는 그 전부를 주택의 임대로 본다. 이 경우 그 주택에 부수되는 토지임대의 범위는 제1항과 같다.\r\n\r\n2. 주택 부분의 면적이 사업용 건물 부분의 면적과 같거나 그보다 작은 때에는 주택 부분 외의 사업용 건물 부분은 주택의 임대로 보지 아니한다. 이 경우 그 주택에 부수되는 토지의 면적은 총토지면적에 주택 부분의 면적이 총건물면적에서 차지하는 비율을 곱하여 계산하며, 그 범위는 제1항과 같다.</blockquote>\r\n\r\n\r\n<blockquote><i><b>소득세법 제168조  【 (사업자등록 및 고유번호의 부여) 】</b>(사업자등록 및 고유번호의 부여)\r\n① 새로 사업을 시작하는 사업자는 <u>대통령령으로 정하는 바에 따라 사업장 소재지 관할 세무서장에게 등록</u>하여야 한다. <개정 2018.12.31>\r\n② 「부가가치세법」에 따라 사업자등록을 한 사업자는 해당 사업에 관하여 제1항에 따른 등록을 한 것으로 본다.\r\n③ 이 법에 따라 사업자등록을 하는 사업자에 대해서는 「부가가치세법」 제8조를 준용한다. <개정 2013.6.7>\r\n⑤ 사업장 소재지나 법인으로 보는 단체 외의 사단·재단 또는 그 밖의 단체의 소재지 관할 세무서장은 다음 각 호의 어느 하나에 해당하는 자에게 대통령령으로 정하는 바에 따라 고유번호를 매길 수 있다.\r\n1. 종합소득이 있는 자로서 사업자가 아닌 자\r\n2. 「비영리민간단체 지원법」에 따라 등록된 단체 등 과세자료의 효율적 처리 및 소득공제 사후 검증 등을 위하여 필요하다고 인정되는 자\r\n\r\n<b>민간임대주택에 대한 특별법 제5조(임대사업자의 등록)</b> ① 주택을 임대하려는 자는 <u>특별자치시장ㆍ특별자치도지사ㆍ시장ㆍ군수 또는 구청장(구청장은 자치구의 구청장을 말하며, 이하 \"시장ㆍ군수ㆍ구청장\"이라 한다)에게</u> 등록을 신청할 수 있다.\r\n② 제1항에 따라 등록하는 경우 다음 각 호에 따라 구분하여야 한다.  <개정 2018. 1. 16.>\r\n1. 삭제  <2018. 1. 16.>\r\n2. 민간건설임대주택 및 민간매입임대주택\r\n3. 공공지원민간임대주택, 장기일반민간임대주택 및 단기민간임대주택\r\n③ 제1항에 따라 등록한 자가 그 등록한 사항을 변경하거나 말소하고자 할 경우 시장ㆍ군수ㆍ구청장에게 신고하여야 한다. 다만, 임대주택 면적을 10퍼센트 이하의 범위에서 증축하는 등 국토교통부령으로 정하는 경미한 사항은 신고하지 아니하여도 된다.\r\n④ 제1항부터 제3항까지에 따른 등록 및 신고의 기준과 절차 등에 필요한 사항은 대통령령으로 정한다.</i></blockquote>\r\n\r\n<H3>2. 임대사업자등록과 혜택</H3>\r\n<strong>세무서장에게 하는 즉, 소득세법상 사업자등록은 이번에 의무사항</strong>이나 <strong>자치단체에 하는 민간임대주택법상 사업자등록은 여전히 선택사항</strong>입다. \r\n\r\n<blockquote>민간임대주택에 관한 특별법 [시행 2019. 10. 24.] [법률 제16386호, 2019. 4. 23., 일부개정] 제5조(임대사업자의 등록) ① <strong>주택을 임대하려는 자는 특별자치시장ㆍ특별자치도지사ㆍ시장ㆍ군수 또는 구청장(구청장은 자치구의 구청장을 말하며, 이하 \"시장ㆍ군수ㆍ구청장\"이라 한다)에게 등록을 신청할 수 있다.</strong>\r\n\r\n   ② 제1항에 따라 등록하는 경우 다음 각 호에 따라 구분하여야 한다. <개정 2018.1.16>\r\n\r\n1. 삭제 <2018.1.16>\r\n\r\n2. 민간건설임대주택 및 민간매입임대주택\r\n\r\n3. 공공지원민간임대주택, 장기일반민간임대주택 및 단기민간임대주택\r\n\r\n   ③ 제1항에 따라 등록한 자가 그 등록한 사항을 변경하거나 말소하고자 할 경우 시장ㆍ군수ㆍ구청장에게 신고하여야 한다. <strong>다만, 임대주택 면적을 10퍼센트 이하의 범위에서 증축하는 등 국토교통부령으로 정하는 경미한 사항은 신고하지 아니하여도 된다.</strong>\r\n\r\n   ④ 제1항부터 제3항까지에 따른 등록 및 신고의 기준과 절차 등에 필요한 사항은 대통령령으로 정한다. </blockquote>\r\n\r\n\r\n민간임대주택법상의 등록이 선택사항이긴하나 임대사업자로서 세제혜택 즉, 취득세와 재산세 감면, 다주택자의 양도소득세 중과배제(2018년 9월 13일 이전 취득분에 한함), 필요경비 60%공제(미등록은 50%), 의료보험감면 등의 혜택을 받기 위해서는 필요하다. \r\n\r\n물론 혜택만 있는 건 아니고요 불이익까지는 아니어도 불편도 있다.  신청당시 4년 또는 8년 이상의 의무임대기간을 정해야 하고 또한 임대료를 전년대비 5% 이상 인상하지 못한다. 어길 경우 3000만원에 달하는 과태료를 부담해야 하고, 기존에 받았던 세제혜택도 모두 토해내야 한다.\r\n\r\n먼저 임대소득세의 경우 주택임대소득 분리과세 신고 시 필요경비 및 기본공제 우대의 혜택을 받을 수도 있다. 임대소득이 2000만원을 넘으면 무조건 종합과세 대상이 되며 총수입금액 2000만원 이하 주택임대사업자는 종합과세와 분리과세 중 하나를 선택할 수 있은데 <strong>종합과세되는 경우 세율은 6~42%를 적용받게 되며 분리과세를 선택하는 경우 14%의 단일세율을 적용받게</strong> 되므로 꼼꼼히 따져 유리한 쪽으로의 결정을 조언할 수 있을 것이다.  또 국민주택을 임대하는 경우 감면을 받을 수도 있다. 소형주택 임대사업자 세액감면은 총수입금액 규모에 상관없이 적용 가능하다. \r\n\r\n양도소득세의 경우 장기보유특별공제 우대와 종합부동산세의 경우 합산배제, 지방세(취득세 및 재산세) 감면 등 다양한 세금혜택을 받을 수도 있다. 주택임대업등록은 세무서 또는 지방자치단체를 방문하지 않고도 인터넷을 통해 간편하게 신청할 수 있다.\r\n\r\n<H3>3. 과세기준</H3>\r\n□보유 주택수별\r\n❶ (1주택) 기준시가가 9억 원이 넘는 국내소재 주택 또는 국외소재 주택으로부터 월세 수입이 있는 경우(보증금은 과세 안함.)\r\n❷ (2주택) 월세 수입이 있는 경우(보증금은 과세 안함.)\r\n❸ (3주택 이상) 월세 수입이 있거나 보증금* 합계가 3억 원을 넘는 경우\r\n   * 소형주택(주거전용면적 40㎡ 이하이면서 기준시가 2억 원 이하)은 보증금 과세대상 주택에서 제외\r\n\r\n□임대유형별\r\n❶ (월  세) 기준시가가 9억 원이 넘는 국내소재 1주택 보유자, 국외소재 1주택 보유자, 2주택 이상 보유자\r\n❷ (보증금) 보증금* 합계가 3억 원을 넘는 3주택 이상 보유자\r\n   * 소형주택(주거전용면적 40㎡ 이하이면서 기준시가 2억 원 이하)은 보증금 과세대상 주택에서 제외\r\n\r\n요약하면 \r\n\r\n<strong>2019년 월세 임대수입을 올린 2주택자</strong>와 <strong>보증금 합계가 3억원을 넘는 3주택 이상 소유자</strong>는 <strong>수입금액이 2000만원 이하</strong>라도 소득세를 신고 납부해야 한다.\r\n\r\n이에 따라 해당 주택사업자는 2월 10일까지 수입금액 등의 사업장 현황신고를 하여야 한다. \r\n\r\n*<strong>2019년 12월31일 이전 임대를 시작한 경우</strong>에는 가산세 적용 시 2020년 1월 1일을 임대개시일로 본다. 따라서 올해 1월 21일까지 사업자등록을 신청해야 한다. \r\n\r\n* 5월에는 소득세를 신고․납부해야 한다.\r\n\r\n* 2020년부터는 임대개시일로부터 20일 이내에 사업자등록을 하여야 하며 주택임대사업자가 세무서에 사업자등록을 하지 않을 경우 가산세(수입금액의 0.2%)를 추가로 부담하게 된다. \r\n\r\n임대사업자는 올해 2월 10일까지 2019년도 주택임대 실적분 수입금액과 임대물건의 소재지, 계약 조건 등 사업장 현황을 사업장 관할 세무서에 신고해야 한다. 또한 5월에는 소득세 신고 납부하여야 한다. \r\n\r\n<H3>4. 임대사업자 등록절차</H3>\r\n소득세법에 따른 사업자등록만 신청할 경우에는 홈택스(www.hometax.go.kr)에서 신청이 가능하며 \'민간임대주택에 관한 특별법\'에 따른 임대사업등록과 소득세법에 따른 사업자등록을 함께 하는 경우에는 렌트홈(www.renthome.go.kr)에서 신청하면 된다.\r\n\r\n:<a href =\"http://www.renthome.go.kr/webportal/cont/rgstProcssGdncView.open\">임대사업자등록 절차안내 </a>',0);
INSERT INTO `article_tbl` VALUES (11,1,18,'01091280586','2020-01-03','2021-04-30','0000-00-00','0000-00-00','부동산 거래 실제 특약 모음','1','부동산 거래에서의 특약 한줄 확인설명서의 한줄 기재가 손해배상의 과실을 다투게 되',NULL,'○ 임대인은 임대차 목적물 인도 익일까지 임차인에게 불리한 등기부상 권리관계 변경을 하지 아니하기로 하며 이의 위반시 임차인은 즉시 계약을 해지할 수 있으며 위약금은 계약금의 배액으로 하기로 한다.\r\n\r\n○ 공인중개사는 묵시적 갱신과 관련하여 중개대상물의 하자, 권리관계의 하자, 법령상 이용제한사항 등  확인설명의무를 비롯한 일체의 책임을 지지 아니한다.\r\n\r\n○ 선순위 임대차보증금 현황은 임대인이 고지하지 않았으며(또는 임대인 구술진술에 의하며), 임차인은 임대차 계약서를 가지고 \"확정일자 정보열람\"이 가능함을 공인중개사에게 안내 받았음\r\n\r\n: 계약에서 전입신고시까지 임차인 입장에서 권리의 공백이 발생하며 그에 따른 사고의 예방과 계약해지의 근거마련을 위한 특약\r\n\r\n매도시 \r\n○ 매도인은 소유권등기이행시까지 매도인에게 불리한 권리변경행위를 하지 않기로 하며 이에 위반시 매수인은 즉시 계약을 해지할 수 있으며 위약금은 본 계약 계약금의 배액으로 하기로 한다. \r\n\r\n표준임대차 계약시\r\n○[중개보수] 개업공인중개사는 임대인 또는 임차인의 본 계약 불이행에 대하여 책임을 지지 않는다. 또한 중개보수는 본 계약 체결과 동시에 계약 당사자 쌍방이 각각 지불하며, 개업공인중개사의 고의나 과실 없이 본 계약이 무효, 취소 또는 해제 되어도 중개보수는 지급한다. 공동중개인 경우에 임대인과 임차인은 자신이 중개 의뢰한 개업공인중개사에게 각각 중개보수를 지급한다.\r\n\r\n민간임대주택에 관한 특별법  제43조(임대의무기간 및 양도 등) ① 임대사업자는 임대사업자 등록일 등 대통령령으로 정하는 시점부터 제2호제4호 또는 제5호의 규정에 따른 기간(이하 \"임대의무기간\"이라 한다) 동안 민간임대주택을 계속 임대하여야 하며, 그 기간이 지나지 아니하면 이를 양도할 수 없다.  <개정 2020. 8. 18.>\r\n  ② 제1항에도 불구하고 임대사업자는 <u>임대의무기간 동안에도 국토교통부령으로 정하는 바에 따라 시장ㆍ군수ㆍ구청장에게 신고한 후 민간임대주택을 다른 임대사업자에게 양도할 수 있다. 이 경우 양도받는 자는 양도하는 자의 임대사업자로서의 지위를 포괄적으로 승계하며, 이러한 뜻을 양수도계약서에 명시하여야 한다.</u>\r\n  ③ 제2항은 임대사업자가 임대의무기간이 지난 후 민간임대주택을 양도하는 경우에도 준용한다. 다만, 양수하는 자가 임대사업자로 등록하지 아니하는 경우에는 제2항 후단을 적용하지 아니한다.\r\n  ④ 제1항에도 불구하고 임대사업자는 임대의무기간 중에도 다음 각 호의 어느 하나에 해당하는 경우에는 임대의무기간 내에도 계속 임대하지 아니하고 말소하거나, 대통령령으로 정하는 바에 따라 시장ㆍ군수ㆍ구청장에게 <b>허가를 받아 임대사업자가 아닌 자에게 민간임대주택을 양도할 수 있다.</b>  <개정 2018. 1. 16., 2020. 8. 18.>\r\n  1. 부도, 파산, 그 밖의 대통령령으로 정하는 경제적 사정 등으로 임대를 계속할 수 없는 경우\r\n  2. 공공지원임대주택을 20년 이상 임대하기 위한 경우로서 필요한 운영비용 등을 마련하기 위하여 제21조의2제1항제4호에 따라 20년 이상 공급하기로 한 주택 중 일부를 10년 임대 이후 매각하는 경우\r\n  3. 제6조제1항제11호에 따라 말소하는 경우',0);
INSERT INTO `article_tbl` VALUES (14,1,18,'01091280586','2020-01-03','2021-04-30','0000-00-00','0000-00-00','주택외 부동산의 거래시의 부가가치세에 관하여','1','',NULL,'주로 주택만 거래하다보면 부동산거래에도 부가가치세가 있다는거를 잊고는 한다. \r\n\r\n먼저 주택거래에서도 부가가치세가 부과되는 경우가 있다고 합니다. \r\n\r\n부동산매매업으로 등록하지 국세청이 사업상의 목적이 있는 것으로 간주하는 경우로는 부가가치세법 시행규칙에 따라 ▲부동산 매매업으로 사업자 등록을 내고 주택을 거래하는 경우 ▲사업상의 목적으로 6개월(1월1일∼6월30일 또는 7월1일∼12월31일) 중 한 번 이상 부동산을 사고 두 번 이상 파는 경우가 있습니다.\r\n\r\n<blockquote>제2조(사업의 범위) ① 「부가가치세법 시행령」(이하 \"영\"이라 한다) 제3조제1항제6호 단서에 따른 전ㆍ답ㆍ과수원ㆍ목장용지ㆍ임야 또는 염전은 지적공부상의 지목과 관계없이 실제로 경작하거나 해당 토지의 고유 용도에 사용하는 것으로 한다.\r\n\r\n② 건설업과 부동산업 중 재화를 공급하는 사업으로 보는 사업에 관한 영 제3조제2항에서 \"기획재정부령으로 정하는 사업\"이란 다음 각 호의 어느 하나에 해당하는 사업을 말한다.\r\n\r\n1. 부동산 매매(주거용 또는 비거주용 건축물 및 그 밖의 건축물을 자영건설하여 분양ㆍ판매하는 경우를 포함한다) 또는 그 중개를 사업목적으로 나타내어 부동산을 판매하는 사업\r\n\r\n2. 사업상 목적으로 1과세기간 중에 1회 이상 부동산을 취득하고 2회 이상 판매하는 사업\r\n<cite>부가가치세법 시행규칙 제2조</cite>\r\n</<blockquote>\r\n\r\n또한 근린생활시설로 구분되는 주택의 거래에 있어서의 이에 대해 확인하지 않아 분쟁이 발생하는 경우가 있습니다. 이론적으로야 다중주택은 개별호실에 취사시설을 둘 수 없고 그런 구분이 되나 실제에 있어서는 그 구분이 용이하지 않으며 실제 주택으로 사용하는 경우가 많으며 근린 생활시설의 경우에도 특히 빌라의 건축과정에서 수익성의 문제로 인해 근린생활로 허가받아 실제 주택으로 사용하는 경우가 다수 있습니다. \r\n\r\n이러한 과정에서의 분쟁의 유형으로는 \r\n\r\n1. 이에 따라 매매계약 후 관련 분쟁-위반건축물 여부 이후 미래 부동산 거래에 대한 불안감등의 고객불만\r\n\r\n2. 부가가치세에 대한 부담문제가 발생하고 있습니다. 포괄양수도로 하는 경우 반드시 업종이 같아야 되고 사업자등록도 확인하셔야 합니다. \r\n\r\n3. 전세대출과 관련된 문제 - 불법 건축물이나 근린생활시설의 경우 전세자금대출이 진행되지 않습니다. \r\n\r\n따라서 거래시 <strong>건축물 대장 꼭! 확인</strong> 하셔야 하며 부가가치세의 경우 실질과세의 원칙이라는 것이 있어 실제 주택으로 사용될 경우 그에 대해 비과세의 주장이 있으나 이에 대한 법원의 판단은 다음과 같았습니다. \r\n\r\n[대법원 1996.10.11, 선고, 96누8758, 판결]\r\n\r\n【판시사항】\r\n\r\n[1] 부가가치세의 과세요건인 부동산매매업에 해당하는 부동산 거래행위의 요건\r\n\r\n[2] 근린생활시설로 준공검사를 받은 건물을 용도변경 허가 없이 국민주택규모 면적의 주택으로 개조한 경우, 부가가치세가 면제되는 국민주택에 해당하는지 여부(소극)\r\n\r\n[3] 납세자가 건물을 양도하고 양도소득세를 자진납부한 후에, 그를 부동산매매업자로 인정하여 부가가치세를 부과한 경우, 이중과세에 해당하는지 여부(소극)\r\n\r\n\r\n【판결요지】\r\n\r\n구 조세감면규제법(1991. 12. 27. 법률 제4451호로 개정되기 전의 것) <strong>제74조 제1항 제1호 소정의 부가가치세가 면제되는 국민주택은, 그 법의 목적 등에 비추어 적어도 주택의 용도로 적법하게 건축허가를 받아 그에 따라 건축된 건물만 해당되고, 근린생활시설로 건축허가를 받아 준공검사까지 마친 다음 용도변경의 허가를 받음이 없이 주택으로 개조한 경우</strong>에는, 설사 그 면적이 국민주택 규모에 해당한다고 하더라도 위 규정 <strong>소정의 부가가치세가 면제되는 국민주택에 해당한다고 할 수 없다</strong>.',0);
INSERT INTO `article_tbl` VALUES (16,1,36,'01091280586','2020-01-18','2021-05-03','0000-00-00','0000-00-00','신대림공인중개사사무소 ','0','홍대와 상암동을 연결하는 지역으로 주변지역-망원 연남 상암-과 비교하여 상대적으로',NULL,'대표 : 조항준 \r\n주소 : 서울시 마포구 월드컵북로 188(성산2동)\r\n\r\n홍대와 상암동을 연결하는 지역으로 주변지역-망원 연남 상암-과 비교하여 상대적으로 저렴한 부동산 거래 가격을 형성하고 있다. \r\n\r\n대단지아파트로는 성산시영아파트- 안전진단 D등급(2020.01)-아파트와 대림아파트(약 800세대)가 입지하고 있다. \r\n\r\n하지만 전통적인 주거지역으로 주변에 유흥가등이 입지않지 않고 있는 반명 초중학교가 풍부하게 입지하고 있으며 최근 학원의 입지가 눈에 뛰고 있다. \r\n\r\n초등학교 : 중동초등학교 신북초등학교 \r\n중학교 : 성사중학교 중암중학교',0);
INSERT INTO `article_tbl` VALUES (17,1,32,'01091280586','2020-01-18','2021-05-10','0000-00-00','0000-00-00','간이과세자인 공인중개사의 부가가치세 거래징수','0','간이과세자에게 거래징수 규정은 적용되지 아니하나 간이과세자의 과세표준은 부가가치세',NULL,'부가, 기획재정부 부가가치세제과-415, 2016.08.30\r\n\r\n[ 제 목 ]\r\n간이과세자인 공인중개사의 부가가치세 거래징수 여부\r\n[ 요 지 ]\r\n간이과세자에게 거래징수 규정은 적용되지 아니하나 간이과세자의 과세표준은 부가가치세가 포함된 공급대가이므로 거래상대방으로부터 부가가치세를 수령할 수 있으며 중개보수와 부가가치세를 합산한 금액이 법정 중개보수를 초과하는지 여부는 공인중개사법에 따라 결정될 사항임\r\n[ 회 신 ]\r\n1.「부가가치세법」제31조의 거래징수 규정은 간이과세자에게는 적용되지 않습니다. 그러나 간이과세자의 부가가치세 과세표준은「부가가치세법」제61조 제1항 및 같은 법 제63조 제1항에 따라 부가가치세가 포함된 공급대가이므로 간이과세자는 거래상대방으로부터 부가가치세를 수령할 수 있음.\r\n2. 간이과세자인 공인중개사가 중개보수와는 별도로 부가가치세를 수령하여 그 둘을 합산한 금액이 법정 중개보수를 초과하는지 여부는 중개 보수를 규정한 공인중개사법에 따라 결정될 사항임.\r\n[ 관련법령 ]	○ 부가가치세법 시행령 제31조\r\n\r\n\r\n안건명	  06-0211, 「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제33조제3호(부동산..즐겨찾기에추가\r\n질의	「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제33조제3호에서 부동산 중개업자는 사례ㆍ증여 그 밖의 어떠한 명목으로도 동법 제32조제3항에서 규정하는 수수료를 초과하여 수령하는 것을 금지하고 있는바, 공인중개사가 이러한 법정수수료를 초과하여 부가가치세를 수령하는 것이 「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제33조제3호의 규정에 위반되는지 여부\r\n<strong>회답	「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제32조제3항에서 규정하고 있는 법정수수료에는 부가가치세가 포함되지 아니하므로 공인중개사가 법정수수료를 초과하여 부가가치세를 수령하는 것은 동법 제33조제3호의 규정에 위반되지 않습니다.</strong>\r\n해석기관\r\n및 출처	<해석기관 : 건설교통부, 출처 : 법제처 법령해석포탈서비스(http://ahalaw.moleg.go.kr)>',0);
INSERT INTO `article_tbl` VALUES (20,1,18,'01091280586','2020-01-18','2021-04-30','0000-00-00','0000-00-00','부동산 대리계약에 관하여','0','위임은 당사자일방이 상대방에 대하여 사무의 처리를 위탁하고 상대방이 이를 승낙함으',NULL,'부동산 중개실무에서 대리라는 말을 많이 사용한다.  하지만 우리가 대리라는 말을 쓰는 만치 그 법적인 의미가 넓지는 않다. 그래서 대리란 무엇인지를 먼저 살펴보면 \r\n\r\n가. 대리란 무엇인가?\r\n\r\n대리라는 것은 사적 자치의 확장 보충의 의미를 가진다.  민법 총칙편에 정해진 대리란 대리인이 본인을 위한다는 것을 나타내어 의사표시를 하거나 의사표시를 받아 그 법률효과가 본인에게 직접 생기게 하는 것을 말한다(민법 제114조～제136조). \r\n\r\n여기서의 핵심은 의사표시이며 그것이 대리라고 한다면 나온 사람이 대리인이라는 표현해야 하다는 거다.  그래서 계약서에는 대리기재란이 있다.\r\n\r\n하지만 <strong>실무에서 대리라고 표현되는 대부분의 행위는 이러한 의사표시를 수반하지 않는다</strong>는 것이다.  모든 내용이 권리자에 의해 결정했는데 단지 그 자리에 없어 부인이 나온 경우 계약서에 대리인으로 표시할 이유가 없다.  이것은 법적으로 본다면 ‘제 3자가 타인의 이름으로 한 법률행위(使者의 행위)라고 해서 구분한다.  의사표지의 주체가 권리자가 되고 그 경우 대리인의 표시 없이 권리자의 이름을 나온 사람이 기재한다고 해서 문제될 부분은 없다.  물론 실무적으로 그것을 개업공인중개사가 본인의 의사가 분명하다면 부동산 소유자의 이름을 기재한다고 하여 문제가 될 부분도 없다. \r\n\r\n나. 대리와 위임장의 징구 \r\n\r\n그렇다면 실무에서 계약을 앞둔 시점에 가장 분쟁의 생기는 것이 위임장의 징구와 관련된 사항이고 \r\n\r\n1. 먼저 위임장이 징구(徵求)되어야 하는가를 살펴보면 \r\n\r\n[질의회신] 국토교통부 토지정보과 8622, 2010. 4. 14\r\n\r\n<blockquote>위임은 당사자일방이 상대방에 대하여 사무의 처리를 위탁하고 상대방이 이를 승낙함으로써 그 효력이 생긴다라고 민법에서 규정하고 있는 사항이며 따로 절차를 두고 있지는 않습니다. 따라서 위임에 의하여 거래계약서를 작성할 경우, 중개업자에게 위임관계의 사실확인 의무는 있다할 것이나, 그 사실을 확인하기 위하여 반드시 위임장을 징구하여야 한다고는 볼 수 없을 것으로 생각이 됩니다(유권해석, 국토교통부 8622, 2010. 4. 14).</blockquote>\r\n\r\n라고 하고 있다. \r\n\r\n2. 만약 위임장을 징구하였다면 누구에게 교부하여야 하는가의 문제이다. \r\n\r\n이에 대해 \r\n\r\n법무부 법무심의관실(2017. 5. 31.)은 \r\n\r\n[질의]\r\n\r\n1.주택매매계약시 대리계약을 했을때 본인의 위임장및 인감증명서를 징구하였을 경우 매수인에게 교부해야한지, 공인중개사 사무소에 보관해야 하는지요?\r\n\r\n2. 매수인에게원본을 교부하고 사본을 공인중개사 사무소에 보관하면 되는지요?\r\n\r\n[답변]\r\n\r\n1. 질의의 요지\r\n\r\n ○ 귀하께서 국민신문고를 통해 질의하신 민원에 대해 안내드립니다. 귀하는 ①대리로 주택매매계약을 체결하는 경우 본인의 위임장 및 인감증명서를 매수인에게 교부해야 하는지 아니면 공인중개사 사무소에 보관해야 하는지, ②매수인에게 위임장 및 인감증명서 원본을 교부하고 사본을 공인중개사 사무소에 보관하면 되는 것인지에 대해 질의하셨습니다.\r\n  \r\n2. 검토의견 \r\n\r\n ○ 질의①, ②에 대한 답변  \r\n  -「민법」제563조는 “매매는 당사자 일방이 재산권을 상대방에게 이전할 것을 약정하고 상대방이 그 대금을 지급할 것을 약정함으로써 그 효력이 생긴다.”고 규정하고, 계약의 형식이나 첨부서류 등에 대해서는 특별히 규정하지 않고 있습니다. 따라서 <strong>민법 이외의 다른 법령 및 당사자의 약정이 없는 한 당사자의 인감증명서 및 위임장(대리인이 계약을 체결하는 경우) 등은 매매계약의 효력발생을 위해 반드시 첨부되어야 하는 것은 아니라고 생각</strong>됩니다.\r\n\r\n  - 그런데 귀하께서는 대리인이 본인의 위임장 및 인감증명서를 받은 경우 이를 누구에게 교부해야 되는지를 문의하신 것으로 판단됩니다. 대리인이 본인을 대리하여 매매계약을 체결하는 경우에도 매매계약의 당사자는 본인과 상대방이기 때문에 원칙적으로 <strong>본인의 위임장 및 인감증명서는 공인중개사 사무소가 아닌 상대방에게 교부하는 것이 적절할 것으로 판단</strong>됩니다.\r\n\r\n  - 다만, 본인의 위임장 및 인감증명서 교부와 관련하여 민법 이외의 법령(「공인중개사법」등)에서 특별한 규정이 존재하는 경우 혹은 당사자 사이에 다른 약정이 있는 경우에는 교부의 주체가 달라질 수 있음을 유의하시기 바랍니다.\r\n\r\nQ	공인중개사 갑이 자기의 직계비속 병의 부동산을 병의 위임에 따라 제3의 장소에서 매수자인 을과 부동산매매 계약서를 작성한 경우 갑의 행위가 공인중개사의 업무 및 부동산 거래신고에 관한 법률에 정한 중개행위로 볼 수 있는 지 여부 \r\n\r\n공인중개사의 업무 및 부동산 거래신고에 관한 법률 제2조제1호의 규정에 따라 “중개”라 함은 중개대상물에 대하여 거래당사자간의 매매·교환·임대차 그 밖의 권리의 득실변경에 관한 행위를 알선하는 것을 말하고, 동법 제25조 및 제26조의 규정에 따라 중개업자는 중개의뢰를 받은 중개대상물에 대하여 권리를 취득하고자 하는 중개의뢰인에게 중개대상물 확인·설명서와 거래계약서를 작성·교부하는 시점에 중개행위는 종료하게 됨.\r\n\r\n따라서, <strong>공인중개사의 중개행위는 거래당사자간의 중개의뢰 여부가 전제되어야 하므로 중개의뢰인의 의뢰가 없이 공인중개사가 본인의 직계비속 재산인 중개대상물을 위임에 따라 매수자와 거래계약을 체결한 경우에 공인중개사의 업무 및 부동산거래신고에 관한 법령에 정한 중개행위로 볼 수는 없음.【국민신문고 민원답변】</strong>\r\n\r\nQ	공인중개사(갑)가 자기의 직계비속(병)의 부동산을 병의 위임에 따라 제3의 장소에서 매수자(을)와 부동산 매매계약서를 작성한 경우 갑의 행위가 공인중개사의 업무 및 부동산 거래신고에 관한 법률에서 정한 중개 행위로 볼 수 있는지 여부\r\n \r\n우리나라의 부동산 매매거래방식은 중개업자의 중개에 의하거나 거래 당사자간의 합의에 따른 계약의 형태로 이루어지고 있음. 질의내용처럼 <strong>중개업자(갑)와 매도자(병)가 가족관계일 경우 子인 병의 위임에 의하여 父의 신분인 갑이 병을 대신하여 매매계약을 체결할 수 있으므로(당사자간 거래), 중개업자 신분인 갑(갑은 이중적 지위를 갖음)이 개입되어 있다고 모두 중개행위라고 볼 수 없고</strong>, 이 경우 중개업자의 중개행위인지 여부는 중개의뢰 여부, 중개수수료 수수, 중개업자와 계약자간의 관계 등을 종합적으로 고려하여 판단하여야 함.\r\n\r\n다만, <strong>현행 공인중개사의 업무 및 부동산 거래신고에 관한 법령에서는 계약이 당사자의 합의에 따라 자유로이 이루어지는 점을 고려 별도의 법정서식(내용이나 형식)을 두고 있지 아니하므로 거래계약서의 공인중개사란에 대표자 서명, 등록번호 등이 기재되어있다 하여 이를 근거로 중개업자의 중개행위라고 단정할 수는 없을 것임.</strong>【국민신문고 민원답변】\r\n\r\n\'중개행위로 단정지을 수 없다\'의 의미는 잘 아실라고 생각하고 설명을 생략하겠습니다. \r\n\r\n라. 실무적으로 주의할 점\r\n\r\n 먼저 대리계약은 공인중개사를 위한 장치가 아니다.  대리라는 것이 법률행위를 하는 사람을 위한 제도이지 공인중개사를 위한 제도가 아니라는 것이다.  즉, 대리라는 것에 공인중개사를 방어할 수 있는 수단은 전무하다는 것이다.   따라서 본인에 대한 확신이 없다면 개업공인중개사는 위임장 인감증명을 넘어선 무엇이 있어도 계약을 진행하지 않는 것이 정답니다.\r\n\r\n* 대리계약과 확정일자\r\n<strong>대리인 자격을 나타내는 문구와 대리인의 서명 또는 기명날인이 있으면 임대인(본인)의 서명 또는 기명 날인이 없더라도 확정일자 부여 가능</strong>\r\n- 대리인 자격을 나타내면 충분하므로 반드시 그 표시가 ‘대리인’이어야만 하는 것은 아니고‘代’, ‘대’ 등으로 표시된 경우에도 부여 가능하며, 이 때 대리인의 인적사항이 있는 것이 바람직하나 없더라도 확정일자를 부여할 수 있음(계약서에 대리인의 인적사항을 적는 란이있으면 공란으로 두지 않기 위해 인적사항을 기재하거나 삭선을 그어야 함)[2017 주택임대차확정일자 업무편람 법제처]\r\n\r\n\r\n출처 https://molit.go.kr/USR/policyTarget/m_24066/dtl.jsp?idx=419',0);
INSERT INTO `article_tbl` VALUES (21,1,36,'01031669958','2020-01-22','2021-05-03','0000-00-00','0000-00-00','뉴퍼스트부동산중개법인(주)','0','뉴퍼스트부동산중개법인(주)(New First Real Estate Agency)은 주재원 및 사택에 대하여 다년간의 경험과 노하우에 따른 만족스런 생활써포트와 체계적인관리로 고객의 입장에서 고객의 니즈에 맞춘 맞춤형 컨설팅을 제시하겠습니다.',NULL,'대표 : 공인중개사 최보경  \r\n\r\n뉴퍼스트부동산중개법인(주)은 (사)서울글로벌부동산협회 정회원으로 한국에 진출한 외국계 기업의 사무실이전, 주재원 및 일반사원 사택관리 전문기업입니다. 현재 로컬분들께도 사랑받으며 마곡지구에서 새롭게 단장하였습니다.\r\n<p>부동산은 국지성•개별성으로 인하여 누구에게나 새롭고(New) 처음(First) 일 수밖에 없습니다.\r\n따라서, 뉴퍼스트부동산중개법인(주)(New First Real Estate Agency)은 정부의 다변화된 정책과 규제에 임하는 시장참여자 분들께는 대응전략 수립과 새로운 패러다임 제시하여 고객의 이익 실현에 최선을 다 하겠습니다.\r\n\r\n또한, 주재원 및 사택에 대하여 다년간의 경험과 노하우에 따른 만족스런 생활써포트와 체계적인관리로 고객의 입장에서 고객의 니즈에 맞춘 맞춤형 컨설팅을 제시하겠습니다.\r\n\r\n저희 임직원일동은 고객의 소중한의뢰, 신뢰를 바탕으로 한 확실한 업무추진을 약속드립니다.\r\n감사합니다.',0);
INSERT INTO `article_tbl` VALUES (22,1,18,'01091280586','2020-01-18','2021-04-30','0000-00-00','0000-00-00','대항력 우선변제 최우선 변제 정리','0','임대차의 최우선 변제',NULL,'상담중에 저만 그런지 몰라도 진짜 가장 헷갈리는게 최우선 변제이다.  그담에 대항력과 우선변제인데 물론 대부분의 경우 2요건을 모두 갖추어야 하는데 그중 하나만을 갖춘 경우가 상담의 내용이 됐을때 헷갈릴 수 밖에 없다. \r\n\r\n이를 위해서 대항력과 우선변제권 먼저 구분해보자 \r\n\r\n대항력은 뭔지는 공인중개사는 다 아니까 \r\n\r\n주택임대차보호법 제3조(대항력 등) ① 임대차는 그 등기(登記)가 없는 경우에도 <u>임차인(賃借人)이 주택의 인도(引渡)와 주민등록을 마친 때</u>에는 그 다음 날부터 제삼자에 대하여 효력이 생긴다. 이 경우 전입신고를 한 때에 주민등록이 된 것으로 본다.\r\n\r\n② 주택도시기금을 재원으로 하여 저소득층 무주택자에게 주거생활 안정을 목적으로 전세임대주택을 지원하는 법인이 주택을 임차한 후 지방자치단체의 장 또는 그 법인이 선정한 입주자가 그 주택을 인도받고 주민등록을 마쳤을 때에는 제1항을 준용한다. 이 경우 대항력이 인정되는 법인은 대통령령으로 정한다.  <개정 2015. 1. 6.>\r\n\r\n③ 「중소기업기본법」 제2조에 따른 중소기업에 해당하는 법인이 소속 직원의 주거용으로 주택을 임차한 후 그 법인이 선정한 직원이 해당 주택을 인도받고 주민등록을 마쳤을 때에는 제1항을 준용한다. 임대차가 끝나기 전에 그 직원이 변경된 경우에는 그 법인이 선정한 새로운 직원이 주택을 인도받고 주민등록을 마친 다음 날부터 제삼자에 대하여 효력이 생긴다.  <신설 2013. 8. 13.>\r\n\r\n④ 임차주택의 양수인(讓受人)(그 밖에 임대할 권리를 승계한 자를 포함한다)은 임대인(賃貸人)의 지위를 승계한 것으로 본다.  <개정 2013. 8. 13.>\r\n\r\n⑤ 이 법에 따라 임대차의 목적이 된 주택이 매매나 경매의 목적물이 된 경우에는 「민법」 제575조제1항ㆍ제3항 및 같은 법 제578조를 준용한다.  <개정 2013. 8. 13.>\r\n\r\n⑥ 제5항의 경우에는 동시이행의 항변권(抗辯權)에 관한 「민법」 제536조를 준용한다.  <개정 2013. 8. 13.>\r\n\r\n결론 <strong>대항력만을 위해서는 확정일자 필요하지 않다.<strong> \r\n\r\n주택임대차보호법 제3조의2(보증금의 회수) <u>② 제3조제1항ㆍ제2항 또는 제3항의 대항요건(對抗要件)과 임대차계약증서(제3조제2항 및 제3항의 경우에는 법인과 임대인 사이의 임대차계약증서를 말한다)상의 확정일자(確定日字)를 갖춘 임차인</u>은 「민사집행법」에 따른 경매 또는 「국세징수법」에 따른 공매(公賣)를 할 때에 임차주택(대지를 포함한다)의 환가대금(換價代金)에서 후순위권리자(後順位權利者)나 그 밖의 채권자보다 우선하여 보증금을 변제(辨濟)받을 권리가 있다.  <개정 2013. 8. 13.>\r\n\r\n[전문개정 2008. 3. 21.]\r\n\r\n<strong>우선변제를 위해서는 <확정일자 대항요건(전입신고) 다 갖추어야 한다.</strong>\r\n\r\n임차인인 세입자가 임차주택인 전세나 월세 집에서 임차보증금(전세금이나 월세보증금)을 보호받을 수 있는 권리가 우선변제권과 최우선변제권이다.\r\n\r\n우선변제권은 임차인이 경매나 공매 시 경락대금에서 배당순서대로 배당금을 받는 권리로 대항력요건인 입주(주택의 인도)와 전입신고(주택등록)를 하고 임대차계약서에 확정일자를 받는 경우 인정이 되며, 임차인이 대항력을 갖추면 임차주택이 경매나 공매 되었을 때 경락대금에서 후 순위 권리자에게 우선해 배당금을 받을 수 있다.\r\n\r\n최우선변제권은 임차인이 배당순서에 관계없이 최우선적으로 먼저 배당금을 받는 권리로 주택임대차보호법에 따라 임차주택이 경매나 공매 시 임차인의 소액보증금 중 일정액을 선 순위 권리자보다 우선해 변제를 받을 수 있다.\r\n\r\n<i>주택임대차보호법 제8조(보증금 중 일정액의 보호) ① 임차인은 보증금 중 일정액을 다른 담보물권자(擔保物權者)보다 우선하여 변제받을 권리가 있다. 이 경우 임차인은 주택에 대한 경매신청의 등기 전에 제3조제1항의 요건을 갖추어야 한다.\r\n\r\n② 제1항의 경우에는 제3조의2제4항부터 제6항까지의 규정을 준용한다.\r\n\r\n③ 제1항에 따라 우선변제를 받을 임차인 및 보증금 중 일정액의 범위와 기준은 제8조의2에 따른 주택임대차위원회의 심의를 거쳐 대통령령으로 정한다. 다만, 보증금 중 일정액의 범위와 기준은 주택가액(대지의 가액을 포함한다)의 2분의 1을 넘지 못한다.  <개정 2009. 5. 8.>\r\n\r\n<u>주택임대차보호법 제3조(대항력 등) ① 임대차는 그 등기(登記)가 없는 경우에도 임차인(賃借人)이 주택의 인도(引渡)와 주민등록을 마친 때에는 그 다음 날부터 제삼자에 대하여 효력이 생긴다. 이 경우 전입신고를 한 때에 주민등록이 된 것으로 본다.</u>\r\n\r\n경매신청(경매개시결정기입) 등기 전에 입주와 전입신고의 대항력 요건과 소액보증금 조건을 충족하여야만 인정이 되며 최우선변제 요건을 갖춘 임차인은 낙찰된 가격의 1/2의 범위 내에서 소액보증금 중 일정액을 최 우선으로 변제 받을 수 있다.\r\n\r\n최우선변제 소액보증금 적용범위와 최우선배당금액은 지역별로 차이가 있는데 2016년 9월 기준 서울은 소액보증금 적용범위 1억 원 이하 최우선배당금액은 3400만원, 수도권 과밀억제권역은 보증금 8000만원 이하 2700만원, 광역시(세종, 안산, 용인, 광주 포함) 보증금 6000만원 이하 2000만원, 그 외 지역은 보증금5000만원 이하 1700만원 이다.\r\n\r\n요약하면 <u>최우선변제에는 확정일자는 필요하지 않다</u>.\r\n\r\n주의할 점은\r\n\r\n<b>우선변제권과 최우선변제권 모두 경매나 공매 시 배당요구를 해야 권리행사를 할 수 있다.<b>\r\n\r\n서울 지역 임차인 보증금 범위\r\n\r\n보증금 중 일정액의 범위\r\n<table style=\"width:100%\">\r\n<tr><th>기준시점</th><th>지 역</th><th>임차인 보증금 범위</th><th>보증금 중 일정액의 범위</th></tr>\r\n<tr><td>1990. 2. 19.~</td><td> 서울특별시</td><td> 2,000만원 이하 </td><td>700만원 </td></tr>\r\n<tr><td>1995. 10. 19.~</td><td> 서울특별시</td><td> 3,000만원 이하 </td><td>1,200만원 </td></tr>\r\n<tr><td>2001. 9. 15.~ </td><td>서울특별시</td><td> 4,000만원 이하 </td><td>1,600만원 </td></tr>\r\n<tr><td>2008. 8. 21.~ </td><td>서울특별시</td><td> 6,000만원 이하 </td><td>2,000만원 </td></tr>\r\n<tr><td>2010. 7. 26.~ </td><td>서울특별시</td><td> 7,500만원 이하 </td><td>2,500만원 </td></tr>\r\n<tr><td>2014. 1. 1.~ </td><td>서울특별시</td><td> 9,500만원 이하 </td><td>3,200만원 </td></tr>\r\n<tr><td>2016. 3. 31.~ </td><td>서울특별시</td><td> 1억원 이하 </td><td>3,400만원 </td></tr>\r\n<tr><td>2018. 9. 18.~ </td><td>서울특별시</td><td> 1억 1천만원 이하 </td><td>3,700만원 </td></tr>\r\n<table>',0);
INSERT INTO `article_tbl` VALUES (23,1,31,'01091280586','2021-08-05','2021-08-05','0000-00-00','0000-00-00','우린 왜 ‘반지하’에 살게 됐을까?… 한국 ‘반지하’의 역사 ','0','공인중개사로서 일상으로 대하게 되는 반지하공간과 그에 대해 함께 해야할 고민에 대하여 말해본다.</br>\r\n-영화 ‘기생충’이 보여준 공간과 계급의 벽</br>\r\n-일제시대 ‘토막집’부터 도시 개발 속 밀려난 ‘달동네’까지</br>\r\n',NULL,'[부동산 칼럼] 우린 왜 ‘반지하’에 살게 됐을까?… 한국 ‘반지하’의 역사 \r\n\r\n한때 세기를 놀라게 했던 영화 ‘기생충’. 봉준호 감독 특유의 예술성과 대중성은 세계의 뭇 관객을 사로잡기에 충분했다. 개봉 2년이 지난 지금, 영화 기생충은 조금씩 잊혀 가는 듯하다. 하지만 공인중개사인 필자는 개인적으로 이 영화에서 잊히지 않았으면 하는 부분이 하나 있다. \r\n\r\n그건 바로, 기생충이 우리 사회에 던졌던 ‘거주 공간’에 대한 화두다. 이 영화는 사회적 계급에 따른 ‘거주 공간’의 차이를 분명히 보여준다. 물론 이가 차별인지 차이인지는 각 개인이 판단할 문제지만 필자는 이를 좀 더 현실적인 시각에서 바라보고자 한다. \r\n\r\n▲초호화 단독주택 vs 쪽방촌 반지하 방, ‘집’은 곧 ‘계급’  \r\n기생충은 우리가 드러내기 싫었던 거주의 현실을 극으로 드러냈다. 극 중 최상류층이 사는 한남동 단독주택과 극빈층이 사는 충정로 쪽방촌 반지하 방의 차이는 결코 영화만의 이야기는 아니다. \r\n\r\n서울 도심의 빽빽한 주택가에는 수많은 반지하 방이 있다. 반지하 방에 사는 이들은 대부분이 ‘서민’에 속하며, 보통의 사회는 이들을 ‘하류’로 인식한다. 그럼, 이런 반지하 방은 국내에 어떻게 처음 생기게 됐을까? 필자와 함께 한번 살펴보자.\r\n\r\n▲일제강점기 토막집 ‘살기 위해 땅 속으로’ \r\n반지하의 역사는 역시 도시 빈민층의 발생과 떼려야 뗄 수 없다. 도시 빈민의 시작은 일제강점기 당시 근대화의 시작과 그 괘를 같이한다. 반지하의 역사를 처음 발견할 수 있는 곳은 군산의 ‘근대역사박물관’이다. 군산은 한국의 도시발달에 있어 여러 중요한 의미를 가지는 도시다. 박물관에 따르면, 이곳에서 발견된 반지하는 당시 토막집으로 불리면서 땅을 파고 가마니를 얹어 주거로 사용하기 시작했다. 당시, 일제의 수탈로 인해 도시 인근으로 빈민촌이 형성됐고, 그들은 산등성이에 임시주거지를 만들어 살아갔다. 남자는 주로 막노동을, 여자들은 일본인 집의 식모와 미선공으로 생계를 유지하며. \r\n\r\n▲68년 121사태 이전\r\n한국전쟁이 끝난 후, 불완전한 토지 분배와 농어촌 지역에 대한 차별로 서울로 인구가 모이게 된다. 이러한 과정은 조정래의 소설 \'한강\'에 잘 묘사돼 있다. 빈민들은 서울 변두리 지역에 주거를 형성하게 된다. 다음은 조정래 소설 ‘한강’의 한 부분이다.\r\n\r\n“서울변두리의 야산들이 집 없는 가난한 사람들에게 꼼짝없이 몸을 파먹히듯 옥수동의 그 산동 이미 목부분까지 먹이가 되어 있었다. 그런데 그 야산은 유난히 너저분하고 구질구질해 보였다. 그럴수 밖에 없는 것이 산을 뒤덥다시피 하고 있는 것은 그나마 판잣집이 아니라 움막집들이었다.\'\r\n\r\n땅을 석 자 정도 깊이로 파내고 그 위에 지붕을 덮은 움막집들은 누추할 수 밖에 없었다.\r\n<소설 ‘한강’中, 조정래>\r\n\r\n그런한 옥수동 금호동은 80년대 90년대를 거쳐 나의 대학 4년의 등하교의 배경이 되었다. 산과 집이 구분되지 않고 그런 계단을 매일 올라다닐 주민들의 수고가 쉽게 가늠되지 않았다.” \r\n\r\n소설은 당시의 반지하 움막을 이렇게 묘사하고 있다. \r\n\r\n\'동네 통장이 새끼줄을 둘러 터를 잡아준 천두만의 움막. 연탄 하나 피울 돈 없는 그가 푸들푸들 떨며 움막 입구를 나오자 밤새 그의 움막 뒤로 새로 자리를 잡은 더 보잘것없는 움막들\'\r\n\r\n\r\n▲70년대의 반지하 - 반지하의 태동기 ‘창고에서 집으로’ \r\n1968년, 김신조 일당의 청와대 침투는 한국 사회에 많은 변화를 가져왔다. 군 복무기간의 연장과 중고교 과정에 교련교육의 포함된 계기이기도 하다. 또한 전까지는 없었던 주택에 방어적 개념에서 ‘지하’라는 개념이 생긴다.\r\n\r\n지하는 지상보다 지대가 낮아 당시 사용했던 연탄을 쌓아두는 창고 등으로 사용됐다. 이후 심각한 주거난을 해결하기 위해 80년대부터 주거용으로 사는 것이 합법화됐다.\r\n\r\n특히 1977년 일어난 박흥숙 사건은 한국의 도시화 과정에서의 주거 문제의 심각성을 보여준 사건이었다. 꼬리에 꼬리를 무는 이야기에는 다음과 같은 대화가 오간다.\r\n\r\n참사가 벌어지기 전 박흥숙은 땅굴을 파고 있었는데 “집을 부수면 어디서 사냐”는 질문에 “땅을 파고 살아라”는 답을 했기 때문이다. \r\n\r\n반지하의 흔적은 90년대 초반까지 우리 사회에 계속 남게 된다. 이때 새로 건축되는 주택에는 일종의 벙커의 개념으로 반지하가 설치가 의무화된다. 하지만 이때의 반지하는 지금의 반지하와는 조금 다른 개념이었다.  지금보다 깊고 지붕은 낮은 것을 특징으로 한다. 이렇게 시작된 반지하는 처음에는 임대차가 불법이었으나 심각한 주택난으로 80년대 들어 합법화되고, 이후 노태우 대통령의 500만호 공급정책과 맞물려 반지하 없이는 건축허가가 나지 않을 정도가 된다.\r\n\r\n▲80년대 달동네의 등장 – 도시 빈민층의 집단 거주지역의 등장 \r\n그리고 이때부터 우리사회에 달동네라는 말이 등장한다.  이런 ‘깔끄막‘에 어찌사냐는 어느 어머님의 말로 기억되는 가빠른 언덕을 따라 이어지는 골목길과 지붕낮은 집들이 모여 있는 동네 그것이 내가 기억하는 달동네의 모습이었다.  하지만 이런 달동내도 도시빈민계층들에게는 나름대로의 기능을 가지고 있었다.   저렴한 주거를 제공할 뿐만아니라 그 나름의 생계를 위한 네트웍의 기능을하며 삶을 위한 기반을 제공했다.  \r\n\r\n\r\n▲80년대 후반~현재 - 반지하 주거의 본격화\r\n80년대 후반부터는 또 다른 반지하의 특징이 생긴다. 박흥숙의 집을 헐던 ‘땅을 파고 살아라’라는 철거반원의 말처럼 외형적으로 도시지역의 빈민촌이 급격히 사라지게 되고, 그 자리에 아파트들이 들어서게 된 것이다.  88올림픽의 성화봉송을 위해 반지하는 숨겨야 하는 우리의 현실이었고 대통령의 눈에 보여서는 안되는 숨겨야 하는 공간이었다. \r\n\r\n이 시기 도시의 빈민들은 달동네로 대표되던 그들의 집단 거주지에서도 해체당해 반지하로 흡수된다. 자신의 집을 침탈당해 땅으로 숨어드는 벌레들처럼. 당시에는 88올림픽이 한창이었고, 각종 도시 정비 사업으로 대대적인 개발이 이루어졌다. 이로 인해 도시의 빈민들 강제철거에 처했고, 그 자리에는 고층 아파트들이 들어선다. 이에 선택의 폭이 좁은 도시 빈민들을 위한 달동네조차 쫓겨 반지하를 선택할 수 밖에 없게 된다. \r\n\r\n▲반지하는 도시 빈민 생존을 위한 ‘투쟁의 흔적’이다\r\n이처럼 반지하는 한국의 도시 근대화 과정에서의 패배와 승리를 극명히 드러내고 있다. 그 과정에서의 가진 자와 가지지 못한 자가 공간적으로 어떻게 나눠지는가를 보여준다. \r\n\r\n가진 자의 입장에서는 상전벽해의 시간이었다면, 가지지 못한 자의 입장에서는 아무런 선택도 할 수 없는 좌절이었다. 박흥숙 사건에서 ‘불’을 빼달라던 그들이 가장 두러워 했던 일이 2021년 우리의 삶에서 현실로 만들어지지 않으란 법이 있을까.\r\n\r\n도시 폭동, 그러한 폭력적인 폭발을 막기 위한 정책이 절실하다. 쌓인 불만과 지친 마음은 폭력과 분노로 표출될 수 밖에 없을 테니까.\r\n\r\n이제 우리는 땅으로 숨어버린, 그래서 언젠가 터져 나올지 모를 도시 빈민 문제를 논의하고 그 해결을 위해 함께 노력해야 한다.',0);
INSERT INTO `article_tbl` VALUES (24,1,18,'01091280586','2020-02-06','2021-04-30','2020-02-11','0000-00-00','중개대상물 확인설명서 작성시의 주의 사항을 ','1','실무를 이제 막 시작하는 공인중개사분들이 중개대상물 확인설명서작성 시 주의 사항들',NULL,'초보 공인중개사가 알아야 할 중개실무 \r\n\r\n해지된 계약서의 보관의무 \r\n\r\n초보 공인중개사가 꼭 알아야할 중개대상물 확인설명서 작성요령 \r\n\r\n아마도 대부분의 경우 소홀히 지나쳤을 수 있는 부분입니다.\r\n\r\n<h3>1. 주거용과 비주거용의 구분</h3>\r\n\r\n애매한 경우에는 주거용으로 작성하라 실제로 주거용과 비주거용의 구분이 용이 하지 않은 경우가 있다.  이것이 쟁점이 되어 재판에서 다룬 적이 있는데 그때 판사는 판단은 주거용은 비주거용의 모든 것을 포함한다.  즉, 비주거용은 주거용에 있는 3가지가 없다.  그 외에는 모두 동일하다였다.  그래서 만약 재판에서 다루에 된다면 주거용으로 작성된 경우라면 유리한 쪽에 있게 된다.  하지만 물론 이 경우에도 중개보수 요율이 주거용과 비주거용이 달라 미련은 남게 된다. \r\n\r\n<h3>2. 계약이 해지 또는 해제된 때에도 계약서 보관의무는 있다. </h3>\r\n\r\n<blockquote>법[구 공인중개사법(2018. 4. 17. 법률 제15597호로 일부개정되기 전의 것)을 말하며, 이하 같다] 제26조 제1항은 ‘개업공인중개사는 중개대상물에 관하여 중개가 완성된 때에는 대통령령이 정하는 바에 따라 거래계약서를 작성하여 거래당사자에게 교부하고 대통령령이 정하는 기간 동안 그 사본을 보존하여야 한다\'고 규정하며, 법 제2조 제1호 는 ‘중개라 함은 제3조의 규정에 의한 중개대상물에 대하여 거래당사자간의 매매·교환·임대차 그 밖의 권리의 득실변경에 관한 행위를 알선하는 것을 말한다\'고 규정한다.\r\n\r\n따라서 법 제26조 제1항에서 말하는 ‘중개가 완성된 때\'라 함은 거래당사자간 매매 등을 알선하는 행위가 완성되는 것을 말하므로, 계약의 중요한 내용이 확정되어 당사자 사이에 더 이상 계약의 내용이 보충되거나 변경될 필요가 없을 때에는 중개가 완성되었다고 해석하여야 할 것이다.\r\n\r\n살피건대, 위 인정사실에 변론 전체의 취지를 더하여 인정되는 다음 각 사정들을 종합하면, 제1차 매매계약서가 작성될 당시 이미 중개대상물에 관하여 중개가 완성된 때라고 볼 수 있어, 원고에게는 제1차 매매계약서의 사본을 보존하여야 할 의무가 있다고 볼 수 있다.\r\n\r\n① 제1차, 제2차 매매계약은 모두 이 사건 부동산 관련 소송이 종결된 이후 소유권이전등기를 마치기로 하고 있고, 원고는 양 계약 모두와 관련하여 중개수수료를 받은 사실이 없는바, 특별히 제1차 매매계약에 대해서만 계약의 중요 내용이 미확정된 상태라고 할 수는 없다.\r\n\r\n② 제1차 매매계약과 제2차 매매계약 사이에는 약 4개월의 시간차가 있는바, 제1차 매매계약 당시 중개가 완성되지 않은 상태에서 제2차 매매계약이 체결되었다기보다는 제1차 매매계약 당시 중개가 완성되어 계약이 유효하게 체결되었고, 추후 당사자간의 합의로 제1차 매매계약이 해제된 후 새로운 제2차 매매계약이 다시 체결되었다고 보는 것이 합리적이다.\r\n\r\n③ 법 제26조 제1항은 공인중개사에게 중개가 완성된 때에는 거래계약서의 사본을 보존할 의무를 부과하고 있을 뿐, 거래계약의 유무효나 해제여부에 따라 보존의무에 대한 예외를 두고 있지 않다. 따라서 이 사건 매매계약의 당사자 사이에 제1차 매매계약서를 파기하기로 하는 합의가 있었다고 할지라도, 원고에게 파기된 제1차 매매계약 서의 보존의무가 없다고 볼 수는 없다.\r\n\r\n④ <u>법 제26조 제1항이 공인중개사에게 거래계약서의 보존의무를 부과하고 있는 취지는, 계약의 양 당사자 사이에서 분쟁이 발생하였을 경우를 대비하여 중립적이고 객관적인 입장의 공인중개사가 계약과 관련된 자료를 보존하도록 하는 것도 포함되어 있다</u>고 볼 수 있다. 이 사건의 경우에도 매매계약 체결 당시 매매목적물에 관하여 법적 분쟁이 계속되고 있었으므로, 이 사건 매매계약을 중개한 원고에게는 이 사건 매매계약서를 보존할 의무가 더욱 요구된다고 할 수 있다.\r\n</blockquote>출처 <a href=\"https://m.lawtimes.co.kr/Content/Case-Curation?serial=20689&t=c\" target=\"_blank\">법률신문</a>\r\n\r\n3. 다음은 중개대상물확인설명설 2번\r\n<img src=\"img/inspect1.jpg\">권리관계에 관한 내용입니다. 최근 이 부분에 소유권에 관한 사항의 작성에 있어서 습관적으로 계약서의 작성내용으로 일치시켜 과태료 처분을 당하는 경우가 알려지고 있습니다.\r\n\r\n물론 다른 민원의 처리과정에서 그 부분이 문제가 된거고요 근데 사실 <strong>등기사항증명서에 기재된 주소</strong>는 이후에 별도의 변경등기를 하지 않는다면, 대부분의 경우 비용을 일부러 들여하는 경우는 없습니다.  따라서 시간의 경과에 따라 <strong>계약서에 기재되는 현재의 주소</strong>은 불일치가 발생하게 됩니다. \r\n\r\n이에 따라 이것이 문제되는 것은 형관펜 표시된 것과 같이 등기부 기재사항으로 적시되어 있고 옆에도 반드시 등기부 기재사항을 기재하도록 별도로 표시-재판과정에서 이런 사항도 반영이 되드라구요-되어 있습니다. 이를 400-500만원 과태료 처분의 근거로 삼고 있습니다. \r\n\r\n<p>이러한 처분 건은 제가 알고 있는 건 3건 정도입니다. 그 중 저에게 연락온 한건에 대해서는 도와드리겠다는 약속에 불구하고 이의 신청이 진행이나 그 결과에 대한 피드백이 없었습니다. 일단 소송에 대한 이기고 지고는 문제가 터지고 난 다음의 문제이고 현재로서는 이에 대한 주의가 필요한 단계인거 같습니다.<p>\r\n\r\n따라서 문제가 되었다면 당연히 다투어야 하지만 일단 <strong>실무과정에서 이에 대해 다시 한번 확인</strong>해 주시는것 잊지마시고요 혹시나 그런 문제 생기면 반드시 이의 신청해주세요 조력을 약속 드립니다.\r\n\r\n<p>이길거 같냐고 많이 물어보시는데 저는 중개대상물 확인설명서의 취지나 행정법상의 과태료 처분에 따른 법익을 고려한다면 그러한 과도한 과태료 처분이 정당성이 가지기는 힘들거 같다고 생각을 합니다.\r\n\r\n<h3>4. 공공지원 민간임대주택이란?</h3>\r\n\r\n요즘 표준임대차계약서 및 중개대상물 확인설명서에 나오는 단어인데 이건 모 새로운 수로를 하는거보다 아래 링크에 잘 정리되어 있어 그거로 대체하도록 하겠다.\r\n\r\n<a href=\"https://www.khug.or.kr/hug/web/lr/ph/lrph000002.jsp\" target=\"_blank\">공공지원 민간임대주택이란?<a>\r\n\r\n<h3>5. 별도 등기있음 이란? </h3>\r\n이런 기재가 있는 경우 대부분은 아파트 빌라 등 필지를 합필해서 건축을 하는 경우에 발생한다. 예를 들어 3개필지를 합필해서 건축을 했는데 그 중에 한 필지가 권리 관계에서 법적분쟁등으로 말소뒤지 못하는 권리가 생기게 된경우 그 권리 관계를 유지하기 위해 대상토지에 별도등기가 있음을 등기부상에 표시하게 된다.  경우에 따라는 그 결과에 따라 지분 등에도 영향을 미치게 되기도 하지만 대부분은 별 영향이 없긴하다.  하지만 조합등을 통해 관련내용을 확인해둘 필요는 있게 된다. \r\n\r\n<h3>6. 중개대상물확인ㆍ설명서 ‘권리관계’의 부동산 소유권자를 기재하는 항에서 등기사항증명서의 소유권자의 주소가 주민등록상의 주소가 다른 경우 어떤 주소를 기재하여야 하는지?</h3>\r\n\r\n◇ 처리기관 : 국토교통부 (국토교통부 부동산산업과)\r\n◇ 접수번호 : 2AA-2003-0252885\r\n◇ 접 수 일 : 2020.03.12.\r\n◇ 질 문 자 : 이 기 찬\r\n◇ 답 변 일 : 2020.03.25.\r\n◇ 담당자(연락처)최단비 (044-201-3416)\r\n\r\n[답변 : 국토교통부부동산산업과 2020.03.25]\r\n기본적으로는 등기사항증명서를 확인하여 적도록 하고 있습니다.\r\n다만, 부동산 소유권자(매도인 또는 임대인)의 주소는 거래당사자의 인적사항으로 확인ㆍ설명서 3쪽의 하단부 및 거래계약서 상에 별도로 적어야 하는 사항인 바, 현행화가 되어 있는 주민등록상 주소를 확인하여 적되 등기사항증명서의 주소와 상이함을 해당 란에 별도로 표기하면 될 것으로 판단됩니다.\r\n\r\n[추가 유선질문에 대한 보충답변 취지]\r\n“등기사항증명서의 주소와 상이함을 해당 란에 별도로 표기하면 될 것으로 판단됩니다.”와 관련하여 국토교통부 담당자 주무관 최단비 202.03.25 10:30 전화(044-201-3416)로 확인 결과 <u>‘권리관계’에는 소유권자에 관한 사항은 등기사항부에서 나타나는 사항을 그대로 적고 그 아래에 “주민등록상의 현 주소와 상이 함.”</u>이라고 적으면 되고, <u>주민등록상의 주소는 확인ㆍ설명서의 3쪽 거래당사자 항의 “매도인(소유권자) 주소” 항에 기재하면 된다는 취지의 답변</u>을 하였음.\r\n\r\n<h3>7. 임대보증금에 대한 보증가입 의무</h3>\r\n\r\n임대사업자는 다음의 어느 하나에 해당하는 민간임대주택을 임대하는 경우 임대보증금에 대한 보증에 가입하여야 합니다(「민간임대주택에 관한 특별법」 제49조제1항 및 규제「민간임대주택에 관한 특별법 시행령」 제38조제1항).\r\n1. 민간건설임대주택\r\n2. 분양주택 전부를 우선 공급받아 임대하는 민간매입임대주택\r\n3. 동일 주택단지에서 100호 이상의 주택을 임대하는 민간매입임대주택(2.에 해당하는 민간매입임대주택은 제외)\r\n※ 임대보증금에 대한 보증에 가입해야 하는 임대사업자로서 보증에 가입하지 않은 자는 2년 이하의 징역이나 2천만원 이하의 벌금에 처해집니다(「민간임대주택에 관한 특별법」 제65조제2항제6호).\r\n\r\n<u>민간건설임대주택 또는 분양주택 전부를 우선 공급받아 임대하는 민간매입임대주택의 임대사업자</u>는 사용검사를 받은 날(사용검사 전에 임차인을 모집하는 경우에는 임차인을 모집한 날)부터 임대의무기간이 종료되는 날 까지 임대보증금에 대한 보증에 가입해야 합니다.\r\n\r\n표준임대차 계약서 4. 제1조 ⑤ 임차인은 <u>당월 분의 월임대료를 매달 말일</u>까지 내야하며, 이를 내지 않을 경우에는 연체된 금액에 제4항에 따른 연체요율을 적용하여 계산한 연체료를 더하여 내야 한다\r\n\r\n  제3조(월임대료의 계산) ① <u>임대기간이 월의 첫날부터 시작되지 않거나 월의 말일에 끝나지 않는 경우에는 그 임대기간이 시작되거나 끝나는 월의 임대료는 일할로 산정한다.</u>\r\n\r\n제4조(관리비와 사용료) ① 임차인이 임대주택에 대한 관리비와 사용료를 임대사업자 또는 임대사업자가 지정한 관리주체에게 납부해야 하는 경우에는 <u>특약으로 정하는 기한까지</u> 내야하며, 이를 내지 않을 경우에는 임대사업자는 임차인으로 하여금 연체된 금액에 대해 제1조제4항에 따른 연체요율을 적용하여 계산한 연체료를 더하여 내게 할 수 있다.\r\n\r\n    ② 임대사업자는 <u>관리비와 사용료를 징수할 때에는 관리비와 사용료의 부과 명세서를 첨부하여 임차인에게 이를 낼 것을 통지해야 한다.</u>\r\n\r\n(6쪽 중 5쪽)\r\n\r\n표준계약서 제12조(민간임대주택의 양도) 생략\r\n    ② 임대사업자가 「민간임대주택에 관한 특별법」 제43조제2항에 따라 <u>위 주택을 다른 임대사업자에게 양도하는 경우에는 양수도계약서에서 양도받는 자는 양도하는 자의 임대사업자로서의 지위를 포괄적으로 승계한다는 뜻을 분명하게 밝혀야 한다.</u>',0);
INSERT INTO `article_tbl` VALUES (30,1,34,'01091280586','2020-01-03','0000-00-00','2020-02-21','0000-00-00','[개정법률]부동산 거래의 해제등 신고에 관하','0','',NULL,'<H3><2020 개정법률></H3> \r\n그동안 부동산거래신고 후 거래계약이 해제, 무효 또는 취소된 경우에 그에 대한 신고의무가 없었습니다. 이에 따라 이를 악용해 부동산의 자전거래에 이용하여 시장의 교란행위에 이용된다는 의심이 있어왔고 이에 따라 올해부터는 부동산거래신고등에관한법률 제3조의2(부동산 거래의 해제등 신고)를 신설하여 사유의 발생시 30일 이내에 신고하여야합니다. 이를 위반할 경우 동법 28조에 의해 500만원이하의 과태료 처분사유가 됩니다. \r\n\r\n*자전거래란? \r\n원래는 증권에 쓰이는 용어로 증권 회사가 같은 종류ㆍ가격ㆍ수량으로 매도와 매수 주문을 동시에 하여 주식을 거래하는 방법을 말합니다. \r\n\r\n<p><strong>부동산거래신고등에관한법률 제3조의2(부동산 거래의 해제등 신고)</strong> ① 거래당사자는 제3조에 따라 신고한 후 해당 <strong>거래계약이 해제, 무효 또는 취소(이하 \"해제등\"이라 한다)된 경우 해제등이 확정된 날부터 30일 이내</strong>에 해당 신고관청에 공동으로 신고하여야 한다. 다만, 거래당사자 중 일방이 신고를 거부하는 경우에는 국토교통부령으로 정하는 바에 따라 단독으로 신고할 수 있다.<br>\r\n② 개업공인중개사가 제3조제3항에 따라 신고를 한 경우에는 제1항에도 불구하고 개업공인중개사가 같은 항에 따른 신고(공동으로 중개를 한 경우에는 해당 개업공인중개사가 공동으로 신고하는 것을 말한다)를 할 수 있다. 다만, 개업공인중개사 중 일방이 신고를 거부한 경우에는 제1항 단서를 준용한다.<br>\r\n③ 제1항 및 제2항에 따른 신고의 절차와 그 밖에 필요한 사항은 국토교통부령으로 정한다.<br>\r\n[본조신설 2019. 8. 20.]\r\n<strong>[시행일 : 2020. 2. 21.]</strong> </p>',0);
INSERT INTO `article_tbl` VALUES (32,1,18,'01091280586','2020-01-03','2021-04-30','2020-01-23','0000-00-00','건축법 시행령 (제14조제4항 각 호 외의 ','0','',NULL,'<p><strong>건축법 시행령 (제14조제4항 각 호 외의 부분 단서 신설)</strong> 용도변경에 따른 건축물대장 기재내용의 변경 신청 대상 확대<br>\r\n ㅇ 건축물의 체계적인 관리를 위해 건축물의 용도를 불특정 다수인이 이용하는 시설로서 화재 등 재난 발생 시 피해 우려가 높은 용도*로 변경하는 경우에는 같은 시설군 안에서 용도 변경하는 등의 경우에도 건축물대장 기재내용의 변경을 신청하도록 함<p>\r\n\r\n<p><strong>* 단란주점, 학원, 영화관, 비디오물감상실, 게임제공업소, 노래연습장, 산후조리원, 골프연습장 등 </strong><strong>[시행 2020. 1. 23.] [대통령령 제30145호, 2019. 10. 22., 일부개정] </strong><p>\r\n',0);
INSERT INTO `article_tbl` VALUES (34,1,32,'01091280586','2020-02-12','2021-04-30','2019-12-03','0000-00-00','1세대 1주택 VS 1가구 1주택','0','‘1가구’란 세대별 주민등록표에 기재되어 있는 세대주와 그 가족 및 ‘형제자매’를',NULL,'<h3>같은 듯 다른 1세대 1가구에 관하여</h3>\r\n\r\n1세대 1주택에 대한 고민은 크게 부동산과 관련해서 고민이 되는 분야는 취득-1가구 1주택-과 양도-1세대 1주택-과정에서이다.  <u>취득세는 지방세로 지방세법의 적용을 받으며 양도속득세는 국세로 소득세법의 적용을 받는다.</u>  그러다보니 1세대 1주택을 판단하는데 차이를 가지게 된다.  \r\n\r\n먼저 2020년 개정세법을 기준으로 살펴보면 취득세에 있어서의 1세대 1주택은 다음과 같이 정의하고 있다. \r\n\r\n <blockquote>지방세법 시행령 제29조(1가구 1주택의 범위) ① 법 제15조제1항제2호가목에서 <strong>\"대통령령으로 정하는 1가구 1주택\"</strong>이란 <u>상속인(「주민등록법」 제6조제1항제3호에 따른 재외국민은 제외한다. 이하 이 조에서 같다)과 같은 법에 따른 <strong>세대별 주민등록표(이하 이 조에서 \"세대별 주민등록표\"라 한다)에 함께 기재되어 있는 가족(동거인은 제외한다)으로 구성</strong>된 1가구(상속인의 배우자, <strong>상속인의 미혼인 30세 미만의 직계비속</strong> 또는 상속인이 미혼이고 30세 미만인 경우 그 부모는 각각 <strong>상속인과 같은 세대별 주민등록표에 기재되어 있지 아니하더라도 같은 가구</strong>에 속한 것으로 본다)가 국내에 1개의 주택[주택(법 제11조제1항제8호에 따른 주택을 말한다)으로 사용하는 건축물과 그 부속토지를 말하되, 제28조제4항에 따른 고급주택은 제외한다)]을 소유하는 경우</u>를 말한다.  <개정 2015. 7. 24., 2015. 12. 31., 2016. 12. 30., 2017. 12. 29., 2018. 12. 31.>\r\n  ② 제1항을 적용할 때 1주택을 여러 사람이 공동으로 소유하는 경우에도 공동소유자 각각 1주택을 소유하는 것으로 보고, 주택의 부속토지만을 소유하는 경우에도 주택을 소유하는 것으로 본다.  <신설 2015. 7. 24.>\r\n  ③ 제1항 및 제2항을 적용할 때 1주택을 여러 사람이 공동으로 상속받는 경우에는 지분이 가장 큰 상속인을 그 주택의 소유자로 본다. 이 경우 지분이 가장 큰 상속인이 두 명 이상일 때에는 지분이 가장 큰 상속인 중 다음 각 호의 순서에 따라 그 주택의 소유자를 판정한다.  <개정 2015. 7. 24.>\r\n  1. 그 주택에 거주하는 사람\r\n  2. 나이가 가장 많은 사람 </blockquote>\r\n\r\n하지만 소득세법의 적용을 받는 양도소득에서의 1세대 1주택에 대해서 살펴보면 \r\n\r\n먼저 소득세법 제88조 6호에서는 1세대를 다음가 같이 정의하고 있다. \r\n\r\n<blockquote>6. \"1세대\"란 거주자 및 그 배우자(법률상 이혼을 하였으나 생계를 같이 하는 등 사실상 이혼한 것으로 보기 어려운 관계에 있는 사람을 포함한다. 이하 이 호에서 같다)가 그들과 같은 주소 또는 거소에서 <u>생계를 같이 하는 자</u>[거주자 및 그 배우자의 직계존비속(그 배우자를 포함한다) 및 형제자매를 말하며, 취학, 질병의 요양, 근무상 또는 사업상의 형편으로 본래의 주소 또는 거소에서 일시 퇴거한 사람을 포함한다]와 함께 구성하는 가족단위를 말한다. 다만, 대통령령으로 정하는 경우에는 배우자가 없어도 1세대로 본다.</blockquote>\r\n\r\n여기서 대통령령으로 정하는 경우는 다음과 같이 정의하고 있다. \r\n\r\n<blockquote>근거법령  소득세법 시행령 제152조의3(1세대의 범위) 법 제88조제6호 단서에서 \"대통령령으로 정하는 경우\"란 다음 각 호의 어느 하나에 해당하는 경우를 말한다.\r\n  1. 해당 거주자의 나이가 30세 이상인 경우\r\n  2. 배우자가 사망하거나 이혼한 경우\r\n  3. 법 제4조에 따른 소득이 「국민기초생활 보장법」 제2조제11호에 따른 기준 중위소득의 100분의 40 수준 이상으로서 소유하고 있는 주택 또는 토지를 관리ㆍ유지하면서 독립된 생계를 유지할 수 있는 경우. 다만, 미성년자의 경우를 제외하되, 미성년자의 결혼, 가족의 사망 그 밖에 기획재정부령이 정하는 사유로 1세대의 구성이 불가피한 경우에는 그러하지 아니하다.\r\n[본조신설 2017. 2. 3.]</blockquote>\r\n\r\n<blockquote><a href=\'http://www.reuni.kr/index.html?article_id=34\' target=\'_blank\'> 2020 취득세 주요 내용</a></blockquote>\r\n이러한 1세대의 단위는 <strong>생계의 단위</strong>이다.  즉, 생계를 함께 하는 가족을 하나의 세대로 본다.  따라서 주민등록상 세대를 기준으로 하며, 배우자와 미혼인 30세 미만 자녀는 따로 거주하더라도 1세대에 포함된 것으로 간주한다. 또한 <strong>결혼을 했더라도 30세 미만일 경우 기준중위소득이 40%이상으로 독립된 생활을 유지할 수 있다는걸 입증</strong>*이 가능해야 한다 \r\n\r\n<blockquote>*여기서 \"기준 중위소득\"이란 보건복지부장관이 급여의 기준 등에 활용하기 위하여 중앙생활보장위원회의 심의·의결을 거쳐 고시하는 국민 가구소득의 중위값을 말한다(국민기초생활 보장법 제2조 제11호).\r\n\r\n2020년에는 <strong>1인가구 1,757,194 2인가구 2,991,980</strong> 3인가구 3,870,577 4인가구 4,749,174으로 결정되었다.</blockquote>\r\n\r\n정말 이러한 지방세와 소득세법의 차이를 더군다나 실제적용에서 판단하기는 쉽지 않아 이를 판례에서 찾아보면 3심-대법원 2014두42377(2015.01.15) 취득세 판례에서는 <blockquote>그런데, ① 소득세법 제89조에서는 ‘1가구’와 달리 ‘1세대’라는 용어를 사용하고 있고, 같은 법 시행령 제154조 제1항에서는 <u>‘1세대’</u>를 \"거주자 및 그 배우자가 그들과 <u>동일한 주소 또는 거소에서</u> 생계를 같이 하는 가족과 함께 구성하는 1세대\"라고 규정하고 있으므로, <u>‘1가구’는 ‘1세대’와는 다른 용어</u>인 점, ② 조세감면요건 규정 가운데 명백히 특혜규정이라고 볼 수 있는 것은 엄격하게 해석하는 것이 조세공평의 원칙에 부합하는 점(<대법원 2009. 8. 20. 선고, 2008두11372 판결> 등 참조) 등에 비추어 보면, 위 규정에서 말하는 <u>‘1가구’는 동일 세대에서 생계를 같이하는 경우로 한정하여 축소 해석할 수는 없고, 법문언대로 ‘세대별 주민등록표에 기재되어 있는 세대주와 그 가족(나아가 소득세법 시행령 제154조 제6항은 ‘가족’이라 함은 거주자와 그 배우자의 직계존비속(그 배우자를 포함한다) 및 ‘형제자매’를 말하며, 취학ㆍ질병의 요양, 근무상 또는 사업상의 형편으로 본래의 주소 또는 거소를 일시퇴거한 자를 포함한다고 규정하고 있다.)’으로 엄격하게 해석</u>하여 <u>세대별 주민등록표의 기재에 따라 획일적으로 판단하여야 할 것</u>이다.</strong> 출처 : <a href=\"http://www.olta.re.kr/explainInfo/detailView/decisionDtlView.do?srchWrd=&relationshipNum=20146119&num=60073802#\" target=\"_blank\">지방세 법령정보 시스템</a></blockquote>\r\n\r\n이라고 적시하고 있다.  \r\n\r\n따라서 이를 보면 취득세에서의 1가구란 세대별 주민등록표의 개념이고 1세대는 생계의 개념으로 판단할 수 있다. \r\n\r\n이중 2020년의 개정 세법에서 눈에 뛰는 부분이 취득세 부분에서 있었다.  즉, 그동안 낮은 세율을 적용받은 주택의 유상취득에서\r\n\r\n○ 그러나 4주택 이상을 보유하는 다주택자의 경우까지 낮은 세율을 적용하면 주택 소유 격차를 확대하여 서민 주택난을 가중할 우려가 있고, 조세형평성을 저해한다는 지적이 계속되어 특례세율 적용대상에서 제외하기로 한 것이다.\r\n\r\n○ 이 때, 1세대는 주민등록상 세대를 기준으로 하며, 배우자와 미혼인 30세 미만 자녀는 따로 거주하더라도 1세대에 포함된 것으로 간주한다.\r\n\r\n또한 이번 취득세 개정의 주요목표는 (취득세율) 문턱효과 개선에 촛점을 두었다. \r\n\r\n<blockquote><문턱효과>\r\n□ 현행 주택 취득세율은 6억원 이하 1%, 6억원 초과 ~ 9억원 이하 2%, 9억원 초과 3%의 계단형 구조여서, 6억원과 9억원에서 취득가액이 조금만 상승해도 상위구간의 세율이 적용되어 취득세액이 크게 증가하는 취득세액이 크게 증가하는 문제점이 있었다.</blockquote>\r\n\r\n그리고 실무적으로 많이 질문되는 경우가 \'30세이상으로 한집에 사는 경우 세대 분리가 가능한가?\'이다. 먼저 정확히 표현하면 주민등록표의 분리로 말하여 져야 할 것 같다. 이때는 <strong>한지붕 세대분리</strong>라고 하여 가능하다.  이는 민원 24시나 주민센터에서 가능하고 민원 24시보다는 주민센터가 편리하다. \r\n\r\n\r\n실제>>\r\n	○ 상속으로 인하여 1가구 1주택 및 부속토지를 취득하는 경우 취득세가 감면됩니다.\r\n - 취득 당시(피상속인의 사망일) 상속주택 외 주택 소유 사실이 차후 확인되면 감면받은 세액과 가산세가 추징됨. 농가주택, 무허가 주택을 소유하고 있는 경우도 감면 대상에서 제외\r\n\r\n-이에 남편명의의 1주택에 살고 있던 분이 갑작스럽게 돌아가시게 도면서 상속이 이루어지면서 취득세 감면을 기대한 경우 \r\n\r\n근데 남편분과 함께 그 여동생이 전입이 되어 있었는데 그분의 집이 있어서 최득세 감면이 안되는 경우를 보았습니다. \r\n\r\n일단 취득세는 >같은 듯 다른 1세대 1가구에 관하여</h3>\r\n\r\n1세대 1주택에 대한 고민은 크게 부동산과 관련해서 고민이 되는 분야는 취득-1가구 1주택-과 양도-1세대 1주택-과정에서이다.  <u>취득세는 지방세로 지방세법의 적용을 받으며 양도속득세는 국세로 소득세법의 적용을 받는다.</u>  그러다보니 1세대 1주택을 판단하는데 차이를 가지게 된다.  \r\n\r\n먼저 2020년 개정세법을 기준으로 살펴보면 취득세에 있어서의 1세대 1주택은 다음과 같이 정의하고 있다. \r\n\r\n <blockquote>지방세법 시행령 제29조(1가구 1주택의 범위) ① 법 제15조제1항제2호가목에서 <strong>\"대통령령으로 정하는 1가구 1주택\"</strong>이란 <u>상속인(「주민등록법」 제6조제1항제3호에 따른 재외국민은 제외한다. 이하 이 조에서 같다)과 같은 법에 따른 <strong>세대별 주민등록표(이하 이 조에서 \"세대별 주민등록표\"라 한다)에 함께 기재되어 있는 가족(동거인은 제외한다)으로 구성</strong>된 1가구(상속인의 배우자, <strong>상속인의 미혼인 30세 미만의 직계비속</strong> 또는 상속인이 미혼이고 30세 미만인 경우 그 부모는 각각 <strong>상속인과 같은 세대별 주민등록표에 기재되어 있지 아니하더라도 같은 가구</strong>에 속한 것으로 본다)가 국내에 1개의 주택[주택(법 제11조제1항제8호에 따른 주택을 말한다)으로 사용하는 건축물과 그 부속토지를 말하되, 제28조제4항에 따른 고급주택은 제외한다)]을 소유하는 경우</u>를 말한다.  <개정 2015. 7. 24., 2015. 12. 31., 2016. 12. 30., 2017. 12. 29., 2018. 12. 31.>\r\n  ② 제1항을 적용할 때 1주택을 여러 사람이 공동으로 소유하는 경우에도 공동소유자 각각 1주택을 소유하는 것으로 보고, 주택의 부속토지만을 소유하는 경우에도 주택을 소유하는 것으로 본다.  <신설 2015. 7. 24.>\r\n  ③ 제1항 및 제2항을 적용할 때 1주택을 여러 사람이 공동으로 상속받는 경우에는 지분이 가장 큰 상속인을 그 주택의 소유자로 본다. 이 경우 지분이 가장 큰 상속인이 두 명 이상일 때에는 지분이 가장 큰 상속인 중 다음 각 호의 순서에 따라 그 주택의 소유자를 판정한다.  <개정 2015. 7. 24.>\r\n  1. 그 주택에 거주하는 사람\r\n  2. 나이가 가장 많은 사람 </blockquote>\r\n\r\n하지만 소득세법의 적용을 받는 양도소득에서의 1세대 1주택에 대해서 살펴보면 \r\n\r\n먼저 소득세법 제88조 6호에서는 1세대를 다음가 같이 정의하고 있다. \r\n\r\n<blockquote>6. \"1세대\"란 거주자 및 그 배우자(법률상 이혼을 하였으나 생계를 같이 하는 등 사실상 이혼한 것으로 보기 어려운 관계에 있는 사람을 포함한다. 이하 이 호에서 같다)가 그들과 같은 주소 또는 거소에서 <u>생계를 같이 하는 자</u>[거주자 및 그 배우자의 직계존비속(그 배우자를 포함한다) 및 형제자매를 말하며, 취학, 질병의 요양, 근무상 또는 사업상의 형편으로 본래의 주소 또는 거소에서 일시 퇴거한 사람을 포함한다]와 함께 구성하는 가족단위를 말한다. 다만, 대통령령으로 정하는 경우에는 배우자가 없어도 1세대로 본다.</blockquote>\r\n\r\n여기서 대통령령으로 정하는 경우는 다음과 같이 정의하고 있다. \r\n\r\n<blockquote>근거법령  소득세법 시행령 제152조의3(1세대의 범위) 법 제88조제6호 단서에서 \"대통령령으로 정하는 경우\"란 다음 각 호의 어느 하나에 해당하는 경우를 말한다.\r\n  1. 해당 거주자의 나이가 30세 이상인 경우\r\n  2. 배우자가 사망하거나 이혼한 경우\r\n  3. 법 제4조에 따른 소득이 「국민기초생활 보장법」 제2조제11호에 따른 기준 중위소득의 100분의 40 수준 이상으로서 소유하고 있는 주택 또는 토지를 관리ㆍ유지하면서 독립된 생계를 유지할 수 있는 경우. 다만, 미성년자의 경우를 제외하되, 미성년자의 결혼, 가족의 사망 그 밖에 기획재정부령이 정하는 사유로 1세대의 구성이 불가피한 경우에는 그러하지 아니하다.\r\n[본조신설 2017. 2. 3.]</blockquote>\r\n\r\n<blockquote><a href=\'http://www.reuni.kr/index.html?article_id=34\' target=\'_blank\'> 2020 취득세 주요 내용</a></blockquote>\r\n이러한 1세대의 단위는 <strong>생계의 단위</strong>이다.  즉, 생계를 함께 하는 가족을 하나의 세대로 본다.  따라서 주민등록상 세대를 기준으로 하며, 배우자와 미혼인 30세 미만 자녀는 따로 거주하더라도 1세대에 포함된 것으로 간주한다. 또한 <strong>결혼을 했더라도 30세 미만일 경우 기준중위소득이 40%이상으로 독립된 생활을 유지할 수 있다는걸 입증</strong>*이 가능해야 한다 \r\n\r\n<blockquote>*여기서 \"기준 중위소득\"이란 보건복지부장관이 급여의 기준 등에 활용하기 위하여 중앙생활보장위원회의 심의·의결을 거쳐 고시하는 국민 가구소득의 중위값을 말한다(국민기초생활 보장법 제2조 제11호).\r\n\r\n2020년에는 <strong>1인가구 1,757,194 2인가구 2,991,980</strong> 3인가구 3,870,577 4인가구 4,749,174으로 결정되었다.</blockquote>\r\n\r\n정말 이러한 지방세와 소득세법의 차이를 더군다나 실제적용에서 판단하기는 쉽지 않아 이를 판례에서 찾아보면 3심-대법원 2014두42377(2015.01.15) 취득세 판례에서는 <blockquote>그런데, ① 소득세법 제89조에서는 ‘1가구’와 달리 ‘1세대’라는 용어를 사용하고 있고, 같은 법 시행령 제154조 제1항에서는 <u>‘1세대’</u>를 \"거주자 및 그 배우자가 그들과 <u>동일한 주소 또는 거소에서</u> 생계를 같이 하는 가족과 함께 구성하는 1세대\"라고 규정하고 있으므로, <u>‘1가구’는 ‘1세대’와는 다른 용어</u>인 점, ② 조세감면요건 규정 가운데 명백히 특혜규정이라고 볼 수 있는 것은 엄격하게 해석하는 것이 조세공평의 원칙에 부합하는 점(<대법원 2009. 8. 20. 선고, 2008두11372 판결> 등 참조) 등에 비추어 보면, 위 규정에서 말하는 <u>‘1가구’는 동일 세대에서 생계를 같이하는 경우로 한정하여 축소 해석할 수는 없고, 법문언대로 ‘세대별 주민등록표에 기재되어 있는 세대주와 그 가족(나아가 소득세법 시행령 제154조 제6항은 ‘가족’이라 함은 거주자와 그 배우자의 직계존비속(그 배우자를 포함한다) 및 ‘형제자매’를 말하며, 취학ㆍ질병의 요양, 근무상 또는 사업상의 형편으로 본래의 주소 또는 거소를 일시퇴거한 자를 포함한다고 규정하고 있다.)’으로 엄격하게 해석</u>하여 <u>세대별 주민등록표의 기재에 따라 획일적으로 판단하여야 할 것</u>이다.</strong> 출처 : <a href=\"http://www.olta.re.kr/explainInfo/detailView/decisionDtlView.do?srchWrd=&relationshipNum=20146119&num=60073802#\" target=\"_blank\">지방세 법령정보 시스템</a></blockquote>\r\n\r\n이라고 적시하고 있다.  \r\n\r\n따라서 이를 보면 취득세에서의 1가구란 세대별 주민등록표의 개념이고 1세대는 생계의 개념으로 판단할 수 있다. \r\n\r\n이중 2020년의 개정 세법에서 눈에 뛰는 부분이 취득세 부분에서 있었다.  즉, 그동안 낮은 세율을 적용받은 주택의 유상취득에서\r\n\r\n○ 그러나 4주택 이상을 보유하는 다주택자의 경우까지 낮은 세율을 적용하면 주택 소유 격차를 확대하여 서민 주택난을 가중할 우려가 있고, 조세형평성을 저해한다는 지적이 계속되어 특례세율 적용대상에서 제외하기로 한 것이다.\r\n\r\n○ 이 때, 1세대는 주민등록상 세대를 기준으로 하며, 배우자와 미혼인 30세 미만 자녀는 따로 거주하더라도 1세대에 포함된 것으로 간주한다.\r\n\r\n또한 이번 취득세 개정의 주요목표는 (취득세율) 문턱효과 개선에 촛점을 두었다. \r\n\r\n<blockquote><문턱효과>\r\n□ 현행 주택 취득세율은 6억원 이하 1%, 6억원 초과 ~ 9억원 이하 2%, 9억원 초과 3%의 계단형 구조여서, 6억원과 9억원에서 취득가액이 조금만 상승해도 상위구간의 세율이 적용되어 취득세액이 크게 증가하는 취득세액이 크게 증가하는 문제점이 있었다.</blockquote>\r\n\r\n그리고 실무적으로 많이 질문되는 경우가 \'30세이상으로 한집에 사는 경우 세대 분리가 가능한가?\'이다. 먼저 정확히 표현하면 주민등록표의 분리로 말하여 져야 할 것 같다. 이때는 <strong>한지붕 세대분리</strong>라고 하여 가능하다.  이는 민원 24시나 주민센터에서 가능하고 민원 24시보다는 주민센터가 편리하다. \r\n\r\n\r\n실제>>\r\n	○ 상속으로 인하여 1가구 1주택 및 부속토지를 취득하는 경우 취득세가 감면됩니다.\r\n - 취득 당시(피상속인의 사망일) 상속주택 외 주택 소유 사실이 차후 확인되면 감면받은 세액과 가산세가 추징됨. 농가주택, 무허가 주택을 소유하고 있는 경우도 감면 대상에서 제외\r\n\r\n-이에 남편명의의 1주택에 살고 있던 분이 갑작스럽게 돌아가시게 도면서 상속이 이루어지면서 취득세 감면을 기대한 경우 \r\n\r\n근데 남편분과 함께 그 여동생이 전입이 되어 있었는데 그분의 집이 있어서 최득세 감면이 안되는 경우를 보았습니다. \r\n\r\n일단 취득세는 가구를 기준으로 삼고 가구는 세대별 주민등록표에 함께 기재된 가족으로 구성된것을 의미하는 데 이때 가족은 상속인을 기준으로 거주자와 그 배우자의 직계존비속(그 배우자를 포함한다) 및 ‘형제자매’를 포함하는데 세대별 주민등록표에 기재된 여동생이 국내에 주택을 보유하고 있었기 때문입니다. 이때 주택은 농가주택, 무허가 주택을 소유하고 있는 경우도 감면 대상에서 제외됩니다. ',0);
INSERT INTO `article_tbl` VALUES (35,1,32,'01091280586','2020-02-12','2021-04-30','0000-00-00','0000-00-00','[1] 형사범죄에 대한 고소장을 직접 제출해','0','',NULL,'나에게 정말 작은 땅이 있다.  두렁으로 자연 경계를 이루고 있었는데 어느날 다음(daum)의 항공촬영 사진을 보니 형상의 변경이 있음을 알게되었다.  그래서 2020년 1월 12일 현장을 방문 확인한 결과 소유자인 저에게 연락한번 없이 메꿔버려 기존의 경계를 확인할수도 없고 그리인해 재산권의 행사 또한 불가능하게 만들었다.  인근 아마도 빌라단지 조성과정에서 제 토지가 그 입구에 있어 범죄행위가 발생한거 같고 이후에 그 형상대로 단지 집입등을 위한 용도로 사용한 듯한 느낌이었다.  그래서 난생 처음으로 고소장이라는 접수해 보고 그 과정을 기록으로 남겨보기로 했다. \r\n\r\n1. 일단 그것이 어떤 죄가 되는지 부터 살펴봤다.  우리\r\n\r\n형법 제370조(경계침범) 경계표를 손괴, 이동 또는 제거하거나 기타 방법으로 토지의 경계를 인식 불능하게 한 자는 3년 이하의 징역 또는 500만원 이하의 벌금에 처한다.  <개정 1995. 12. 29.>\r\n\r\n<blockquote>경계침범죄(境界侵犯罪) 계표(界表)를 손괴·이동 또는 제거하거나 기타의 방법으로 토지의 경계를 인식불능하게 하는 죄. 계표의 손괴, 이동 또는 제거는 토지의 경계를 인식불능하게 하는 행위의 예시이고, 기타의 방법으로 경계를 인식불능하게 하는 행위도 동조의 범죄를 구성한다.</blockquote>\r\n\r\n\'경계표\'는 토지의 경계를 표시하는 표지(標識)이다. 경계표는 그것이 어느 정도 객관적으로 통용되는 사실상의 경계를 표시하는 것이라면 영속적인 것이 아니고 일시적인 것이라도 상관이 없으며, 비록 실제상의 경계선에 부합되지 않는 경계표라 할지라도 그것이 종전부터 일반적으로 승인되어 온 것이라면 계표에 해당된다라고 해석하고 있다.\r\n\r\n2. 그래서 일단 고소라는걸 해야 하는 상황임은 어렵지 않게 판단할 수 있었다.  문의에 대한 답은 많이해봤는데 실제로 내가 진행본적이 없어놔서 고소장을 접수해봤다.  이왕이면 부동산범죄관련 범죄를 선택했고   \r\n\r\n<blockquote>고소는 서면 또는 구두 진술로 가능하나, 반드시 검사 또는 사법경찰관에게 해야 합니다. 구두로 고소한 경우 수사 기관은 조서를 작성해야 합니다. <strong>고소장은 일정한 양식이 없습니다. 다만, 고소인과 피고소인의 인적 사항, 고소하는 범죄사실, 처벌을 원하는 의사 표시가 포함되어 있어야 합니다.</strong>\r\n\r\n피고소인의 인적 사항을 몰라도 고소할 수 있지만, 피고소인을 특정하기 위해서는 고소인이 피해 당한 사실이 구체 적으로 밝히고, 피해사실에 대한 증빙자료를 첨부하여야 합니다.\r\n\r\n고소는 대리인을 지정하여 대리인으로 하여금 고소하게 하더라도, 반드시 본인의 명의로 해야 합니다.가명이나 다 른 사람의 명의로 고소한 사실이 밝혀질 경우 수사기관은 수사를 중단하고 사건을 종결할 수 있습니다.(http://www.spo.go.kr/site/spo/01/10101050200002018112210.jsp)</blockquote>\r\n\r\n확인하였지만 일단 관할 경찰서를 확인하여보니 충남아산경찰서였다.  2020년 1월 13일 아산 경찰서 홈페이지http://www.cnpolice.go.kr/SEO/AS/를 찾다 적당한곳을 찾지 못해 서장에게 바란다에 올렸다.  그러면 당담부서를 찾아서 답을 해주겠지 기대를 했지만 통상 민원의 답변기한인 7일을 넘겨도 그에 대한 답은 없었다.(이에 대한 답은 2020년 2월 20일까지도 없다.)  결국 국민신문고를 통해 민원을 접수하고서야 답을 얻을 수 있었다. \r\n\r\n특별한 양식이 없다고는 하지만 그래도 인터넷을 찾아보니 그럴듯한 경찰서의 양식을 찾을 수 있어 그것을 이용했다.  그리고 피의자를 특정할 수는 없어-그걸 특정할 수 있다면 고소라는 과정도 필요없었을 수도 있고 하지만 그것을 찾는 것도 경찰의 일이라고 생각해서-그대로 비워둔채 항공사진을 이용한 증거사진과 현장방문시 촬열한 증거사진을 프린트해서 첨부했다. \r\n\r\n3. 우편으로 고소가 가능함을 알고 민원 답변 안내에 따라 고소장을 우편으로 표지에 친절하게 고소장 재출이라고까 써서 우편 발송하였고 1월 29일 우편도달을 확인하였습니다.  하지만 현재까지 아무런 진행이 없다.  결국 그래서 다시 국민신문고를 통해 또 다시 경찰청에 민원을 접수하게 되었다. \r\n\r\n그리고 고소인의 권리와 의무를 살펴보았다.\r\n\r\n<blockquote><H4>고소인의 권리·의무</H4>\r\n고소인은 수사기관에 출석하여 고소사실을 진술할 수 있고 사건 결과를 통지 받을 수 있습니다. 검사가 고소사건을 불기소 처분한 경우, 처분의 이유를 물을 수 있고 이의제기(항고, 재정신청)도 할 수 있습니다.고소인은 수사기관의 수사에 협조할 의무가 있고 수사기관의 협조요청에 응하지 않을 경우 수사기관은 수사를 중단 하고 사건을 종결할 수 있습니다.</blockquote>\r\n\r\n그 사이 1월 28일 민원실에 전화를 했다.  고소장을 우편접수할려고 하는데 어디로 접수하면 되냐 고소장접수하면 접수학인은 어떻게 확인하냐의 두가지 질문였는데 답은 인터넷 보면 나온다고 한다.  이런 답을 바라고 전화한건 아니었는데...그래도 이후 인터넷 고발접수확인이 가능-민원 24에거 관할 경찰서별로 조회할 수 있다.-함을 알고 확인해봤는데 그 조차도 확인이 되지 않았다. \r\n\r\n여기까지 경험하면서 느낀 점은 너무도 쉽고 너무도 당연한 과정을 참 힘들게 한다는 생각이 들었다.  이후 진행과정도 진행에 따라 공개하도록 하겠습니다. ',0);
INSERT INTO `article_tbl` VALUES (38,1,31,'01091280586','2020-02-15','2021-04-30','0000-00-00','0000-00-00','중개보수 청구소송 실무(준비중)','0','',NULL,'중개실무에서 가장 빠르게 변화되 나가는 것 중에 하나가 중개보수일 것입니다.  예전처럼 복비의 개념이 아니고 이제는 보수의 개념으로 정착하면서 법적이 쟁점이 많아지고 소비자나 공인중개사나 그 법적인 분쟁을 굳이 피하지 않습니다.  그에 따라 예전과 같이 무조건 조정을 통해 법정한도의 반이 아니고 이제는 판결을 통해 전액을 받는 경우도 많아지고 있습니다. \r\n\r\n하지만 이를 처음 접하는 입장에서는 많은 부분이 어렵기만 합니다.  공인중개사의 입장에서는 많은 경우 가능하면 법적인 분쟁을 피할려고하고 \r\n\r\n*실제 소송에서 가장 쟁점이 되는 부분은* \r\n실제 소송에서 가장 쟁점이 많이 되는 부분은 합의의 존재여부입니다.  \r\n\r\n*변호사 없이 가능한지*\r\n대부분의 중개보수 청구는 나홀로 소송으로 진행된다.  왜냐면 중개보수의 특성상 대부분은 변호사를 고용하기에 부담스러운 금액이다. \r\n\r\n*조정명령을 반드시 받아들여야 하는지*\r\n조정과정이라는게 어르고 달래는 거다. 쉽게말해 줘야할 사람에는 어짜피줘야 할 거 빨리줘라 재판으로 가봐야 손해다 받아야 할 사람에는 이거 재판으로 가면 진다. 그러니까 조정을 받아들여라 등의 얘기들이 나온다고 한다.  하지만 조정을 받아들이지 않고 재판을 통해 승소한 경우는 수없이 ㅁ많다. 심리적인 두려움을 극복하는 게 관건이다.  \r\n',0);
INSERT INTO `article_tbl` VALUES (39,1,32,'01091280586','2020-02-15','2021-05-07','2021-06-01','0000-00-00','[국민신문고]직접거래의 판단','0','부인명의로 된 임대차 계약의 전세물건(중개업자의 전세권이 아닌 물건)을 남편인 중',NULL,'공인중개사의 업무 및 부동산 거래신고에 관한 법률 제33조제6호에 중개업자 등이 중개의뢰인과 직접거래를 하거나 거래당사자 쌍방을 대리하는 행위를 금지행위로 규정하고 있음. 질의내용과 같이 부인명의로 된 임대차 계약의 전세물건(중개업자의 전세권이 아닌 물건)을 남편인 중개업자가 의뢰를 받아 중개를 하는 경우 동 규정에서 정한 직접거래로 보기 어려움.【국민신문고 민원답변】\r\n\r\n출처>http://www.molit.go.kr/USR/policyTarget/dtl.jsp?idx=419',0);
INSERT INTO `article_tbl` VALUES (41,1,18,'01091280586','2020-02-17','2021-04-30','0000-00-00','0000-00-00','내용증명의 작성','0','',NULL,'<H4>내용증명(內容證明)이란</H4>\r\n\r\n내용증명이란 등기취급을 전제로 우체국창구 또는 정보통신망을 통하여 발송인이 수취인에게 어떤 내용의 문서를 언제 발송하였다는 사실을 우체국이 증명하는 특수취급제도를 말합니다. (「우편법」 제15조제3항 및 「우편법 시행규칙」 제25조제1항제4호가목).\r\n\r\n“배달증명”이란 등기취급을 전제로 우편물의 배달일자 및 수취인을 배달우체국에서 증명하여 발송인에게 통지하는 특수취급제도를 말합니다(「우편법」 제15조제3항 및 「우편법 시행규칙」 제25조제1항제4호다목).\r\n\r\n배달증명은 내용증명증서를 수취인이 받았음을 증명해 줍니다.\r\n\r\n<H4>내용증명의 발송의 목적</H4>\r\n\r\n어떤 내용의 문서를 언제 발송하였다는 사실을 다투는 경우에 내용증명으로 보내게 됩니다, 이런 경우로서 실무에서 다음과 같은 경우를 예로 들 수 있을 것이다. \r\n\r\n주택임대차보호법 제6조(계약의 갱신) ① 임대인이 임대차기간이 끝나기 6개월 전부터 1개월 전까지의 기간에 임차인에게 갱신거절(更新拒絶)의 통지를 하지 아니하거나 계약조건을 변경하지 아니하면 갱신하지 아니한다는 뜻의 통지를 하지 아니한 경우에는 그 기간이 끝난 때에 전 임대차와 동일한 조건으로 다시 임대차한 것으로 본다. 임차인이 임대차기간이 끝나기 1개월 전까지 통지하지 아니한 경우에도 또한 같다.\r\n\r\n\r\n실무에서 많이 발생하는 경우인데 통보가 언제의 문제가 분쟁 발생시에 대립하게 된다. 또한 공인중개사 협회의 임대차계약서에 보면 다음의 내용이 있다.\r\n\r\n제7조 [채무불이행과 손해배상의 예정] 임대인 또는 임차인이 본 계약상의 내용에 대하여 불이행이 있을 경우 그 상대방은 불이행 한 자에 대하여 서면으로 최고(催告)하고 계약을 해제 할 수 있다. 이 경우 계약 당사자는 계약해제에 따른 손해배상을 각각 상대방에게 청구할 수 있으며, 손해배상에 대하여 별도의 약정이 없는 한 계약금을 손해배상의 기준으로 본다.\r\n\r\n이러한 서면에 의한 최고(催告)의 방법 중의 하나가 내용증명이 되는 것이다.\r\n\r\n하지만 실무적으로 본다면 이러한 목적을 넘어서 심리적 압박 등 의미는 크게 가지지 않아도 다양한 목적으로 이용된다. 내용증명의 발송목적은 증거보전의 필요와 상대방(채무자 등)에게 심리적 압박감을 주어 그 이행을 실현하게 하거나 어떠한 사실(계약해제 등)을 정확하게 알리는 목적이 있다.\r\n\r\n<H4>내용증명의 기재요령</H4>\r\n\r\n내용증명의 기재형식에는 특별한 규정이 없으나 제목도 최고 또는 통지 등으로 명확한 것이 좋으며 어떠한 제목을 선택하여 기재하여도 좋으나, 다만 그 내용에 있어서는 자기의 권리 및 상대방의 불이행 사실을 빠뜨리지 않아야 하며 그 근거-법령 및 계약 조항 등-가 있다면 함께 기재하는게 좋다. 내용문서의 원본 및 등본은 A4용지 작성하되, 등본은 내용문서의 원본을 복사한 것이어야 한다.(「우편법 시행규칙」 제49조제1항).\r\n\r\n내용문서의 원본 또는 등본의 문자나 기호를 정정·삽입 또는 삭제한 때에는 “정정”·“삽입” 또는 “삭제”의 문자 및 자수를 난외(欄外) 또는 말미 여백에 기재하고 그 곳에 발송인의 인장 또는 지장을 찍거나 서명하여야 한다.(「우편법 시행규칙」 제50조제1항).\r\n\r\n작성된 내용증명서는 3부가 필요합니다. 1통은 원본으로 사용되고 2통은 등본으로 사용된다..\r\n\r\n① 제목의 결정\r\n\r\n근데 여기에 더욱 민망한 건 내용의 제목으로 내용증명이라고 크게 써서 보내는 경우입니다. 하지만 위에서 살펴본 바와 같이 내용증명이란 제도를 말하는 것으로 흔히 말하는 내용증명을 썻다라고 말하거나 내용증명을 보냈다라는 말은 내용증명으로 보냈다라고 표현되어야 한다.\r\n\r\n제목의 적절한 예로는 임대차 갱신 거절 통지, 중도급 지급 최고 등으로 하면 좋을 듯 하다.\r\n\r\n② 내용증명서 상단 또는 하단에 보내는 사람과 받는 사람의 주소와 성명을 써야 한다.\r\n\r\n내용증명우편물의 내용문서 원본, 그 등본 및 우편물의 봉투에 기재하는 발송인 및 수취인의 성명·주소는 같아야 한다.(「우편법 시행규칙」 제51조제1항). 그리고 내용증명서 봉투에 내용증명서에 쓴 보내는 사람과 받는 사람의 주소와 성명을 동일하게 합니다.\r\n\r\n③ 내용증명을 보내는데 대한 양해로 시작하는걸 권한다. 본의 아니게 내용증명을 대신 작성해주고 봐주게 되면서 내용증명을 보내고 받으면서 기분 좋을 일은 없지만 그에 대한 양해로 시작한다면 서로에게 좋을 듯 하다.\r\n\r\n임대차 갱신 거절의 통지발신(임대) : 수신(임차) : 1. 추후 예상되는 상호분쟁의 예방을 위하여 내용증명의 방식으로 전달되게 됨에 대하여 양해를 구하여 귀댁의 평안을 기원합니다. 2. 아래 표시 부동산의 임대인은 주택임대차 보호법 제6조에 의거 임대인은 임대차 기간 1개월 전까지 통지하도록 되어 있어 이에 따른 임대차 갱신 거절을 통지합니다. 부동산의 표시 주택임대차보호법 제6조(계약의 갱신) ① 임대인이 임대차기간이 끝나기 6개월 전부터 1개월 전까지의 기간에 임차인에게 갱신거절(更新拒絶)의 통지를 하지 아니하거나 계약조건을 변경하지 아니하면 갱신하지 아니한다는 뜻의 통지를 하지 아니한 경우에는 그 기간이 끝난 때에 전 임대차와 동일한 조건으로 다시 임대차한 것으로 본다. 임차인이 임대차기간이 끝나기 1개월 전까지 통지하지 아니한 경우에도 또한 같다.\r\n\r\n<H4>내용증명의 발송방법절차</H4>\r\n\r\n내용증명우편물을 발송할 때는 내용문서 원본 및 그 등본 2통을 제출해야 합니다(「우편법 시행규칙」 제48조제1항).\r\n\r\n동문내용증명 우편물인 경우에는 각 수취인별·내용문서 원본과 수취인 전부의 성명 및 주소를 적은 등본 2통을 제출해야 합니다(「우편법 시행규칙」 제48조제2항).\r\n\r\n제출받은 등본 중 한통은 우체국에서 발송한 다음 날부터 3년간 보관하고 나머지 한통은 발송인에게 이를 되돌려 줍니다. 다만, 발송인이 등본을 필요로 하지 않는 때에는 한통의 등본만을 제출할 수 있습니다(「우편법 시행규칙」 제48조제3항).\r\n\r\n<H4>내용증명의 재증명 및 등본열람 청구</H4>\r\n\r\n내용증명우편물의 발송인 또는 수취인은 내용증명우편물을 발송한 다음 날부터 3년까지는 우체국에 특수우편물수령증·주민등록증 등의 관계 자료를 내보여 같은 우편물의 발송인 또는 수취인임을 입증하고 내용증명의 재증명을 청구할 수 있습니다(「우편법 시행규칙」 제54조제1항).\r\n\r\n재증명 청구인은 우체국에서 보관 중인 최초의 내용문서 등본과 같은 등본을 우체국에 제출해야 하며, 재증명 청구를 받은 우체국은 청구인이 제출한 내용문서를 재증명하여 내주어야 합니다. 다만, 청구인이 분실 등의 사유로 내용문서를 제출하기 어려운 경우에는 우체국에서 보관 중인 내용문서를 복사한 후 재증명하여 내줄 수 있습니다(「우편법 시행규칙」 제54조제2항).\r\n\r\n내용증명우편물의 발송인 또는 수취인은 우편물을 발송한 다음 날부터 3년까지는 발송우체국에 특수우편물수령증·주민등록증 등의 관계 자료를 내보여 동 우편물의 발송인 또는 수취인임을 입증하고 내용문서 등본의 열람을 청구할 수 있습니다(「우편법 시행규칙」 제55조).\r\n\r\n<H4>배달증명서의 송부</H4>\r\n\r\n내용증명을 발송하는 경우 많은 경우 배달증명으로 보내게 됩니다. 배달증명우편물을 배달한 때에는 발송인에게 배달증명서를 우편으로 송부합니다. 다만, 발송인이 원하는 경우에는 정보통신망을 통한 전자적 방법으로 송부할 수 있습니다(「우편법 시행규칙」 제58조).',0);
INSERT INTO `article_tbl` VALUES (44,1,32,'01091280586','2020-02-20','0000-00-00','2020-02-25','0000-00-00','내 땅 개발행위허가, 이제는 방문 없이 인터','0','',NULL,'그동안 시·군·구청을 방문하여 신청했던 개발행위허가* 민원을 앞으로는 인터넷(http://www.upis.go.kr/iuweb)으로 신청하여 처리결과를 조회하고 준공검사필증도 발급받을 수 있게 된다.\r\n\r\n* 건축물의 건축, 토지형질변경(절토, 성토, 포장 등) 등 토지이용 행위를 하려는 경우 국토계획법에 따라 행정청의 허가를 받도록 하는 제도\r\n\r\n\r\n국토교통부(장관 김현미)는 전문업체 등 대리인도 온라인으로 개발행위허가 민원을 신청할 수 있도록 하고 인허가 진행경과를 문자로 알려주는 등 개발행위허가 시스템을 개선하고 2월 24일부터 통합인허가지원시스템(http://www.upis.go.kr/iuweb)에서 서비스를 실시한다고 밝혔다.\r\n\r\n➊ 주요 서비스 내용\r\n\r\n이번에 개선되는 주요 서비스는 다음과 같다.\r\n\r\n① 대리인의 온라인 민원 신청 서비스\r\n\r\n민원인의 위임을 받은 대리인(위임장 첨부)이 통합인허가지원시스템에 접속하여 개발행위허가 민원을 온라인으로 신청할 수 있게 된다.\r\n\r\n민원인(대리인 포함)은 단계별 민원 진행상황을 조회하고 신청 내용에 대한 수정 및 자료를 보완하여 제출할 수 있으며, 인허가 처리결과를 확인(허가서)하고 준공 시 준공검사필증을 발급받을 수 있다.\r\n\r\n② 전자결재 연계 및 전자협의\r\n\r\n온라인으로 신청된 개발행위허가 신청 정보는 해당 지자체 담당부서로 전달되고 담당자가 전자결재 시스템(온나라)을 연계하여 자동으로 민원을 처리하게 된다.\r\n\r\n➋ 신청방법 및 신청 가능지역\r\n\r\n개발행위허가를 받고자 하는 사람은 통합인허가지원시스템(개발행위허가)에 접속하여 대리인을 지정하게 되면, 대리인이 개발행위허가 신청서를 작성, 첨부서류 등록 및 수수료를 납부하고 신청하게 된다.(붙임 신청방법 참조)\r\n\r\n신청인은 해당 지자체 업무처리 담당자 및 처리 진행과정을 확인할 수 있으며 개발행위 허가서 및 준공검사 필증도 발급받을 수 있다.\r\n\r\n온라인 개발행위허가 서비스는 서울을 제외한 전국 16개 시도, 203개 시군구에서 신청할 수 있으며, 서울은 자체 개발한 도시계획정보시스템에 올해 하반기부터 적용할 예정이다.\r\n\r\n➌ 추진경과 및 향후계획\r\n\r\n국토교통부는 온라인 개발행위허가 활성화를 위하여 작년 8월부터 통합인허가지원시스템 구축사업을 추진하여 모든 지자체에 시스템을 설치하였다.\r\n\r\n10개 지자체 시범운영(2.3~2.7)을 통하여 시스템을 안정화하고 2월 24일 전국 개발행위허가 온라인 서비스를 실시한다.\r\n\r\n아울러, 지자체 담당자 및 민원인의 문의에 응대하기 위하여 콜센터(031-426-9973~5)를 운영할 계획이다.\r\n\r\n온라인 개발행위허가가 활성화되면 지자체를 직접 방문해야 했던 불편이 감소되고, 개발행위허가 정보의 이력 관리를 통해 국민들에게 개발행위허가 정보를 신속하고 투명하게 제공할 수 있을 것으로 기대된다.\r\n\r\n또한, 오는 5월 ｢토지이용 인ㆍ허가 절차 간소화를 위한 특별법｣에 따라 통합인허가지원시스템 구축을 마무리하고 개발행위허가뿐 아니라 건축허가, 공장설립 승인도 한 곳에서 신청할 수 있도록 할 계획이다.',0);
INSERT INTO `article_tbl` VALUES (52,1,18,'01091280586','2020-03-04','2021-04-30','0000-00-00','0000-00-00','업무용 오피스텔 중개실무(쟁점 및 특약)','1','',NULL,'최근들어 공인중개사들에게 가장 큰 고민 중의 하나는 업무용 오피스텔의 전입신고에 대한 부분이다.  먼저 왜 이것이 쟁점이 되는지를 살펴보기로 하며 다음으로 공인중개사에게 이것이 왜 쟁점이 되는지를 살펴보도록 하겠다. \r\n\r\n<div class=\"float-clear\"><br />\r\n<div class=\"float-box\"><br />\r\n<img src=\"img/officetel.jpg\"><br />\r\n</div>우리나라는 1세대 1주택에 많은 혜택을 주고 있다.  주택이 투기의 대상이 되어서는 안된다는 것 그리고 의식주의 기본이 된다는 사실때문에 85m<sup>2</sup>이하 주택에는 부가가치세를 비과세하고 있으며 취득세에 있어서도 혜택을 주고 있으며 양도소득세도 비과세를 하고 있다.  또한 같은 취지로 주택임대사업자에게는 일반사업자가 아닌 부가가치세 면세사업자를 내주고 있으며 또한, 임대주택으로 등록하고 주거용으로 사용할 경우 취득세 지원도 가능하다.  \r\n\r\n하지만 만약 1세대 1주택이 부정된다면 통상 업무용 오피스텔에 있어서 *영업의 포괄양도를 통해 환급받았던 부가가치세를 환급받았던 부가가치세를 토해내야하며 1가구 1주택이 부정됨으로서 취득세의 혜택이 있었다면 취득세를 내야하고, 후에 매도시에도 양도소득세가 문제가 되게 된다. \r\n\r\n이에 대한 자세한 내용은 아래링크를 클릭하면 알 수 있다. <a href=\"http://news.chosun.com/site/data/html_dir/2018/10/03/2018100301394.html\" target=\"_blank\">업무용 오피스텔, 주거용으로 임대 땐 부가가치세 환급 안 돼</a>\r\n\r\n하지만 세입자의 입장에서는 전입를 함으로서 얻어지는 이익도 작지않다.  전입신고는 세입자에게 대항력 및 우선변제권 뿐만 아니라 외국인에게는 거소신고의무의 의미를 가지고 봉급생활자에게는 소득공제의 혜택을 준다.  \r\n\r\n이러한 주택이냐 업무용의 판단은 1세대 1주택 비과세규정을 적용함에 있어 “주택”이라 함은 공부상 용도 또는 사업자등록 여부와 관계없이 사실상 상시 주거용으로 사용하는 건물을 말하는 것임. 으로 판단하고 있다. 따라서 주택여부의 1차적인 판단은 전입여부로 판단이 되고있다.  \r\n\r\n그에 따라 세입자들은 전입신고시 임대인과의 갈등이 발생하고 그 사이에서 공인중개사는 소송까지도 일이 커지는 상황이 발생하게 된다.  왜냐면 임대인입장에서는 금전적으로 수천만원에 이르기도 하기 때문이다. \r\n\r\n이러한 갈등의 전제조건은 임대인이 일반과세자여야 하고 대상중개물건이 업무용 오피스텔이어야 하고 세입자의 전입신고가 있어야 한다. \r\n\r\n이와 관련한 몇가지 사례를 살펴보면 \r\n\r\n사례1 일반임대사업자이니 전입신고 안하는 조건이며 임차인의 전입신고 때문에 발생한 피해는 임차인이 부담한다고 특약에 명시하였으나 관리비(수도비) 문제로 전입신고가 이루어졌고 세무서에서 조기환급 되었던 건축물분 부가세(10%)를 반환하여야 하는 상황이 발생하였으며\r\n\r\n사례2 세입자는 외국인으로 이 경우에도 전입신고 안하는 조건으로 특약에 명시 출입국사무소에서 연락이와서 해당 물건지에 거소신고를 하였으나 문제는 최근 거소신고가 출입국관리소에서 주민센터로 업무가 이관되어 자동으로 전입신고가 됨으로서 문제가 발생한 사례가 있으며 \r\n\r\n단, 관련해서 세무사 상담시 만일 임대인과 임차인이 세금계산서를 주고받고 있으면 숙소 등으로 사용 가능하며 전입신고를 해도 괜찮다고 얘기를 들었으며, 임차인이 해당 오피스텔에 사업자등록증을 낸다면 대표에 한해서 전입신고가 가능하다고 얘기를 들었음\r\n\r\n이에 따라 일선 개업공인중개사들은 \"일선 현장에서는 업무용 오피스텔(일반임대사업자)을 숙소로 엄청 많이 중개를 하고 있으며 임차인이 법인이면 부가세 정산을 위해서 반드시 업무용 오피스텔에 들어가야 하는 상황에서 관련된 제도의 정비가 필요하다고 판단\"되다고 말하고 있다. 즉, 오피스텔에 한해서 주택임대사업자, 일반임대사업자 일원화 하거나 법인이나 개인사업자 숙소 등으로 사용시 완화 등의 조치를 필요하다고 한다. \r\n\r\n또한 실무에서 전입신고 불가라는 특약의 의미를 따져 보면 \r\n\r\n일단 <strong>탈세의 목적이 분명하기 때문에 전입신고를 안하게다는 조항이 유효함을 주장할 수 없을 것으로 판단</strong>되며 \r\n\r\n조세심판의 사례에서 보면 \r\n\r\n<blockquote>쟁점오피스텔 임대차계약서 특약사항에 ‘전입신고 불가 및 소득공제 신고시 부가가치세를 별도로 지불해야한다는 조건’을 명시한 것은 쟁점오피스텔이 주거용으로 사용될 수 있음을 충분이 인지하였을 뿐만 아니라, 주거용으로 사용되는 사실이 과세관청에 포착되지 않게 하기 위한 의도로 보인다.</blockquote>\r\n\r\n라고 판단하고 있다. \r\n\r\n또한 공인중개사 입장에서는 특약을 어떻게하든 세입자의 신고 또는 미신고를 강제할 수 있는 수단이 없으며 또한 수익자는 공인중개사가 아니라 임대인이는 사실에게 거래당사자와 의뢰관계에 있는 공인중개사에게 그 책임을 묻는 것은 부당할 것으로 생각되어 진다. ',0);
INSERT INTO `article_tbl` VALUES (54,1,18,'01091280586','2020-03-05','2021-04-30','2020-02-21','0000-00-00','공인중개사법 시행령시행규칙 2020.02.2','1','',NULL,'제목 : 제목: - 안녕하십니까? 마포구청 부동산정보\r\n- 안녕하십니까? 마포구청 부동산정보과입니다. \r\n- 공인중개사법 시행령시행규칙이 2020.02.21. 일부 개정시행됨에 따라 다음과 같이 알려드립니다. ① 중개대상물 확인설명 의무와 설명의 근거자료 제시 의무 중 한가지만 위반한 경우 과태료 하향 조정[400만원->250만원] ② 중개대상물 확인설명서 서식이 변경[중개보수 지급시기 추가] ③ 부동산중개사무소 휴폐업 신고시 사업자등록 휴폐업 신고를 같이 할 경우 등록관청은 신고서를 관할 세무서에 송부 ④ 집값담합 등 부동산거래질서교란행위 신고센터(https://cleanbudongsan.go.kr) 설치운영에 관한 사항(업무위탁: 한국감정원, ☎1833-4324)',0);
INSERT INTO `article_tbl` VALUES (56,1,32,'01091280586','2020-03-09','2021-04-30','0000-00-00','0000-00-00','자료제출요구와 개인정보보호','1','',NULL,'기본정보\r\n\r\n펼침/닫힘\r\n신청번호 1AA-1307-129528\r\n신청인 구분 개인\r\n신청인 성명 조항준\r\n유선전화 02-375-4489\r\n휴대전화 010-9128-0586\r\n주소 (121-250) 서울특별시 마포구 성산동 200-364\r\n추가정보\r\n\r\n통지방식 서면, 이메일, 문자메시지\r\n민원 확인 방식 간편형 보안형 전환\r\n\r\n신청일 2013-07-24 19:51:56\r\n직업 기타\r\n민원 신청내용\r\n제목 의견부탁드립니다.\r\n내용 공인중개사 조항준입니다. 다름이 아니라 개인정보 보호에 관련한 질의를 드릴려고요 등록관청에서는 오래전부터 <strong>공인중개사 업무에 대한 민원발생시 공인중개사의 업무 및 거래신고에 관한 법률 37조 근거를 주장하며 행정처분을 목적으로 제출 대상에 대한 특정(계약서 5년 중개대상물 확인설명서 3년 보관의무에 근거)없이 구두 또는 전화상으로 계약서를 포함한 자료제출을 요구할시 그에 응하여야 하는가</strong>에 대하여 질의 드립니다.\r\n\r\n왜냐면 <u>계약서라는게 그 자체로도 개인정보 이지만 성명 전화번호 주민등록번호 주소등의 개인정보를 포함하고 있어 그 특정없이 자료의 제출을 요구할 시 공인중개사로서 그에 응하여야 하는가</u>라는 점이 혼란스럽습니다. 사실 계약 그 자체가 개인정보이고 제가 계약의 당사자라면 그것이 공공기관이라고 하더라도 계약내용이나 주소 주민등록번호 주소 등의 개인정보를 임의로 보는 걸 원하지 않을거 같습니다. 또한\r\n\r\n일단 개인정보보호법 제 3조(개인정보 보호 원칙) ① 개인정보처리자는 개인정보의 처리 목적을 명확하게 하여야 하고 그 목적에 필요한 범위에서 최소한의 개인정보만을 적법하고 정당하게 수집하여야 한다.\r\n② 개인정보처리자는 개인정보의 처리 목적에 필요한 범위에서 적합하게 개인정보를 처리하여야 하며, 그 목적 외의 용도로 활용하여서는 아니 된다.\r\n\r\n이라고 정의하고 있으며 이는 지방단치단체를 포함하고 있는 것으로 알고 있습니다. 따라서 그 법의 취지에 따른다면 <u>지방단체의 경우에도 행정처분을 목적으로 한다면 그 계약서를 특정하여야 할 것으로 판단되며 또한 해당되는 개인정보의 취급에 대한 약속도 있어야 할 것으로 판단되어집니다</u>.\r\n\r\n계약서 보관에 대한 의무가 공인중개사에 있는한 공인중개사라고 하더라도 공공기관의 불특정기간의 개인정보의 집합체의 제출에 대하여 응하여야 하는가라는 생각이 들어서요 이에 대한 답변부탁드립니다.\r\n\r\n<hr>\r\n처리기관 정보\r\n처리기관 안전행정부 창조정부전략실 제도정책관 개인정보보호과\r\n담당자(연락처) 이공주 (02-2100-2817) 신청번호 1AA-1307-129528\r\n접수일 2013-07-26 10:29:12 처리기관 접수번호 2AA-1307-295384\r\n처리 예정일 2013-08-10 23:59:59\r\n\r\n처리결과 안내\r\n답변일 2013-07-31 17:10:39\r\n처리결과 안내 \r\nㅇ 안녕하십니까? 안전행정부 개인정보보호과입니다. \r\n개인정보보호법에 대한 귀하의 관심에 감사드리오며 질의에 답변드리겠습니다\r\n\r\n「개인정보 보호법」은 <strong>원칙적으로 개인정보를 당초의 수집이용목적 외로 제3자에게 제공하는 것을 금지</strong>하고 있습니다. 다만 <strong>예외적으로 1) 정보주체의 별도 동의가 있었거나 2) 다른 법률에 특별한 규정이 있는 경우 등에는 개인정보를 제3자에게 제공하는 것이 허용</strong>됩니다. \r\n\r\n  이와 관련하여, <strong>중앙행정기관이나 지방자치단체 등에서 법률에 정해진 바에 따라 감독, 관리, 감사 등의 수행을 위한 자료 제출을 요구하는 경우에는 ‘다른 법률에 특별한 규정이 있는 경우’에 해당되어 개인정보의 제3자 제공이 허용될 수 있습니다. 다만 이러한 경우에도 반드시 해당 법률에서 규정하고 있는 자료 제출 요구의 목적, 대상, 요구절차 등이 준수되어야 할 것</strong>입니다. \r\n\r\n「공인중개사의 업무 및 부동산 거래신고에 관한 법률」은 국토교통부, 시도, 등록관청에서 1) 부동산투기 등 거래동향 파악에 필요한 경우 2) 동법 위반행위 확인, 공인중개사 자격취소 등 행정처분에 필요한 경우에는 자료제출 명령을 할 수 있도록 규정하고 있으므로 이에 해당하는 경우에는 개인정보가 포함된 자료를 제출할 수 있다고 판단됩니다(공인중개사의 업무 및 부동산 거래신고에 관한 법률 제37조 참조). \r\n\r\n질의에 답변이 되셨기를 바랍니다\r\n답변내용과 관련하여 궁금하신 사항은 02-2100-2817로 연락주시면 친절히 답변드리겠습니다..감사합니다   \r\n<hr>\r\n처리기관 정보\r\n처리기관 국토교통부 주택토지실 토지정책관 부동산산업과\r\n담당자(연락처) 홍창빈 (044-201-3416) 신청번호 1AA-1307-129528\r\n접수일 2013-07-26 14:48:38 처리기관 접수번호 2AA-1307-300326\r\n처리 예정일 2013-08-02 23:59:59\r\n\r\n처리결과 안내처리결과(추가답변)\r\n답변일 2013-07-30 08:55:59\r\n처리결과 안내 \r\n고객님께 만족스러운 답변을 드리지 못한 점 유감스럽게 생각합니다.\r\n\r\n공인중개사의 업무 및 부동산거래신고에 관한 법령 내에서 답변 드리다 보니 한계가 있는 점 양해하여 주시기 바랍니다.\r\n\r\n또한, 고객님께서 주신 소중한 의견은 추후 부동산중개업 제도 개선시 검토할 예정임을 알려드립니다. \r\n\r\n추가 문의사항은 부동산산업과(044-201-3416)으로 연락주시면 친절하게 안내하여 드리겠습니다.\r\n\r\n고객님, 항상 건강하시고 행복한 일만 가득하시길 기원합니다.\r\n\r\n감사합니다.  끝.\r\n\r\n첨부파일 첨부파일이 없습니다.\r\n\r\n\r\n\r\n신청인 입력사항\r\n기본정보\r\n\r\n펼침/닫힘\r\n신청번호 1AA-1307-131922\r\n신청인 구분 개인\r\n신청인 성명 조항준\r\n전자우편 bestroe@lycos.co.kr\r\n유선전화 02-375-4489\r\n휴대전화 010-9128-0586\r\n주소 (121-250) 서울특별시 마포구 성산동 200-364\r\n\r\n신청일 2013-07-25 11:08:22\r\n직업 전문직\r\n민원 신청내용\r\n제목 의견부탁드립니다.\r\n내용 공인중개사 조항준입니다. 다름이 아니라 개인정보 보호에 관련한 질의를 드릴려고요 등록관청에서는 오래전부터 공인중개사 업무에 대한 민원발생시 공인중개사의 업무 및 거래신고에 관한 법률 37조 근거를 주장하며 행정처분을 목적으로 제출 대상에 대한 특정(계약서 5년 중개대상물 확인설명서 3년 보관의무에 근거)없이 구두 또는 전화상으로 계약서를 포함한 자료제출을 요구할시 그에 응하여야 하는가에 대하여 질의 드립니다.\r\n\r\n왜냐면 계약서라는게 그 자체로도 개인정보 이지만 성명 전화번호 주민등록번호 주소등의 개인정보를 포함하고 있어 그 특정없이 자료의 제출을 요구할 시 공인중개사로서 그에 응하여야 하는가라는 점이 혼란스럽습니다. 사실 계약 그 자체가 개인정보이고 제가 계약의 당사자라면 그것이 공공기관이라고 하더라도 계약내용이나 주소 주민등록번호 주소 등의 개인정보를 임의로 보는 걸 원하지 않을거 같습니다. 또한\r\n\r\n일단 개인정보보호법 제 3조(개인정보 보호 원칙) ① 개인정보처리자는 개인정보의 처리 목적을 명확하게 하여야 하고 그 목적에 필요한 범위에서 최소한의 개인정보만을 적법하고 정당하게 수집하여야 한다.\r\n② 개인정보처리자는 개인정보의 처리 목적에 필요한 범위에서 적합하게 개인정보를 처리하여야 하며, 그 목적 외의 용도로 활용하여서는 아니 된다.\r\n\r\n이라고 정의하고 있으며 이는 지방단치단체를 포함하고 있는 것으로 알고 있습니다. 따라서 그 법의 취지에 따른다면 지방단체의 경우에도 행정처분을 목적으로 한다면 그 계약서를 특정하여야 할 것으로 판단되며 또한 해당되는 개인정보의 취급에 대한 약속도 있어야 할 것으로 판단되어집니다.\r\n\r\n계약서 보관에 대한 의무가 공인중개사에 있는한 공인중개사라고 하더라도 공공기관의 불특정기간의 개인정보의 집합체의 제출에 대하여 응하여야 하는가라는 생각이 들어서요 이에 대한 답변부탁드립니다.\r\n첨부파일 첨부파일이 없습니다.\r\n처리기관 정보\r\n처리기관 \r\n담당자(연락처) 이공주 (02-2100-2817) 신청번호 1AA-1307-131922\r\n접수일 2013-07-25 15:54:58 처리기관 접수번호 2AA-1307-287123\r\n처리 예정일 2013-08-09 23:59:59\r\n<hr>\r\n처리결과 안내\r\n답변일 2013-07-31 17:07:54\r\n처리결과 안내 \r\nㅇ 안녕하십니까? 안전행정부 개인정보보호과입니다. \r\n개인정보보호법에 대한 귀하의 관심에 감사드리오며 질의에 답변드리겠습니다\r\n\r\n「개인정보 보호법」은 원칙적으로 개인정보를 당초의 수집이용목적 외로 제3자에게 제공하는 것을 금지하고 있습니다. 다만 예외적으로 1) 정보주체의 별도 동의가 있었거나 2) 다른 법률에 특별한 규정이 있는 경우 등에는 개인정보를 제3자에게 제공하는 것이 허용됩니다. \r\n\r\n  이와 관련하여, 중앙행정기관이나 지방자치단체 등에서 법률에 정해진 바에 따라 감독, 관리, 감사 등의 수행을 위한 자료 제출을 요구하는 경우에는 ‘다른 법률에 특별한 규정이 있는 경우’에 해당되어 개인정보의 제3자 제공이 허용될 수 있습니다. 다만 이러한 경우에도 반드시 해당 법률에서 규정하고 있는 자료 제출 요구의 목적, 대상, 요구절차 등이 준수되어야 할 것입니다. \r\n\r\n「공인중개사의 업무 및 부동산 거래신고에 관한 법률」은 국토교통부, 시도, 등록관청에서 1) 부동산투기 등 거래동향 파악에 필요한 경우 2) 동법 위반행위 확인, 공인중개사 자격취소 등 행정처분에 필요한 경우에는 자료제출 명령을 할 수 있도록 규정하고 있으므로 이에 해당하는 경우에는 개인정보가 포함된 자료를 제출할 수 있다고 판단됩니다(공인중개사의 업무 및 부동산 거래신고에 관한 법률 제37조 참조). \r\n\r\n질의에 답변이 되셨기를 바랍니다\r\n답변내용과 관련하여 궁금하신 사항은 02-2100-2817로 연락주시면 친절히 답변드리겠습니다..감사합니다   \r\n첨부파일 첨부파일이 없습니다.\r\n\r\n기본정보\r\n\r\n펼침/닫힘\r\n신청번호 1AA-1307-165883\r\n신청인 구분 개인\r\n신청인 성명 조항준\r\n전자우편 bestore@lycos.co.kr\r\n유선전화 \r\n휴대전화 010-9128-0586\r\n주소 (121-250) 서울특별시 마포구 성산동 200-364\r\n추가정보\r\n\r\n통지방식 이메일, 문자메시지\r\n민원 확인 방식 간편형 보안형 전환\r\n※ 간편형 : 로그인만으로 확인 가능\r\n\r\n※ 보안형 : 로그인(1단계) ⇒ 신청번호 등(2단계) 입력 후 확인 도움말\r\n\r\n민원 공개여부 비공개\r\n※ 공개에 동의하시면 민원내용과 답변내용이 민원업무 처리나 정부정책에 반영하기 위해 다른 행정기관에 제공 될 수 있으며, 필요 시 행정기관 등의 누리집(홈페이지)를 통해 일반국민들에게 민원사례로 제공 될 수 있습니다.\r\n\r\n신청일 2013-07-31 17:34:46\r\n직업 기타\r\n민원 신청내용\r\n제목 민원인 신청번호 1AA-1307-129528처리기관접수번호 2AA-1307-295384 관련하여 추가질의 드립니다.\r\n내용 개인정보보호법 15조 16조에 의한다면 등록관청에서 민원발생으로 행정처분을 위하여 자료를 요청할 수 있습니다. 이 부분에 대해서는 이해를 하고요\r\n\r\n하지만 그 경우에도 개인정보 보호법\r\n\r\n제16조(개인정보의 수집 제한) ① 개인정보처리자는 제15조제1항 각 호의 어느 하나에 해당하여 개인정보를 수집하는 경우에는 그 목적에 필요한 최소한의 개인정보를 수집하여야 한다. 이 경우 최소한의 개인정보 수집이라는 입증책임은 개인정보처리자가 부담한다.\r\n\r\n그 목적을 위한 최소한의 개인정보가 수집어야합니다. 물론 그 입증책임은 등록관청에서 부담하여야 하는거고요 그러하다면 마땅히 그 개인정보보호의 요청범위는 민원이 발생한 부분으로 한정되어야 할 것입니다. 하지만 관례적으로 민원이 발생하면 전체 또는 상당기간 실제사례에서는 3년 정도의 자료제출을 요구합니다.\r\n\r\n이것이 개인정보보호법의 취지에 타당한가를 질의드린것이며 이에 대한 법령해석을 요청합니다.\r\n첨부파일 첨부파일이 없습니다.\r\n처리기관 정보\r\n처리기관 안전행정부 창조정부전략실 제도정책관 개인정보보호과\r\n담당자(연락처) 이공주 (02-2100-2817) 신청번호 1AA-1307-165883\r\n접수일 2013-07-31 17:36:59 처리기관 접수번호 2AA-1307-350915\r\n처리 예정일 2013-08-16 23:59:59\r\n※ 민원처리기간은 최종 민원 처리기관의 접수일로부터 보통 7일 또는 14일입니다.\r\n    (해당 민원을 처리하는 소관 법령에 따라 달라질 수 있음)\r\n\r\n처리결과 안내\r\n답변일 2013-08-09 11:40:03\r\n처리결과 안내 \r\nㅇ 안녕하십니까? 안전행정부 개인정보보호과입니다. \r\n개인정보보호법에 대한 귀하의 관심에 감사드리오며 질의에 답변드리겠습니다\r\n\r\n개인정보보호법 제3조제①항에 따라 개인정보처리자는 개인정보의 처리 목적을 명확하게 하여야 하고 그 목적에 필요한 범위에서 최소한의 개인정보만을 적법하고 정당하게 수집하여야 합니다\r\n따라서, <strong>해당민원의 처리에 필요한 범위 내에서 개인정보를 수집하여야 할 것이며 불필요하게 과도한 개인정보를 수집할 경우는 개인정보보호법의 취지에 적정하지 않을 것</strong>으로 판단됩니다.\r\n\r\n질의에 답변이 되셨기를 바라오며\r\n법령해석 질의가 많아 답변이 지연되고 있는 점 양해 부탁드립니다\r\n답변내용 중 추가로 궁금하신 사항은 개인정보보호과 ☏02-2100-2817로 연락주시면 친절히 답변드리겠습니다..감사합니다\r\n첨부파일 첨부파일이 없습니다.\r\n \r\n ',0);
INSERT INTO `article_tbl` VALUES (57,1,32,'01091280586','2020-03-11','0000-00-00','2020-03-13','0000-00-00',' ｢부동산 거래신고 등에 관한 법률 시행령｣','0','국토교통부(장관 김현미)는 자금조달계획서 제출 대상지역 확대 등을 주요 내용으로 ',NULL,'국토교통부(장관 김현미)는 자금조달계획서 제출 대상지역 확대 등을 주요 내용으로 하는 ｢부동산 거래신고 등에 관한 법률 시행령｣ 일부 개정안이 국무회의를 통과함에 따라 오는 3월 13일부터 본격 시행*될 예정이라고 밝혔다.\r\n\r\n* ｢부동산 거래신고 등에 관한 법률 시행규칙｣ 일부 개정안도 같은 날 시행\r\n\r\n\r\n이번 개정은 지난 ’19.12.16. 관계부처 합동으로 발표한 ｢주택시장 안정화 방안｣ 후속조치의 일환으로 추진되었으며, 투명하고 공정한 거래질서 확립을 위해 주택 취득 시 제출하는 자금조달계획서의 ① 제출 대상지역 확대, ② 증빙자료 제출, ③ 신고항목 구체화 등을 내용으로 하고 있다.\r\n\r\n이번 ｢부동산 거래신고 등에 관한 법률 시행령·시행규칙｣ 개정안의 주요 내용은 다음과 같다.\r\n\r\n주요 개정·시행 내용\r\n\r\n① 자금조달계획서 제출 대상지역 확대(시행령 개정안 제3조)\r\n\r\n조정대상지역 3억원 및 非규제지역 6억원 이상의 주택 거래 신고 시 ‘주택취득자금 조달 및 입주계획서(자금조달계획서)’ 제출이 의무화된다.\r\n\r\n<strong>* (기존) 투기과열지구 3억원 이상 주택 →\r\n(변경) 투기과열지구·조정대상지역 3억원 이상 주택, 非규제지역 6억원 이상 주택</strong>\r\n\r\n\r\n그간 자금조달계획서 제출대상이 투기과열 지구 내 3억원 이상 주택 거래 시로 제한되어 있어, 과열 우려가 있는 조정대상지역과 非규제지역의 투기적 수요 조사에 한계가 있었다.\r\n\r\n이에 조정대상지역과 非규제지역 내 자금조달의 투명성을 강화하고, 과열 우려가 있는 지역을 중심으로 자금조달계획서를 제출토록 함으로써 이상 거래와 불법 행위에 대한 점검을 강화하기 위하여 자금조달계획서 제출 대상지역을 확대하였다.\r\n\r\n* 3억원 이상 주택 거래 신고 시 자금조달계획서 제출 대상지역이 “31곳”에서 “45곳”으로 확대(규제지역 시·군·구 기준, 기타지역은 6억원 이상 주택 거래 신고 시 제출)\r\n\r\n\r\n이에 따라 3월 13일 거래계약분부터는 조정대상지역 3억원 이상과 <strong>투기과열지구 또는 조정대상지역이 아닌 일반지역(非규제지역) 6억원 이상의 주택 거래계약을 체결하는 경우, 관할 시·군·구 실거래 신고 시(30일 이내) 자금조달계획서도 제출</strong>하여야 한다.\r\n\r\n② 자금조달계획서 증빙자료 제출(시행령 개정안 제3조, 시행규칙 개정안 제2조)\r\n\r\n</strong>‘투기과열지구 9억원 초과 주택’ 거래 신고 시 자금조달계획서의 작성 항목 별로 예금잔액증명서, 소득금액증명원 등 객관적인 증빙자료를 첨부하여 제출</strong>하도록 한다.\r\n\r\n그간 실거래 신고 시 자금조달계획서만 제출하고, 사후적으로 의심거래에 한하여 소명자료를 제출토록 했으나, 이러한 방식으로는 비정상 자금조달 등 이상거래에 대한 신속한 대응과 선제적인 조사에 한계가 있었다.\r\n\r\n이에 ‘투기과열지구 9억원 초과 주택’ 거래 신고 시 자금조달계획서와 객관적인 증빙자료를 함께 제출토록 한 것이다.\r\n\r\n이때 증빙자료로는 자금조달계획서에 기재한 항목별로 객관적으로 진위를 입증할 수 있는 관련 자료를 제출하되, 자금조달계획서 제출 시점에서 본인 소유 부동산의 매도계약이 아직 체결되지 않았거나, 금융기관 대출 신청이 이루어지지 않는 등 증빙자료가 존재하지 않는 경우에는 계획 중인 내용을 자금조달계획서 항목에는 기재하고 증빙자료는 제출하지 않을 수 있다.\r\n\r\n다만 잔금지급 등 거래가 완료된 이후 국토부 또는 신고관청이 증빙자료 제출을 요청하면 이에 응하여야 한다.\r\n\r\n* 증빙자료를 제출하지 아니할 경우 ｢부동산 거래신고 등에 관한 법률｣ 제28조제2항제4호 위반에 해당하여 500만원 과태료 처분대상임\r\n\r\n\r\n③ 자금조달계획서 신고항목 구체화(시행규칙 개정안 별지 제1호의2 서식)\r\n\r\n자금조달계획서 신고 항목 중 편법 증여나 대출 규제 위반 등 위법행위 발생 가능성이 높은 항목에 대하여 자금 제공자의 관계 등 구체적인 사항*과 조달자금의 지급수단** 등을 명시하도록 함으로써 이상거래에 대한 신속한 대응과 선제적인 조사가 이루어질 수 있도록 하였다.\r\n\r\n* 증여·상속 자금 제공자 관계, 그 밖의 차입금 제공자 관계, 금융기관 대출 유형별 세부 구분(주택담보·신용·그 밖의 대출, 그 밖의 대출은 대출 종류를 기재) 등\r\n** 계좌이체, 현금지급, 보증금·대출 승계 등\r\n\r\n\r\n이번에 개정되는 시행령·시행규칙 개정안은 법제처 국가법령정보센터(http://www.law.go.kr)에서 확인할 수 있다.\r\n\r\n부동산 시장 불법행위 등 집중 단속\r\n\r\n한편, 국토부는 지난 2월 21일 출범한 국토부 “부동산시장불법행위대응반*(13명)”과 감정원 “실거래상설조사팀(40명)”을 3월 13일부터 수도권 조정대상지역 등으로 확대된 자금조달계획서 조사에 즉시 투입할 계획이다.\r\n\r\n* (부동산시장불법행위대응반) 국토부 특사경 7명, 검찰·경찰·국세청·금융위·금감원·감정원 등 6명으로 구성하여 실거래 조사 및 부동산 범죄행위 수사업무 등 수행\r\n\r\n\r\n자금조달계획서 제출이 확대됨에 따라 조사지역을 기존 투기과열지구에서 전국으로 확대하는 한편, <strong>수원, 안양 등 신규 조정대상지역 및 군포, 시흥, 인천 등 최근 가격이 급등하고 있는 주요 지역에 대하여는 집중 모니터링을 실시</strong>하여 과열이 지속되는 경우 국토부가 직접 고강도 기획조사를 실시할 예정이다.\r\n\r\n증빙자료 제출이 의무화된 투기과열지구 9억원 초과 주택 중 업·다운계약, 편법대출, 편법증여 등이 의심되는 이상거래를 집중 관리대상으로 선정하여 자금조달계획서 제출 즉시 조사에 착수한다.\r\n\r\n또한, <strong>최근 주택 매수비중이 늘어나고 있는 부동산업 법인에 대해서도 조사를 강화</strong>한다.\r\n\r\n<strong>다주택자 양도소득세 중과와 합산과세 회피를 위해 설립한 것으로 보이는 소규모 부동산업 법인 등에 대해서는 국세청과 협력하여 법인자금을 유출하여 고가 아파트를 취득하는 행위, 차명계좌를 통한 수입금액 누락 행위 등 불법 탈루행위에 대한 강도 높은 조사를 이어갈 계획</strong>이다.\r\n\r\n국토교통부 김영한 토지정책관은 “투기과열지구 고가주택에 대한 증빙자료 제출이 의무화됨에 따라 실거래 신고 즉시 이상 거래와 불법 행위 등 조사에 착수할 수 있게 되어, 조사 착수 시점이 현행 대비 2개월 이상 단축될 것으로 기대된다”면서, “‘부동산시장불법행위대응반’을 중심으로 실거래 조사와 불법행위 집중단속을 강도 높게 전개하여, 투기 수요를 철저히 차단하고 주택시장을 실수요자 중심으로 안정적으로 관리해 나갈 계획”이라고 언급했다.',0);
INSERT INTO `article_tbl` VALUES (58,1,32,'01091280586','2020-03-11','2021-04-30','0000-00-00','0000-00-00','자료제출요구와 개인정보보호','1','',NULL,'최근에는 이러한 부당한 요구가 사람진 거로 알았습니다.  오래전 민원발생시의 감독 관청의 지도 감독권의 행사의 시작은 계약서 1년치 들고와라 2년치 들고와라 식의요구였다.  하지만 개인정보보호법의 실행과 함께 공인중개사의 계약서는 사인(私人)간의 거래의 증표의 의미를 넘어 개인정보의 집합체-주소 전화번호 거래내용 주민등록번호 등-로서의 의미를 가지게 되었다.  \r\n\r\n<h3>1. 개인정보보호법의 취급자와 처리자</h3>\r\n먼저 확인하여야할 개념은 개인정보보호법의 개인정보 취급자와 처리자의 구분이다. \r\n\r\n가. \"개인정보 취급자\"란 개인정보처리자의 지휘·감독을 받아 개인정보를 처리하는 업무를 담당하는 자로서 임직원, 파견근로자, 시간제근로자 등을 말한다.*\r\n\r\n*개인정보의 안전성 확보조치 기준[시행 2019. 6. 7.] [행정안전부고시 제2019-47호, 2019. 6. 7., 일부개정]\r\n\r\n나. 현 개인정보보호법에서 \'개인정보 처리자\'는 업무를 목적으로 개인정보 파일을 운용하기 위해 개인정보를 처리하는 공공기관, 법인, 단체 및 개인을 뜻한다.\r\n\r\n이 구분이 의미를 가지는 것은 개인정보보호법으로 처벌을 받을 수 있는가의 기준을 제시하기 때문이다.  즉,  개인정보 처리자는 개인정보호법으로 처벌할 수 있다.  하지만 개인정보취급자는 개인정보보호법으로 처벌할 수 없다. \r\n\r\n<h3>2. 개인정보의 수집에 관하여</h3>\r\n또한 개인정보보호법에서 \r\n\r\n수집에 있어서 개인정보보호법 제3조(개인정보 보호 원칙) ① 개인정보처리자는 개인정보의 처리 목적을 명확하게 하여야 하고 그 목적에 필요한 범위에서 최소한의 개인정보만을 적법하고 정당하게 수집하여야 한다.\r\n<생략>\r\n⑦ 개인정보처리자는 개인정보를 익명 또는 가명으로 처리하여도 개인정보 수집목적을 달성할 수 있는 경우 익명처리가 가능한 경우에는 익명에 의하여, 익명처리로 목적을 달성할 수 없는 경우에는 가명에 의하여 처리될 수 있도록 하여야 한다.  <개정 2020. 2. 4.>\r\n\r\n라고 규정하고 있다. \r\n\r\n\r\n 제15조(개인정보의 수집·이용) ① 개인정보처리자는 다음 각 호의 어느 하나에 해당하는 경우에는 개인정보를 수집할 수 있으며 그 수집 목적의 범위에서 이용할 수 있다.\r\n  1. 정보주체의 동의를 받은 경우\r\n  2. 법률에 특별한 규정이 있거나 법령상 의무를 준수하기 위하여 불가피한 경우\r\n  <u>3. 공공기관이 법령 등에서 정하는 소관 업무의 수행을 위하여 불가피한 경우</u>\r\n  4. 정보주체와의 계약의 체결 및 이행을 위하여 불가피하게 필요한 경우\r\n  5. 정보주체 또는 그 법정대리인이 의사표시를 할 수 없는 상태에 있거나 주소불명 등으로 사전 동의를 받을 수 없는 경우로서 명백히 정보주체 또는 제3자의 급박한 생명, 신체, 재산의 이익을 위하여 필요하다고 인정되는 경우\r\n  6. 개인정보처리자의 정당한 이익을 달성하기 위하여 필요한 경우로서 명백하게 정보주체의 권리보다 우선하는 경우. 이 경우 개인정보처리자의 정당한 이익과 상당한 관련이 있고 합리적인 범위를 초과하지 아니하는 경우에 한한다.\r\n  ② <u>개인정보처리자는 제1항제1호에 따른 동의를 받을 때에는 다음 각 호의 사항을 정보주체에게 알려야 한다.</u> 다음 각 호의 어느 하나의 사항을 변경하는 경우에도 이를 알리고 동의를 받아야 한다.\r\n  1. 개인정보의 수집ㆍ이용 목적\r\n  2. 수집하려는 개인정보의 항목\r\n  3. 개인정보의 보유 및 이용 기간\r\n  4. 동의를 거부할 권리가 있다는 사실 및 동의 거부에 따른 불이익이 있는 경우에는 그 불이익의 내용\r\n\r\n   제16조(개인정보의 수집 제한) ① 개인정보처리자는 제15조제1항 각 호의 어느 하나에 해당하여 개인정보를 수집하는 경우에는 그 목적에 필요한 최소한의 개인정보를 수집하여야 한다. 이 경우 최소한의 개인정보 수집이라는 입증책임은 개인정보처리자가 부담한다.\r\n\r\n② 개인정보처리자는 정보주체의 동의를 받아 개인정보를 수집하는 경우 필요한 최소한의 정보 외의 개인정보 수집에는 동의하지 아니할 수 있다는 사실을 구체적으로 알리고 개인정보를 수집하여야 한다.  <신설 2013. 8. 6.>\r\n\r\n<이하생략>\r\n\r\n<h3>의문들</h3>3.\r\n1. 부당한 요구에 응하여야 하는가?\r\n결론은 <srong>부당한 요구에 응할 필요는 없으며 최소한 그에 대한 관련 기관의 판단을 요구할 수 있다.</srong> 왜냐면 행안부의 답변은 <strong>해당민원의 처리에 필요한 범위 내에서 개인정보를 수집하여야 할 것이며 불필요하게 과도한 개인정보를 수집할 경우는 개인정보보호법의 취지에 적정하지 않을 것으로 판단</strong>하고 있으며 이에 대한 입증책임은 행정기관이 부담하기 때문이다. \r\n\r\n2. 그걸 다 들고 가면 유리한가. \r\n오히려 많은 경우 불리하게 작용한다.  왜냐면 민원이 발생하였을 경우 예전에는 어떤 민원이 발생했다는 걸 알려줬는데 그게 개인정보보호법과의 충돌로 인해 최근에는 그냥 들고 들어오라고 한다. 근데 해당민원만 확인하는 것이 아니라 제출된 자료를 근거로 처분을 위한 흠결을 찾는 경우가 대부분이다. 그럴 경우 아무리 꼼꼼하게 계약서를 작성하였다해도 조그만 꼬트리라도 잡힐 경우 확인설명의무 위반으로 400만원의 과태료 처분이 처해지는 경우가 많다. \r\n\r\n',0);
INSERT INTO `article_tbl` VALUES (60,1,36,'01024567375','2020-03-12','2021-05-03','0000-00-00','0000-00-00','GPlan 공인중개사사무소','0','단순한 재산증감의 약속문서가 아닌 새로운 터전의 움직임의 시작이었으며 그 시작은 ',NULL,'안녕하십니까? \r\n손희균입니다\r\n\r\n항상 아낌없는 성원을 보내주신 귀하께 깊이 감사의 말씀을 드립니다. \r\n\r\n그동안 잠시 광명을 떠나 서울 가산, 경기도 화성.평택, 충남 서산.천안, 전북 군산등에서 여러가지 부동산중개 및 분양대행. 건물관리. 부동산 업무위탁등의 풍부한 실무경험을 바탕으로 여러분들의 성원에 힘입어 부족한 제가 이번에 광명KTX 역세권 태영데시앙 스튜디오 단지내상가에 지플랜(GPLAN)공인중개사 사무소를 개업 하게 되었습니다. \r\n\r\n20여년 부동산중개라는 한길만을 걸어온 저에게 중개계약이란 여러 중개의뢰인들이 계획하는 좋은계획들의 시작이었습니다. \r\n단순한 재산증감의 약속문서가 아닌 새로운 터전의 움직임의 시작이었으며 그 시작은 <strong>바로 좋은(Good) 계획(Plan)</strong>의 시작이었습니다. \r\n\r\n지플랜(GPLAN)공인중개사는 이 좋은계획을 여러분들과함께 하고픈 마음에 공정하고 정직하게 그리고 성실하게 책임중개 할 것입니다. \r\n좋은계획에는 불의가 없기 때문입니다.\r\n여러분들의 가정에도 선하고 행복한 좋은계획을 함께하고자합니다. \r\n\r\n해가 다르게 바뀌는 부동산 정책에 맞추어 공인중개사분야에서 최고의 전문성으로 여러분들께 최적의 서비스를 제공해드리겠습니다. \r\n\r\n또한 부동산 컨설팅 개발 및 공급 분양대행.임대관리. 사옥. 사택관리. 각종 중개 위탁업무. 청소대행도 겸업하게 되었습니다.\r\n\r\n정중히 모시고 개업을 알려야 하나 요즘 코로나19로 인한 사적모임취소에 동참하고자 문자로 대신함을 양해해 주시길 바랍니다. \r\n\r\n많은 격려와 성원 부탁드립니다. 감사합니다.\r\n\r\n지플랜 (GPLAN) 공인중개사 \r\n대표 손희균 올림',0);
INSERT INTO `article_tbl` VALUES (64,1,32,'01091280586','2020-03-24','2021-04-30','0000-00-00','0000-00-00','다가구 주택의 두 얼굴 ','0','다가구주택은 공동주택과 단독주택 성격을 모두 갖고 있기 때문이다. 그 판단에 따라',NULL,'다가구 주택의 두 얼굴 \r\n\r\n1세대 1주택 양도세 비과세, 이건 늘 진리이다. 하지만 아닌 경우가 발생하게 된다.  3층짜리 다가구 주택에 더해 옥탑을 주택용도로 세를 주고 있었다.  이를 매각하면서 당연히 비과세를 기대했는데 그렇지 못했다.  \r\n\r\n단독주택은 단독주택과 다가구 주택이 있는데 다가구 주택은 소유권이 구분되지 않은 주택이다까지가 일반적으로 알고 있는 사실이다. 하지만 다가구주택은 공동주택과 단독주택 성격을 모두 갖고 있기 때문이다. 그 판단에 따라 여러 가구가 살고 있지만 세금 계산시 한 채로 취급해 1세대 1주택 비과세 혜택을 받는 수도 받지 못할 수도 있다. \r\n\r\n먼저 위에 말한 사례에서 1세대 1주택의 비과세 혜택을 받을 수 없었는지 살펴보기 위해 건축법을 살펴보면 건축법에서의 다가구 주택은 다음과 같이 정의하고 있다. \r\n\r\n<blockquote>■ 건축법 시행령 [별표 1] <개정 2019. 10. 22.>\r\n 다. 다가구주택: 다음의 요건을 모두 갖춘 주택으로서 공동주택에 해당하지 아니하는 것을 말한다.\r\n  1) 주택으로 쓰는 층수(지하층은 제외한다)가 <strong>3개 층 이하</strong>일 것. 다만, 1층의 전부 또는 일부를 필로티 구조로 하여 주차장으로 사용하고 나머지 부분을 주택 외의 용도로 쓰는 경우에는 해당 층을 주택의 층수에서 제외한다.\r\n  2) 1개 동의 주택으로 쓰이는 바닥면적(부설 주차장 면적은 제외한다. 이하 같다)의 합계가 660제곱미터 이하일 것\r\n  3) <strong>19세대(대지 내 동별 세대수를 합한 세대를 말한다) 이하</strong>가 거주할 수 있을 것</blockquote>\r\n\r\n3층의 다가구주택에서 옥탑을 주거용으로 사용하고 있다면 3개층 이하여야 한다는 규정을 위반하고 있어 공동주택*에 포함되어 양도세 중과세가 적용되게 되게 된다.  이럴 경우 비과세가 적용되기 위해서는 결국 옥탑을 비우고 철거하는 방법밖에 업게 된다. \r\n\r\n<blockquote>* ■ 건축법 시행령 [별표 1] <개정 2019. 10. 22.>다. 다세대주택: 주택으로 쓰는 1개 동의 바닥면적 합계가 660제곱미터 이하이고, 층수가 4개 층 이하인 주택(2개 이상의 동을 지하주차장으로 연결하는 경우에는 각각의 동으로 본다)</blockquote>\r\n\r\n또한 다가구 주택은 취득시에도 고급주택의 범주에 포함될 수 있다.\r\n\r\n취득세와 다가구 주택 \r\n지방세법 시행령 제28조(별장 등의 범위와 적용기준)\r\n\r\n<blockquote>지방세법 시행령 제28조(별장 등의 범위와 적용기준)④ 법 제13조제5항제3호에 따라 <strong>고급주택으로 보는 주거용 건축물과 그 부속토지</strong>는 <strong>다음 각 호의 어느 하나에 해당하는 것</strong>으로 한다. 다만, 제1호ㆍ제2호ㆍ제2호의2 및 제4호에서 정하는 주거용 건축물과 그 부속토지 또는 공동주택과 그 부속토지는 법 제4조제1항에 따른 <strong>취득 당시의 시가표준액이 6억원을 초과하는 경우</strong>만 해당한다.  <개정 2010. 12. 30., 2011. 12. 31.>\r\n\r\n<생략>\r\n\r\n4. <strong>1구의 공동주택(<u>여러 가구가 한 건축물에 거주할 수 있도록 건축된 다가구용 주택을 포함</u>하되, 이 경우 한 가구가 독립하여 거주할 수 있도록 구획된 부분을 각각 1구의 건축물로 본다)의 건축물 연면적(공용면적은 제외한다)이 245제곱미터(복층형은 274제곱미터로 하되, 한 층의 면적이 245제곱미터를 초과하는 것은 제외한다)를 초과하는 공동주택과 그 부속토지</strong></blockquote>\r\n\r\n이에 해당 경우에는 고급주택으로 취급되어 중과세 대상이 될수 있다. \r\n\r\n따라서 취득 또는 양도 과정에서 다가구 주택에 대한 확인 설명에서 주의가 필요할 것으로 판단된다. \r\n',0);
INSERT INTO `article_tbl` VALUES (66,1,18,'01091280586','2020-03-28','2021-05-20','0000-00-00','0000-00-00','가등기 경료된 주택의 임대차 계약과 공인중개','1','소유권이전청구권가등기에 관한 공인중개사의 설명의무 위반',NULL,'손해배상\r\n[서울남부지법 2008. 5. 21., 선고, 2008가단2993, 판결 : 확정]\r\n【판시사항】\r\n임차 목적 부동산에 경료된 소유권이전청구권가등기에 관한 공인중개사의 설명의무 위반을 이유로 손해배상책임을 인정한 사례\r\n\r\n【판결요지】\r\n공인중개사가 임차 목적 부동산에 경료된 소유권이전청구권가등기가 담보가등기라는 임대인의 말을 진실인 것처럼 의뢰인에게 그대로 전달하여 의뢰인이 그 말을 믿고 임대차계약을 체결하였으나 가등기권자가 소유권이전등기를 하고 건물인도집행을 한 사안에서, 공인중개사의 설명의무 위반으로 인한 손해배상책임을 인정한 사례.\r\n\r\n【참조조문】\r\n공인중개사의 업무 및 부동산 거래신고에 관한 법률 제25조 제1항,\r\n제30조 제1항,\r\n민법 제681조\r\n\r\n【참조판례】\r\n대법원 1993. 5. 11. 선고 92다55350 판결(공1993하, 1684),\r\n대법원 1999. 5. 14. 선고 98다30667 판결(공1999상, 1153)\r\n\r\n\r\n\r\n【전문】\r\n【원 고】\r\n【피 고】\r\n【변론종결】\r\n2008. 4. 30.\r\n\r\n【주 문】\r\n \r\n1.  피고는 원고에게 3백만 원 및 이에 대한 2008. 1. 24.부터 2008. 5. 21.까지는 연 5%, 다음날부터 갚는 날까지는 연 20%의 각 비율에 의한 돈을 지급하라.\r\n \r\n2.  나머지 청구를 기각한다.\r\n \r\n3.  소송비용은 70%는 원고가, 30%는 피고가 부담한다.\r\n \r\n4.  제1항은 가집행할 수 있다.\r\n\r\n\r\n【청구취지】\r\n4천만 원 및 지연손해금.\r\n\r\n【이 유】\r\n1. 기초 사실\r\n \r\n가.  원고는 공인중개사인 피고의 중개로 2006. 7. 4. 소외 1로부터 서울 구로구 구로동 (건물이름, 호수 생략)호를 아래와 같이 임차하였다.\r\n－ 보증금은 7천만 원으로, 계약금 3백만 원은 계약일, 잔금 67,000,000원은 2006. 8. 3. 각 지급한다.\r\n－ 소외 2 명의로 2005. 9. 27. 된 ‘소유권이전청구권가등기’는 잔금시 해제하되 위반시 전액 환불한다.\r\n \r\n나.  원고는 소외 1에게 위 계약일에 계약금 3백만 원을, 2006. 7. 31. 잔금 일부로 3백만 원을 각 지급하고, 2006. 8. 9.경(이 날이 전입신고일이고, 계약서상 입주일은 2008. 8. 2.인바 2006. 7. 31. 잔금 일부로 3백만 원을 지급하기 이전에 입주한 것인지 명확하지 않다) 입주하여 2006. 8. 28. 잔금 일부로 34,000,000원을 지급하였다.\r\n \r\n다.  소외 2는 위 가등기에 기해 2007. 6. 27. 소유권이전등기를 하고, 원고를 상대로 이 법원 2007가단57118호로 건물인도를 구하여 승소 판결을 받아 집행하였다.\r\n[다툼 없음]\r\n \r\n2.  원고 주장 \r\n가.  피고는 임대차 계약 당시 ( 소외 1의 남편 소외 3과 함께) 원고에게 “ 소외 2는 소외 3의 사촌동생이고, 소외 2의 가등기로 담보되는 채권은 3천만 원밖에 되지 않으므로 보증금 7천만 원을 회수하는 데 문제가 없다.”는 취지로 설명하였다.\r\n \r\n나.  원고가 입주하고 잔금 지급을 보류한 상태에서 피고는 가등기 해지는 자신이 책임지겠으니 잔금 일부를 지급하라고 독촉하여 위와 같이 지급하였다.\r\n〓 결론적으로, 소외 2의 가등기는 담보가등기가 아니었고, 원고는 보증금을 반환받지 못하고 인도당하였으므로 피고는 업무상 과실로 권리관계를 잘못 설명하여 원고가 입은 손해로, 보증금 4천만 원에 대해 배상책임이 있다.\r\n \r\n3.  판 단 \r\n가.  사실인정\r\n원고 주장 가. 부분에 대해서는 피고도 다투지 않고, 나. 부분은 원고 주장 이외에는 인정할 증거가 없다.\r\n \r\n나.  손해배상책임의 성립\r\n부동산중개업자와 중개의뢰인과의 법률관계는 민법상의 위임관계와 같으므로, 중개업자는 선량한 관리자의 주의로써, 중개의뢰의 본지에 따라 의뢰받은 중개업무를 처리하여야 할 의무가 있을 뿐 아니라, 중개물건의 권리관계, 법령의 규정에 의한 거래 또는 이용제한사항 등을 확인하여 중개의뢰인에게 설명할 의무가 있다( 대법원 1993. 5. 11. 선고 92다55350 판결등).\r\n이러한 설명의무를 이 사건에 적용하면, <u>임차 대상 부동산에 가등기가 경료된 경우 등기부 기재만으로 담보가등기인지 여부가 불분명하다면 담보가등기인지 여부, 피담보채권액 등을 가등기권자에게 직접 확인하여 설명할 의무까지는 없을 것이나, 후순위권리자에게 위험도가 더 큰 소유권이전청구권보전가등기일 수도 있거나 담보가등기이더라도 피담보채권액을 알 수 없다</u>고 설명하여야지 담보가등기로서 채권액이 3천만 원이라는 임대인의 말을 진실인 것처럼 의뢰인에게 그대로 전달하여 의뢰인이 그 정보를 믿고 상대방과 계약에 이르게 되었다면, 부동산중개업자의 그러한 행위는 선량한 관리자의 주의로 신의를 지켜 성실하게 중개행위를 하여야 할 중개업자의 의무에 위반한 것이므로 이로 인한 의뢰인의 손해를 배상하여야 한다.\r\n \r\n다.  손해배상의 범위\r\n위와 같은 잘못된 설명으로 원고가 지급하게 될 보증금 전액에 대해 반환받을 수 없는 위험을 초래하기는 하였으나, 한편 <u>피고(공인중개사)는 <strong>계약금을 제외한 보증금 잔금은 가등기 해제 서류와 동시에 지급한다</strong>는 <strong><특약사항></strong>을 마련하여 줌으로써 잔금에 대해서는 이러한 위험을 해소하였는데도 원고가 이러한 특약상 항변권을 포기하고 지급하였으므로 피고의 책임은 위 특약에 의해 보호되지 못한 계약금 3백만 원에 한정함</u>이 상당하다.\r\n \r\n4.  결 론\r\n청구는 주문 인정 범위에서만 이유 있다.\r\n\r\n\r\n판사 이형주',0);
INSERT INTO `article_tbl` VALUES (67,1,18,'01091280586','2020-03-31','2021-04-30','0000-00-00','0000-00-00','담보신탁 계약 실무 ','1','담보신탁이 되어 있는 경우-하고 싶지 않지만 하여야 하는 상황에 놓이는 경우가 있',NULL,'1. 부동산 담보신탁이란? \r\n토지ㆍ건물 등 부동산을 담보로 제공하고 자금을 대출받고자 하는 경우에 이용할 수 있는 신탁 상품이다.\r\n\r\n2. 담보신탁을 이용하는 이유 \r\n실무에서 보면 부동산 담보신탁이 발생하는 대부분의 경우가 임대인수가 많거나, 방갯수가 많은 상가주택 또는 다가구의 경우 소위 방공제가 들어가되며 이에 따라 처음 기대했던 만큼의 대출액이 나오지 않게된다.  이럴때 공제부분이 없이 진행이 되는 담보신탁을 이용하여 담보대출을 받게된다. \r\n\r\n이러한 담보신탁이 되어 있는 경우-하고 싶지 않지만 하여야 하는 상황에 놓이는 경우가 있게된다.- 어떻게 계약을 하는데 있어 주의할 점을 실제 판례를 통해 살펴보도록 하겠다. \r\n\r\n 3. 계약실무 \r\n\r\n예를 들어 등기사항증명서에서 수탁자가 지정되어 있는 경우 이 계약을 위해서는 수탁자와 위탁자(소유자) 대출금융기관이 관여하게 된다. \r\n\r\n신탁해지를 조건으로 계약을 진행하는 경우에는 수탁자의 동의가 필요하지 않으나 그렇지 않은 경우에는 수탁자의 동의가 필요하다.  \r\n\r\n하지만 이를 위해 수탁자에 확인하며 대출금융기관의 동의를 먼저 요구한다.  따라서 계약을 위해서는 대출금융기관을 먼저확인하고 그 동의 후 수탁사의 동의를 얻어 계약의 진행이 가능해진다. \r\n\r\n인천지방법원 2016. 5. 10. 선고 2015가단206774 판결\r\n \r\n\r\n\r\n[판결 요지]\r\n\r\n부동산중개업자로서는 <u>담보신탁된 건물에 관한 임대차계약을 중개함에</u> 있어, 임차의뢰인인에게 신탁원부를 제시하면서 건물에 관하여 담보신탁계약이 체결되어 신탁회사 앞으로 신탁을 원인으로 하는 소유권이전등기가 마쳐진 사실과 더불어 그 법적 효과 즉, <u>신탁회사가 건물의 소유자이므로 의뢰인이 체결하는 임대차계약은 임대인의 소유가 아닌 부동산에 관한 것이고, <strong>신탁회사의 사전승낙을 받지 아니하고 임의로 체결한 임대차계약은 소유자인 신탁회사에게 효력을 주장할 수 없다</strong>는 사실을 성실․정확 하게 설명할 의무</u>가 있고, 만일 중개업자가 고의나 과실로 이러한 의무를 위반하여 임차의뢰인에게 재산상의 손해를 발생하게 한 때에는 공인중개사법 제30조에 의하여 이를 배상할 책임이 있다고 한 사례.\r\n\r\n<h3 align=\"center\">주 문</h3>\r\n\r\n1. 피고들은 공동하여 원고에게 12,500,000원 및 이에 대하여 피고 정○○은 2015. 3.6 부터, 피고 한국공인중개사협회는 2015. 3. 7.부터, 각 2016. 5 10.까지는 연 5%의,각 그 다음날부터 다 갚는 날까지는 연 15%의 각 비율로 계산한 금원을 지급하라.\r\n\r\n2. 원고의 주장요지\r\n\r\n피고 정○○은 이 사건 임대차계약을 중개한 공인중개사로서 이 사건 건물의 소유자인 국제신탁으로부터 임대차계약체결에 대한 동의 내지 승낙을 받았는지 여부를 확인할 의무가 있다. 그럼에도 불구하고 피고 정○○은 이를 확인하지 아니한 채 위탁자인 이○○와 임대차계약을 해야한다는 취지로 설명하였고, 이를 믿은 원고는 피고 정○○의 잘못된 설명을 믿고 이 사건 임대차계약을 체결하게 되었다.\r\n\r\n3. 판단\r\n\r\n가. 손해배상책임의 발생\r\n\r\n1) 신탁된 부동산에 관한 중개업자의 확인․설명의무\r\n\r\n공인중개사법 제25조 제1, 2항, 같은 법 시행령 제21조, 같은 법 시행규칙 제16조에 의하면, 공인중개사는 중개대상물에 대한 권리를 취득하고자 하는 중개의뢰인에게 중개가 완성되기 전에 중개대상물의 소유권․전세권․저당권․지상권 및 임차권 등 권리관계 등을 확인하여 이를 설명하고, 설명의 근거자료를 제시하여야 하며, 그 확인 ​설명을 위하여 중개대상물의 매도의뢰인·임대의뢰인 등에게 당해 중개대상물의 상태에관한 자료를 요구할 수 있고, 중개가 완성되어 거래계약서를 작성할 때에는 위 확인․설명사항을 같은 법 시행규칙 제16조가 정한 서식에 따른 중개대상물확인․설명서에 기재하여 거래당사자에게 교부하여야 하며, 매도의뢰인․임대의뢰인 등이 중개대상물의 상태에 관한 자료 요구에 불응한 경우에는 그 사실을 매수의뢰인․임차의뢰인 등에게 설명하고 위 중개대상물확인․설명서에 그 사실을 기재하여 거래당사자에게 교부하여야 한다.\r\n\r\n그리고 위 중개대상물 확인․설명서에 대한 서식에는 중개대상물의 권리관계란에 ‘등기부 기재사항’ 이외에 ‘실제 권리관계 또는 공시되지 아니한 물건의 권리사항’을 기재하도록 하고 있다.\r\n\r\n이와 같이 공인중개사 법령의 관련 규정들이 중개업자의 중개대상물에 대한 확인․설명의무의 내용과 방법을 상세히 정한 것은 공정하고 투명한 부동산거래질서를 확립하여 국민의 재산권을 보호하는 데 그 입법취지가 있는 것이다(대법원 2012. 1. 26. 선고 2011다63857 판결)\r\n\r\n또한 구 부동산등기법(2013. 5. 28.법률 제11826호로 개정되기 전의 것) 제81조 제2항은 ‘신탁원부는 등기기록의 일부로본다.’고 규정하고 있고, 앞서 살핀 바와 같이 이 사건 신탁계약 제9조 제2항, 제10조제3, 4항에서 ‘위탁자는 수탁자의 사전승낙이 없는 경우 신탁부동산을 임대하지 못하고, 위탁자가 임의로 체결한 임대차계약은 수탁자에게 그 효력을 주장할 수 없다’는 취지로 명시적으로 규정하고 있다.\r\n\r\n그러므로 중개업자로서는 담보신탁된 이 사건 건물에 관한 임대차계약을 중개함에 있어, 임차의뢰인인 원고에게 신탁원부를 제시하면서 이 사건 건물에 관하여 담보신탁계약이 체결되어 국제신탁 앞으로 신탁을 원인으로 하는 소유권이전등기가 마쳐진 사실과 더불어 그 법적 효과 즉, 국제신탁이 이 사건 건물의 소유자이므로 원고가 체결하는이 사건 임대차계약은 임대인인 이○○의 소유가 아닌 부동산에 관한 것이고, 국제신탁의 사전승낙을 받지 아니하고 임의로 체결한 이 사건 임대차계약은 소유자인 국제신탁에게 효력을 주장할 수 없다는 사실을 성실․정확하게 설명할 의무가 있고,\r\n\r\n만일 중개업자가 고의나 과실로 이러한 의무를 위반하여 임차의뢰인에게 재산상의 손해를 발생하게 한 때에는 공인중개사법 제30조에 의하여 이를 배상할 책임이 있다.\r\n\r\n2) 피고들의 손해배상책임\r\n\r\n① 피고 정○○은 공인중개사로서 이사건 임대차계약을 중개함에 있어 이 사건 신탁계약의 내용을 면밀히 검토한 뒤, 원고에게 이 사건 신탁계약의 내용이 앞서 살핀 바와 같은 담보신탁계약인 점, 이러한 신탁의 법적 효과로서 수탁자인 국제신탁이 원고와 같은 제3자에 대하여 소유자가 되어원칙적으로 이○○에게 임대권한이 없다는 점을 제대로 설명하지 아니하고 ‘이○○가집주인이니까 계약해도 된다’는 취지로 설명한 점,\r\n\r\n② <u>피고 정○○은 이 사건 임대차계약 체결 당시 국제신탁에 대하여 사전승낙 여부를 확인하였다고 하나, 그 사전승낙 여부 및 확인 여부를 알 수 있는 객관적인 자료</u>가 전혀 없을 뿐만 아니라, <u>임대의뢰인인이○○나 이○○의 대리인이라고 칭해지는 장○○에게 국제신탁의 사전승낙에 관한 근거자료를 제출하여 줄 것을 요구한 사정</u>도 전혀 보이지 않는 점,\r\n\r\n③피고 정○○으로부터 위와 같은 설명으로 제대로 듣지 못한 원고는 이○○와 이 사건 임대차계약을 체결하여도 아무런 문제가 없을 것으로 오인하여 이 사건 임대차계약을 체결한 뒤 이○○에게 임대차보증금을 지급하기에 이른 점 등에 비추어 보면, 피고 정○○은 중개대상물에 대한 확인․설명의무를 다하지 못하였다고 판단되고, 갑 제2호증의 기재와 같이 피고 정○○이 <u>이 사건 임대차계약서에 이 사건 건물의 소유자가 국제신탁이 라는 사실을 기재하였다는 사정 내지 증인 승○○의 일부 증언만으로는 위와 같은 인정을 뒤집기에 부족</u>하다.',0);
INSERT INTO `article_tbl` VALUES (69,1,32,'01091280586','2020-04-02','2021-04-30','0000-00-00','0000-00-00','카카오톡 대화 상대방 프로필 이름 변경하기','0','카카오톡 단체 대화방에서 대화 상대방 프로필 이름을 기억하기 쉽도록 변경하는 방법',NULL,'공인중개사들의 모임에도 카카오톡이 많이 <p>이용되면서 카카오프로필의 이름을 쉽게 했으면 하는데 예를 들어 지역 실명 등으로 규칙을 정하는 경우가 많은데 \r\n\r\n당사자 입장에서는 본인이 속한 단체 카카오단체 톡방이 한둘이 아니다 보니까 바꾸는 것이 쉽지 않은 경우가 많습니다. \r\n\r\n그런 규칙없이 그냥 각자 상대방을 기억하기 쉬운 방법으로 정하면 어떨까요?  이렇겠요<br></p>\r\n\r\n\r\n<p>1. <img src=\"img/profile2.jpg\"><p>\r\n<p>2. <img src=\"img/profile3.jpg\"><p>\r\n<p>3.<img src=\"img/profile4.jpg\"></p>',0);
INSERT INTO `article_tbl` VALUES (70,1,31,'01091280586','2020-04-02','2021-04-30','2020-04-02','2020-04-15','공인중개사의 눈으로 본 부동산 공약 1. 고','0','총선에서의 공약들은 공인중개사 입장에서 살펴보기로 한다.  먼저 제1야당인 미래통',NULL,'<blockquote>한편 제1야당인 미래통합당은 부동산 대출규제 등에 적용되는 고가주택 기준을 현행 \'시세 9억원 초과\'에서 <strong>\'공시가격 12억원 이상\'으로 상향</strong>하는 공약을 내놨다. 또 급격한 공시가격 인상도 저지하기로 했다. 출처 : 머니투데이 https://realestate.daum.net/news/detail/main/20200402111803700</blockquote>\r\n\r\n현재의 고가주택 기준은 <strong>시가 9억원 기준</strong>으로 이를 기준으로 주택 보유세가 늘어나 양도소득세, 취득세 등 세금, 대출 등 정부 규제 적용 여부가 결정되어 지고있다.  \r\n\r\n이러한 공시가에 대해 국토교통부는 2020년 공시가율 재고율을 시가 9억원미만에 대해서는 미적용키로 결정하고 시세 9억원 초과 주택(전체주택의 4.8%)에 대해서는 구간별로 8%-12%의 현실화율 제고를 결정하였다.  이 때문에 고가주택 보유자 상당수는 세부담이 증가하였다는 평가에 부닥치기도 하였다. \r\n\r\n하지만 고가주택의 기준은 시가에서 공시가로 그리고 9억에서 12로 변경하는 것에 대해  공인중개사 입장에서 먼저 드는 생각은 공시지가 12억 이상인 주택은 얼마나 되는가의 확인이 필요했다. \r\n \r\n그래서 국토교통부 2020년 3월 18일 보도자료 중  시ㆍ도 공시가격(안) 수준별 공동주택 분포를 보기로 하였다.  \r\n\r\n이에 따르면 전국의 공동주택은 13,830,052이며 이중 공시가격(안)*에 따르면 <strong>그중 12억 이상인 공동주택은 185,014으로 전체의 1.337767927%</strong>에 지나지 않는다. \r\n\r\n<blockquote>*합리적으로 자기집의 공동주택 가격을 올려달라는 사람을 없을 거 같고 설령 있다고 해도 낮춰달라는 사람보다는 많을 것 같지 않다는게 합리적이라고 본다면 고가주택의 수는 이보다 줄어들긴해도 늘어나진 않을 것이다.</blockquote> \r\n\r\n또한 울산 세종 강원 충북 충남 전북 전남 경북 경남은 공시가 12억이상 공동주택은 단 한 채도 없으며 광역시 광주에는 단 2채뿐니다.  \r\n\r\n그럼 결국 서울 특히 강남 만을 타겟으로 한 규제에 불과하고, 규제의 대상으로 1%가 과연 규제로서의 효과를 가질지도 의문이며 마찬가지이유로 그 다음 수순은 고가주택규정의 폐지로 갈것이 자명하다.  이를 현실의 주택시장에 대한 정책의 포기로 보인다. ',0);
INSERT INTO `article_tbl` VALUES (71,1,32,'01091280586','2020-04-06','2021-04-30','2020-04-06','0000-00-00','서울시 수도요금 이사정산','0','이사시 이사정산을 하게되는데 이전에는 120을 통해 정산을 해야했는데 코로나로 인',NULL,'이사시 이사정산을 하게되는데 이전에는 120을 통해 정산을 해야했는데 코로나로 인한 재택근무로 인해 재택근무시 정산확인이 안되어 사는 <u>동에 따라 120아닌 해당 수도사업소</u>에 직접 전화를 해서 정산을 해야 한다고 하네요\r\n\r\n<table class=\"calwater\">\r\n<caption><h3>수도사업소 관할지역 및 전화번호</h3></caption>\r\n<tr>\r\n<td>중부수도사업소</td><td> 종로구, 중구, 용산구, 성북구</td><td>TEL 02) 3146-3500</td>\r\n</tr>\r\n<tr>\r\n<td>서부수도사업소 </td><td> 은평구, 서대문구, 마포구의 전지역 </td><td>TEL 02) 3146-5000</td>\r\n</tr>\r\n<tr>\r\n<td>북부수도사업소 </td><td>강북구, 도봉구 , 노원구 지역 </td><td> TEL 02) 3146-3200</td>\r\n</tr>\r\n<tr>\r\n<td>동부수도사업소</td><td>성동,광진,중랑구,동대문구 </td><td>TEL 02) 3146-2600</td>\r\n</tr>\r\n<tr>\r\n<td>강동수도사업소</td><td> 송파구, 강동구 </td><td>TEL 02) 3146-5000</td>\r\n</tr>\r\n<tr>\r\n<td>강남수도사업소</td><td> 강남·서초구 </td><td>TEL 02) 3146-4700</td>\r\n</tr>\r\n<tr>\r\n<td>남부수도사업소</td><td> 동작구,영등포구, 금천구</td><td>TEL 02) 3146-4400</td>\r\n</tr>\r\n<tr>\r\n<td>강서수도사업소</td><td> 양천, 강서, 구로구</td><td> TEL 02) 3146-3800</td>\r\n</tr>\r\n</table>',0);
INSERT INTO `article_tbl` VALUES (78,1,18,'01091280586','2020-04-30','2021-04-30','2020-04-24','0000-00-00','[법령해석]공인중개사가 중개보조원이 될 수 ','0','「공인중개사법」 제2조제2호에 따른 공인중개사가 같은 조 제5호의 소속공인중개사가',NULL,'민원인 - 공인중개사가 중개보조원이 될 수 있는지 여부(「공인중개사법」 제2조 등 관련\r\n안건번호20-0053회신일자2020-04-27\r\n1. 질의요지\r\n「공인중개사법」 제2조제2호에 따른 공인중개사가 같은 조 제5호의 소속공인중개사가 아닌 같은 조 제6호의 중개보조원이 될 수 있는지?\r\n2. 질의배경\r\n  민원인은 위 질의요지에 대한 국토교통부의 회신내용에 이견이 있어 법제처에 법령해석을 요청함.\r\n3. 회답\r\n  「공인중개사법」 제2조제2호에 따른 공인중개사는 같은 조 제6호의 중개보조원이 될 수 없습니다.\r\n4. 이유\r\n  「공인중개사법」 제2조에서는 개업공인중개사에 소속된 공인중개사로서 중개업무를 수행하거나 개업공인중개사의 중개업무를 보조하는 자를 “소속공인중개사”로(제5호), 공인중개사가 아닌 자로서 개업공인중개사에 소속되어 중개대상물에 대한 현장안내 및 일반서무 등 개업공인중개사의 중개업무와 관련된 단순한 업무를 보조하는 자를 “중개보조원”으로 정의(제6호)하고 있는바, 같은 법에 의한 공인중개사자격을 취득한 자가 “공인중개사”(제2호)임을 고려하면 “공인중개사가 아닌 자”는 같은 법에 의한 공인중개사 자격을 취득하지 않은 자를 의미하는 것이 문언상 명백합니다.\r\n\r\n  그리고 「공인중개사법」은 공인중개사의 업무 등에 관한 사항을 정하여 그 전문성을 제고하고 부동산중개업을 건전하게 육성함을 목적(제1조)으로 하는 법률로서 소속공인중개사와 중개보조원을 공인중개사인지 여부와 수행하는 업무에 따라 구분한 것은 공인중개사 자격을 취득한 자로 하여금 개업공인중개사 또는 소속공인중개사로서 중개업에 종사하도록 하여 공인중개사가 책임을 지고 중개업무를 수행하도록 하는 동시에 공인중개사 자격 제도를 기반으로 한 부동산중개업을 건전하게 육성하려는 것임을 고려하면, 공인중개사는 소속공인중개사가 아닌 중개보조원이 될 수 없다고 보는 것이 입법취지에도 부합하는 해석입니다.\r\n\r\n  아울러 「공인중개사법」상 중개보조원은 중개업무는 수행할 수 없고 중개업무와 관련된 단순한 업무만 보조할 수 있음에도 불구하고 공인중개사가 중개보조원이 되는 것이 허용된다고 할 경우, 공인중개사 자격을 갖춘 중개보조원이 사실상 중개업무를 수행하는 문제가 발생할 가능성이 크다는 점도 이 사안을 해석할 때 고려해야 합니다.\r\n\r\n※ 법령정비 권고사항 \r\n\r\n  「공인중개사법」 제2조제6호는 중개보조원의 정의 규정임을 고려할 때 공인중개사는 중개보조원이 될 수 없도록 금지하는 내용을 별도로 규정할 필요가 있습니다. \r\n< 관계 법령>\r\n공인중개사법\r\n제2조(정의) 이 법에서 사용하는 용어의 정의는 다음과 같다.  \r\n  1. \"중개\"라 함은 제3조의 규정에 의한 중개대상물에 대하여 거래당사자간의 매매ㆍ교환ㆍ임대차 그 밖의 권리의 득실변경에 관한 행위를 알선하는 것을 말한다.\r\n  2. \"공인중개사\"라 함은 이 법에 의한 공인중개사자격을 취득한 자를 말한다.\r\n  3. \"중개업\"이라 함은 다른 사람의 의뢰에 의하여 일정한 보수를 받고 중개를 업으로 행하는 것을 말한다.\r\n  4. \"개업공인중개사\"라 함은 이 법에 의하여 중개사무소의 개설등록을 한 자를 말한다.\r\n  5. \"소속공인중개사\"라 함은 개업공인중개사에 소속된 공인중개사(개업공인중개사인 법인의 사원 또는 임원으로서 공인중개사인 자를 포함한다)로서 중개업무를 수행하거나 개업공인중개사의 중개업무를 보조하는 자를 말한다.\r\n  6. \"중개보조원\"이라 함은 공인중개사가 아닌 자로서 개업공인중개사에 소속되어 중개대상물에 대한 현장안내 및 일반서무 등 개업공인중개사의 중개업무와 관련된 단순한 업무를 보조하는 자를 말한다. \r\n\r\n관계법령\r\n- 공인중개사법 제2조6호‚ 제15조‚ 제16조 등',0);
INSERT INTO `article_tbl` VALUES (90,1,32,'01091280586','2020-06-05','2021-04-30','0000-00-00','0000-00-00','이 멍청한 신한 농협 전세대출 담당자와 능력','0','대한민국의 개업공인중개사는 최소한 은행창구직원보다는 공인(公認)중개사이며 공인중개',NULL,'최근 중소기업청년대출(이하 중기청)의 수요가 증가하고 있다.  그런데 좀 이상하다.\r\n\r\n중기청 외의 LH나 SH 등의 정책대출은 임차 예정물건의 심사에 필요한 정보를 해당기관에 보내면 심사 후 임차 예정 물건에 대한 대출가부가 결정되고 나서 해당 중개대상물건의 계약을 진행하게 된다.  하지만 유일하게 중기청만은 계약을 하고나서 그 계약서를 가지고서 금융기관에서 대출의 가부를 알겨주게 된다.  하지만 어떤 이유에서 그것을 대출 불가의 결정이 될 경우 거래 당사들은 난감한 상황에 빠지게 된다.  \r\n\r\n그러면서 자기네 고객들은 위해서 한다는 것이 거래 협상에서 약자의 위치에 있는 세입자에게 \'대출 불가일 경우 조건없이 계약금을 돌려준다\'는 특약을 넣어오라고 한다. \r\n\r\n과연 그들이 임대인이라면 심사기간 동안 짧게는 1주에서 2주에 이르는 기간을 자기의 의지와 상관없이 계약이 불안정한 상태에 놓이는 특약을 받아들이겠는지를 묻고 쉽다.  중기청 아니라도 괜찮은 전세물건 찾는 임차인은 많은데 말이다.  \r\n\r\n더군다나 이러한 특약을 요구할 경우 우리의 거래 관행은 1. 임대차는 30일에서 45일정도의 거래 기간을 가지고 2. 새로운 임차인의 계약금을 나가는 임차인에게 내줌으로서 임대차의 종료의 증표로서의 역활뿐만 아니라, 나가는 임차인은 새로의 집의 계약금으로 그 금전을 사용하게 된다.  그런 상황에서 이러한 특약은 임대인에게는 나가는 임차인에게 해당 금전을 지급할 수 없게하고, 나가는 임차인 까지도 집을 보러다닐 시간을 뺏았아 불안한 상황에 놓이는 결과를 가져오게 된다.  이는 분명 은행의 고갱인 차주에게 뿐만 아니라 그 거래상대방인 임대인에게까지 그리고 심지어는 나가는 임차인에게까지 영향을 미치는 금융기관의 갑질이다. \r\n\r\n이러한 갑질에 더해 그 오지랖은 어찌나 넓은지 계약의 또 다른 특약에도 관여한다.  대한민국의 한국공인중개사협회의 공식 거래작성 프로그램인 KREN을 사용하는 공인중개사의 계약에는 다음의 특약이 자동으로 들어간다. \r\n\r\n<img src=\"http://www.reuni.kr/img/speclause.jpg\">\r\n\r\n이중에 \"<u>2.임차인은 위 부동산에 존재하는 선순위 권리(근저당권, 임차권 등)로 인하여 경매 등이 실행될 경우 임차보증금의 전부 또는 일부를 반환받지 못할 수도 있음을 확인한다.</u>\"에 특히 날선 시비를 건다.  이건 창구에 않은 멍청한 신한 농협직원처럼 가오잡을려고 들어간 특약이 아니다.  은행의 상품판매에서 그렇듯 <strong>불완전 판매</strong>를 막기위한 특약은 그것을 알려주라는 것이 또한 대한민국 법원의 판단이다.  더불어 대한민국의 모든 개업공인중개사는 안전한 거래를 위해 최선의 노력을 다하지만 어느 누구의 잘못의 아닌 시장으로부터 오는 위험을 통제할 수 없고, 공인중개가는 그런 위험에 대해 알리는 것이 개업공인중개사의 당연의 업이기도 하다.  그걸 가지고 공인중개사도 아닌 일개 창구직원이, 더군다나 법률전문가도 아닌 은행직원이, 자기의 고객을 붙잡고 \'왜 그런 특약을 넣냐?\'는 오지랖을 한다.  이것은 전의 갑질에 더한 전형적인 오지랖이다.  그럼 제대로 읽어볼 시간도 안주는 은행의 서류는 그런 문구가 없는지 스스로 살펴봤으면 좋겠다.  \r\n\r\n결국 이러한 하나 하나가 더구나 전세구하기 힘든 청년들의 집구하기를 더욱 힘들게 만들고 그 없는 전세를 겨우 구해 청년들을 돕는 공인중개사의 노력을 더욱 힘들게 하는 결과를 가져오고 있다.  \r\n\r\n대한민국의 개업공인중개사는 최소한 은행창구직원보다는 공인(公認)인 중개사이며 공인중개사법의 의해 그 업을 하는 전문인다.  은행의 이런 어설픈 갑질 오지랖은 개선되었으면 한다. \r\n\r\n하지만 더 화나는건 한국공인중개사협회 상담실이다.  우리 손님이 한국공인중개사협회 상담실에 그 특약에 대해 문의했을 때 그에 대해 답조차 못하면서 왜 그 자리에 있는건지 모르겠다.  하긴 모... 전 20만원 안주면 안갑니다. ㅎㅎ 어떻게 공인중개사의 가치가 돈만으로 평가되는건 아니지만 협회가 젤 안쳐주니 이런 상황이 생기는 지도 모르겠다. ',0);
INSERT INTO `article_tbl` VALUES (91,1,32,'01091280586','2020-06-23','2021-04-30','0000-00-00','0000-00-00',' \"21번째 부동산 대책, 서민 \'내집 마련','0','21번째 부동산 대책에 대한 공인중개사의 이야기 ',NULL,' \"21번째 부동산 대책, 서민 \'내집 마련\' 꿈 무너뜨려\"다고 합니다. \r\n \r\n 서민의 내 집마련의 꿈은 빚을 내어 내집을 마련하는 것이 아닙니다.  정말 가끔 궁금해집니다.  과연 나는, 우리는 죽을 때 빚없이 죽을 수 있는지 학자금대출에 자동차 대출에 집대출까지 하지만 그 중에 가장 무서운 것은 집 대출일 것입니다.  가장 큰 금액으로 가장 긴 기간 서민을 압박하기 때문입니다.  \r\n\r\n빚을 내어 내집을 마련해야 하는 절박함을 꿈으로 포장하지 마십시오.  \r\n\r\n내일이면 더 오를 거 가면 그러다 보면 소박한 내집 마련의 꿈은 더욱 멀어질거 같고 애 커가면서 들어갈 돈 생각하면 지금 빚이라도 내서 사지 않으면 영원히 내 집은 가져보지 못해 빚이라도 내서 사는 절박함이 서민의 꿈이라 포장되어서는 안됩니다.  \r\n\r\n빚으로 부동산 시장은 왜곡되고 서민들은 신음하고 있습니다.  \r\n\r\n소위 갭투자는 전세보증에서 매매가의 차액만으로 집을 사는 것을 말합니다.  하지만 그 보증금의 실체는 빚입니다.  어느 고객이 \'아파트도 아닌 빌라를 2년마다 5000씩 대출 받아 올려주니까 어느 순간 불싸지르고 싶다\'라는 말을 합니다.  시장이 빚으로 움직여 갈때 그것은 왜곡되어지고 레버리지라는 이름으로 포장되어 왜곡은 확대 재생산되어집니다.  \r\n\r\n공인중개사의 미래는 서민의 꿈과 함께 합니다. \r\n\r\n없지는 않을 것입니다.  하지만 그것이 전부는 아닙니다.  서민이 미래를 계획할 수 있는때 공인중개사는 미래도 가능합니다.  방 한칸 더 있는 집으로 이사를 계획하고 , 내 집 마련을 계획할 수 있을 때 공인중개사의 미래도 현실이 됩니다.  엄마들이 놀이터에 모여 말합니다.  몇해전까지만 해도 그래도 내 집마련을 해볼까 바둥 바둥했다. 근데 언젠가부터 포기하게 되드라 그게 오늘의 서민입니다. \r\n \r\n',0);
INSERT INTO `article_tbl` VALUES (92,1,18,'01091280586','2020-06-23','2021-04-30','2020-09-01','0000-00-00','자금조달계획서 제출대상 확대','0','□ (개선) 투기과열지구‧조정대상지역내에서 주택을 거래하는 경우 거래가액과 무관하',NULL,'② 자금조달계획서 제출대상 확대\r\n\r\n□ (현행) 자금조달계획서 제출 대상이 투기과열지구‧조정대상지역내 3억원 이상 주택 거래 시로 제한되어 있어,\r\n\r\n ㅇ 투기과열지구‧조정대상지역내 3억원 미만 저가 주택의 경우 자금출처 조사 등 실효성 있는 투기수요 점검에 한계\r\n\r\n□ (개선) 투기과열지구‧조정대상지역내에서 주택을 거래하는 경우 거래가액과 무관하게 자금조달계획서를 제출토록 함\r\n\r\n□(적용시기) ｢부동산거래신고법 시행령｣ 등 개정 후 즉시 시행(’20.9월)',0);
INSERT INTO `article_tbl` VALUES (95,1,18,'01091280586','2020-06-23','2021-04-30','2020-09-01','0000-00-00','자금조달계획서에 대한 증빙자료 제출대상 확대','0','자금조달계획서에 대한 증빙자료 제출대상 확대',NULL,'③ 자금조달계획서에 대한 증빙자료 제출대상 확대\r\n\r\n□ (현행) 투기과열지구 9억원 초과 주택 거래신고 시 자금조달계획서 기재내용에 대한 객관적 진위를 입증할 수 있는 증빙자료를 제출\r\n\r\n   * 자조서 작성 항목별로 예금잔액증명서, 소득금액증명원 등 증빙자료를 첨부‧제출\r\n\r\n ㅇ 투기과열지구 9억원 이하 중‧저가 주택의 경우 비정상 자금조달 등 이상거래에 대한 신속한 대응 및 선제적 조사가 제한\r\n\r\n□ (개선) 투기과열지구 내 주택 거래 신고 시 거래가액과 무관하게 자금조달계획서 작성 항목 별 증빙자료를 첨부하여 제출토록 함\r\n\r\n ㅇ 증빙자료 확인을 통해 불법 증여, 대출규정 위반 등 의심거래는 집중 관리대상으로 선정하고, 실거래 신고 즉시 조사에 착수\r\n\r\n□(적용시기) ｢부동산거래신고법 시행령｣ 등 개정 후 즉시 시행(’20.9월)\r\n',0);
INSERT INTO `article_tbl` VALUES (97,1,18,'01091280586','2020-06-23','2021-04-30','2020-07-01','0000-00-00','규제지역내 주택담보대출 취급 시 전입·처분 ','0','규제지역내 주택담보대출 취급 시 전입·처분 요건 강화(무주택자/1주택자)\r\n',NULL,'① 규제지역내 주택담보대출 취급 시 전입·처분 요건 강화\r\n\r\n< 무주택자 >\r\n\r\n□ (현행) 투기지역·투기과열지구 내 시가 9억원 초과 주택 구입을 위해 주택담보대출을 받는 경우, 1년내 전입 의무를 부과\r\n\r\n ㅇ 조정대상지역의 경우 2년내 전입 의무 부과\r\n\r\n□ (개선) 全규제지역* 내 주택 구입을 위해 주택담보대출을 받는 경우 주택가격과 관계없이 <u>6개월내 전입 의무 부과</u>\r\n\r\n   * 투기지역, 투기과열지구, 조정대상지역\r\n\r\n□ (적용시기) 행정지도 시행* 이후 신규대출 신청 분**부터 적용\r\n\r\n   * 시행시기 : 전산개발 및 준비 등을 감안하여 ’20.7.1일부터 시행\r\n  ** <u>다만, 행정지도 시행 전에 주택매매계약(가계약 불포함)을 체결하고 계약금을 이미 납부한 사실을 증명한 차주, 대출 신청접수를 완료한 차주 등에 대해서는 종전규정 적용</u>\r\n\r\n< 1주택자 > \r\n\r\n□ (현행) 투기지역·투기과열지구내 주택 구입을 위해 주택담보대출을 받는 경우 1년내 기존주택 처분 및 신규주택 전입 의무 부과\r\n\r\n ㅇ 조정대상지역은 2년내 기존주택 처분 및 신규주택 전입 의무 부과\r\n\r\n□ (개선) 全규제지역내 주택 구입을 위해 주택담보대출을 받는 경우 6개월내 기존주택 처분 및 신규주택 전입 의무 부과\r\n\r\n□ (적용시기) 행정지도 시행* 이후 신규대출 신청분**부터 적용\r\n\r\n   * 시행시기 : 전산개발 및 준비 등을 감안하여 ’20.7.1일부터 시행\r\n  ** 다만, 행정지도 시행 전에 주택매매계약(가계약 불포함)을 체결하고 계약금을 이미 납부한 사실을 증명한 차주, 대출 신청접수를 완료한 차주 등에 대해서는 종전규정 적용',0);
INSERT INTO `article_tbl` VALUES (99,1,18,'01091280586','2020-06-23','2021-04-30','2020-12-01','0000-00-00',' 거주요건을 갖춘 경우 조합원 분양신청 허용','0','수도권 투기과열지구의 재건축에서는 조합원 분양신청 시까지 2년 이상 거주*한 경우',NULL,'\r\n (2) 거주요건을 갖춘 경우 조합원 분양신청 허용\r\n\r\n\r\n□ (현행) 재건축사업에서 거주여부와 관계없이 모든 토지등소유자에게 조합원 자격요건이 부여되고, 상대적으로 낮은 가격에 분양신청 가능\r\n\r\n□(개선) 수도권 투기과열지구의 재건축에서는 조합원 분양신청 시까지 2년 이상 거주*한 경우에 한하여 분양 신청 허용\r\n\r\n   * 현재 소유한 주택에서 소유 개시 시점(매각 후 재매입 시에는 재매입 시점부터 기산)부터 조합원 분양신청 시까지 2년 이상 거주(연속 거주가 아닌 합산 거주기간)\r\n\r\n□ (적용시기) ｢도시 및 주거환경정비법｣ 개정(’20.12) 후 최초 조합설립인가 신청 사업부터 적용',0);
INSERT INTO `article_tbl` VALUES (101,1,18,'01091280586','2020-06-23','2021-04-30','2020-12-01','0000-00-00','① 재건축부담금의 본격 징수 시작','0','① 재건축부담금의 본격 징수 시작',NULL,'① 재건축부담금의 본격 징수 시작\r\n\r\n□(현행) 헌법재판소의 재건축 초과이익환수제에 대한 “합헌” 결정(‘19.12.27)에 따라 제도의 본격 시행을 준비\r\n\r\n ㅇ국가징수분 재 배분 시 주거복지센터 설치, 공공임대 건설 등 주거복지 증진 위해 노력하는 지자체에 인센티브 부여\r\n\r\n□(계획) 한남연립(17억원)·두산연립(4억원) 시작으로 하반기부터 본격 징수\r\n\r\n ㅇ지자체 대상 집중교육 기 시행(`20.2), 주기적 집합교육 시행(`20.下～)\r\n\r\n   * 62개 조합(37개 지자체)에 약 2,533억원의 부담금 예정액(’18.4～’20.6) 기 통지\r\n\r\n\r\n※ 재건축부담금 시뮬레이션 결과(강남 5개 단지, 강북 1개 단지, 경기 2개 단지)\r\n\r\n□ 재건축부담금 예상액(조합원 1인당)\r\n\r\n ㅇ 강남 5개 단지 평균 : 4.4억~5.2억원(최고 6.3억~7.1억원, 최저 2.1억~2.3억원)\r\n\r\n ㅇ 강북 1개 단지 : 1천~1.3천만원\r\n\r\n ㅇ 수도권(경기) 2개 단지 : 60만~4.4천만원\r\n\r\n< 조합원1인당 재건축부담금 >\r\n\r\n강남(5개)\r\n단지1\r\n 단지2\r\n단지3\r\n 단지4\r\n단지5\r\n6.33억~7.13억원\r\n5.59억~7.03억원\r\n3.82억~5.02억원\r\n4.34억~4.40억원\r\n2.14억~2.28억원\r\n강북(1개)\r\n단지6\r\n경기(2개) \r\n단지7\r\n단지8\r\n\r\n1,080만~1,290만원\r\n2,340만~4,350만원\r\n60만~210만원\r\n\r\n\r\n\r\n② 실효성 있는 시행을 위한 제도 보완\r\n\r\n□(현행) 공시가격 현실화에 따라 종료시점과 개시시점의 주택가액 공시비율 차이가 발생하여 부담금 산정기준 논란\r\n\r\n ㅇ 광역 지자체가 주요 기반시설을 설치함에도 불구하고, 기초 지자체에 대한 재건축 부담금 배분율이 더 높음(광역 20%, 기초 30%)\r\n\r\n□(개선) 재건축 부담금 산정 개시 및 종료시점 주택가액 산정 시 동일한 공시비율을 적용*\r\n\r\n   * 지자체·조합의 정확한 부담금 산정을 위한 한국감정원의 지원근거 마련(’20.12)\r\n\r\n ㅇ 재건축 부담금 귀속비율을 광역지자체 30%, 기초지자체 20%로 조정\r\n\r\n□ (적용시기) ｢재건축초과이익 환수에 관한 법률｣ 개정(’20.12) 후 최초 재건축부담금 부과 조합부터 적용\r\n',0);
INSERT INTO `article_tbl` VALUES (103,1,18,'01091280586','2020-06-23','2021-04-30','2020-07-01','0000-00-00','① 주택 매매‧임대사업자 주택담보대출 금지','0','□ (개선) 모든 지역* 주택 매매‧임대 사업자**에 대하여 주담대 금지\r\n',NULL,'① 주택 매매‧임대사업자 주택담보대출 금지\r\n\r\n□ (현행) 규제지역내 주택매매‧임대 사업자 주담대는 LTV 20%~50%, 비규제지역내 주택매매‧임대 사업자 주담대는 LTV 규제 없음\r\n\r\n□ (개선) 모든 지역* 주택 매매‧임대 사업자**에 대하여 주담대 금지\r\n\r\n    * 규제지역·비규제지역 모두 포함      ** 법인·개인 사업자 모두 포함\r\n  *** 주택 매매‧임대 사업자인 경우라도 국토부가 인정하는 예외사유에 해당하는 경우 주담대 이용 가능\r\n\r\n□ (적용시기) 행정지도 시행* 이후 신규대출 신청 분**부터 적용\r\n\r\n   * 시행시기 : 전산개발 및 준비 등을 감안하여 ’20.7.1일부터 시행\r\n  ** 다만, 행정지도 시행 전에 주택매매계약(가계약 불포함)을 체결하고 계약금을 이미 납부한 사실을 증명한 차주, 대출 신청접수를 완료한 차주 등에 대해서는 종전규정 적용',0);
INSERT INTO `article_tbl` VALUES (106,1,32,'01091280586','2020-07-02','2021-04-30','2020-06-30','2020-08-30',' ｢빈집 및 소규모 주택 정비에 관한 특례법','0','앞으로 가로주택정비사업, 자율주택정비사업 등 소규모주택정비사업을 추진하는 경우 인',NULL,'* 가로구역의 범위 (단, 아래의 요건 모두 충족 시)\r\n\r\n 1. 가로구역 면적이 1만㎡ 미만(도계위 심의를 거치면 최대 2만㎡까지 확대 가능)\r\n\r\n 2. 도시계획도로 또는 「건축법」에 따른 6m 이상 도로 등으로 둘러싸인  일단의 지역 (공원, 녹지, 하천, 공공공지, 공용주차장, 도로 예정지 등도 도로로 간주)\r\n\r\n 3. 가로구역 내 통과 도시계획도로가 없을 것 \r\n\r\n앞으로 가로주택정비사업, 자율주택정비사업 등 소규모주택정비사업을 추진하는 경우 인근 주차장 사용권 확보로 의무적으로 설치해야 하는 주차 면수를 대체할 수 있는 비율이 최대 50%까지확대된다.\r\n-----------------------------------\r\n국토교통부(장관 김현미)는 ｢수도권 주택공급 기반 강화방안(’20.5.6)｣에 따른 후속조치로서 이러한 내용을 반영한 ｢빈집 및 소규모 주택 정비에 관한 특례법(이하 ‘소규모주택정비법’) 시행령｣ 일부개정안을 마련하여 6월 30일 입법예고(’20.6.30~8.9)한다고 밝혔다.\r\n\r\n이번 개정안의 내용은 다음과 같다.\r\n\r\n소규모주택정비사업* 또는 빈집정비사업(이하 ‘소규모주택정비사업 등’)을 시행하는 경우, 1) 소규모주택정비사업 등의 사업시행구역(이하 ‘사업시행구역’) 내에 공용 주차장을 함께 설치하고 해당 공용 주차장의 사용권을 확보하거나, 2) 사업시행구역 밖이라도 도시재생활성화계획에 따라 설치된 공용주차장의 사용권을 확보하면, 사용권 확보 면수로 주차 설치 의무면수를 최대 50%까지 (현재 최대 30%) 인정받을 수 있다.\r\n\r\n* 가로주택정비사업, 자율주택정비사업, 소규모재건축\r\n\r\n\r\n이에 따라, 조합이 사업시행구역 내 공용주차장 설치 부지를 제공하고 해당 공용주차장 사용권을 확보하는 경우, 조합원 등의 주차장 설치 부담이 줄어들고 인근 지역에 공용주차장이 추가로 공급되는 효과가 있을 것으로 기대된다.\r\n\r\n또한, 도시재생활성화지역 내 공용주차장 사용권으로 대체할 수 있는 주차 면수가 확대되어, 사업시행구역이 협소하여 주차장 설치가 어려운 소규모주택정비사업의 추진에도 도움이 될 것으로 보인다.\r\n\r\n개정안은 입법예고 이후 관계기관 협의, 법제처 심사, 국무회의 등을 거쳐 올해 10월 경 시행될 예정이다.\r\n\r\n전문은 국토교통부 누리집(http://www.molit.go.kr) “정보마당/법령정보/입법예고”에서 볼 수 있으며, 개정안에 대해 의견이 있는 경우 우편, 팩스, 국토부 누리집을 통해 제출할 수 있다.\r\n\r\n* 의견제출처: (우)30103 세종특별자치시 도움6로11 정부세종청사 5동 603호 국토교통부 주거재생과(전화번호: 044-201-4941, 4942 팩스: 044-201-5612)\r\n\r\n\r\n한편, 서울시 내 주택공급 활성화를 위해 국토교통부·서울시·LH·SH가 합동으로 진행 중인 ‘공공참여형 가로주택정비사업지 공모’에는 22개 지구가 접수(‘20.5월)하여 현재 사업성을 분석하고 있다. 해당 지구에 대해서는 주민 협의(‘20.7월)를 거쳐 오는 8월경 사업 지구를 최종 선정할 계획이다.\r\n\r\n국토교통부 주거재생과 이지혜 과장은 “소규모주택정비사업은 도심 내 주택 공급 확대뿐만 아니라 노후 저층 주거지를 재생하는 효과가 있으므로 보다 활성화될 필요가 있다”면서, “소규모주택정비법령 등 제도적인 개선이 필요한 부분을 지속적으로 발굴하고, 이와 관련한 다양한 의견을 적극 수렴하겠다”고 밝혔다.',0);
INSERT INTO `article_tbl` VALUES (108,1,32,'01091280586','2020-07-04','2021-04-30','0000-00-00','0000-00-00','[2] 형사범죄에 대한 고소장을 직접 제출해','0','불기소 처분에 대해 서는 불기소 이유 고지 청구가 가능하며 이에 대한 불복은 항고',NULL,'정말 오래 걸리네요 저도 지금에서 확인서 보니 제가 기사를 올린게 2월 21일 오늘이 7월 4일이니까 5개월까지는 안되지만 4개월이 넘어 걸린거죠 \r\n\r\n결과는 \'각하\' \r\n\r\n혐의없음(증거불충분) 죄가안됨 공소권없음에 해당될 때 내려지는 처분인데 처음부터 기필고 형사처벌해야되라는 의지가 있던건 아니지만 그래도 기소유예 정도는 나올 줄 알았는데 워낙 판례 등을 볼때 혐의는 소위 \'딱\' 떨어지기 때문에 \r\n\r\n그래서 이럴때 하는 방법이 \r\n\r\n\'불기소 이유 고지\'가 가능하다.  통지서에는 우편으로 하여야 하는거처럼 안내 되어 있지만 사실 전자민원(www.spo.go.kr)으로도 가능하다. 요즘시대에 굳이 움직일 필요는 없을 거 같아\r\n\r\n그리하여 5분만에 완료하였으나 늘 법을 다룰때는 날자에 민감해야 하는데 항고 즉, 검사에 처분에 대한 불복은 30일이내에 이루어 져야 하며 저의 경우 7월 2일날 받았으니까 대출 8월 2일 전까지는 하여야 하며 기한을 넘긴 경우 \'기각\'이 되게 됩니다. \r\n',0);
INSERT INTO `article_tbl` VALUES (110,1,18,'01091280586','2020-07-04','2021-04-30','0000-00-00','0000-00-00','term & breaking clause i','0','Undering of Korea Tenancy in term & breaking ',NULL,'<b>Make break clause if you can</b>\r\nYour agreement will be one of the following two kinds:\r\n\r\nPeriodic tenancies – A “periodic tenancy” is one that just keeps going until either you or the landlord gives notice to the other that you want to end it. There’s no fixed end date. If your agreement says nothing at all about when it will end, it’s a periodic tenancy. \r\n\r\nFixed-term tenancies – A fixed-term tenancy lasts for a set time, like six months or one year. It has a start date and an end date recorded in the agreement.\r\n\r\nTenancy agreement in Korea is mostly fixed-term tenancy that runs on two-year rent period to the next.  But a fixed-term tenancy automatically becomes an indefinite (periodic) tenancy when the end date is reached, unless you or the landlord gives notice to the other saying you don’t want the tenancy to continue or unless the two of you agree on something else, like another fixed-term tenancy.  If you don\'t give the correct period of notice to end your agreement you may remain responsible for paying the rent.  The landlord must give the notice to the tenant of the right to renewal no more than 6 months and not less than 1 month prior to the end of the lease.  And renter also must give the notice not less than 1 months.\r\n\r\nAccording to tenancy law of Korea, if you do not determine lease term or determine less than 2 year when sign on your contract, your lease term is deemed 2 years.  However, tenant can assert less than 2 years term that you determined. \r\n\r\n주택임대차 보호법 제6조(계약의 갱신) ① 임대인이 임대차기간이 끝나기 6개월 전부터 1개월 전까지의 기간에 임차인에게 갱신거절(更新拒絶)의 통지를 하지 아니하거나 계약조건을 변경하지 아니하면 갱신하지 아니한다는 뜻의 통지를 하지 아니한 경우에는 그 기간이 끝난 때에 전 임대차와 동일한 조건으로 다시 임대차한 것으로 본다. 임차인이 임대차기간이 끝나기 1개월 전까지 통지하지 아니한 경우에도 또한 같다.\r\n\r\n  ② 제1항의 경우 임대차의 존속기간은 2년으로 본다.  <개정 2009. 5. 8.>\r\n\r\n  ③ 2기(期)의 차임액(借賃額)에 달하도록 연체하거나 그 밖에 임차인으로서의 의무를 현저히 위반한 임차인에 대하여는 제1항을 적용하지 아니한다.\r\n\r\n[전문개정 2008. 3. 21.]\r\n\r\n \r\n\r\nFor some reason you want to move out before the end of the term, you can only end the agreement early if:\r\n\r\nthere is a term in your agreement, known as a break clause, which allows you to end the agreement early. The break clause should say how much notice you have to give, or your landlord agrees to you ending the agreement early. This is called surrender.\r\n\r\nIf you leave before the end of the fixed term without your landlord’s consent, you are liable to pay the rent until the term ends even if you aren’t living there.\r\n\r\nHowever, situations may come up that could affect the tenant ability to live in the rental for the entire lease term.  If you can, it will be best way to add break clause.  However, most landlord do not like the breaking clause or less than 2 years term.\r\n\r\nl  Example of break clause\r\n\r\nTenant shall have an option to terminate this Lease prior to the expiration of the Primary Lease Term at any time after April 30, 2019. Tenant shall provide written notice to Landlord of its intention to exercise such early termination option at least 90 days prior to the requested termination date and, with the written notice, Tenant shall pay a termination fee representing liquidated damages[1] to the Landlord of Five Thousand U.S. Dollars ($5,000).\r\n\r\n임차인은 임대차 목적물 인도 이후 언제든 계약의 해제를 요구할 수 있다.  이때 임차인은 3개월 전에 임대인에게 서면통보하여야 해지통보 도달 후 3개월이 경과한 함으로써 계약은 해지된 것으로 본다. 이때 임차인은 이때 위약금으로 3개월치의 월세를 위약금으로 지불할 경우 즉시 보증금을 반환키로 한다.\r\n\r\nAnother way but most common way to move out early is to assign your place to a new tenant.  Assigning means that the new tenant replaces you.  The amount of rent and all other details of the agreement stay the same or change.  You must ask your landlord for permission to assign.  \r\n\r\n\r\n[1] Liquidated damages is a legal term that means putting a predicted dollar value on a breach of the contract before that breach occurs. For example, a lease could stipulate that if the tenant breaches the lease, the tenant will owe $1,000. Liquidated damages is the opposite of actual damages.',0);
INSERT INTO `article_tbl` VALUES (111,1,32,'01091280586','2020-07-06','2021-04-30','0000-00-00','0000-00-00','부동산 기사 제대로 읽기 1 - 집값상승률 ','0','아파트 상승률은 방향과 양의 값을 모두 표현하는 벡터의 의미를 가진다.  따라서 ',NULL,'\r\n\r\n기사제목은 <a href=\"https://news.chosun.com/site/data/html_dir/2020/06/25/2020062503882.html?utm_source=daum&utm_medium=original&utm_campaign=news\">김포 집값 상승률 90배, 웃음밖에 안나오는 부동산 대책</a>\r\n\r\n이었고 상승률의 출처는 한국감정원 있었다. \r\n\r\n세상의 물리적 현상을 표현하는 스칼라와 벡터라는 2가지 방법이 있다고 한다.  여기서 스칼라는 크기만을 나타내고 벡터는 크기와 동시에 방향을 가진다고 한다.  \r\n\r\n물리를 말하자는 건 아니고 과연 기사의 90배 올랐다고 말하는 것이 정당한 것인지를 알아보기 위한 화두이다. \r\n\r\n그럼 기사의 아파트 상승률이라는 것을 어떻게 계산하는지 알아보겠다.  우리가 1억짜리 100세대의 아파트가 이번주에 3개가 1억 2000만원에 거래되었다고 할 때 사람들은 2000만원이 올랐데, 그리고 그것은 1억의 20%로 바로 계산된다.  \r\n\r\n하지만 아파트 가격의 상승률이라는 그 1억짜리 아파트 100세대의 총 가격은 100억(1억원 X 100채)이 된다.  그리고 한 주 동안에 이 100채의 아파트 중에서 3채가 1억 2,000만원으로 계약이 되었다고 가정하면 거래가 안 된 1억원의 아파트 97채의 총 가격 97억원과 거래된 1억 2,000만원에 거래된 3채의 총 합계인 3억 6,000만원을 합친 금액이 100억 6,000만원이 되는 것이다.  이는 1주만에 20%가 아니고 0.6%가 올랐다고 언론에 보도가 되는 것입니다.  \r\n\r\n이러한 수치는 결국 스칼라인 양이 아니고 방향 양의 값을 모두 표현하는 벡터의 의미를 가지게 되는 것이다.  따라서 아파트의 가격 상승률은 방향성을 표시해주는 의미를 가지는 것으로 저렇게 절대적 량으로 표시될 수는 없는 성질을 가진다.  또한 거래량이 적은 상태에서 우리의 직관을 충분히 왜곡시킬 수 있다. ',0);
INSERT INTO `article_tbl` VALUES (112,1,32,'01091280586','2020-07-07','2021-04-30','0000-00-00','0000-00-00','부동산 기사 제대로 읽기 2-국민임대 사는 ','0','과연 이들은 서민일까?  주택시장 안정을 위한 관리방안(617부동산 대책)의 영향',NULL,'<a href=\"https://realestate.daum.net/news/detail/main/20200706040321722?fbclid=IwAR1nbXtyo2YtgnhEBbvQWx0yT_w0eN9ucF9dEyoImqHy92tKNp7YQLfSAcg\">\"국민임대 사는 내가 투기꾼?\".. 잔금대출 막힌 서민들 거리로</a> 국민일보|이택현 기자|입력2020.07.06 04:03\r\n\r\n이 기사에서 특히 주목한 부분은 \r\n\r\n<i>\"남편과 함께 집회에 참석한 신모씨는 수원 내 국민임대주택에 거주하는 동안 돈을 모아 내년 2월 입주하는 수원역 푸르지오 자이 아파트를 분양받았다. 하지만 정부 6·17 대책으로 수원 전역이 투기과열지구로 격상되면서 잔금 마련이 어려워지자 사채까지 고려하고 있다. 신씨는 “국민임대주택에서 살려면 소득이 맞벌이 기준으로 415만원 이하여야 하는데 입주 반년 남기고 1억원을 더 어디에서 구해야 하나”라며 “결국 계약금 수천만원을 날릴 수도 있다는 얘긴데 몇 년에 걸쳐 모은 돈이다”고 말했다.\"</i>\r\n\r\n이다.  그런데 수원역 푸르지오 자이 아파트는 경기도 수원시 팔달구 고등동 270-7에 소재한 아파트로 수원팔달은 2016년 11월 이미 조정대상지역이었고 이번에 투기과열지구가 되면서 대출에 영향은 받는 부분은 이전에 LTV(Loan to Value)가 50%에서 40%줄어들게 된 것이다.  그런데 1억원이 더 필요하게 되었다고 한다면 결국 어떤건지 몰라도 0.5와 0.4의 차이가 1억이라면 분양가 10억원대로 추정되면 대출 예정이었던 금액은 5억원대로 추정된다.  최저금리 2.48로 20년으로 계산해도 매달 264만원정도를 내야 하고 150만원 정도로 생활을 해야 할 것이다.  또한 114제곱미터c형이 현재 시세 9억정도인데 이 정도면 경기도권에서 아파트로 2020년 1월을 기준으로 상위 10%안에 충분히 들어가는 가격대이다.  \r\n\r\n따라서 일단 기자로서 검증 없이 올려다고 해도 그정도면 국민임대주택에 거주할 사람(맞벌이 기준 415만원이하)인가도 의심이 갈 뿐더러 제목에서 말하는 서민인가에 대한 의심은 합리적 의심일 것이다. ',0);
INSERT INTO `article_tbl` VALUES (116,1,32,'01091280586','2020-07-24','2021-04-30','2020-09-16','2020-07-30','주택의 1/2, 토지에 관한 재산세를 납부','0','9월 16~30일에는 주택의 1/2, 토지에 관한 재산세를 납부해야 합니다. 다만',NULL,'9월 16~30일에는 주택의 1/2, 토지에 관한 재산세를 납부해야 합니다. 다만 주택분 재산세의 세액이 20만 원 이하일 경우에는 7월에 전액을 부과합니다. ',0);
INSERT INTO `article_tbl` VALUES (117,1,32,'01091280586','2020-07-30','2021-04-30','0000-00-00','0000-00-00','2020년 주택문제 & 정책을 보며-조항준','0','최근의 엄청나게 쏟아지는 부동산 관련 정책들에 대한 수긍해야 하는 입장에 있지만 ',NULL,'말을 해야만 할 것같다.  그것이 개업공인중개사로서의 책임일 수도 있다는 생각을 하게 된다.  공급을 늘려야 한다. 그러면 모든 부동산 문제는 해결될 것이라는 새로운 교조(敎條)가 생겨나고 있다.   \r\n\r\n<b>그럼 정말 주택은 부족할까?</b>  \r\n주택수/일반가구수×100으로 계산하는 주택보급율로 서울의 주택보급률은 2018년 95.9%이다.  그리고 전체가구의 약 30%가 1인가구임을 고려한다면 100%라고 봐도 그게 틀리지는 않을 것이다.  물론 부분별 수요가 공급에 있어서의 불균형은 발생할 수 있을 것이다.  하지만 일단 시작부터 공급이 현재의 문제의 해결책이다 외치기에는 뭔가 그 시작부터 근거가 부족해 보인다. 하지만 일반가구중  자신이 소유한 주택에서 자신이 살고 있는 주택의 비율로 표시되는 자가 점유율은 꾸준히 늘고 있지만 40%대를 넘지 못하고 있다.   이는 10가구중에 4가구 만이 자신의 소유한 주택에서 살고 있다는 것이고 집이 있는 사람은  2개이상의 집을 가지고 있다는거다.\r\n\r\n<b>재건축이 답인가?</b>\r\n정치권 언론 학계까지 나름이 전문가라는 이름으로 재건축이고 이를 위한 용적율과 건폐율의 완화를 얘기하고 있다. 하지만 백보양보해 주장대로 물량의 부족이 문제라고 하더라도 재건축은 오히려 시장의 물량의 수급의 불균형을 가져 온다.  \r\n\r\n먼저 우리나라의 경우 학교 직장 등의 이유가 없다면 현재의 위치에서 크게 벗어나지 않는다.  80%정도의 이사가 반경 8km이내라는 말도 있다. 예를 들어 4000세대의 재건축을 진행될 경우 3200세대 정도의 세대들이 이주할 공간이 인근이 있어야 한다는 계산이 나온다.  하지만 이정도의 여유물량이 있었다면 우리가 부동산 문제가 심각하다 얘기하지도 않았을 것이다.  따라서 재건축은 가격 안정이 아니고 인근지역에 급격한 가격 상승가져오고 그를 주변지역으로까지 확산시키고 경험적으로 본다면 이후에도 상승된 가격은 쉽게 내려가지 않을뿐더러 새롭게 공급되는 물량이 특정 계층에 집중될 수 밖에 없는 획일적 공동주택임을 감안한다면 전체적인 측면에서의 주택공급은 더욱줄어들게 된다.  강남에 아무리 아파트를 진다해도 강북에 빌라하고 호환성을 가지기는 힘들거다. \r\n\r\n두 번째, 재건축은 기존주택을 허물로 신규주택을 만든다는 의미에서 대체의 효과는 있을지 몰라도 시장에서 기대만큼 주택의 공급을 가져오지는 못한다. 4000세대 헐어야 6000세대 정도 인거로 느껴진다.  기대만치의 공급이이루어지지 않는 이유로는 현재의 주거지역에서의 아파트의 층 높이 제한은 35층 용적율은 300%이다.  모 지역의 경우 현재 16층에 148%정도의 용적율을 가지고 있다.  그걸 단순화 시키면 동일평수로 최대로 진다면 최대 2배정도 늘어날 수 있지만 인동간격(隣棟間隔])이라고 층수가 올라가면 채광 등을 위해 건물 간 간격이 늘어나게 된고 기대되는 만치의 공급량이 발생하지는 않는 것이다.  또한 같은 평수에 살기 위해 재건축을 할 조합원은 없다.  결국 아파트의 층고는 거의 고정되어 있어서 평수(가로 세로)가 늘어나면 용적률에 묶어 건물의 층수가 줄어들게 되 전체 세대수는 기대했던 만치 늘어나지 않겠된다.\r\n\r\n세번째 주택의 공급을 말하면서 고의인지 몰라서인지 기존주택(existing home)에 대해 논의는 배제되고 있다. 하지만 주택의 공급은 new build(건축) 과 existing home(기존주택) 모두를 포함하는 개념이다.  기존주택의 공급량은 제한되어 있지 않냐 반론할 수 있지만 그런 의미에서라면 새로운 주택의 공급도 토지와 결합되어야 하는 주택의 특성상 제한적이다.  주택의 자가점유율을 올리고 주택의 공급의 한 방법으로는 특정지역에 밀집된 가구를 줄이고 기존주택이 시장에 나오게 더욱 나오게 하는 것이다.  이미 거론 하였듯이 인구의 분산을 유도하는 강력한 요인은 직장과 학교이다.  따라서 직장과 학교부터 지역재편을 통해 분산시키고 이를 통해 수요를 줄이고 집을 공실로 유지되는 것은 마지막 대안임을 고려한다면 결국 기존주택은 주택시장으로 나올 수 밖에 없게되는 것이다.  물론 조세(租稅)도 한 방법이 될 것이다. \r\n\r\n<b>주택문제를 바라보는 새로운 패러다임</b>\r\n\r\n사실 이러한 노력들은 위해서는 그동안 산업의 측면에서만 바로보다 주거의 문제를 환경 생태의 관점에서 접근해볼 필요가 있다.  주택이 아니라 사람의 삶을 담는 공간이라는 것에 대한 공감이 필요하다.  공생이 있어야 하고 쾌적한 환경이 있어야 하고 발전이 있어야 하고 균형이 있어야 하는 사람의 환경이 되어야 하는 것이다.  ',0);
INSERT INTO `article_tbl` VALUES (124,1,18,'01091280586','2020-08-12','2021-04-30','2020-08-21','0000-00-00','중개대상물의  명시사항 세부기분 고시 제정 ','0','「중개대상물의 표시·광고 명시사항 세부기준」을 제정함에 있어, 그 취지와 주요내용',NULL,'1. 제정이유\r\n  ‘20.8.21일부터 시행되는 ｢공인중개사법｣ 제18조의2제1항 및 제2항, 같은 법 시행령 제17조의2 제3항*에 따라 중개대상물의 표시・광고 명시사항에 관한 세부기준을 정하고자 함\r\n<br><i><font size=\"2em\" color=\"green\">공인중개사법 제18조의2(중개대상물의 표시ㆍ광고) ① 개업공인중개사가 의뢰받은 중개대상물에 대하여 표시ㆍ광고(「표시ㆍ광고의 공정화에 관한 법률」 제2조에 따른 표시ㆍ광고를 말한다. 이하 같다)를 하려면 중개사무소, 개업공인중개사에 관한 사항으로서 대통령령으로 정하는 사항을 명시하여야 하며, <b>중개보조원에 관한 사항은 명시해서는 아니 된다.</b>  <개정 2014. 1. 28., 2019. 8. 20.>\r\n\r\n② 개업공인중개사가 <b>인터넷을 이용하여 중개대상물에 대한 표시ㆍ광고를 하는 때</b>에는 제1항에서 정하는 사항 외에 중개대상물의 종류별로 대통령령으로 정하는 소재지, 면적, 가격 등의 사항을 명시하여야 한다.  <신설 2019. 8. 20.>\r\n\r\n③ 개업공인중개사가 아닌 자는 중개대상물에 대한 표시ㆍ광고를 하여서는 아니 된다.  <개정 2014. 1. 28., 2019. 8. 20.>\r\n\r\n④ 개업공인중개사는 중개대상물에 대하여 다음 각 호의 어느 하나에 해당하는 부당한 표시ㆍ광고를 하여서는 아니 된다.  <신설 2019. 8. 20.>\r\n\r\n1. 중개대상물이 존재하지 않아서 실제로 거래를 할 수 없는 중개대상물에 대한 표시ㆍ광고\r\n\r\n2. 중개대상물의 가격 등 내용을 사실과 다르게 거짓으로 표시ㆍ광고하거나 사실을 과장되게 하는 표시ㆍ광고\r\n\r\n3. 그 밖에 표시ㆍ광고의 내용이 부동산거래질서를 해치거나 중개의뢰인에게 피해를 줄 우려가 있는 것으로서 대통령령으로 정하는 내용의 표시ㆍ광고\r\n\r\n⑤ 제4항에 따른 부당한 표시ㆍ광고의 세부적인 유형 및 기준 등에 관한 사항은 국토교통부장관이 정하여 고시한다.  <신설 2019. 8. 20.>\r\n\r\n[본조신설 2013. 6. 4.]\r\n[시행일 : 2020. 8. 21.] 제18조의2\r\n\r\n공인중개사법 시행령 제17조의2(중개대상물의 표시ㆍ광고) 법 제18조의2제1항에서 \"대통령령으로 정하는 사항\"이란 다음 각 호의 사항을 말한다.  <개정 2014. 7. 28.>\r\n\r\n1. 중개사무소의 명칭, 소재지 및 연락처\r\n\r\n2. 개업공인중개사의 성명(법인인 경우에는 대표자의 성명)\r\n\r\n[본조신설 2013. 12. 4.]\r\n</i><br></font>\r\n2. 주요내용\r\n가. 중개사무소에 관한 표시․광고 명시사항을 규정함(안 제3조)\r\n나. 개업공인중개사의 표시․광고 명시사항을 규정함(안 제4조)\r\n다. 중개대상물의 종류별 인터넷 표시․광고 명시사항을 규정함(안 제5조에서 제9조)\r\n\r\n3. 참고사항\r\n가. 관계법령 : 공인중개사법 제18조의2제1항 및 제2항\r\n나. 예산조치 : 별도조치 필요 없음\r\n다. 합    의 : 별도조치 필요 없음\r\n라. 기    타 : 별도조치 필요 없음\r\n국토교통부고시 제2020-  호\r\n\r\n\r\n중개대상물의 표시·광고 명시사항 세부기준 고시 제정(안)\r\n\r\n제1장 총 칙\r\n\r\n제1조(목적) 이 고시는 「공인중개사법」제18조의2제1항 및 제2항, 같은 법 시행령 제17조의2제3항에 따라 중개대상물의 표시・광고 명시사항에 관한 세부기준을 정함을 목적으로 한다.\r\n\r\n제2조(정의) 이 고시에서 사용하는 용어는 「공인중개사법」(이하 \"법\"이라 한다) 제2조 각 호에서 정한 용어의 정의와 같으며, “표시・광고”는 「표시・광고의 공정화에 관한 법률」 제2조제1호 및 제2호에서 정한 용어의 정의와 같다.  \r\n\r\n제2장 중개사무소 및 개업공인중개사의 표시·광고 명시사항\r\n\r\n제3조(중개사무소에 관한 표시·광고 명시사항) 법 제18조의2제1항 및 제2항에 따라 개업공인중개사가 표시・광고에 명시하여야 하는 중개사무소에 관한 사항은 다음 각 호와 같다. \r\n 1. 중개사무소의 “명칭”은 중개사무소 등록증에 기재된 명칭을 표시하여야 한다. 다만, ‘사무소’ 및 ‘법인사무소’는 생략하여 표시할 수 있다.\r\n   (예시) 홍길동공인중개사, 한국부동산중개\r\n 2. 중개사무소의 “소재지”는 중개사무소 등록증에 기재된 소재지를 표시하여야 한다. 다만, 지번과 건물번호는 생략하여 표시할 수 있으며 ‘시·도·군, 구’를 줄여서 등록관청을 기준으로 표시할 수 있다.\r\n  (예시) 서울 영등포 의사당대로, 서울 영등포 국회대로 70길, 서울 영등포 여의도동\r\n 3. 중개사무소의 “연락처”는 ‘등록관청에 신고된 중개사무소의 전화번호(휴대전화번호를 포함한다)’를 표시하여야 한다. 다만, <b>중개보조원 등 공인중개사가 아닌 자의 전화번호(휴대전화번호를 포함한다)는 표시할 수 없다.</b>\r\n 4. 중개사무소의 “등록번호”는 중개사무소 등록증에 기재된 등록번호를 표시하여야 한다.\r\n\r\n제4조(개업공인중개사의 표시·광고 명시사항) 법 제18조의2제1항 및 제2항에 따라 개업공인중개사가 표시·광고에 명시하여야 하는 개업공인중개사의 “성명”은 중개사무소 등록증에 기재된 개업공인중개사의 성명(법인은 대표자 성명, 분사무소는 분사무소 책임자 성명)을 표시하여야 한다.\r\n\r\n제3장 중개대상물의 종류별 인터넷 표시・광고 명시사항\r\n\r\n제5조(토지에 관한 인터넷 표시・광고 명시사항) 법 제18조의2제2항에 따라 개업공인중개사가 토지에 관한 인터넷 표시・광고를 할 때에 명시하여야 하는 사항은 다음 각 호와 같다. \r\n 1. “소재지”는 등기사항증명서에 기재된 소재지를 표시하되, 읍․면․동․리까지 표시할 수 있다.\r\n 2. “면적”은 등기사항증명서에 기재된 면적을 표시하되, 제곱미터로 표시하여야 한다.\r\n 3. “가격”은 거래 형태에 따라 구분하여 중개가 완성되기 전 거래예정금액을 단일가격으로 표시하여야 한다.\r\n 4. “중개대상물 종류”는 「공간정보의 구축 및 관리 등에 관한 법률」 제67조에 따른 지목의 종류로 구분하여 표시하여야 한다.\r\n   (예시) 전, 답, 과수원, 목장용지, 임야, 광천지, 염전, 대(垈), 공장용지, 학교용지, 주차장, 주유소용지, 창고용지, 도로, 철도용지, 제방(堤防), 하천, 구거(溝渠), 유지(溜池), 양어장, 수도용지, 공원, 체육용지, 유원지, 종교용지, 사적지, 묘지, 잡종지로 구분하여 표시\r\n5. “거래 형태”는 매매․교환․임대차 그 밖에 권리의 득실변경으로 구분하여 표시하여야 한다. \r\n\r\n제6조(건축물 및 그 밖에 토지의 정착물에 관한 인터넷 표시・광고 명시사항) 법 제18조의2제2항에 따라 개업공인중개사가 건축물 및 그 밖에 토지의 정착물에 관한 인터넷 표시・광고를 할 때에 명시하여야 하는 사항은 다음 각 호와 같다.\r\n 1. “소재지”는 등기사항증명서에 기재된 소재지를 표시한다. \r\n\r\n  가. 건축물 중 건축법 시행령 별표1의 제1호 가목의 단독주택은 해당 건축물의 지번을 포함하여야 한다. 다만, 중개의뢰인이 원하지 않는 경우에는 읍․면․동․리까지 표시할 수 있다. \r\n\r\n  나. 건축물 중 건축법 시행령 별표1의 제1호 가목의 단독주택을 제외한 주택은 해당건축물의 지번과 동, 층수를 포함하여야 한다. 다만, 중개의뢰인이 원하지 않는 경우에는 층수를 저/중/고로 대체할 수 있다. \r\n\r\n  다. 건축물 중 근린생활시설 등 상가건물은 읍․면․동․리까지 표시할 수 있고, 이 경우 층수는 포함하여야 한다.\r\n\r\n 2. “면적”은 전용면적과 공급면적을 나누어 표시하되, 제곱미터로  표시하여야 한다.\r\n\r\n 3. “가격”은 거래 형태에 따라 매매는 매매가격, 임대차는 보증금과 차임으로 구분하여 중개가 완성되기 전 거래예정금액을 단일가격으로 표시하여야 한다. \r\n\r\n 4. “중개대상물 종류”는 「건축법」 제2조제1항제2호에 따른 건축물과 그 밖의 토지의 정착물로 구분하여 표시하되, 건축물은 「건축법」 제2조제2항에 따른 건축물의 용도로 구분하여 표시하여야 한다.\r\n\r\n   (예시) 단독주택, 공동주택, 제1종 근린생활시설, 제2종 근린생활시설, 문화 및 집회시설, 종교시설, 판매시설, 운수시설, 의료시설, 교육연구시설, 노유자(老幼者: 노인 및 어린이)시설, 수련시설, 운동시설, 업무시설, 숙박시설, 위락(慰樂)시설, 공장, 창고시설, 위험물 저장 및 처리 시설, 자동차 관련 시설, 동물 및 식물 관련 시설, 자원순환 관련 시설, 교정(矯正) 및 군사 시설, 방송통신시설, 발전시설, 묘지 관련 시설, 관광 휴게시설, 장례시설, 야영장 시설, 그 밖의 토지의 정착물로 구분하여 표시\r\n\r\n 5. “거래 형태”는 매매․교환․임대차 그 밖에 권리의 득실변경으로 나누어 표시하되, 임대차는 전세와 월세로 구분하여 표시하여야 한다. \r\n\r\n 6. “총 층수”는 중개대상물이 소재하는 해당 건축물의 등기사항증명서에 기재된 총 층수를 표시하여야 한다. \r\n\r\n 7. “입주가능일”은 실제 입주가 가능한 세부 날짜를 표시하되, ‘즉시입주’ 문구로 표시할 수 있다.\r\n\r\n 8. “방 수 및 욕실 수”는 건축물 현황도에 기재된 방 수 및 욕실 수를 표시하여야 한다. \r\n\r\n 9. “사용검사일・사용승인일・준공인가일”은 해당 건축물 및 그 밖의 토지의 정착물을 규율하는 법률에 따라 행정기관이 승인한 날짜를 정확하게 표시하여야 한다.\r\n\r\n 10. <b>“주차대수”는 총 가능한 주차대수와 세대 당 가능한 주차대수를 구분하여 표시</b>하여야 한다.\r\n\r\n 11. “관리비”는 「공동주택관리법」 제23조에 따른 관리비의 월 평균액수를 표시하되, 그 외의 비목이 포함된 경우 그 내용을 표시하여야 한다.\r\n   (예시) 다세대주택의 경우, 관리비 매월 4만원, 수도료 매월 1만원 \r\n\r\n 12. “방향”은 <b>주거용 건축물의 경우 거실이나 안방 등 주실(主室)의 방향을 기준</b>으로, 그 밖의 건축물은 주된 출입구의 방향을 기준으로 8가지 방향(동향, 서향, 남향, 북향, 북동향, 남동향, 남서향, 북서향)으로 표시하되, 그 기준을 함께 표시하여야 한다.\r\n\r\n제7조(입목에 관한 인터넷 표시・광고 명시사항) 법 제18조의2 제2항에 따라 개업공인중개사가 입목에 관한 인터넷 표시・광고를 할 때에 명시하여야 하는 사항은 다음 각 호와 같다.\r\n\r\n 1. “소재지”는 입목등기부에 기재된 소재지를 표시하되, 읍․면․동․리까지 표시할 수 있다.\r\n\r\n 2. “면적”은 입목등기부에 기재된 면적을 표시하되, 그 단위는 제곱미터로 한다.\r\n\r\n 3. “가격”은 거래 형태에 따라 구분하여 중개가 완성되기 전 거래예정금액을 단일가격으로 표시하여야 한다.\r\n\r\n 4. “입목내역”은 입목등기부에 기재된 수종(樹種)ㆍ수량(數量)ㆍ수령(樹齡)을 표시하여야 한다. \r\n\r\n 5. “거래 형태”는 매매․교환․임대차 그 밖에 권리의 득실변경으로 구분하여 표시하여야 한다. \r\n\r\n제8조(공장재단에 관한 인터넷 표시・광고 명시사항) 법 제18조의2제2항에 따라 개업공인중개사가 공장재단에 관한 인터넷 표시・광고를 할 때에 명시하여야 하는 사항은 다음 각 호와 같다.\r\n 1. “소재지”는 공장재단등기부에  기재된 소재지를 표시하되, 읍․면․동․리까지 표시할 수 있다.\r\n 2. “가격”은 거래 형태에 따라 구분하여 중개가 완성되기 전 거래예정금액을 단일가격으로 표시하여야 한다.\r\n 3. “거래 형태”는 매매․교환․임대차 그 밖에 권리의 득실변경으로 구분하여 표시하여야 한다. \r\n\r\n제9조(광업재단에 관한 인터넷 표시・광고 명시사항) 법 제18조의2제2항에 따라 개업공인중개사가 광업재단에 관한 인터넷 표시・광고를 할 때에 명시하여야 하는 사항은 다음 각 호와 같다.\r\n 1. “소재지”는 광업재단등기부에  기재된 소재지를 표시하되, 읍․면․동․리까지 표시할 수 있다.\r\n 2. “가격”은 거래 형태에 따라 구분하여 중개가 완성되기 전 거래예정금액을 단일가격으로 표시하여야 한다.\r\n 3. “거래 형태”는 매매․교환․임대차 그 밖에 권리의 득실변경으로 구분하여 표시하여야 한다. \r\n\r\n제4장 보 칙\r\n\r\n제10조(재검토기한) 국토교통부는 「훈령·예규 등의 발령 및 관리에 관한 규정」에 따라 이 고시에 대하여 2021년 1월 1일을 기준으로 매 3년이 되는 시점(매 3년째의 12월 31일까지를 말한다)마다 그 타당성을 검토하여 개선 등의 조치를 하여야 한다.\r\n\r\n부칙\r\n\r\n이 고시는 2020년 8월 21일부터 시행한다. \r\n\r\n\r\n\r\n',0);
INSERT INTO `article_tbl` VALUES (126,1,18,'01091280586','2020-08-13','2021-04-30','2020-08-18','2020-12-09','폐지유형의 임대주택에 대한 자발적 등록말소 ','0','  - 기존에는 임대등록 시 단기(4년), 장기일반·공공지원(8년) 유형으로 등록',NULL,'① 단기임대(4년) 및 아파트 장기일반 매입임대(8년) 폐지\r\n\r\n  - 기존에는 임대등록 시 단기(4년), 장기일반·공공지원(8년) 유형으로 등록 가능했으나, 앞으로는 단기임대와 아파트 장기일반매입임대는 폐지되므로 해당 유형으로 신규 등록할 수 없으며, 기 등록된 단기임대유형에서 장기임대(장기일반, 공공지원)로 전환도 금지된다. \r\n\r\n< 등록임대주택 유형별 신규등록 가능여부 현황 >\r\n\r\n<TABLE border=\"1\" cellspacing=\"0\" cellpadding=\"0\" style=\'border-collapse:collapse;border:none;\'>\r\n<TR>\r\n	<TD rowspan=\"2\" colspan=\"2\" valign=\"middle\" bgcolor=\"#ffffcb\"  style=\'width:280;height:54;border-left:none;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>주택 구분</SPAN></P>\r\n	</TD>\r\n	<TD colspan=\"2\" valign=\"middle\" bgcolor=\"#ffffcb\"  style=\'width:345;height:27;border-left:solid #000000 0.4pt;border-right:none;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>신규등록 가능여부</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" bgcolor=\"#ffffcb\"  style=\'width:173;height:27;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>매입임대</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#ffffcb\"  style=\'width:173;height:27;border-left:solid #000000 0.4pt;border-right:none;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>건설임대</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD>\r\n	<P>4년 단기임대</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:146;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>단기</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:173;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle18><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";line-height:160%\'>폐 지</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:173;height:32;border-left:solid #000000 0.4pt;border-right:none;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle18><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";line-height:160%\'>폐 지</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD rowspan=\"2\" valign=\"middle\" style=\'width:134;height:65;border-left:none;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>8년 장기임대</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#d0eaed\"  style=\'width:146;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>장기일반</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#d0eaed\"  style=\'width:173;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle19 STYLE=\'background-color:#ffffff;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";line-height:100%\'>허용</SPAN><SPAN STYLE=\'font-size:11.0pt;font-family:\"맑은 고딕\";line-height:100%\'>(다만, 아파트불가)</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#d0eaed\"  style=\'width:173;height:32;border-left:solid #000000 0.4pt;border-right:none;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle18><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";line-height:160%\'>허 용</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" bgcolor=\"#d0eaed\"  style=\'width:146;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'>공공지원</SPAN><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";font-weight:bold;line-height:140%\'><SUP></SUP></SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#d0eaed\"  style=\'width:173;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle20><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";line-height:100%\'>허 용</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#d0eaed\"  style=\'width:173;height:32;border-left:solid #000000 0.4pt;border-right:none;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:0.0pt 0.0pt 0.0pt 0.0pt\'>\r\n	<P CLASS=HStyle18><SPAN STYLE=\'font-size:13.0pt;font-family:\"맑은 고딕\";line-height:160%\'>허 용</SPAN></P>\r\n	</TD>\r\n</TR>\r\n</TABLE>\r\n\r\n  * 종전 법에 따른 3년, 4년, 5년 임대 및 아파트 매입형 준공공임대, 10년 임대도 폐지\r\n ② 폐지유형의 최소임대의무기간 종료 시 자동 등록말소 추진\r\n\r\n  - 법 개정 전 폐지유형(단기, 아파트 장기일반 매입임대)으로 등록된 기존 임대주택은 법 시행 후 임대의무기간이 종료한 날 자동으로 등록이 말소된다. 특히 법 시행일 전에 이미 임대의무기간이 경과한 경우 법 시행일에 그 임대주택의 등록이 말소된 것으로 본다. \r\n\r\n ③ 폐지유형의 임대주택에 대한 자발적 등록말소 기회 부여\r\n\r\n  - 종전 자발적 등록말소는 등록 후 일정기간1) 이내 한정적으로만 가능했으나, 폐지유형(단기ㆍ아파트 장기일반 매입임대)으로 등록된 기존 임대주택은 임대의무기간 내에도 자발적 등록말소를 허용하며, 임대의무기간 미준수에 따른 과태료도 적용되지 않도록 하였다2).\r\n\r\n    1) 자진말소 허용기간 : (’20.12.9까지) 1개월 이내 → (’20.12.10 後) 3개월 이내 \r\n\r\n    2) 공적 의무를 준수한 적법 사업자에 한하여 적용되며, 사업자 의무위반 적발시 원칙대로 행정처분 부과\r\n\r\n  - 다만, 이 경우에도 현재 거주 중인 임차인의 신뢰 보호 필요성을 감안하여 자진말소 신청은 현재 임대차계약 체결 중인 임차인의 동의가 있는 경우에 한정하여 가능토록 하였다.',0);
INSERT INTO `article_tbl` VALUES (128,1,31,'01091280586','2020-08-14','2021-04-30','0000-00-00','0000-00-00','2020 부동산 시장을 고민한다. ','0','결국 이번 대책은 어떤식으로든 시장에 변화를 가져올 것이다.  그 변화를 예측하는',NULL,'이번 부동산 대책은 많은 사람들이 우려를 한다.  근데 우려의 실체를 놓고 보면 다르다.  어느쪽은 기대를 어느쪽은 걱정이 그 우려의 실체가 된다.\r\n  \r\n결국 이번 대책은 어떤식으로든 시장에 변화를 가져올 것이다.  그 변화를 예측하는 일은 어떤 배경에서 이번 대책이 나오고 그 배경의 원인을 무엇이었던가에 대한 이해가 필요할 듯 하다.  \r\n\r\n문제는 단순했다. 집값이 너무 올랐고 전세값이 너무 올랐다. \r\n\r\n이제 기억에 의존해 나가보자. 지금부터 십 몇년전 그때 어느 친구는 주식의 쌍봉곡선이 주택시장에 나타났다.  장기하락을 전망했다.  많은 개업공인중개사들도 비슷한 전망을 냈었다.  그리고 그것은 실제가 되는 듯했다. \r\n\r\n그러던 어느날 대학생 전세자금대출이 나왔다.  그 한도는 7000만원이었다.  그러면서 앉은 자리에서 6000에 나온 전세가 7000이 되기도 했다.  대출을 받는 차주의 입장에는 돈 만원도 안팎의 차이였으니까 그로 인해 대출이 풀리면서 귀해진 전세를 놓치고 싶지 않았다. 그러면서 5000부터 7000까지의 전세는 순식간에 사라지고 그 위의 전세로 순차적으로 올라가기시작했다.  \r\n\r\n전세자금대출은 거기서 끝나지 않았다.  한도는 계속 늘어 현재는 대부분의 정책자금이 12000까지 늘었고 사실상 그것이 전세 보증금의 하한가를 형성하게 되었다.  또한 다양한 상품들이 금융권에서도 나오기 시작했고 사람들은 이사가기를 두려워하지 않기 시작했다.  그 전까지 공인중개사들은 70% 정도를 안전한 거래의 한계점으로 설정했다.  그것이 깨지기 시작했고 80-90%까지 올라가면서 갭투자의 물리적 기반을 마련해주었고 전세가 매매가를 밀어올리는 시장이 되었다. \r\n\r\n집있는 사람들은 집을 전세놓고 은행 또는 직장에서 전세대출을 받아 더 좋은 곳 서울로 그중에서도 강남으로 몰렸고 이는 서울과 지방의 차이를 강남과 강북의 차이를 확대 재생산하고 있었다. 또한 그 여유자금을 가지고 너도 나도 갭투자 시장에 뛰어들었고 전세와 매매가는 그에 맞추어 미친듯이 올랐갔고 서울의 갭이 벌어지자-매매가와 전세가의 차이가 커지자-이제 지방으로까지 확대되기 시작했다. \r\n\r\n이 미친 시장을 잡으면 정권이 망하고 못잡으면 나라가 망할지도 모르는 위기에 몰린것이다.  세상 물정에 빠른 사람들은 직장일보다 부동산에 빠져들고 있고 사람들은 자산의 차이는 노력의 차이가 아니라 순간의 선택에 따라 넘을 수 없는 차이를 만들어갔다.  같은 시기에 집을 사는걸 택한 사람과 전세를 택한 사람의 지금의 차이는 좌절을 만들어 내고 있었다. \r\n\r\n이런 미친 듯한 시장을 만들어 낸 것은 갭투자자들이었다.  그들은 막아야 했다.  그런 갭투자가 가능해진데는 2가지 물적인 기반이 있다.  높은 전세가와 대출이다. \r\n\r\n그래서 대출을 잡아야 했다.  먼저 은행을 잡았다.  다주택에 대한 대출을 제한했다.  하지만 부족하다.  일종의 사금융인 전세시장이 있다.  금융권이 60% 묶이면 전세는 80-90%의 무이자 금융이 가능한 전세가 있다.  그 전세시장을 주도하면 무감각하게 달려든 사람들은 자기 주택이 있는 사람들이었다.  전세가 오르면 자기 집의 전세도 올려면 됐으니까 그래서 유주택자에 대한 전세자금대출을 막았다.  양쪽을 다 막지 않으면 무의미했다.  그러면 이것은 시장에 얼마만한 파장을 가져올 수 있을까 경험적으로 보면 전세자금 대출이 가능하던 전세3억짜리의 집이 건축물 대장상 불법건축물로 등재되면서 전세자금대출이 불가능해지자 가격은 2억 3000으로 떨어진 경우도 있었다.  물론 2년이라는 계약기간이 있기 때문에 당장 그 효과가 가시적이긴 힘들다.  또한 주택담보대출에 있어서도 2018년의 928대책은 2주택이상자에 대한 주택담보대출을 원칙적으로 막았고 일시적 2주택자들에게는 2년이라는 시간을 줬다.  그럼 일시적 2주택자로 2년안에 처분해야 하는 시안이 돌아오고 있고 현재까지 3만개의 주택을 처분해야 하는 상황이다. 기한 이익의 상실이라는 이름의 대출을 바로 상환해야 하는 상황을 만들 어리석은 사람은 없을 거니까 \r\n\r\n이런 전세가 하락이 현실되면 가장 취약한 고리는 갭투자자들이 될 것이다.  그게 떨어지기를 기대했는데 한군데의 10%하락은 감당을 한다해도 그 10%가 20%가 되고 그게 여러개가 된다면 갭투자자들은 견뎌낼 수가 없다.  어쨋거나 시장에 매물들로 나와야 한다.  그런릴가 없다고 잊었을 뿐이지 그런적이 없던것은 아니다.  십몇년전에도 그런적이 있었다.  그때 개업공인중개사들은 종종 잔금 등이 준비안돼 동동거리고 울고 결국 급매로 내 놓는 고객들을 기억할 수 있을 것이다. \r\n\r\n우리나라의 부동산 시장은 아주 견고한거 같지만 그것은 어디까지나 오를때다.  내리기 시작하면 아주 취약해지고 자산의 80%가까이가 부동산자산인 상황에서 버틸 수 있는 시간은 제한되어 있고 급매가 나오면서 부동산 시장은 급박한 하락장이 현실이 될 수 있는게 현실이다.  굳이 그걸 지금 인정하고 싶지 않을뿐인거다.  그들은 틀리지 않았다.  아주 치밀하게 정확하게 시장을 압박하고 있고 관건은 그거이 얼마나 지속될 수 있는가에 있을 뿐이다.  ',0);
INSERT INTO `article_tbl` VALUES (134,1,32,'01090544679','2020-09-15','2021-04-30','0000-00-00','0000-00-00','주택의 중개에 대한 보수와는 별도로 부가가치','0','「부가가치세법」 제61조 제1항에 따른 간이과세자에 해당하는 개업공인중개사가 「공',NULL,'○ 간이과세자인 공인중개사가 법정 중개보수와 별도로 부가가치세를 받을 수 있는지(「공인중개사법」제33조제3호 등 관련)\r\n\r\n1. 질의요지\r\n\r\n「공인중개사법」 제33조 제3호에서는 사례ㆍ증여 그 밖의 어떠한 명목으로도 제32조에 따른 보수 또는 실비를  초과하여 금품을 받는 행위를 금지한다고  규정하고 있는바, \r\n\r\n「부가가치세법」 제61조 제1항에 따른 간이과세자에 해당하는 개업공인중개사가 「공인중개사법」 제32조제4항에 따라 정해진 주택의 중개에 대한 보수와는 별도로 부가가치세를 수령하여 \'그 둘을 합산한 금액\'이 법정 중개보수를 초과하는 경우 「공인중개사법」 제33조제3호에 위반되는지?\r\n\r\n2. 질의배경\r\n\r\n○민원인은 간이과세자인 개업공인중개사가 법정 중개보수를 초과하여 부가가치세를 별도로 받는 경우가「공인중개사법」 제33조 제3호에 위반되는지에 대하여 국토교통부에 질의하였는데, \r\n\r\n국토교통부에서는 일반과세자와 달리 간이과세자에게는 「부가가치세법」 제31조의 적용이 배제되어 별도로 소비자에게 부가가치세를 징수할 수 없기 때문에, 부가가치\r\n세를 받은 결과 중개보수와 합산한 가액이 법정 중개보수의 한도를 초과한다면 「공인중개사법」제33조제3호에 위반된다고 회신하자, \r\n\r\n이에 이견이 있어 직접 법제처에 법령해석을 요청함. \r\n\r\n3. 회답\r\n\r\n「부가가치세법」 제61조제1항에 따른 간이과세자에 해당하는 개업공인중개사가「공인중개사법」제32조제4항에 따라 정해진 주택의 중개에 대한 보수와는 별도로 부가가치세를 수령하여  그 둘을 합산한 금액이 법정 중개보수를 초과하더라도,  \'\'그 부가가치세를 제외한 금액\'\' 이 법정 중개보수를 초과하지 않는 경우에는 「공인중개사법」제33조제3호에 위반되지 않습니다. \r\n\r\n4. 이유\r\n\r\n  「공인중개사법」 제32조제1항에서는 개업공인중개사는 중개업무에 관하여 중개의뢰인으로부터 소정의 보수를 받는다고 규정하고 있고, 같은 조 제4항에서는 주택의 중개에 대한 보수와 같은 조 제2항에 따른 실비의 한도 등에 관하여 필요한 사항은 국토교통부령이 정하는 범위 안에서  특별시ㆍ광역시ㆍ도 또는 특별자치도의 조례로 정한다고 규정하고 있으며, 같은 법 제33조제3호에서는 개업공인중개사등이 사례ㆍ증여  그 밖의 어떠한 명목으로도 같은 법 제32조에 따른 보수 또는 실비를 초과하여 금품을 받는 행위를 금지한다고 규정하고 있습니다. \r\n  \r\n그리고,「부가가치세법」제4장 제31조에서는 사업자가 재화 또는 용역을 공급하는 경우에는 같은 법 제29조제1항에 따른  공급가액에 같은 법 제30조에 따른 세율을 적\r\n용하여  계산한 부가가치세를 재화 또는 용역을 공급받는 자로부터 징수하여야 한다고 규정하고 있는데, 같은 법 제61조제1항에서는 직전 연도의 재화와 용역의 공급에 대한 대가 (부가가치세가 포함된 대가를 말하며, 이하 “공급대가”라 함)의 합계액이 대통령령으로 정하는 금액에 미달하는 개인사업자는 간이과세자로서  이 법에서 달리 정하고 있는 경우를 제외하고는 제4장부터 제6장까지의 규정에도 불구하고 제7장의 규정을 적용받는다고 규정하고 있고, 그 위임에 따라 같은 법 시행령 제109조 제1항에서는 “대통령령으로 정하는 금액”을 4천800만원으로 규정하고 있는바,  이 사안은 「부가가치세법」 제61조제1항에 따른 간이과세자에 해당하는 개업공인중개사가 「공인중개사법」 제32조제4항에 따라 정해진 주택의 중개에 대한 보수(이하 “법정 중개보수”라 함)와는 별도로 부가가치세 명목의 별도 금전을 중개의뢰인에게 수령함으로써,  그 중개보수와 부가가치세를 합산한 금액이 법정 중개보수를 초과하는 경우가 「공인중개사법」제33조제3호에 위반되는지에 관한 것이라 하겠습니다. \r\n  \r\n먼저, 부가가치세는 기업이 일정 기간 동안에 생산ㆍ유통 등의 사업 활동을 통해 창출한 부가가치를 과세표준으로 하여 과세하는 조세로서, 조세부담을 거래 단계별로 거래상대자에게 전가하여 종국적으로는 최종소비자가 그 부담을 지도록 하는 일반소비세에 해당하는바, 부가가치세의 실제 담세자는 사업자 등으로부터 재화나 용역을 공급받는 최종소비자라고 할 것입니다. \r\n\r\n  이에 따라, 일반과세자가 재화 또는 용역을 공급하는 경우에 대하여는 「부가가치세법」 제31조에서 사업자가 재화 또는 용역을 공급받는 자로부터 부가가치세를 징수하도록 하는 직접적인 근거규정을 두고 있고, 간이과세자가 재화 또는 용역을 공급하는 경우에는 같은 법 제61조제1항에서 재화와 용역의 대가에 부가가치세가 포함되는 “공급대가”를 수령하는 것으로 규정함으로써, 간이과세자도 재화 또는 용역을 공급받는 자에게 부가가치세를 전가할 수 있도록 하는 간접적인 근거규정을 두고 있다고 할 것입니다. \r\n\r\n  따라서, 간이과세자의 경우에는 「부가가치세법」상 일반과세자와 같이 부가가치세를 소비자에게 직접 징수할 수 있도록 규정되어 있지 아니하더라도, 부가가치세를 사실상 누가 부담하며 어떻게 전가할 것인지의 문제는 사적 자치가 허용되는 영역으로 거래당사자의 약정 또는 거래관행 등에 의하여 결정될 사항이고(헌법재판소 2000. 3. 30. 결정 98헌바7 결정례 참조), 부가가치세의 실제 담세자는 최종소비자라는 부가가치세의 원리에 따라 간이과세자인 개업공인중개사도 사인 간의 약정을 통해 부가가치세 상당액을 소비자에게 요구할 수 있다고 할 것입니다. \r\n\r\n  그리고, 「공인중개사법」 제32조 및 제33조제3호에서 규정하고 있는 법정 중개보수는 공인중개사가 용역의 대가로서 받는 적정한 이익·비용 등을 의미하는 것으로서, 이러한 법정 중개보수에는 그에 따르는 부가가치세까지를 포함하고 있는 것은 아니라고 할 것인바(법제처 2006. 9. 25. 회신 06-0211 해석례 참조), 개업공인중개사가 간이과세자인지 일반과세자인지 여부와 관계없이 법정 중개보수는 부가가치세가 제외된 금액이라고 할 것입니다. \r\n\r\n  또한, 「부가가치세법」 제63조제1항에서는 “공급대가”를 간이과세자의 과세표준으로 규정하고 있는데, 이는 주로 소규모 영세사업자로 구성된 간이과세자의 간편한 납세액 산정을 위한 과세기준인 것이지, 간이과세자가 수령하는 모든 “대가”를 예외 없이 부가가치세가 포함된 “공급대가”로 보려는 취지는 아니라고 할 것입니다. 만약, 간이과세자가 수령하는 “대가”를 모두 “공급대가”로 판단하여 일반과세자와 달리 간이과세자에 해당하는 개업공인중개사가 수령하는 법정 중개보수에 이미 부가가치세가 포함된 것으로 보게 된다면, 결과적으로 일반과세자보다 영세한 간이과세자인 개업공인중개사는 일반과세자인 개업공인중개사보다 더 적은 중개보수를 수령하여야 하는 불공평한 상황이 발생할 수 있다는 것도 이 사안을 판단할 때 고려하여야 할 것입니다. \r\n\r\n  더욱이, 「공인중개사법」 제33조제3호에서 “사례ㆍ증여 그 밖의 어떠한 명목으로도 제32조에 따른 보수 또는 실비를 초과하여 금품을 받는 행위”를 금지하고 있는 것은 사례 또는 증여와 같이 아무런 용역의 제공 등이 없이 무상으로 이익을 취하는 행위를 금지하는 것으로, 같은 규정에서 말하는 “그 밖의 어떠한 명목”이 의미하는 것은 사례 또는 증여와 유사한 행위로서 이익을 취하는 것을 의미하는 것으로 보아야 할 것이지 부가가치세와 같이 용역을 제공받는 자가 부담하여야 할 세금까지 포함하는 것은 아니라 할 것입니다(법제처 2006. 9. 25. 회신 06-0211 해석례 참조). \r\n  \r\n이상과 같은 점을 종합해 볼 때,「공인중개사법」제33조 제3호에 위반되는지 여부는  별도의  기준 및 약정에 따라 수령한 부가가치세 상당액을 제외하고 판단하여야 할 것인바, 「부가가치세법」 제61조제1항에 따른 간이과세자에 해당하는 개업공인중개사가 법정 중개보수와는 별도로 부가가치세를 수령하여 그 둘을 합산한 금액이 법정 중개보수를 초과하더라도, 그 부가가치세를 제외한 금액이 법정 중개보수를 초과하지 않는 경우에는 「공인중개사법」제33조제3호에 위반되지 않는다고 할 것입니다.',0);
INSERT INTO `article_tbl` VALUES (135,1,18,'01080073279','2020-09-15','2021-06-04','2020-08-26','0000-00-00',' 집합건물을 중개함에 있어서의 확인설명의무 ','0','서초구청장은 서초구 소재 집합건물을 중개함에 있어 중개대상물 확인 설명서의 근거자료로 토지대장 및 지적도를 제시하지 않았다는 점을 들어 중개대상물 확인 설명의무에 관한 위반행위가 있다고 보아 각 4,000,000원의 관태료 부과에 대한 법원의 판결입니다. ','khj.jpg','<h4>1. 사건의 경과</h4>\r\n서초구청장은 위반자들이 2018.8.22경 서울 서초구 소재 집합건물을 중개함에 있어 중개대상물 확인 설명서의 근거자료로 토지대장 및 지적도를 제시하지 않았다는 점을 들어 공인중개사법 제25조 제1항에서 정하고 있는 중개대상물 확인 설명의무에 관한 위반행위가 있다고 보아 위반자들에게 각 4,000,000원의 관태료를 부과\r\n\r\n<h4>2. 판단</h4>\r\n공인중개사법 제25조 제1항의 \"매수대상물에 관한 권리를 취득하고자하는 중개의리인\"은 그 문언 그대로 중개대상물의 \"매수의뢰인\" 혹인 \"임차의뢰인\"으로 해석함이 상당하고,\r\n<생략> \r\n<blockquote>공인중개사법 제25조 제1항에서 제시하여야 할 설명의 근거자료에 항상 토지대장이나 지적도를 포함시키도록 규정하고 있지 않은 점, 이 사건 건물은 집합건물로서 공인중개사법 제 25조 제1항 각호 소정의 사항을 설명함에 있어 토지대장이나 지적도가 반드시 필수적이라고 단정할 수 없는 점, </blockquote>\r\n<생략>\r\n이 사건 건물의 매수에 관한 중개를 함에 있어 매수의뢰인측에 대하여 공인중개사법 제25조 제1항에서 정하고 있는 중개대상물 확인 설명의무를 다하였다고 봄이 상당하다. \r\n<h4>3. 결론</h4> \r\n위반자들에게 과태료를 부과하지 아니한다.\r\n---------------------------------- \r\n서초구청 부동산정보과장 국종호(☎2155-6928), 부동산행정팀장 전재철(☎2155-6904), 주무관 김나영(☎2155-6909)',0);
INSERT INTO `article_tbl` VALUES (180911,1,18,'01091280586','2021-01-21','2021-04-30','0000-00-00','0000-00-00','외국인 및 재외국민의 국내 부동산 처분 등에','0','외국인 및 재외국민의 국내 부동산 처분 등에 따른 등기신청 절차',NULL,'\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:14.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>□ </SPAN><SPAN STYLE=\'font-size:14.0pt;font-family:\"휴먼명조\";letter-spacing:-20%;font-weight:bold;line-height:160%\'>외국인 및 재외국민의 국내 부동산 처분 등에 따른 등기신청 절차</SPAN></P>\r\n\r\n<P CLASS=HStyle0></P>\r\n<TABLE border=\"1\" cellspacing=\"0\" cellpadding=\"0\" style=\'border-collapse:collapse;border:none;\'>\r\n<TR>\r\n	<TD colspan=\"3\" valign=\"middle\" bgcolor=\"#d6d6d6\"  style=\'width:640;height:31;border-left:solid #000000 1.1pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.1pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'margin-left:4.0pt;margin-right:4.0pt;text-align:left;line-height:150%;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:150%\'>&nbsp;&nbsp;&nbsp;&nbsp;▣ 외 국 인</SPAN><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";line-height:150%\'>(대한민국 국적을 보유하고 있지 아니한 자 )</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD colspan=\"2\" valign=\"middle\" style=\'width:64;height:27;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:solid #000000 1.1pt;border-bottom:double #000000 1.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:150%\'>구 분</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:576;height:27;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.1pt;border-bottom:double #000000 1.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:150%\'>필 요 서 면</SPAN><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";line-height:150%\'>(일반적으로 등기신청서에 필요한 서면은 제외함)</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:32;height:758;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-1%;font-weight:bold;line-height:150%\'>처</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-1%;font-weight:bold;line-height:150%\'>&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-1%;font-weight:bold;line-height:150%\'>분</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-1%;font-weight:bold;line-height:150%\'>&nbsp;</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:32;height:758;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-1%;font-weight:bold;line-height:150%\'>입국하지 않은</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:150%;\'><SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-1%;font-weight:bold;line-height:150%\'>경우</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:576;height:758;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle2 STYLE=\'line-height:180%;\'>1. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:180%\'>처분위임장</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>처분대상의 부동산과 수임인이 구체적으로 특정되도록 기재</SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-5%;line-height:180%\'>위임하는 법률행위의 종류와 위임취지를 기재(예: 처분권한 일체를 수여한다 등)</SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>본국(국적취득국)에 인감증명제도가 있는 경우 그 인감을 날인하고, 인감증명 제도가 없는 경우 본인의 서명을 함</SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>등기필정보가 없는 경우에는 “등기필정보가 없다”는 뜻도 기재하여 공증인의 공증을 받아야 함</SPAN></P>\r\n	<P CLASS=HStyle2 STYLE=\'line-height:180%;\'>2. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:180%\'>인감증명&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>본국에 인감증명 날인제도가 있는 경우(예: 일본 등) </SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";letter-spacing:-5%;line-height:180%\'>위임장에 날인한 인감에 대하여 본국 관공서가 발행한 인감증명을 첨부</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>본국에 인감증명 날인제도가 없는 경우(예: 미국 등)</SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>위임장에 한 서명에 관하여 본인이 직접 작성하였다는 취지의 본국 관공서의 증명이나 이에 대한 공증을 첨부</SPAN></P>\r\n	<P CLASS=HStyle2 STYLE=\'line-height:180%;\'>3. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:180%\'>주소를 증명하는 서면</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>본국에 주소증명서 등을 발급하는 기관이 있는 경우(예: 일본 등)</SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>본국 관공서의 주소증명서 또는 거주사실증명서를 첨부</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>본국에 주소증명서 등을 발급하는 기관이 없는 경우(예: 미국 등)</SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>주소를 공증한 서면을 첨부</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>본국에 주소증명서를 발급하는 기관은 없으나, 그 주소증명서를 대신할 수 있는 증명서(운전면허증 또는 신분증 등)를 본국 관공서에서 발급하는 경우 </SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>관할등기소 등기관에게 그 증명서 및 그 사본(원본과 동일하다는 취지를 기재)을 제출하여 원본과 동일함을 확인받거나, </SPAN></P>\r\n	<P CLASS=HStyle4 STYLE=\'line-height:180%;\'>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>또는 그 증명서 사본(원본과 동일하다는 취지를 기재)에 본국 관공서의 증명이나 공증인의 공증 또는 외국주재 한국 대(영)사관의 확인을 받아&nbsp; 주소증명서 대신 제출할 수 있음</SPAN></P>\r\n	<P CLASS=HStyle2 STYLE=\'line-height:180%;\'>4. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:180%\'>외국국적 취득으로 성명이 변경된 경우</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>변경 전&#8228;후의 성명이 동일인이라는 본국 관공서의 증명 또는 공증을 첨부</SPAN></P>\r\n	<P CLASS=HStyle2 STYLE=\'line-height:180%;\'>5. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:180%\'>번역문&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle3 STYLE=\'line-height:180%;\'>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:180%\'>신청서에 첨부된 서류가 외국어로 되어 있으면 모두 번역문을 첨부</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD colspan=\"3\" valign=\"middle\" bgcolor=\"#d6d6d6\"  style=\'width:640;height:31;border-left:solid #000000 1.1pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.1pt;border-bottom:solid #000000 1.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'margin-left:4.0pt;margin-right:4.0pt;text-align:left;line-height:150%;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:150%\'>&nbsp;&nbsp;&nbsp;&nbsp;▣ 외 국 인</SPAN><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";line-height:150%\'>( 대한민국 국적을 보유하고 있지 아니한 자 )</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD colspan=\"2\" valign=\"middle\" style=\'width:64;height:24;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:solid #000000 1.4pt;border-bottom:double #000000 1.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>구 분</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:576;height:24;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.4pt;border-bottom:double #000000 1.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>필 요 서 면</SPAN><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>(</SPAN><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";line-height:160%\'>일반적으로 등기신청서에 필요한 서면은 제외함)</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:32;height:415;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>처</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>분</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:32;height:415;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>입</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>국</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>한&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>경</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>우</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:576;height:415;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle2>1. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>인감증명&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>본국에 인감증명 날인제도가 있는 경우(예: 일본 등) </SPAN></P>\r\n	<P CLASS=HStyle4>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>위임장 등에 날인한 인감에 대한 본국 관공서가 발행한 인감증명 제출</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>본국에 인감증명 날인제도가 없는 경우(예: 미국 등)</SPAN></P>\r\n	<P CLASS=HStyle4>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>위임장 등에 한 서명이 본인의 서명임을 증명하는 본국 관공서의 증명이나 이에 대한 공증서면 또는 주한 본국 대(영)사관의 확인서면으로도 가능</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>『출입국관리법』에 의하여 외국인등록을 한 자는『인감증명법』에 의한 인감증명을 발급받아 제출 할 수 있음</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>국내거소신고를 한 외국국적동포의 경우『인감증명법』에 의한 인감을 발급&nbsp;&nbsp; 받아 제출할 수 있음</SPAN></P>\r\n	<P CLASS=HStyle2>2. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>주소를 증명하는 서면</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>외국인등록사실증명 또는 국내거소신고를 한 외국국적동포의 경우에는 국내거소신고사실증명으로도 가능</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>따라서 앞서 기술한 주소증명서면을 제출하거나 위의 외국인등록사실증명 또는 국내거소신고사실증명을 제출해도 됨</SPAN></P>\r\n	<P CLASS=HStyle2>3. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>외국국적 취득으로 성명이 변경된 경우의 첨부서면 및 번역문을 첨부해야 할 경우는 앞에서 기술한 것과 같음</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:32;height:295;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:solid #000000 1.1pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>취</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>득</SPAN></P>\r\n	</TD>\r\n	<TD colspan=\"2\" valign=\"middle\" style=\'width:608;height:295;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.1pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle2>1. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>외국인 부동산등기용 등록번호를 부여받아야 함</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>등록번호 부여신청은 체류지 출입국관리소장 또는 출입국관리사무소 출장소장</SPAN></P>\r\n	<P CLASS=HStyle0><SPAN STYLE=\'font-family:\"휴먼명조\"\'>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; </SPAN><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>(국내에 체류지가 없을 경우 대법원 소재지를 체류지로 본다)에게 함</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-5%;line-height:160%\'>국내 거소신고를 한 외국국적동포의 경우에는 국내거소신고번호로 대신할 수 있음</SPAN></P>\r\n	<P CLASS=HStyle2>2. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>계약을 원인으로 토지를 취득하는 경우</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-5%;line-height:160%\'>『부동산 거래신고 등에 관한 법률』제9조 제1항 각호(재외동포의 출입국과 법적 지위에 관한 법률에 의하여 국내거소신고를 한 외국국적동포의 경우에는 같은 항 제1호)의 허가구역 내의 부동산에 해당하는 때에는 시장&#8228;군수&#8228;구청장의 “토지취득허가증” 을 첨부해야 하며, 이에 해당하지 않을 때에는 “토지이용계획확인원”을 첨부함</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:10.5pt;font-family:\"휴먼명조\";letter-spacing:-5%;line-height:160%\'>『부동산 거래신고 등에 관한 법률』제11조에 따라 “토지거래계약허가증”을 첨부한 경우에는 위 “토지취득허가증” 은 첨부하지 않음</SPAN></P>\r\n	<P CLASS=HStyle2>3. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;주소를 증명하는 서면은 처분시 첨부할 서면과 같음</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD colspan=\"3\" valign=\"middle\" style=\'width:640;height:106;border-left:solid #000000 1.1pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.1pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>수임인의 신청</SPAN></P>\r\n	<P CLASS=HStyle4>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>수임인은 그가 본인(외국인)의 대리인임을 현명하고 대리인 자격으로 직접 신청하거나 법무사 등에게 그 신청을 위임할 수 있음. 이 때 수임인의 인감증명을 제출해야함</SPAN></P>\r\n	<P CLASS=HStyle4>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>원인증서도 수임인이 본인을 위한 것임을 표시하고 대리인 자격으로 작성함</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD colspan=\"3\" valign=\"middle\" bgcolor=\"#d6d6d6\"  style=\'width:640;height:31;border-left:solid #000000 1.1pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.1pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'margin-left:4.0pt;margin-right:4.0pt;text-align:left;line-height:150%;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:150%\'>&nbsp;&nbsp;&nbsp;&nbsp;▣ 재외국민</SPAN><SPAN STYLE=\'font-size:9.0pt;font-family:\"휴먼명조\";letter-spacing:-11%;line-height:150%\'>(대한민국의 국민으로서 외국의 영주권을 취득한 자 또는 영주할 목적으로 외국에 거주하고 있는 자)</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD colspan=\"2\" valign=\"middle\" style=\'width:64;height:20;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:solid #000000 1.1pt;border-bottom:double #000000 1.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:130%;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:130%\'>구 분</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:576;height:20;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:solid #000000 1.1pt;border-bottom:double #000000 1.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:130%;\'><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:130%\'>필 요 서 면</SPAN><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";line-height:130%\'>(일반적으로 등기신청서에 필요한 서면은 제외함)</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD rowspan=\"2\" valign=\"middle\" style=\'width:32;height:587;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 0.9pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>처</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>분</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:32;height:467;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>입국하지</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>않은 경우</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:576;height:467;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:double #000000 1.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle2>1. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;처분위임장</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>처분대상의 부동산과 수임인이 구체적으로 특정되어야 함</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>위임하고자 하는 법률행위의 종류와 위임취지가 기재되어야 함(예: 처분권한 일체를 수여한다 등)</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>우리나라에서 발급받은 본인의 인감을 날인 함</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>등기필정보가 없는 경우에는 “등기필정보가 없다”는 뜻도 기재하여 공증인의 공증도 받아야 함(재외공관의 공증도 가능)</SPAN></P>\r\n	<P CLASS=HStyle2>2. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>인감증명&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>인감증명의 제출</SPAN></P>\r\n	<P CLASS=HStyle4>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>위임장에 찍힌 인영이 본인의 것임을 증명하기 위하여 본인의 인감증명(우리 나라의 인감증명)을 제출하여야 하며, 이때 등기원인이 매매인 경우에는 부동산매수자란에 매수자의 성명&#8228;주소(법인인 경우에는 법인명과 주된 사무소의 소재지) 및 주민등록번호를 기재한 부동산매도용 인감증명서를 제출함(인감증명법 시행령 제13조 제3항 참조)</SPAN></P>\r\n	<P CLASS=HStyle2>3. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>주소를 증명하는 서면</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>외국주재 대한민국 대(영)사관에서 발행하는 재외국민 거주사실증명 또는 재외국민 등록부등본을 첨부해야 함 </SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>다만 주재국에 대사관 등이 없어 그와 같은 증명을 발부 받을 수 없을 때에는 주소를 공증한 서면으로 대신할 수 있음</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:32;height:120;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.9pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>입</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>국</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>한경우</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:576;height:120;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.9pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'margin-bottom:4.0pt;\'><SPAN STYLE=\'font-family:\"휴먼명조\"\'>&#160;</SPAN><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>첨부서면은&#160;위의&#160;경우와&#160;같다.&#160;다만,&#160;&#65378;주민등록법&#65379; 제10조의2 제1항에 따른 재외국민신고를 한 경우에 한하여 주소를&#160;증명하는&#160;서면으로서 주민등록등&#8228;초본도&#160;가능</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:32;height:442;border-left:solid #000000 1.1pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.9pt;border-bottom:solid #000000 0.9pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>취</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>득</SPAN></P>\r\n	</TD>\r\n	<TD colspan=\"2\" valign=\"middle\" style=\'width:608;height:442;border-left:solid #000000 0.4pt;border-right:solid #000000 1.1pt;border-top:solid #000000 0.9pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle2>1. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>주소를 증명하는 서면(처분시와 같음)</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>외국주재 대한민국 대(영)사관에서 발행하는 재외국민 거주사실증명 또는 재외국민 등록부등본을 첨부 </SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>다만 주재국에 대사관 등이 없어 그와 같은 증명을 발부 받을 수 없을 때에는 주소를 공증한 서면으로 대신할 수 있음</SPAN></P>\r\n	<P CLASS=HStyle2>2. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>부동산등기용등록번호&nbsp;</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>등기권리자(취득&#8228;상속 등)로서 신청하는 때에 주민등록번호가 없는 경우에 대법원소재 관할 등기소(현재 서울중앙지방법원 등기국)에서 부동산등기용 등록번호를 부여받아야 함</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>국내거소신고번호로 부동산등기용 등록번호를 갈음할 수 없음</SPAN></P>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";letter-spacing:-5%;line-height:160%\'>종전에 주민등록번호를 부여받은 경우 및 </SPAN><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>&#65378;주민등록법&#65379;제10조의2제1항에 따른 재외국민신고를 하여 주민등록번호를 부여받은 경우에는 </SPAN><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";letter-spacing:-5%;line-height:160%\'>새로이 부동산등기용 등록번호를 부여받지 않음</SPAN></P>\r\n	<P CLASS=HStyle2>3. <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>상속에 있어서의 특례 </SPAN></P>\r\n	<P CLASS=HStyle0><SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>&nbsp;&nbsp;&nbsp;재외국민의 상속재산의 협의분할시 인감증명은 상속재산 협의분할서상의 서명 또는&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 날인이 본인의 것임을 증명하는 재외공관의 확인서 또는 이에 관한 공정증서로&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 대신할 수 있음</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD colspan=\"3\" valign=\"middle\" style=\'width:640;height:116;border-left:solid #000000 1.1pt;border-right:solid #000000 1.1pt;border-top:solid #000000 0.9pt;border-bottom:solid #000000 1.1pt;padding:1.4pt 1.4pt 1.4pt 1.4pt\'>\r\n	<P CLASS=HStyle3>□ <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>수임인의 신청</SPAN></P>\r\n	<P CLASS=HStyle4>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>수임인은 그가 본인(재외국민)의 대리인임을 현명하고 대리인 자격으로 직접 신청하거나 법무사 등에게 그 신청을 위임할 수 있음. 이 때 수임인의 인감증명을 제출해야함</SPAN></P>\r\n	<P CLASS=HStyle4>? <SPAN STYLE=\'font-size:11.0pt;font-family:\"휴먼명조\";line-height:160%\'>원인증서도 수임인이 본인을 위한 것임을 표시하고 대리인 자격으로 작성</SPAN></P>\r\n	</TD>\r\n</TR>\r\n</TABLE>\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:12.0pt;font-family:\"휴먼명조\";line-height:160%\'>&nbsp;&nbsp;&nbsp;「등기예규」제1568호, 제1602호</SPAN></P>\r\n',0);
INSERT INTO `article_tbl` VALUES (180912,1,32,'01091280586','2021-05-01','2021-05-01','2021-05-03','0000-00-00','2021년 달라지는 부동산 세금','0','1.과세가 되지 않는 1주택자의 조건의 변경 \r\n\r\n 앞으로는 다른 모든 주택을 ','','1.과세가 되지 않는 1주택자의 조건의 변경 \r\n\r\n 앞으로는 다른 모든 주택을 판 후 1주택자가 된 날로부터 2년 이상 집을 가지고 있어야 비과세 대상으로 분류 ',0);
INSERT INTO `article_tbl` VALUES (180913,1,31,'01091280586','2021-05-01','2021-05-01','0000-00-00','0000-00-00','성산2동 매매동향 ','0','최근 구형 빌라에 대한 매매 거래 증가 성산2동에 한정된 것이 아니고 인근지역까지',NULL,'최근 구형 빌라에 대한 매매 거래 증가 성산2동에 한정된 것이 아니고 인근지역까지 폭 넓게 진행되고 있는 것으로 판단되며 소형정비사업에 대한 기대 등이 원인으로 추정되고 있다. ',0);
INSERT INTO `article_tbl` VALUES (180915,1,18,'01091280586','2021-05-01','2021-05-01','0000-00-00','0000-00-00','1. 가계약과 매매계약의 성립|판시사항[대법','0','부동산 매매에 관한 가계약서 작성 당시 매매목적물과 매매대금 등이 특정되고 중도금',NULL,'■ 대법원 2006. 11. 24. 선고 2005다39594 판결\r\n\r\n소유권이전등기\r\n\r\n​\r\n\r\n【판시사항】\r\n\r\n​\r\n[1] 계약의 성립을 위한 당사자 사이의 ‘의사의 합치’의 정도\r\n\r\n​\r\n[2] 부동산 매매에 관한 가계약서 작성 당시 매매목적물과 매매대금 등이 특정되고 중도금 지급방법에 관한 합의가 있었다면\r\n\r\n​\r\n그 가계약서에 잔금 지급시기가 기재되지 않았고 후에 정식계약서가 작성되지 않았다 하더라도 매매계약은 성립하였다고 본 사례.\r\n\r\n​[3] 해약금에 관한 민법 제565조, 제1항의 ‘\'이행을 착수할 때까지\'’의 의미\r\n\r\n​[4] 매매계약 당시 매수인이 중도금 일부의 지급에 갈음하여, 매도인에게 제 3자에 대한 대여금채권을 양도하기로 약정하고, 그 자리에 제 3자도 참석한 경우, \r\n\r\n​\r\n\r\n매수인은 매매계약과 함께 채무의 일부 이행에 착수하였으므로, 매도인은 민법 제565조, 제1항에 정한 해제권을 행사할 수 없다고 본 사례',0);
INSERT INTO `article_tbl` VALUES (180916,1,18,'01091280586','2021-05-01','2021-05-07','0000-00-00','0000-00-00','2. 가계약과 매매계약의 성립|이유[대법원]','0','',NULL,'?【이 유】\r\n\r\n​상고이유를 판단한다.\r\n\r\n​1. 계약이 성립하기 위하여는 당사자 사이에 의사의 합치가 있을 것이 요구되고 이러한 의사의 합치는 당해 계약의 내용을 이루는 모든 사항에 관하여 있어야 하는 것은 아니나 \r\n\r\n​\r\n\r\n그 본질적 사항이나, 중요 사항에 관하여는 구체적으로 의사의 합치가 있거나 적어도 장래 구체적으로 특정할 수 있는 \'\'기준과 방법 등에 관한 합의\'\'는 있어야 한다. (대법원 2001.3. 23. 선고 2000다51650 판결 참조). \r\n\r\n​\r\n한편, 매매계약은 당사자 일방이 재산권을 상대방에게 이전할 것을 약정하고 상대방이 그 대금을 지급할 것을 약정하는 계약으로, \r\n\r\n​매도인이 재산권을 이전하는 것과 매수인이 그 대가로서 금원을 지급하는 것에 관하여, \'\'쌍방 당사자의 합의가 이루어짐으로써 성립하는 것이다\'\' ( 대법원 1996. 4. 26. 선고 94다34432 판결 등 참조).\r\n\r\n​원심은 그 채용 증거들을 종합하여 그 판시와 같은 사실을 인정한 다음, \'\'비록 이 사건 가계약서에 잔금 지급시기가 기재되지 않았고, 후에 그 정식계약서가 작\r\n\r\n성되지 않았다 하더라도\'\'\r\n\r\n위 \'\'가계약서 작성 당시 매매계약의 중요 사항인 매매목적물과 매매대금 등이 특정되고 중도금 지급방법에 관한 합의가 있었으므로 원·피고 사이에 이 사건 부동\r\n\r\n산에 관한 매매계약은 성립되었다고\'\' 판단하였다.\r\n\r\n앞서 본 법리와 기록에 의하여 살펴보면, 원심의 이러한 사실인정과 판단은 정당하고, 거기에 상고이유로서 주장하는 바와 같은 채증법칙 위배로 인한 사실오\r\n\r\n인이나, \'\'계약성립에 관한 법리오해, 처분문서의 효력에 관한 법리오해 등의 위법이 없다\'\'\r\n\r\n2. 매도인이 민법 제565조에 의하여 계약금의 배액을상환하고 계약을 해제하려면 매수인이 이행에 착수할\r\n\r\n때까지 하여야 할 것인바, \r\n\r\n​여기에서 이행에 착수한다는 것은 객관적으로 외부에서 인식할 수 있는 정도로, \'\'채무의 이행행위의 일부를 \r\n\r\n하거나, 또는 이행을 하기 위하여 필요한 전제행위\'\' 를 하는 경우를 말한다\'\'( 대법원 2002.11. 26. 선고 2002다 46492 판결 등 참조).\r\n\r\n​원심은, 피고가 원고에게 이 사건 매매계 약의 계약금 배액을 상환하고 위 매매계약 을 적법히 해제하였다는 피고의 주장에 대하여, \r\n\r\n​이 사건 매매계약 당시, 원고가 중도금 일부 의 지급에 갈음하여 원고의 이희완에 대한 대여원리금채권을 피고에게 양도하기로 약정함으로써 \r\n\r\n​위 계약 성립과 함께 위 채권은 양도되었고, 그 채무자인 이희완도 위 계약에 참석하였 기 때문에 위 채권양도의 통지도 그 자리에 서 이루어졌다고 봄이 상당하므로, 원고는 위 매매계약과 함께 그 채무의 일부 이행에 \r\n\r\n착수한 것이고, \r\n\r\n​따라서 계약금의 배액상환을 원인으로 한 피고의 해제 의사표시는 원고가 이미 이행에 착수한 이후에 이루어진 것으로서 그 효력이 없다고 판단하여, 피고의 위 주\r\n\r\n장을 배척하였다.\r\n\r\n​위 법리와 기록에 비추어 살펴보면, 원심의 이러한 판단은 정당한 것으로 수긍할 수 있고, 거기에 상고이유에서 주장하는 계약해제에 관한 법리오해의 위법 등이 \r\n\r\n있다고 할 수 없다.\r\n\r\n​3. 그러므로, 상고를 기각하고, 상고비용은 패소자가 부담하는 것으로 하여, 관여 대법 관의 일치된 의견으로 주문과 같이 판결한 다.\r\n\r\n​대법관   김능환(재판장) 김용담 박시환(주심)',0);
INSERT INTO `article_tbl` VALUES (180917,1,32,'01090544679','2021-05-07','2021-05-07','0000-00-00','0000-00-00','「주택 임대차 신고제」시행(`21.6.1)','0','오는 6월부터 임대차 계약 당사자가 임대기간, 임대료 등의 계약내용을 시군구청에 신고하도록 하는 주택 임대차 신고제가 시행된다. 임대차 시장 정보를 투명하게 공개하고 임차인의 권리를 보호하기 위해 도입되는 제도인데, 그렇다면 이로써 우리 일상의 무엇이 달라지게 될까?',NULL,'｢부동산거래신고법｣ 하위법령 개정안 입법예고  \r\n\r\n \r\n\r\n-「주택 임대차 신고제」시행(`21.6.1) 따른 신고대상 ․ 절차 등 규정\r\n\r\n \r\n\r\n- 계약서만 있으면 방문없이 무료로 확정일자까지  한번에 처리\r\n\r\n \r\n\r\n- 투명한 임대차 시장의 정보제공 및 대출, 보증상품 등 접목 가능\r\n\r\n \r\n\r\n- 수도권·광역시 등, 보증금 6천만원 또는 월 30만원 초과 시행\r\n\r\n \r\n\r\n가. 임대차 신고제 개요\r\n\r\n \r\n\r\n \r\n\r\n□ 국토교통부(장관 변창흠)는 오는 6월 1일부터「주택 임대차 신고제」를 시행하기 위해\r\n\r\n \r\n\r\n ㅇ 임대차 신고의 대상, 신고내용, 절차 등 법률*에서 위임된 내용을 정하기 위한「부동산거래신고 등에 관한 법률」하위법령 개정안을 입법예고한다고 밝혔다.\r\n\r\n \r\n\r\n    * 『부동산거래신고 등에 관한 법률』 일부개정안 개정․공포 (`20.8.18) →시행(‘21.6.1)\r\n\r\n \r\n\r\n ㅇ 임대차 신고제는 임대차 계약 당사자가 임대기간, 임대료 등의 계약내용을 신고하도록 하여 임대차 시장 정보를 투명하게 공개하고 임차인의 권리를 보호하기 위해 도입되는 제도이다.\r\n\r\n \r\n\r\n \r\n ※ 임대차신고제 주요내용 (부동산거래신고법)\r\n\r\n \r\n\r\n  1) 신고의무 : 임대인+임차인이 계약 체결일로부터 30일 이내에 공동신고\r\n\r\n  2) 신고주택 : 주택임대차보호법 상 주택\r\n\r\n  3) 신고대상 : 대통령령으로 정하는 지역에서 대통령령으로 정하는 금액을 초과하는 계약\r\n\r\n  4) 신고관청 : 시군구청 → (조례로 위임허용) 읍면동 및 출장소\r\n\r\n  5) 위반 시 제재 : 미신고 또는 거짓신고 시 100만원 이하의 과태료\r\n\r\n \r\n\r\n□ 주택 임대차 신고제 시행을 위한「부동산거래신고법」하위법령 일부개정안의 주요 내용은 다음과 같다.\r\n\r\n \r\n\r\n나. 하위법령 주요내용\r\n\r\n \r\n\r\n \r\n\r\n➊ 주택 임대차 신고 지역 및 금액 등\r\n\r\n \r\n\r\n ㅇ 신고지역은 수도권(서울, 경기도, 인천) 전역, 광역시, 세종시 및 도(道)의 시(市) 지역으로 규정하였다.\r\n\r\n \r\n\r\n  - 임대차 거래량이 작고 소액 계약 임대차 비중이 높아 신고 필요성이 상대적으로 낮은 도 지역의 군(郡)은 신고지역에서 제외하였다.\r\n\r\n \r\n\r\n ㅇ 신고금액은 확정일자 없이도 최우선변제를 받을 수 있는 임차보증금의 최소금액이 6천만원*인 점을 고려하여\r\n\r\n \r\n\r\n   * 서울 1.5억, 경기 대부분 및 세종 1.3억, 광역시 등 7천, 그 외 6천만원\r\n(현재 주택임대차보호법 시행령 개정 입법예고중이며 4월말 개정 시행예정)\r\n\r\n \r\n\r\n  - 임대차 보증금 6천만원을 초과하거나 또는 월차임 30만원을 초과하는 임대차 계약으로 규정하였다.\r\n\r\n \r\n\r\n ㅇ 신규, 갱신계약 모두 신고하여야 하며, 다만 계약금액의 변동이 없는 갱신계약은 신고대상에서 제외하였다.\r\n\r\n \r\n\r\n \r\n➋ 임대차 계약 신고내용·절차 및 방법\r\n\r\n \r\n\r\n< 신고내용 >\r\n\r\n \r\n\r\n ㅇ 신고 항목은 임대인ㆍ임차인의 인적사항, 임대 목적물 정보(주소, 면적 또는 방수), 임대료, 계약기간, 체결일 등 표준임대차계약서에 따른 일반적인 임대차 계약 내용으로 하고,\r\n\r\n \r\n\r\n  - 갱신계약의 경우 종전 임대료, 계약갱신요구권 행사여부를 추가하도록 규정하였다.\r\n\r\n \r\n\r\n< 신고 절차 및 방법 >\r\n\r\n \r\n\r\n ㅇ 신고방법은 계약 당사자인 임대인과 임차인이 임대차 계약 신고서(참고1)에 공동으로 서명 또는 날인하여 신고하는 것을 원칙으로 하되,\r\n\r\n \r\n\r\n  - 신고의 편의를 위해 임대인 또는 임차인 중 한 명이 당사자가 모두 서명 또는 날인한 계약서를 제출하는 경우 공동으로 신고한 것으로 간주하도록 규정하였다.\r\n\r\n \r\n\r\n ㅇ 임대차 신고는 임대한 주택의 관할 읍면동 주민센터를 방문하여 통합민원창구에서 오프라인으로 신청할 수 있고,\r\n\r\n \r\n\r\n  - 신고인의 편의를 위해 관할 주민센터 방문없이 비대면 온라인 신고*도 가능하도록 전용시스템 구축을 완료하였다.\r\n\r\n \r\n\r\n   * 검색포털에서 ‘임대차 신고’를 검색하거나 직접 주소입력(부동산거래관리시스템, https://rtms.molit.go.kr)하여 사이트 접속\r\n\r\n \r\n\r\n   ** 온라인으로 신고할 경우에는 계약서 원본을 pdf, jpg 등 파일로 변환하거나 스마트폰으로 촬영한 사진파일(png)을 첨부하여 신고\r\n\r\n \r\n\r\n ㅇ 임대인 또는 임차인이 임대차계약서를 제출하여 신고를 접수한 경우 상대방에게는 문자 메시지로 임대차 신고가 접수 완료되었음이 통보된다.\r\n\r\n \r\n\r\n \r\n ※ 공동으로 작성한 계약서가 없는 경우, 계약자 중 한 명이 계약금 입금내역 등 임대차 계약내용을 확인할 수 있는 서류와 함께 신고서를 작성하여 신고할 수 있도록 하되,\r\n\r\n \r\n\r\n  - 이 경우에도 계약 상대방에게 본인과 관련된 임대차신고가 접수되었으며 본인도 기한 내 신고하여야 함을 문자로 통보할 계획이다.\r\n\r\n \r\n\r\n❸ 다른 법률에 따른 신고의 의제 절차\r\n\r\n \r\n\r\n ㅇ「주민등록법」상 전입신고를 할 경우, 임대차 계약서를 첨부하면 임대차 계약 신고를 한 것으로 규정하였으며,\r\n\r\n \r\n\r\n ㅇ 임대차 신고 시 계약서를 제출*한 경우,「주택임대차보호법」에 따른 확정일자가 부여되는 것으로 하였다.\r\n\r\n \r\n\r\n   * 온라인으로 신고하는 경우 pdf, jpg, png 등 계약서를 파일로 제출\r\n\r\n \r\n\r\n❹ 임대차 계약 신고서 작성 및 제출 대행 등\r\n\r\n \r\n\r\n ㅇ 임대차 계약 당사자의 신고 편의를 위하여 계약 당사자로부터 위임을 받은 자가 임대차 계약 신고서의 작성 및 제출 대행할 수 있도록 하고 위임장 등 필요한 서류를 규정하였다.\r\n\r\n \r\n\r\n➎ 과태료 부과기준 \r\n\r\n \r\n\r\n ㅇ 임대차 계약을 미신고하거나 거짓 신고하는 경우, 100만원 이하의 과태료를 부과하도록 함에 따라,\r\n\r\n \r\n\r\n  - 거짓신고는 100만원을 부과하고, 미신고의 경우 계약금액 규모가 작고, 신고 해태기간이 짧을수록 과태료를 최소 4만원까지 낮추는 등 차등적으로 부과할 예정이다.\r\n\r\n \r\n\r\n \r\n ㅇ 다만, 신규 제도 도입에 따른 일반 국민들의 적응기간 등을 감안하여 시행일로부터 1년(`21.6.1~`22.5.31) 동안은 과태료를 부과하지 않는 계도기간을 운영할 예정이며,\r\n\r\n \r\n\r\n   - 계도기간 이후에도 자진신고시 과태료를 면제하는 등 일반 국민의 부담을 최소화하면서 제도가 조기 정착될 수 있도록 지원할 계획이다.\r\n\r\n \r\n\r\n다. 임대차 신고제 시범운영\r\n\r\n \r\n\r\n \r\n\r\n□ 본 시행에 앞서 그동안 준비한 업무처리 절차 및 전산 시스템이 정상적으로 운영되는지 점검하기 위해 4. 19일부터 신고제 시행 전 까지 5개 동의 주민센터*에서 신고제를 시범운영할 예정이다.\r\n\r\n \r\n\r\n   * 대전광역시 서구 월평1ㆍ2ㆍ3동, 세종특별자치시 보람동, 용인시 기흥구 보정동\r\n\r\n \r\n\r\n ㅇ 시범운영 지역은 사전에 지자체 신청*을 통해 선정하였으며, 일반 국민들이 전입신고 및 확정일자 부여를 위해 방문 시 제도를 안내하고 신고를 받을 예정이다.\r\n\r\n \r\n\r\n   * 임대차신고제 시행에 대한 지자체 의견수렴시 시범운영 신청접수 (‘21.1.27～.2.10)\r\n\r\n \r\n\r\n라. 임대차 신고제 도입에 따른 기대효과 및 예상편익\r\n\r\n \r\n\r\n \r\n\r\n ➊ 임대차 신고를 통해 확정일자가 자동적으로 부여됨에 따라 임차인 보호가 대폭 강화될 전망이다.\r\n\r\n \r\n\r\n  - 소액계약, 단기계약, 갱신계약 등 그간 확정일자를 받지 않는 경향이 있었던 계약에도 신고제를 통해 확정일자가 부여되어 임대차 보증금 보호가 강화될 것으로 예상된다.\r\n\r\n \r\n\r\n ➋ 온라인 임대차 신고제 도입으로 임차인의 편익이 제고될 전망이다.\r\n\r\n \r\n\r\n \r\n  - 현재 확정일자는 주민센터 또는 법원 등기소에서 부여받을 수 있는데 대부분 일과중 주민센터를 방문하여 부여 받고 있다.\r\n\r\n \r\n\r\n   * 확정일자 부여건수(‘19): 총 217만건, 주민센터 183만건(84%), 등기소 35만건(16%)\r\n\r\n \r\n\r\n  - 온라인 임대차 신고제가 도입되면 확정일자를 부여받기 위해 일과중에 주민센터를 방문하여야 하는 임차인의 번거로움이 대폭 줄어들 것으로 예상된다.\r\n\r\n \r\n\r\n   * 주민센터에서 확정일자 부여시 부과하는 수수료(600원)도 임대차 신고를 통해 확정일자를 부여받는 경우 면제할 계획\r\n\r\n \r\n\r\n ➌ 임대차 신고제를 통해 임대차 가격·기간·갱신율 등 임대차 시장 정보가 투명하게 공개되어 거래편의가 높아질 것으로 기대된다.\r\n\r\n \r\n\r\n  - 임차인은 주변의 신규·갱신 임대료 정보를 확인한 후 임대차 계약을 체결할 수 있어 합리적 의사 결정이 가능해지고\r\n\r\n \r\n\r\n  - 임대인도 임대물건 주변 시세를 정확히 파악할 수 있어 적정한 임대료 책정을 통한 공실 위험 감소에 도움이 될 것으로 예상된다.\r\n\r\n \r\n\r\n□ 국토교통부 김수상 주택토지실장은 “신고에 따른 국민 불편을 해소하기 위해 현장 방문 없이 비대면 신고처리가 가능하도록 차질없이 준비중에 있으며,\r\n\r\n \r\n\r\n ㅇ 향후 신고된 계약내용을 기존 기금대출, 보증상품 등과 접목*시켜 행정서비스 향상에 기여하고 국민에게 꼭 필요한 제도로 안착될 수 있도록 노력할 것”이라고 밝혔다.\r\n\r\n \r\n\r\n   * 현재 기금 전월세대출 및 보증금 반환보증 신청시 금융기관에서 신청인에게 계약서를 제출하도록 하고 있으나, 향후 서류제출없이 신고제 내용을 전산으로 확인하여 제출서류를 간소화하고 심사기간을 단축하는 방안을 HUG와 협의중\r\n\r\n \r\n\r\n \r\n□ 이번 「부동산거래신고법」 하위법령 일부개정안에 대해 의견이 있는 경우 2021년 4월 26일까지 국민참여입법센터(http://opinion.lawmaking.go.kr), 우편, 팩스 등을 통해 의견을 제출할 수 있다.\r\n\r\n \r\n\r\n   * 의견제출처 : (우) 30103 세종특별자치시 도움6로11 정부세종청사 6동 국토교통부 주택임대차지원팀 / 팩스 : 044-201-5529',0);
INSERT INTO `article_tbl` VALUES (180918,1,18,'01090544679','2021-05-08','2021-12-08','0000-00-00','0000-00-00','민간임대주택의 보증의무와 면제 ','0','임대인이 민간임대주택에 관한 특별법의 적용대상이 되는 경우 표준임대차계약서를 작성하여야 하며 이때 임대보증금에 대한 보증 가입여부를 확인하도록 되어 있다. 이에 대하여 살펴보기록 하자. ',NULL,'민간임대주택에 관한 특별법\r\n\r\n등록주택임대사업자 임대보증금 보증과 관련한 민간임대주택에 관한 특별법 일부 개정안이 시행됨에 따라 <b>아래와 같은 두가지 임차인 동의서가 추가</b>되었습니다. \r\n\r\n1) 민특법 제49조 제3항 제4호에 따른 임대보증금 보증 일부가입 또는 계산 결과 대상금액이 0 이하로 보증가입이 불필요한 경우   임대보증금 보증 일부가입에 대한 임차인 동의서를\r\n\r\n2) 보증금이 최우선변제금 이하인 경우에는   민특법 제 49조 제7항 제 1호에 따라 임대보증금 보증 미가입에 대한 임차인 동의서를 사용하여야 합니다. \r\n\r\n다운로드 : 렌트홈>알림마당>민원법정서식\r\n\r\n\r\n이에 따라 관련조항들을 살펴보면\r\n\r\n제49조(임대보증금에 대한 보증) ① 임대사업자는 다음 각 호의 어느 하나에 해당하는 민간임대주택을 임대하는 경우 임대보증금에 대한 보증에 가입하여야 한다.  <개정 2019. 4. 23., 2020. 8. 18.>\r\n  1. 민간건설임대주택\r\n  2. 제18조제6항에 따라 분양주택 전부를 우선 공급받아 임대하는 민간매입임대주택\r\n  3. 동일 주택단지에서 100호 이상으로서 대통령령으로 정하는 호수 이상의 주택을 임대하는 민간매입임대주택(제2호에 해당하는 민간매입임대주택은 제외한다)\r\n  4. 제2호와 제3호 외의 민간매입임대주택\r\n  ② 제1항에 따른 보증에 가입하는 경우 보증대상은 임대보증금 전액으로 한다. 다만, 임대사업자가 사용검사 전에 임차인을 모집하는 경우 임차인을 모집하는 날부터 사용검사를 받는 날까지의 보증대상액은 임대보증금 중 사용검사 이후 납부하는 임대보증금을 제외한 금액으로 한다.  <개정 2017. 1. 17.>\r\n  <b>③ 제2항에도 불구하고 다음 각 호에 모두 해당하는 경우에는 담보권이 설정된 금액과 임대보증금을 합한 금액에서 주택가격의 100분의 60에 해당하는 금액을 뺀 금액 이상으로 대통령령에서 정하는 금액을 보증대상으로 할 수 있다. 이 경우 주택가격의 산정방법*은 대통령령으로 정한다.  <개정 2019. 4. 23., 2021. 9. 14.></b>\r\n* 주택가격의 산정방법\r\n<blockquote>\r\n\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>국토교통부 고시 제2021 - 1026호</SPAN></P>\r\n\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>&nbsp;「민간임대주택에 관한 특별법 시행령」제39조제2항제2호의 규정에 따라 「부동산 가격공시에 관한 법률」 제16조부터 제18조까지의 규정에 따라 공시된 가액 및 「소득세법」제99조제1항제1호다목에 따라 국세청장이 매년 산정ㆍ고시하는 기준시가에 대해 적용하는 비율 및 기타 가격기준 적용사항을 다음과 같이 고시합니다.</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'text-align:right;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>국토교통부장관</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>공시가격 및 기준시가 적용비율</SPAN></P>\r\n\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>&nbsp;「민간임대주택에 관한 특별법」제49조제3항 각 호 외의 부분 후단에 따른 주택가격의 산정방법 중 「부동산 가격공시에 관한 법률」 제16조부터 제18조까지의 규정에 따라 공시된 가액 및 「소득세법」제99조제1항제1호다목에 따라 국세청장이 매년 산정</SPAN><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";letter-spacing:1%;line-height:160%\'>ㆍ고시하는 기준시가에 대해 적용하는 비율 및 기타 가격기준 적용사항을 다음과 같이 한다.</SPAN></P>\r\n\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>“별표 1”을 별지와 같이 한다. </SPAN></P>\r\n\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'><BR></SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>부&nbsp; 칙</SPAN></P>\r\n\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:22.3pt;text-indent:-22.3pt;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>이 고시는 2021년 8월 17일부터 시행한다.</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'line-height:130%;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:130%\'>【별표 1】</SPAN></P>\r\n\r\n\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;text-decoration:underline;line-height:160%\'>1. 공시가격 및 기준시가 적용비율</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:22.5pt;text-align:left;text-indent:-22.5pt;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'>□ </SPAN><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>「부동산 가격공시에 관한 법률」 제16조부터 제18조까지의 규정에 따라 </SPAN><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>공시된 가액</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'text-align:left;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>&nbsp;&nbsp;ㅇ 공시된 가액에 따라 다음과 같이 적용함</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'text-align:center;\'>\r\n<TABLE border=\"1\" cellspacing=\"0\" cellpadding=\"0\" style=\'border-collapse:collapse;border:none;\'>\r\n<TR>\r\n	<TD valign=\"middle\" bgcolor=\"#fefce3\"  style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>&nbsp;구분 </SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#fefce3\"  style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>9억원 미만</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#fefce3\"  style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>9∼15억원</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" bgcolor=\"#fefce3\"  style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>15억원 이상</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>공동주택</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>150%</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>140%</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>130%</SPAN></P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>단독주택</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>190%</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>180%</SPAN></P>\r\n	</TD>\r\n	<TD valign=\"middle\" style=\'width:144;height:32;border-left:solid #000000 0.4pt;border-right:solid #000000 0.4pt;border-top:solid #000000 0.4pt;border-bottom:solid #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>160%</SPAN></P>\r\n	</TD>\r\n</TR>\r\n</TABLE></P>\r\n<P CLASS=HStyle0 STYLE=\'text-align:center;\'></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'><BR></SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:22.5pt;text-align:left;text-indent:-22.5pt;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'>□ </SPAN><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>「소득세법」제99조제1항제1호다목에 따라 국세청장이 매년 산정ㆍ고시하는 </SPAN><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>기준시가</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:22.5pt;text-align:left;text-indent:-22.5pt;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'><BR></SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:22.5pt;text-align:left;text-indent:-22.5pt;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'>&nbsp;&nbsp;ㅇ 적용비율 : </SPAN><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>120%</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:22.5pt;text-align:left;text-indent:-22.5pt;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'><BR></SPAN></P>\r\n\r\n<P CLASS=HStyle0><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";font-weight:bold;text-decoration:underline;line-height:160%\'>2. 기타 가격기준</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'text-align:center;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'><BR></SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:24.3pt;text-indent:-24.3pt;\'><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'>□ </SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;line-height:160%\'>이외에도 </SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;font-weight:bold;line-height:160%\'>보증회사</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;line-height:160%\'>가 </SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;font-weight:bold;line-height:160%\'>전세보증금 반환보증</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;line-height:160%\'>의 </SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;font-weight:bold;line-height:160%\'>심사</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;line-height:160%\'> 시 </SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;font-weight:bold;line-height:160%\'>적용</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";letter-spacing:1%;line-height:160%\'>하고</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'> 있는 </SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'>가격기준</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'> 등</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";font-weight:bold;line-height:160%\'> 준용</SPAN><SPAN STYLE=\'font-size:15.0pt;font-family:\"휴먼명조\";line-height:160%\'> 가능</SPAN></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:22.5pt;text-indent:-22.5pt;\'><SPAN STYLE=\'font-size:16.0pt;font-family:\"휴먼명조\";line-height:160%\'><BR></SPAN></P>\r\n\r\n\r\n</blockquote>\r\n  1. 근저당권이 세대별로 분리된 경우(근저당권이 주택단지에 설정된 경우에는 근저당권의 공동담보를 해제하고, 채권최고액을 감액하는 근저당권 변경등기의 방법으로 할 수 있다)\r\n  2. 임대사업자가 임대보증금보다 선순위인 제한물권(다만, 제1호에 따라 세대별로 분리된 근저당권은 제외한다), 압류ㆍ가압류ㆍ가처분 등을 해소한 경우\r\n  3. 전세권이 설정된 경우 또는 임차인이 「주택임대차보호법」 제3조의2제2항에 따른 대항요건과 확정일자를 갖춘 경우\r\n  <b>4. 임차인이 이 항 각 호 외의 부분 전단에 따른 대통령령으로 정하는 금액을 보증대상으로 하는 데 동의한 경우</b>\r\n  5. 그 밖에 제1호에서 제4호까지에 준하는 경우로서 대통령령으로 정하는 경우\r\n  ④ 제1항에 따른 보증의 가입기간은 다음 각 호의 시점부터 제6조에 따라 임대사업자 등록이 말소되는 날(임대사업자 등록이 말소되는 날에 임대 중인 경우에는 임대차계약이 종료되는 날로 한다)까지로 한다. 이 경우 임대사업자는 제1항에 따른 보증의 수수료를 1년 단위로 재산정하여 분할납부할 수 있다.  <개정 2017. 1. 17., 2019. 4. 23., 2020. 8. 18., 2021. 9. 14.>\r\n  1. 제1항제1호 및 제2호에 해당하는 민간임대주택: 사용검사를 받은 날(사용검사 전에 임차인을 모집하는 경우에는 그 날을 말한다)\r\n  2. 제1호 이외의 민간임대주택 중 등록일에 존속 중인 임대차계약이 있는 경우: 민간임대주택 등록일\r\n  3. 제1호 이외의 민간임대주택 중 등록일에 존속 중인 임대차계약이 없는 경우: 민간임대주택 등록일 이후 최초 임대차계약 개시일\r\n  ⑤ 제1항에 따른 보증에 가입한 임대사업자가 가입 후 1년이 지났으나 제4항에 따라 재산정한 보증수수료를 보증회사에 납부하지 아니하는 경우에는 보증회사는 그 보증계약을 해지할 수 있다. 다만, 임차인이 보증수수료를 납부하는 경우에는 그러하지 아니하다.\r\n  ⑥ 제5항에 따라 보증회사가 보증계약을 해지하는 경우 보증회사는 보증계약 해지 사실을 시장ㆍ군수ㆍ구청장에게 알려야 한다.  <신설 2020. 8. 18.>\r\n\r\n  ⑦ 제1항에도 불구하고 <b>다음 각 호의 어느 하나에 해당하면 임대보증금에 대한 보증에 가입하지 아니할 수 있다.</b>  <신설 2021. 9. 14.>\r\n  <b>1. 임대보증금이 「주택임대차보호법」 제8조제3항(최우선변제)에 따른 금액 이하이고 임차인이 임대보증금에 대한 보증에 가입하지 아니하는 것에 동의한 경우</b>\r\n<blockquote>\r\n주택임대차보호법 시행령\r\n[시행 2021. 5. 11.] [대통령령 제31673호, 2021. 5. 11., 일부개정] 전체조문보기\r\n\r\n 제10조(보증금 중 일정액의 범위 등) ① 법 제8조에 따라 우선변제를 받을 보증금 중 일정액의 범위는 다음 각 호의 구분에 의한 금액 이하로 한다.  <개정 2010. 7. 21., 2013. 12. 30., 2016. 3. 31., 2018. 9. 18., 2021. 5. 11.>\r\n\r\n1. 서울특별시: 5천만원\r\n\r\n2. 「수도권정비계획법」에 따른 과밀억제권역(서울특별시는 제외한다), 세종특별자치시, 용인시, 화성시 및 김포시: 4천300만원\r\n\r\n3. 광역시(「수도권정비계획법」에 따른 과밀억제권역에 포함된 지역과 군지역은 제외한다), 안산시, 광주시, 파주시, 이천시 및 평택시: 2천300만원\r\n\r\n4. 그 밖의 지역: 2천만원\r\n\r\n② 임차인의 보증금 중 일정액이 주택가액의 2분의 1을 초과하는 경우에는 주택가액의 2분의 1에 해당하는 금액까지만 우선변제권이 있다.\r\n\r\n③ 하나의 주택에 임차인이 2명 이상이고, 그 각 보증금 중 일정액을 모두 합한 금액이 주택가액의 2분의 1을 초과하는 경우에는 그 각 보증금 중 일정액을 모두 합한 금액에 대한 각 임차인의 보증금 중 일정액의 비율로 그 주택가액의 2분의 1에 해당하는 금액을 분할한 금액을 각 임차인의 보증금 중 일정액으로 본다.\r\n\r\n④ 하나의 주택에 임차인이 2명 이상이고 이들이 그 주택에서 가정공동생활을 하는 경우에는 이들을 1명의 임차인으로 보아 이들의 각 보증금을 합산한다.\r\n\r\n[전문개정 2008. 8. 21.]\r\n\r\n[제3조에서 이동, 종전 제10조는 제17조로 이동  <2013. 12. 30.>]\r\n\r\n 제11조(우선변제를 받을 임차인의 범위) 법 제8조에 따라 우선변제를 받을 임차인은 보증금이 다음 각 호의 구분에 의한 금액 이하인 임차인으로 한다.  <개정 2010. 7. 21., 2013. 12. 30., 2016. 3. 31., 2018. 9. 18., 2021. 5. 11.>\r\n\r\n1. 서울특별시: 1억5천만원\r\n\r\n2. 「수도권정비계획법」에 따른 과밀억제권역(서울특별시는 제외한다), 세종특별자치시, 용인시, 화성시 및 김포시: 1억3천만원\r\n\r\n3. 광역시(「수도권정비계획법」에 따른 과밀억제권역에 포함된 지역과 군지역은 제외한다), 안산시, 광주시, 파주시, 이천시 및 평택시: 7천만원\r\n\r\n4. 그 밖의 지역: 6천만원\r\n\r\n[전문개정 2008. 8. 21.]\r\n\r\n[제4조에서 이동, 종전 제11조는 제18조로 이동  <2013. 12. 30.>]\r\n</blockquote>\r\n  2. 임대사업자가 「공공주택 특별법」 제45조의2에 따라 기존주택을 임차하는 공공주택사업자*와 임대차계약을 체결하는 경우로서 해당 공공주택사업자가 보증 가입 등 임대보증금 회수를 위하여 필요한 조치를 취한 경우\r\n*공공임대주택사업자란?\r\n<blockquote>\r\n 제4조(공공주택사업자) ①국토교통부장관은 다음 각 호의 자 중에서 공공주택사업자를 지정한다.  <개정 2010. 4. 5., 2012. 1. 17., 2013. 3. 23., 2014. 1. 14., 2015. 1. 20., 2015. 8. 28., 2021. 7. 20.>\r\n  1. 국가 또는 지방자치단체\r\n  2. 「한국토지주택공사법」에 따른 한국토지주택공사\r\n  3. 「지방공기업법」 제49조에 따라 주택사업을 목적으로 설립된 지방공사\r\n  4. 「공공기관의 운영에 관한 법률」 제5조에 따른 공공기관 중 대통령령으로 정하는 기관\r\n  5. 제1호부터 제4호까지의 규정 중 어느 하나에 해당하는 자가 총지분의 100분의 50을 초과하여 출자ㆍ설립한 법인\r\n  6. 주택도시기금 또는 제1호부터 제4호까지의 규정 중 어느 하나에 해당하는 자가 총지분의 전부(도심 공공주택 복합사업의 경우에는 100분의 50을 초과한 경우를 포함한다)를 출자(공동으로 출자한 경우를 포함한다)하여 「부동산투자회사법」에 따라 설립한 부동산투자회사\r\n  ② 국토교통부장관은 제1항제1호부터 제4호까지의 규정 중 어느 하나에 해당하는 자와 「주택법」 제4조에 따른 주택건설사업자를 공동 공공주택사업자로 지정할 수 있다.  <개정 2015. 1. 20., 2015. 8. 28., 2016. 1. 19.>\r\n  ③ 제1항제5호 및 제2항에 따른 공공주택사업자의 선정방법ㆍ절차 및 공동시행을 위한 협약 등에 필요한 사항은 국토교통부장관이 정하여 고시한다.  <신설 2014. 1. 14., 2015. 8. 28.>\r\n[제목개정 2015. 8. 28.]\r\n[법률 제18311호(2021. 7. 20.) 부칙 제2조의 규정에 의하여 이 조 제1항제6호는 2024년 9월 20일까지 유효함]\r\n</blockquote>\r\n  3. 임차인이 보증회사 및 이에 준하는 기관에서 운용하는 전세금 반환을 보장하는 보증에 가입하였고, 임대사업자가 해당 보증의 보증수수료를 임차인에게 전부 지급한 경우\r\n  ⑧ 제1항에 따른 보증에 가입하는 경우 보증수수료의 납부방법, 소요 비용의 부담비율, 보증대상 임대보증금의 범위, 보증의 가입ㆍ유지ㆍ탈퇴 등에 필요한 사항은 대통령령으로 정한다.  <개정 2020. 8. 18., 2021. 9. 14.>\r\n',0);
INSERT INTO `article_tbl` VALUES (180919,1,18,'01091280586','2021-05-14','2021-05-14','0000-00-00','0000-00-00','권리관계 등에 대해 설명해야 하는 시점','0','가계약(假契約)을 체결하는 경우, 그 가계약을 체결하기 전에 중개의뢰인에게 성실·',NULL,'부산광역시 남구청 - 중개업자가 중개대상물의 권리관계 등에 대해 설명해야 하는 시점(「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제25조제1항 관련)\r\n안건번호10-0149\r\n회신일자2010-06-04\r\n1. 질의요지\r\n중개업자가 중개를 의뢰받아 중개를 함에 있어서 「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제25조제3항에 따른 거래계약서를 작성하기 전에 가계약(假契約)을 체결하는 경우, 그 가계약을 체결하기 전에 같은 법 제25조제1항 각 호의 사항에 대하여 중개의뢰인에게 성실·정확하게 설명하고 그 설명의 근거자료를 제시하지 아니한 경우 같은 법 제39조제1항제5호에 따른 행정처분의 대상이 되는지?\r\n3. 회답\r\n  중개업자가 중개를 의뢰받아 중개를 함에 있어서 「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제25조제3항에 따른 거래계약서를 작성하기 전에 가계약(假契約)을 체결하는 경우, 그 가계약을 체결하기 전에 같은 법 제25조제1항 각 호의 사항에 대하여 중개의뢰인에게 성실·정확하게 설명하고 그 설명의 근거자료를 제시하지 아니하였다는 이유만으로 같은 법 제39조제1항제5호에 따른 행정처분의 대상이 되지 않습니다.\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n4. 이유\r\n  「공인중개사의 업무 및 부동산 거래신고에 관한 법률」(이하 “공인중개사법”이라 함) 제2조제1호에 따르면, “중개”라 함은 같은 법 제3조의 규정에 의한 중개대상물에 대하여 거래당사자간의 매매·교환·임대차 그 밖의 권리의 득실변경에 관한 행위를 알선하는 것을 말한다고 규정하고 있고, 같은 법 제25조제1항에 따르면, 중개업자는 중개를 의뢰받은 경우에는 중개가 완성되기 전에 당해 중개대상물의 상태·입지 및 권리관계(제1호), 법령의 규정에 의한 거래 또는 이용제한사항(제2호) 등 같은 항 각 호의 사항을 확인하여 이를 당해 중개대상물에 관한 권리를 취득하고자 하는 중개의뢰인에게 성실·정확하게 설명하고, 토지대장·등기부등본 등 설명의 근거자료를 제시하여야 하며, 같은 조 제3항에 따르면, 중개업자는 중개가 완성되어 거래계약서를 작성하는 때에는 같은 조 제1항의 규정에 의한 확인·설명사항을 대통령령이 정하는 바에 따라 서면으로 작성하여 거래당사자에게 교부하고 대통령령이 정하는 기간 동안 그 사본을 보존하여야 한다고 규정하고 있습니다. \r\n\r\n  한편, 같은 법 제36조제1항제3호에 따르면, 시·도지사는 공인중개사가 소속공인중개사로서 업무를 수행하는 기간 중에 제25조제1항의 규정을 위반하여 성실·정확하게 중개대상물의 확인·설명을 하지 아니하거나\r\n 설명의 근거자료를 제시하지 아니한 경우 6월의 범위 안에서 기간을 정하여 그 자격을 정지할 수 있다고 규정하고 있고, 같은 법 제39조제1항제5호에 따르면, 등록관청은 중개업자가 제25조제1항의 규정을 위반하여 성실·정확하게 중개대상물의 확인·설명을 하지 아니하거나 설명의 근거자료를 제시하지 아니한 경우 6월의 범위 안에서 기간을 정하여 업무의 정지를 명할 수 있다고 규정하고 있습니다. \r\n\r\n  우선, 공인중개사법 제25조제3항에서는 “중개가 완성되어 거래계약서를 작성하는 때”로 규정하고 있으므로 중개의 완성은 거래계약서의 작성으로 이루어진다고 할 것이고, 따라서 같은 법 제25조제1항에서 중개업자가 “중개가 완성되기 전”에 중개대상에 대하여 확인·설명하고 설명의 근거자료를 제시하도록 한 것은 “거래계약서 작성 전”까지 확인·설명하고 설명의 근거자료를 제시하면 되는 것으로 해석함이 타당하다 할 것입니다. \r\n\r\n  또한, 공인중개사가 공인중개사법 제25조제1항의 의무를 이행하지 않은 경우 시·도지사는 같은 법 제36조제1항제3호에 따라 6월의 범위 안에서 공인중개사의 자격을 정지할 수 있고, 같은 법 제39조제1항제5호에 따라 6월의 범위 안에서 중개업자의 업무를 정지할 수 있으며, 이러한 행정처분이 침익적인 처분임을 고려하면 위 규정은 문언\r\n 그대로 엄격하게 해석하여야 할 것이고 이를 확장해석할 수 없다고 할 것인데, 중개업자가 같은 법 제25조제1항 및 제3항에 규정된 시점보다 이른 시점, 즉 중개가 완성되어 거래계약서를 작성하는 시점보다 이른 시점인 가계약 체결시에 같은 항 각 호의 사항을 설명하고 그 설명의 근거를 제시하지 아니하였다는 이유만으로 6월 이내의 영업정지 등의 행정처분을 할 수 없다 할 것입니다. \r\n\r\n  그렇다면, 중개업자가 중개를 의뢰받아 중개를 함에 있어서 「공인중개사의 업무 및 부동산 거래신고에 관한 법률」 제25조제3항에 따른 거래계약서를 작성하기 전에 가계약(假契約)을 체결하는 경우, 그 가계약을 체결하기 전에 같은 법 제25조제1항 각 호의 사항에 대하여 중개의뢰인에게 성실·정확하게 설명하고 그 설명의 근거자료를 제시하지 아니하였다는 이유만으로 같은 법 제39조제1항제5호에 따른 행정처분의 대상이 되지 않습니다.\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n관계법령\r\n- 공인중개사의 업무 및 부동산 거래신고에 관한 법률 제25조\r\n법제처 법령해석의 효력 등에 대한 안내\r\n법제처의 법령해석은 정부 내 통일성 있는 법령집행과 행정운영을 위해 법령해석에 관한 지침을 제시하기 위한 것으로서 법원의 확정판결과 같은 기속력은 없는바, 법령 소관 중앙행정기관에서 구체적인 사실관계 등에 따라 일부 다르게 집행하는 경우도 있다는 점을 유의하시기 바랍니다.\r\n「헌법」 제 101조에 따라 사법권은 법원에 속하고, 「법제업무 운영규정」 제26조 제8항 제2호 및 제11항에 따라 정립된 판례가 있는 경우에는 법제처는 법령해석을 할 수 없는바, 법제처 법령해석과 상충되는 법원의 확정판결이 나온 경우에는 법원의 확정판결을 참고하시기 바랍니다.',0);
INSERT INTO `article_tbl` VALUES (180920,1,32,'01022890629','2021-05-17','2021-06-08','2021-06-01','0000-00-00','6월 1일 시행된 주택 임대차 신고제 알아보기','0','오는 6월부터 임대차 계약 당사자가 임대기간, 임대료 등의 계약내용을 시군구청에 신고하도록 하는 주택 임대차 신고제가 시행된다. 임대차 시장 정보를 투명하게 공개하고 임차인의 권리를 보호하기 위해 도입되는 제도인데, 그렇다면 이로써 우리 일상의 무엇이 달라지게 될까?','mch02.jpg','주택임대차신고는 주택임대차 보호법 상의 모든 주택을 대상으로 하며, 신규 계약은 물론 갱신 계약의 경우에도 계약금액의 변동이 없는 경우를 제외하면 모두 신고해야 하는 점은 특기할 만 하다.\r\n\r\n신고 해당 지역은 수도권(서울, 경기도, 인천) 전역, 광역시, 세종시 및 도(道)의 시(市) 지역으로 신고 대상 금액은 임대차 보증금 6천만원을 초과하거나 또는 월차임 30만원을 초과하는 임대차 계약을 말한다. 서울권의 임대주택은 대부분 이 경우에 해당하는 셈이다.\r\n\r\n또한, 신고주체는 임대인과 임차인으로 계약 신고서에 공동으로 서명 또는 날인하여 계약 체결일로부터 30일 이내에 관할 시군구청에 공동신고해야 하는 점도 주의할 필요가 있다. 다만 신고의 편의를 위해 임대인 또는 임차인 중 한 명이 당사자가 모두 서명 또는 날인한 계약서를 제출하는 경우 공동으로 신고한 것으로 간주되며 대리인도 위임장과 위임하는 당사자의 신분증을 준비하면 방문 또는 온라인 신고 가능하다. \r\n\r\n<blockquote>계약 체결일로부터 30일 이내이지만 계약서 작성 전이라도 임대료와 임대 기간, 주택 등이 확정돼 당사자 간 임대차 계약 합의 후 가계약금이 입금됐다면 가계약금 입금일을 기준으로 30일 이내에 신고해야 한다.</blockquote>\r\n\r\n임대차신고는 임대한 주택의 읍면동 주민센터를 방문, 창구에서 오프라인 신청이 가능하며, <a href=\"https://rtms.molit.go.kr\" target=\"_blank\">부동산거래관리시스템(https://rtms.molit.go.kr)</a>을 이용하여 온라인 신청도 가능하다. 또한, 계약상대방이 임대차계약서를 제출하여 신고를 접수한 경우 상대방에게는 문자 메시지로 임대차 신고가 접수 완료되었음이 통보된다.\r\n\r\n관련 법의 규정도 이번 임대차신고 법령의 실시로 이전과 조금 달라진 모양새다. 가령 「주민등록법」상 전입신고를 할 경우, 임대차 계약서를 첨부하면 임대차 계약 신고를 한 것으로 규정하였으며, 임대차 신고 시 계약서를 제출한 경우,「주택임대차보호법」에 따른 확정일자가 부여되는 것으로 변경되었기 때문이다. \r\n\r\n또한 주택임대사업자는 3개월내 표준계약서 신고 의무인데 1달안에 표준계약서 신고하면 전월세 신고 따로 하지 안해도 된다\r\n\r\n이를 요약하면, 만약 전입신고를 30일 이내면 하게되면 별도의 임대차신고가 필요없게되고, 전입신고를 30일이 지나서 하여야 한다면 30일 이내에 임대차신고를 하고, 후에 전입신고를 하여야 한다. 아울러 임대차 계약을 미신고하거나 거짓 신고하는 경우, 100만원 이하의 과태료를 부과하고 있으니 주의할 필요가 있다. \r\n',0);
INSERT INTO `article_tbl` VALUES (180921,1,32,'01095898924','2021-05-24','2021-05-27','2021-05-24','0000-00-00','똘똘한 한 채의 투자, 관건은 ‘1세대 1주택’','0','최근 양도소득세-취득세-종합부동산세로 이어지는 부동산 3법의 개정이 확정되며 관련 사안이 업계의 큰 이슈로 떠올랐습니다. 덩달아 함께 주목받는 이슈 키워드가 있으니, ‘1세대 1주택’입니다. 사람들은 왜 굳이 1세대에 주목하게 된 것일까요? 그리고 똘똘한 한 채를 제대로 투자하기 위해서, 왜 ‘1세대 1주택’이라는 키워드를 우리는 눈여겨봐야 할까요? 지금부터 그 이야기를 부동산 실무적인 부분에서 정리하도록 하겠습니다.',NULL,'<h3>왜 ‘1세대 1주택’을 주목해야 하나</h3>\r\n\r\n이 키워드를 주시해야 할 이유는 크게 두 가지를 꼽을 수 있습니다. \r\n\r\n먼저는 청약 제도와 관련이 있습니다. 청약의 경우, 현재 조정대상지역과 투기과열지구 같은 부동산 규제지역에서는 오직 각 가구의 세대주에게만 1순위 청약 자격이 주어지고 있습니다. 여기에 무주택 기간까지 일정 기간 이상 더하면 소위 ‘특공’이라고 말하는 굉장한 권한을 가진 청약 자격을 얻게 됩니다. 청약 시장에서 가히 0순위라고 해도 좋죠. 물론 청약 제도 관련 부분은 부동산 중개에서 관심을 크게 둘 포인트가 아니긴 하므로 설명은 이쯤에서 끝내겠습니다. \r\n\r\n부동산 중개와 관련, 눈여겨볼 ‘1세대 1주택’의 핵심 포인트는 바로 세법과 관련이 있습니다. 현행법상 다주택자는 양도소득세 및 취득세, 종합부동산세 중과 대상이 됩니다. 특히 부동산 중개와 관련, 현장에서 가장 크게 맞부딪히는 세목은 바로 양도세와 취득세가 될 것입니다. 지방세로서 지방세법의 적용을 받는 취득세와 국세로 분류되며 소득세법의 적용을 받는 양도소득세는 법이 규정하는 기본 성격부터 확연히 다르며, 대상의 범위 지정도 달라집니다.\r\n\r\n앞서 다주택자는 취득세, 양도소득세 및 종합부동산세의 중과 대상이 된다고 말씀드렸습니다. 바꿔 말해서, 다주택자가 아닌 1세대 1주택자는 이러한 세목의 중과 대상이 되지 않는다고 봐도 좋습니다. 그렇다면 각 법령상 취득세, 양도소득세 및 종합부동산세의 중과 대상이 되지 아니하는 ‘1세대 1주택자’의 정의는 과연 무엇일까요? 그리고 이 개념들은 반드시 일치하는 것일까요?\r\n\r\n<h3>1세대 1주택자의 실무적 정의</h3>\r\n취득세에서 1세대 1주택의 개념은 지방세법 시행령 제28조의3 세대의 기준 부분을 참고하면 좋습니다. 이 조항을 통해 우리 법이 취득세에서 ‘1가구’의 개념을 주택을 취득하는 사람과 \'「주민등록법」 제7조에 따른 세대별 주민등록표에 함께 기재되어 있는 가족으로 구성된 세대\'로 정의하고 있기 때문이죠.\r\n\r\n<blockquote cite=\"https://www.law.go.kr/%EB%B2%95%EB%A0%B9/%EC%A7%80%EB%B0%A9%EC%84%B8%EB%B2%95%EC%8B%9C%ED%96%89%EB%A0%B9\"> 제28조의3(세대의 기준) ① 법 제13조의2제1항부터 제4항까지의 규정을 적용할 때 1세대란 주택을 취득하는 사람과 「주민등록법」 제7조에 따른 세대별 주민등록표(이하 이 조에서 “세대별 주민등록표”라 한다) 또는 「출입국관리법」 제34조제1항에 따른 등록외국인기록표 및 외국인등록표(이하 이 조에서 “등록외국인기록표등”이라 한다)에 함께 기재되어 있는 가족(동거인은 제외한다)으로 구성된 세대를 말하며 주택을 취득하는 사람의 배우자(사실혼은 제외하며, 법률상 이혼을 했으나 생계를 같이 하는 등 사실상 이혼한 것으로 보기 어려운 관계에 있는 사람을 포함한다. 이하 제28조의6에서 같다), 취득일 현재 미혼인 30세 미만의 자녀 또는 부모(주택을 취득하는 사람이 미혼이고 30세 미만인 경우로 한정한다)는 주택을 취득하는 사람과 같은 세대별 주민등록표 또는 등록외국인기록표등에 기재되어 있지 않더라도 1세대에 속한 것으로 본다.\r\n  ② 제1항에도 불구하고 다음 각 호의 어느 하나에 해당하는 경우에는 각각 별도의 세대로 본다.\r\n  1. 부모와 같은 세대별 주민등록표에 기재되어 있지 않은 30세 미만의 자녀로서 「소득세법」 제4조에 따른 소득이 「국민기초생활 보장법」 제2조제11호에 따른 기준 중위소득의 100분의 40 이상이고, 소유하고 있는 주택을 관리ㆍ유지하면서 독립된 생계를 유지할 수 있는 경우. 다만, 미성년자인 경우는 제외한다.\r\n  2. 취득일 현재 65세 이상의 부모(부모 중 어느 한 사람이 65세 미만인 경우를 포함한다)를 동거봉양(同居奉養)하기 위하여 30세 이상의 자녀, 혼인한 자녀 또는 제1호에 따른 소득요건을 충족하는 성년인 자녀가 합가(合家)한 경우\r\n  3. 취학 또는 근무상의 형편 등으로 세대전원이 90일 이상 출국하는 경우로서 「주민등록법」 제10조의3제1항 본문에 따라 해당 세대가 출국 후에 속할 거주지를 다른 가족의 주소로 신고한 경우\r\n[본조신설 2020. 8. 12.]</blockquote>\r\n\r\n하지만 소득세법의 적용을 받는 양도소득세의 경우, 이러한 1세대 1주택자의 개념에 대한 정의가 앞의 경우와 비교했을 때 조금 달라집니다. 관련 조항인 소득세법 제88조 6호를 보면, 이 법에서 규정하는 ‘1세대’란 거주자 및 그 배우자가 그들과 같은 주소 또는 거소에서 생계를 같이 하는 자 와 함께 구성하는 가족단위를 말하고 있습니다.\r\n\r\n<blockquote cite=\"https://www.law.go.kr/%EB%B2%95%EB%A0%B9/%EC%86%8C%EB%93%9D%EC%84%B8%EB%B2%95\">6. “1세대”란 거주자 및 그 배우자(법률상 이혼을 하였으나 생계를 같이 하는 등 사실상 이혼한 것으로 보기 어려운 관계에 있는 사람을 포함한다. 이하 이 호에서 같다)가 그들과 같은 주소 또는 거소에서 생계를 같이 하는 자[거주자 및 그 배우자의 직계존비속(그 배우자를 포함한다) 및 형제자매를 말하며, 취학, 질병의 요양, 근무상 또는 사업상의 형편으로 본래의 주소 또는 거소에서 일시 퇴거한 사람을 포함한다]와 함께 구성하는 가족단위를 말한다. 다만, 대통령령으로 정하는 경우에는 배우자가 없어도 1세대로 본다.</blockquote>\r\n\r\n요약하면 취득세상에서 말하는 1세대란 세대별 주민등록표의 개념이며, 1세대는 생계를 함께 영위하는지 아니하는지 여부에 따른 개념으로 판단할 수 있습니다. 따라서 상황에 따라서 1세대는 아니지만 특정한 경우, 과세당국이 대상을 1가구로 판단될 수도 있으며, 그 반대로 1가구의 형태로 인정되지만 1세대는 아닌 경우로 해석할 소지도 분명히 생길 수 있습니다.\r\n\r\n즉, 부동산 실무에서는 해당 사례에 적용되는 세법이 취득세냐 양도소득세냐에 따라 과세의 판단기준이 달라질 수 있다는 점, 유념해 두시면 좋으며, 따라서 1세대 1주택의 개념이 반드시 법리판단 상에서 일치하지만은 않는다는 포인트 또한 염두하시는 것이 좋습니다. 다만 실제로는 1가구와 1세대라는 개념이 각각 혼재되어 쓰이는 실정이며, 실무에서 굳이 엄정하게 이를 구분할 필요는 없지만, 경우에 따라 아주 일치하지 않는 개념이라는 점만 체크하시면 좋을 듯합니다.\r\n\r\n<h3>절세의 측면에서 눈여겨 볼 ‘1주택’의 개념</h3>\r\n한편, 연말정산에서 청약 통장 가입자를 대상으로 하는 소득공제 가능 여부와 그 대상 범위 역시 이번 부동산3법 개편 확정 이슈에서 우리가 ‘1세대 1주택’이라는 키워드에 주목해야 할 이유입니다. 왜냐하면 이 경우, 소득공제가 가능한 대상은 바로 ‘1주택자’이면서 동시에 ‘세대주’인 경우에 한하기 때문입니다. 정리하면 바로 ‘1세대 1주택’의 개념에 완전일치하는 경우입니다.\r\n\r\n예시를 들면, 부모와 자녀가 주택을 한 채씩 보유하고 있지만 등본상 세대 분리가 되어 있는 경우, 각각 1가구 1주택으로 실무에서는 취급하고 있습니다. 반면 부모와 자녀가 주택을 한 채씩 각자의 명의로 보유하고 있어도 등본상 세대가 분리되지 않은 경우, 세금을 부과할 때 우리 행정당국은 2주택 가구, 즉 다주택자로 간주하고 있는 것이 현실입니다.\r\n\r\n각각 단독 세대로 등본상 분리하기 위해서는 원칙상 기존 세대주의 집에서 나와 따로 살아야 하며, 설령 나와 산다고 하더라도 30세 미만의 미혼자녀라면 별도의 단독 세대주로 인정되기 어려운 점은 분명합니다. 결혼을 한 경우에도 당사자의 연령이 30세 미만일 경우, 기준중위소득 40% 이상의 소득을 보유하여 스스로 독립된 생활을 유지할 수 있다는걸 입증 가능해야 합니다.\r\n\r\n이와 관련, 같은 주소지에 거주하는 부모와 자식이 독립적으로 각각 등본상 단독세대주를 구성하는 것도 가능한가라는 의문이 들 수 있습니다. 이와 관련, 2018년에 행정안전부에서 출간한 주민등록 질의회신 사례집 문헌을 보면, “같은 집에 살더라도 생활하는 층이 다르거나 출입문이 분리되어 있다면, 세대분리가 가능하지만, 그렇지 않은 경우에는 세대분리를 할 수 없다.”라고 명백히 기재되어 있습니다. 따라서 아파트의 경우 사실상 세대 분리가 어렵다고 보는 것이 옳으며, 그에 따라 특정한 경우, 원룸의 명의를 얻어 세대분리하는 방식을 선택하기도 합니다. \r\n\r\n이와 같은 이유로 아파트보다는 2층 이상의 단독주택에 거주할 때, 주소가 같지만 생활하는 층이나 주출입문이 분리되어 있는 경우에 해당하므로 세대분리 가능성 측면에서 볼 때 더 유리하다고 볼 수 있습니다. 아울러 동일 주소지 거주자 간의 세대 분리는 각 지방자치단체가 실사를 통해 가능 여부를 판단하는 경우가 일반적이므로, 이 부분 또한 주의하시면 좋습니다.\r\n\r\n<엔딩>\r\n이상, 확정된 개정 부동산3법과 관련, 왜 1세대 1주택이라는 개념을 제대로 이해하는 것이 중요한지 부동산 실무 측면에서 소개했습니다. 핵심은 결국 청약과 절세라는 두 가지 포인트로 요약할 수 있을 텐데요, 이번 정리가 현장에서 진행하시는 실무에 도움이 되셨으면 좋겠습니다.\r\n',0);
INSERT INTO `article_tbl` VALUES (180924,1,18,'01091280586','2021-06-03','2021-06-03','2021-06-03','0000-00-00','개업공인중개사 온라인 광고 명시의무 위반 주의 필요','0','- 국토교통부 부동산 광고에 대한 SNS 기획조사 시행… 1,084건 지자체에 검증 및 과태료 부과 요청 -','kyj.jpg','- SNS 기획조사 시행… 1,084건 지자체에 검증 및 과태료 부과 요청 -\r\n\r\n□ 국토교통부(장관 노형욱)는 신고·접수된 광고를 대상으로한 기본 모니터링과 필요에 의한 수시모니터링의 결과, 기본모니터링에서 명시의무 위반이 420건, 부당한 표시·광고 금지 위반 304건, 광고주체 위반 55건 등의 위반이 있었다고 밝히고 있다.  이에 따라 국토교통부는 위반의심 광고로 분류된 1,084건에 대해서는 최종 검증을 거쳐 과태료를 부과하는 등 지자체에 법령 위반에 따른 조치를 요구할 예정이다.\r\n\r\n□ 결과에서 주목하여할 부분으로는 SNS의 경우, 조사대상 대비 위반의심 건수 비율(위반율)을 주요 부동산 광고플랫폼과 비교한 결과, SNS가 3배 이상 높은 것으로 나타났다. 이러한 이유로는 개업공인중개사들이 여전히 명시의무에 익숙하지 않음에 대한 반증으로 여겨진다. \r\n\r\n   <blockquote>* (SNS) 유튜브, 인터넷 카페(네이버·다음), 네이버블로그, 당근마켓(광고플랫폼) 네이버부동산, 다방, 직방, 피터팬의 좋은방 구하기, 부동산114</blockquote>',0);
INSERT INTO `article_tbl` VALUES (180925,1,31,'01053540675','2021-06-07','2021-06-07','0000-00-00','0000-00-00','[幸福家得]그 손님을 믿지 마세요','0','집과 사람을 잇는 사람인 공인중개사. 때문에 저절로 다양한 사람들을 만나게 되는 일이라고 하지요. 이번에는 (00에서 활동하시는) 김일숙 공인중개사가 직접 겪었다는, 참으로 영화 같은 이야기를 본지를 통해 소개하려고 합니다.','wellstream.jpg','“저는 몇 해 전에는 힐스테이트 단지 내에서 부동산을 운영하고 있었어요. 그떄 그 손님을 만났죠. 40대 중반쯤 되어 보이는 여성 손님이었어요.”\r\n\r\n범상치 않은, 그 손님과의 기억\r\n김일숙 공인중개사는 햇수가 꽤 지난 일이지만 아직도 그 손님을 잊지 못하는 이유에 대해 이렇게 이야기했습니다.\r\n\r\n“그 손님은 씀씀이가 참 좋은 분이었어요. 우연히 전화가 와서 그 손님을 알게 되었는데, 함께 온동네 물건을 다 보여드리고, 그 손님도 제 점심값을 챙겨 주는 등 여러 모로 훈훈한 분위기였어요. 초반에는요!”\r\n\r\n김 공인중개사는 “첫 만남부터 범상치 않았다”고 술회하며, 처음에는 가벼운 케이스라고 생각하고 3개만 수소문해서 보여드렸는데, 그 손님이 봉투에서 수표를 꺼내서 제게 보여줬죠. 얼핏 보니까 4천만 원은 되어 보였어요.”라고 말하며, “절대 이 손님을 놓치면 안 되겠다”는 생각이 바짝 들었다고 말했습니다.\r\n\r\n손님의 반응도 호의적이여서, 거래는 빠르게 진행이 됐다고 김일숙 공인중개사는 기억했습니다. 그렇게 익일 11시에 매도인과 만나서 계약서를 작성하는 것까지 이야기가 흘렀고, 계약금 중 일부인 500만원을 매도인 계좌로 입금하는 절차에 들어간 상황! 그런데 저녁 퇴근 시간이 다 되어가도록 돈을 입금했다는 소식을 매도인에게 받지 못했다고 합니다. 김일숙 공인중개사는 “전화했더니 금방 보낸다는 말만 하고… 이후 저녁 9시가 넘어가도록 전화를 받지 않았죠. 돈이 없느냐고까지 물었는데, 내일 11시에 만나서 다 주겠다고 하더군요.”라고 그때 기억을 떠올리며, 어쩔 수 없다는 생각에 다음날 출근해서 매도인도 사무실에 오시라고 말씀드려 매도인까지 10시 30분부터 나와 그 정체불명의 손님믈 기다리고 있었다는 말도 보탰습니다.\r\n\r\n불안한 예감은 언제나 틀리지 않는 것\r\n전화가 느닷없이 왔는데, 그 손님이었어요. 회사에 급한 일이 생겼다면서 내일 1시로 미루자고 하더군요. 매도인도 좀 어이없어 하긴 했는데, 일단은 그럴수 있다고 생각하고 하루가 지났어요. 약속 시간인 1시간 되가도록 전화를 받지 않더군요. 한 시간 가까이 지날 때까지 매수자가 나타나지 않으니., 매도인은 지쳐서 집으로 돌아가고, 저는 너무 화가 나서 참을 수가 없었죠. “누굴 갖고 노는 것도 아니고!” 그래서 한 시간 내내 계속 전화를 걸었다는 김 공인중개사. \r\n\r\n이윽고 그로부터 한 시간이 더 지나서 매수자가 전화를 했는데, 아니나 다를까 또 핑계를 대면서 내일 하면 안 되냐고 또 미루려고 했단다. 더는 물러설 수 없다고 판단한 김일술 공인중개사는 그 순간, 기지를 발휘해 매수자를 설득했다. “매도인이 호주 분이어서 내일 호주로 돌아가세요. 그러지 말고 오늘 저녁에 하시는 수밖에 없겠는데요.” 이렇듯 순발력을 발휘한 김 공인중개사의 센스로 잠수 괴담이 될 뻔한 힐스테이트 거래 케이스는 무사히 계약서 작성과 잔금 지급까지 이뤄질 있었다고 합니다. 잔금 치르고, 등기까지 완료! 하지만 그동안 당한 억울함 때문인지, 그 상황에서도 얼떨떨하기만 했다며 김일숙 공인중개사는 웃었습니다.\r\n\r\n“아직도 그 손님의 정체를 모르겠어요.”라고 이야기하는 김일숙 공인중개사. 힘든 가운데 미소를 잃지 않는 그녀의 멋진 행동이 잠수 거래 파투라는 위험을 물리친 것은 아닐까 생각이 드네요.\r\n',0);
INSERT INTO `article_tbl` VALUES (180926,1,32,'01090544679','2021-06-18','2021-07-17','2021-08-18','0000-00-00','모든 주택임대사업자 보증가입 의무 본격시행 (2021년 8월 18일)','0','등록임대주택에 대한 임대보증금 가입의무화가 20.8.18일 시행되었다. 기존 임대주택사업자는 1년 유예기간인 21.8.17일로 종료되면서 모든 주택임대사업자 보증가입 의무가 본격시행을 앞두고 관련 규정을 살펴보고  2021년 12월 31일까지 적용되는 보증료 인하에 대해 알아보기로 한다. ','yms2.jpg','1. 임대주택에 보증보험 가입의무가 21.8.17일 1년의 유예기간를 종료\r\n\r\n임대주택에 보증보험 가입의무가 21.8.17일 1년의 유예기간를 종료를 앞두고 최근 공인중개사 사무실에는 이에 대한 문의가 증가하고 있다.  보증보험 가입의무화는 최근 전세보증금의 급격한 증액으로 인해 우려되는 임대보증금 미반환 방지를 위해 민간임대주택에 관한 특별법 제49조(임대보증금에 대한 보증)에 따른 조치였다.  \r\n\r\n2. 대상\r\n2021년 8월 18일 부터 새로운 계약, 연장계약, 묵시적 갱신 모두 보증가입 의무이다. \r\n\r\n3. 보증금액\r\n가. 원칙 > 임대보증금 전액 \r\n나. 임대사업자가 사용 검사 전에 임차인을 모집하는 경우에는 임차인을 모집하는 날부터 사용검사를 받는 날까지의 보증대상액은 임대보증금 중 사용검사 이후 납부하는 임대보증금을 제외한 금액\r\n다. 담보권이 설정된 금액과 임대보증금을 합한 금액에서 주택가격의 100분의 60에 해당하는 금액을 뺀 금액 이상으로 대통령령에서 정하는 금액\r\n\r\n<blockquote>민간임대주택에 대한 특별법 제49조(임대보증금에 대한 보증) ① 주택임대관리업을 하려는 자는 시장ㆍ군수ㆍ구청장에게 등록할 수 있다. 다만, 100호 이상의 범위에서 대통령령으로 정하는 규모 이상으로 주택임대관리업을 하려는 자[국가, 지방자치단체, 「공공기관의 운영에 관한 법률」 제4조제1항에 따른 공공기관(이하 “공공기관”이라 한다), 「지방공기업법」 제49조제1항에 따라 설립된 지방공사(이하 “지방공사”라 한다)는 제외한다]는 등록하여야 한다.\r\n\r\n② 제1항에 따른 보증에 가입하는 경우 보증대상은 임대보증금 전액으로 한다. 다만, 임대사업자가 사용검사 전에 임차인을 모집하는 경우 임차인을 모집하는 날부터 사용검사를 받는 날까지의 보증대상액은 임대보증금 중 사용검사 이후 납부하는 임대보증금을 제외한 금액으로 한다.  <개정 2017. 1. 17.>\r\n\r\n③ 제2항에도 불구하고 다음 각 호에 모두 해당하는 경우에는 담보권이 설정된 금액과 임대보증금을 합한 금액에서 주택가격의 100분의 60에 해당하는 금액을 뺀 금액 이상으로 대통령령에서 정하는 금액을 보증대상으로 할 수 있다. 이 경우 주택가격의 산정방법은 대통령령으로 정한다.  <개정 2019. 4. 23.>\r\n\r\n1. 근저당권이 세대별로 분리된 경우(근저당권이 주택단지에 설정된 경우에는 근저당권의 공동담보를 해제하고, 채권최고액을 감액하는 근저당권 변경등기의 방법으로 할 수 있다)\r\n\r\n2. 임대사업자가 임대보증금보다 선순위인 제한물권(다만, 제1호에 따라 세대별로 분리된 근저당권은 제외한다), 압류ㆍ가압류ㆍ가처분 등을 해소한 경우\r\n\r\n3. 임차인이 전세권설정을 요구하고 임대사업자가 이에 동의하여 전세권이 설정된 경우\r\n\r\n4. 그 밖에 제1호에서 제3호까지에 준하는 경우로서 대통령령으로 정하는 경우\r\n\r\n④ 제1항에 따른 보증의 가입기간은 다음 각 호의 시점부터 임대의무기간이 종료되는 날(임대의무기간이 종료되는 날에 임대 중인 경우에는 임대차계약이 종료되는 날로 한다)까지로 한다. 이 경우 임대사업자는 제1항에 따른 보증의 수수료를 1년 단위로 재산정하여 분할납부할 수 있다.  <개정 2017. 1. 17., 2019. 4. 23., 2020. 8. 18.>\r\n\r\n1. 제1항제1호 및 제2호에 해당하는 민간임대주택: 사용검사를 받은 날(사용검사 전에 임차인을 모집하는 경우에는 그 날을 말한다)\r\n\r\n2. 제1호 이외의 민간임대주택 중 등록일에 존속 중인 임대차계약이 있는 경우: 민간임대주택 등록일\r\n\r\n3. 제1호 이외의 민간임대주택 중 등록일에 존속 중인 임대차계약이 없는 경우: 민간임대주택 등록일 이후 최초 임대차계약 개시일\r\n\r\n⑤ 제1항에 따른 보증에 가입한 임대사업자가 가입 후 1년이 지났으나 제4항에 따라 재산정한 보증수수료를 보증회사에 납부하지 아니하는 경우에는 보증회사는 그 보증계약을 해지할 수 있다. 다만, 임차인이 보증수수료를 납부하는 경우에는 그러하지 아니하다.\r\n\r\n⑥ 제5항에 따라 보증회사가 보증계약을 해지하는 경우 보증회사는 보증계약 해지 사실을 시장ㆍ군수ㆍ구청장에게 알려야 한다.  <신설 2020. 8. 18.>\r\n\r\n⑦ 제1항에 따른 보증에 가입하는 경우 보증수수료의 납부방법, 소요 비용의 부담비율, 보증대상 임대보증금의 범위, 보증의 가입ㆍ유지ㆍ탈퇴 등에 필요한 사항은 대통령령으로 정한다.  <개정 2020. 8. 18.></blockquote>\r\n\r\n\r\n이에 따라 보증보험은 1년마다 갱신하며 임대인 : 임차인 = 3 (75%) : 1 (25%)의 비율로 부담하게 되며 보증료는 임대인이 납부 후 임차인에게 청구하게 된다. \r\n\r\nLH전세 임차인의 경우 보증보험 가입 면제이며 대신 표준계약서를 LH와 작성하여야 한다. \r\n\r\n4. 주택가정의 산정방법 \r\n보증보험가입시 주택가격의 산정방법은 다음과 같다. \r\n\r\n<blockquote>민간임대주택에 대한 특별법 시행령  제39조(보증대상액) ① 법 제49조제3항 각 호 외의 부분 전단에서 “대통령령에서 정하는 금액”이란 담보권이 설정된 금액과 임대보증금을 합한 금액에서 주택가격의 100분의 60에 해당하는 금액을 뺀 금액을 말한다.\r\n\r\n  ② 법 제49조제3항 각 호 외의 부분 후단에 따른 주택가격의 산정방법은 다음 각 호의 어느 하나에 해당하는 방법으로 한다.  <개정 2020. 12. 8.>\r\n\r\n  1. 감정평가법인등이 「감정평가 및 감정평가사에 관한 법률」 제3조에 따라 감정평가액을 산정하는 방법\r\n\r\n  2. 「부동산 가격공시에 관한 법률」 제16조부터 제18조까지의 규정에 따라 공시된 가격(준주택의 경우에는 「소득세법」 제99조제1항제1호다목에 따른 기준시가를 말한다)에 국토교통부장관이 정하여 고시하는 비율을 곱하여 산정하는 방법\r\n[전문개정 2019. 10. 22.]</blockquote>\r\n\r\n공시가격 및 기준시가 적용비율을 살펴보면 부동산 가격공시에 관한 법률 제 16조부터 18조까지의 규저에 따라 공시된 가액에 따라 공동주택과 단독주택의 구분하여 금액별로 최저 130%에서 150%의 비율을 적용하여 산정한다. \r\n\r\n공시가격 및 기준시가 적용비율을 살펴보면 부동산 가격공시에 관한 법률 제 16조부터 18조까지의 규저에 따라 공시된 가액에 따라 공동주택의 경우 9억원 미만은 130% 9억이상 15억 미만은 130% 15억원이상은 120%를 단독주택의 경우 9억원 미만은 170% 9억이상 15억 미만은 160% 15억원이상은 150%을 적용하고 있다. \r\n\r\n소득세법 제99조제1항제1호다목에 따라 국세청장이 매년 산정고시하는 기준인 경우 적용비율 :120%를 적용하게 된다. ',0);
INSERT INTO `article_tbl` VALUES (180928,1,32,'01090544679','2021-06-18','0000-00-00','2020-12-10','0000-00-00','민간임대주택의 부기등기','0','',NULL,'최근 개업공인중개사사무소에는 민간임대주택의 부기등기에 대한 문의가 증가하고 있다.  먼저 민간임대주택 부기등기 2020년12월10일(목) 시행되었으며 이전의 임대주택은 2년간의 유예 기간을 부여하고 신규등록하는 임대주택은 등록과 동시에 부기등기를 하여야 한다. \r\n\r\n<blockquote>민간임대주택에 대한 특별법 시행령 제5조의2(등록 민간임대주택의 부기등기) ① 임대사업자는 제5조에 따라 등록한 민간임대주택이 제43조에 따른 임대의무기간과 제44조에 따른 임대료 증액기준을 준수하여야 하는 재산임을 소유권등기에 부기등기(附記登記)하여야 한다.[본조신설 2020.6.9]</blockquote>\r\n\r\n임대주택의 부기등기는 2021년 3월 12일(금)부터 전자신청도 가능하다. 개인의 경우를 가정하고 그 절차를 살펴보면 먼저 전자신청 시 사전 준비사항으로 먼저 인증서(범용, 용도제한용 불문)가 준비되어야 하며 인증서가 준비되었다면 전국 등기과(소) 어디서나 사용자등록신청이 직접 방문하여 접근번호를 취득하여 10일이내 대법원인터넷등기소를 방문하여 자신의 인증서와 접근번호를 이용하여 사용자등록번호를 만들면 비로소 절차가 완성된다. 자세한 내용은 대법원인터넷등기소를 통하여 확인할 수 있다. \r\n',0);
INSERT INTO `article_tbl` VALUES (180929,0,31,'01091280586','2021-06-24','2021-07-17','0000-00-00','0000-00-00','공인중개사 소식지 \'터\' 발간사','0','공인중개사가 전하는 부동산 소식의 터전, 공인중개사 소식지 터가 인터넷 신문으로 새롭게 시작합니다. ','sharethumb.jpg','공인중개사가 전하는 부동산 소식의 터전\r\n- 공인중개사 소식지 터\r\n\r\n우리가 일상적으로 말하는 ‘터\'란 단순히 땅이나 집으로 구분하는 것과는 또 다른 의미를 담고 있습니다. 터는 삶을 담고 있는 자리이죠. 다시 말해서, 우리 일상을 품고 있는 있는 자리이기도 합니다. 따라서 ‘공인중개사 소식지 터’란 이름에는 공인중개사의 삶과 일상을 담는 자리가 되자는 의미를 함축하고 있습니다.\r\n\r\n최근 공인중개사의 중개보수에 대한 논란이 뜨겁습니다. 사실 그 이야기의 대부분이 뭘하는데 그렇게 많이 받느냐고 묻습니다. 하지만 우리는 알고 있죠, 분명 뭔가를 하고 있다는 사실을요. 계약서를 작성하는 일 외에도 여러 중요한 절차들을 진행하죠. 그러나 그 대부분의 일은 세간에 결코 보여지지 않는다는 것이 가장 큰 문제입니다. 과거의 세상은 이에 대한 묵시적으로 수긍했다면, 오늘은 다릅니다. 고객들은 우리에게 확실하게 납득할 근거를 요구합니다.\r\n따라서, 고객과 소통하고 우리의 정당한 노력을 알리기 위해 터가 있는 것입니다.\r\n\r\n여러분, 부동산 뉴스처럼 어지러운 세상도 아마 드물 것입니다. 그 가운데 우리의 터는, 가장 정확한 사실만을 전해야 합니다. 과거의 정보가 현재와 섞여있고 미래에 대한 정보가 현재와 섞여있는 곳이 바로 이 부동산 시장입니다. 법과 정책이 매번 시시각각 변하면서 과거에는 널리 통용됐던 사실이 다른 취급을 받기도 하며, 아직 논의 중인 내용조차 기정사실처럼 전달되어지고 있지요. 문제는, 이에 대한 사후 확인의 수단이 공인중개사의 입장에서 볼 때, 심히 부족하다는 데 있습니다. 따라서, 우리 공인중개사 소식지 터는 부동산 뉴스에 있어서 여타 매체처럼 이슈가 아닌 근거와 계속적인 추적을 통해 얻은 정확한 팩트만 말해주는 뉴스로 거듭날 것입니다.\r\n\r\n나아가, 우리는 공인중개사의 권익 지킴이가 되겠습니다. 신속한 정보전달을 통해 부당한 행정처분을 예방하고 부당한 사례에 대해서는 항변하며, 그 사례를 공유하고 그에 따른 대응을 함께 고민하는 공간이 되겠습니다. 중개업이 공인중개사 업무의 핵심이라는 데는 이견이 없을 줄로 압니다. 그에 대한 위협을 논하는 데, 중립이란 있을 수 없습니다. 따라서 우리는 공인중개사를 위한 당당한 편향과 옹호를 강조하며, 이것이 곧 터의 일이 될 것입니다.\r\n\r\n공인중개사소식지 터는 2021년 6월 14일 인터넷신문등록번호 : 서울 아53763 인터넷 소식지터로 문을 열고자 합니다. 지지와 응원을 보내주신 모든 분들께 감사합니다.\r\n\r\n발행편집인 :\r\n  조항준\r\n편집/논설위원 : \r\n  김민주 양미숙 김경희 김일숙\r\n지분(₩21,780,000/50,000,000)참여 명단(참여순)\r\n  1. 문찬호 2. 손희균 3. 김효진 4. 최보경 5. 주진규 6. 박수연 7. 김경희 8. 고순영 9. 곽윤정 10. 오규연 11. 김일숙 12. 정미애 13. 양맹숙\r\n',0);
INSERT INTO `article_tbl` VALUES (180930,1,32,'01090544679','2021-06-26','2021-06-26','0000-00-00','0000-00-00','대구 북구청 공인중개사 개인정보 침해 위법 논란','0','행정처분을 당했다는 사실은 누구라도 만천하에 공개하고 싶지 않은 정보에 해당한다.\r\n특히 공인중개사는 그 지역에서의 평판이나 입소문에 따라 많은 부분 경제적 생계를 의지하고 있는 실정이다. 그런 공인중개사가 관(官)에 의해 과태료 처분을 받은 사실 등이 고지된다면, 이는 개업공인중개사에게 회복할 수 없는 경제적 손실으로 이어질 것이 분명하다.\r\n이와 관련해서, 공인중개사법률소비조합(REUni)은 최근 대구 북구청이 가한 개인정보침해 사례를 확인하고 그에 대한 법적조치를 예고하고 있다',NULL,'당사자가 굳이 공인중개사가 아니어도 분명하다. 행정처분을 당했다는 사실은 누구라도 만천하에 공개하고 싶지 않은 정보일 수밖에 없다. 비록 길을 걷다 침을 뱉어 과태료를 냈다는 아주 사소한 경우라도, 자신이 이전에 과태료 처분을 받았다는 내용을 인터넷에 공개되는 것을 원하는 사람은 없을 것이다.\r\n\r\n이렇듯 개인정보를 중시하는 사회적 변화에 따라, 근래의 공공기관 역시도 개인정보 침해가 발생하지 않도록 주의를 기울이고 있다.\r\n\r\n특히 공인중개사는 그 지역에서의 평판이나 입소문에 따라 많은 부분 경제적 생계를 의지하고 있는 실정이다. 그런 공인중개사가 관(官)에 의해 과태료 처분을 받은 사실 등이 고지된다면, 이는 개업공인중개사에게 회복할 수 없는 경제적 손실으로 이어질 것이 분명하다.\r\n\r\n게다가 그 처분사유 등을 업소명과 등록번호, 주소와 함께 공표한다는 것 또한 법리상 문제가 될 소지가 다분하다. 바로 개인정보보호법에서 규정하는 개인에 대한 \'특정성\' 문제다.\r\n\r\n<blockquote>개인정보보호법 제2조(정의) 이 법에서 사용하는 용어의 뜻은 다음과 같다.  <개정 2014. 3. 24., 2020. 2. 4.>\r\n\r\n1. “개인정보”란 살아 있는 개인에 관한 정보로서 다음 각 목의 어느 하나에 해당하는 정보를 말한다.\r\n\r\n가. 성명, 주민등록번호 및 영상 등을 통하여 개인을 알아볼 수 있는 정보\r\n\r\n나. 해당 정보만으로는 특정 개인을 알아볼 수 없더라도 다른 정보와 쉽게 결합하여 알아볼 수 있는 정보. 이 경우 쉽게 결합할 수 있는지 여부는 다른 정보의 입수 가능성 등 개인을 알아보는 데 소요되는 시간, 비용, 기술 등을 합리적으로 고려하여야 한다.\r\n\r\n다. 가목 또는 나목을 제1호의2에 따라 가명처리함으로써 원래의 상태로 복원하기 위한 추가 정보의 사용ㆍ결합 없이는 특정 개인을 알아볼 수 없는 정보(이하 “가명정보”라 한다)</blockquote>\r\n\r\n이와 관련해서, 공인중개사법률소비조합(http://cafe.naver.com/reisis)은 최근 대구 북구청이 가한 심각한 개인정보침해 사례를 확인하고 그에 대한 법적조치를 예고하고 있다.\r\n\r\n대구 북구청은 2016년12월20일부터 2021년 4월 15일까지 200여건에 달하는 수많은 공인중개사의 행정처분 내역을 현재 구청 누리집에 공개하고 있다. 문제는 공개된 정보의 범위다. 해당 사례는 공인중개사의 등록번호, 업소명, 소재지, 처분내용, 처분일자를 포함하고 있어 읽는 이가 당사자를 특정할 수 있는 소지가 있다. 게다가 공개된 행정처분의 내용은 등록취소, 업무정지, 과태료 처분 일체를 포함하고 있어 그 피해는 더욱 우려된다.\r\n\r\n조합에서는 앞서 대구 북구청 정보공개담당자(이상효 053.665.2240)와의 통화를 여러 번 시도하였으며, 이를 토대로 확인한 쟁점은 \'국민의 재산권 보호\'라는 공익적 측면에서 공개의 이익이 존재한다는 주장과 해당 시스템을 사용하는 타 행정기관 역시 같은 범위로 정보를 공개하고 있다는 것이었다. 이에 조합에서 추가로 내용을 확인한 결과, 현재까지 북구청 외에 대구 동구청이 이러한 정보공개를 고수하고 있는 사실을 밝혀낼 수 있었다.\r\n\r\n물론, 대구 북구청 담당자의 주장대로 위 내용을 공개함으로써 얻을 수 있는 재산권과 관련된 이익이 존재할 수도 있다.\r\n\r\n하지만 모든 범죄자의 신상을 공개하여 그로 인해 발생할 수 있는 범죄의 억제나 범죄예방의 기대효과가 있을 것이라고 해도, 현재 우리 법은 그것을 엄격하게 금지하고, 공개를 위해서는 엄격한 절차를 거쳐야 한다고 규정하고 있다. 보호할 공익에 비해 신상이 공개된 개인이 입게 되는 피해 등 문제가 더 크다고 보기 때문이다.\r\n\r\n이러한 점을 염두한다면, 단순히 행정처분을 받았기 때문에 내지는 그 영업을 위한 상호 등이기 때문에 괜찮다는 북구청의 답변은 일견 타당해 보이지 않는다. 더군다나 그 정보공개의 구체적 내용을 보면, 사망 등에 의한 등록취소까지 포함하고 있어 심히 염려된다.\r\n\r\n특히 우리 법이 종래 개인정보 공개 등에 까다로운 절차를 두는 데는 바로 법의 테두리를 벗어난 이중처벌의 가능성이 존재할 수 있기 때문이다. 그러나 현재 대구 북구청의 경우는 2016년부터 공개되고 있었고 대구 동구청의 경우는 2013년부터의 행정처분을 공개하고 있다. 이는 행정처분의 경과 후에도 당사자에게 처벌과 사회적 낙인 효과가 계속되어질 수 있어 문제가 된다.\r\n\r\n타 지자체의 사례를 보면 문제는 더욱 명확해진다. 대구 북구청과 동일 사안에 대해 서울시는 정보공개법 제9조 1항 5호 6호를 근거로 비공개결정을 내리고 있으며, 안동시청은 부동산중개업 행정처분대상 업소명 및 인적사항을 비공개 대상으로 적시하고 이 있다.\r\n<blockquote>공공기관의 정보공개에 관한 법률 제9조(비공개 대상 정보) ① 공공기관이 보유ㆍ관리하는 정보는 공개 대상이 된다. 다만, 다음 각 호의 어느 하나에 해당하는 정보는 공개하지 아니할 수 있다.  <개정 2020. 12. 22.>\r\n<생략> \r\n        6. 해당 정보에 포함되어 있는 성명ㆍ주민등록번호 등 「개인정보 보호법」 제2조제1호에 따른 개인정보로서 공개될 경우 사생활의 비밀 또는 자유를 침해할 우려가 있다고 인정되는 정보. 다만, 다음 각 목에 열거한 사항은 제외한다.\r\n \r\n        가. 법령에서 정하는 바에 따라 열람할 수 있는 정보\r\n \r\n        나. 공공기관이 공표를 목적으로 작성하거나 취득한 정보로서 사생활의 비밀 또는 자유를 부당하게 침해하지 아니하는 정보\r\n \r\n        다. 공공기관이 작성하거나 취득한 정보로서 공개하는 것이 공익이나 개인의 권리 구제를 위하여 필요하다고 인정되는 정보\r\n \r\n        라. 직무를 수행한 공무원의 성명ㆍ직위\r\n \r\n        마. 공개하는 것이 공익을 위하여 필요한 경우로서 법령에 따라 국가 또는 지방자치단체가 업무의 일부를 위탁 또는 위촉한 개인의 성명ㆍ직업\r\n</blockquote>\r\n\r\n또한, 해당사안에 대해 공인중개사법률소비조합(REUni) 자문변호사인 오빛나라변호사는 \'식품위생법이나 공중위생관리법, 석유및 석유대체연료사업법 같은 경우에는 위반사실 공표에 대해 법에서 명시적으로 규정하고 있는데, 부동산중개업은 법령의 규정이 없는데 공표하는 것이어서 문제가 있다\'는 의견을 제시하기도 했다.\r\n\r\n<엔딩>\r\n개업공인중개사의 등록번호는 우리나라의 성인남녀라면 누구나 갖고 있는 주민등록번호와 마찬가지로 고유번호의 성격을 지닌다.\r\n\r\n그 상호 또한 동일한 행정동에서 같은 이름이 존재할 수 없게끔 (내부준칙/내규/법률)으로 규정되어 있다. 이렇듯 상당 수준의 고유성을 띤 등록번호와 상호가 해당 사무실의 실주소와 함께 공개되어진다면? 1인 사무실이 대부분인 공인중개사 업장의 특성상 이는 명확히 개인을 특정할 수 있는 충분한 정보라고 볼 수 있지 않을까? 행정청의 엄중한 판단을 바란다.',0);
INSERT INTO `article_tbl` VALUES (180940,1,32,'01091280586','2021-07-01','0000-00-00','2021-07-01','0000-00-00','2021년 하반기(7.1) 부터 달라지는 것','0','2021년 하반기(7.1) 부터 달라지는 것',NULL,'2021년 하반기(7.1) 부터 달라지는 것\r\n\r\n* 공시가격 6억원 이하 1주택자에 대한 재산세율 인하 행정안전부 부동산세제과 (☎ 044-205-3840)\r\n올해부터 공시가격 6억원 이하 1세대 1주택자는 주택 재산세 세율이 0.05%p 인하됩니다.\r\n(’21.7월·9월 부과)\r\n\r\n공동주택 중 재산세 특례세율이 적용되는 공시가격 6억원 이하 주택은 전체의 92.1%인 1308만 8000호, 서울은 70.6%인 182만 5000호가 해당한다. [출처] 대한민국 정책브리핑(www.korea.kr)\r\n\r\n• 추진배경 「부동산 공시가격 현실화 계획」 발표(국토부, ’20.11월)와 함께 서민·실수요자에 대한 세부담은 완화 추진\r\n• 주요내용 공시가격 6억원 이하 1세대 1주택자인 경우에는 재산세 세율을 0.05% 인하\r\n\r\n• 시행일 2021년 1월 1일 (재산세 부과는 7·9월)\r\n\r\n서민·실수요자 주택담보대출\r\n우대요건 완화 및 우대혜택 확대\r\n금융위원회 금융정책과 (☎ 02-2100-2836 / 2824)\r\n2021년 7월 1일부터 주택담보대출 우대혜택(무주택자 대상)을 받을 수 있는 요건이 완화되고,\r\n우대혜택도 확대됩니다.\r\n▣▣소득기준 : 부부합산 소득기준이 8천만원 이하에서 9천만원 이하로 상향됩니다.(생애최초구입자는\r\n9천만원 이하에서 1억원 미만)\r\n▣▣가격기준 : 투기과열지구의 경우 6억원 이하에서 9억원 이하로, 조정대상지역은 5억원 이하에서\r\n8억원 이하로 완화됩니다.\r\n▣▣우대혜택 : 위 요건을 충족하는 경우 받을 수 있는 LTV 우대 혜택이 기존 10%p에서 최대 20%p로 확대됩니다.(4억원 한도 이내)',0);
INSERT INTO `article_tbl` VALUES (180941,1,31,'01063060523','2021-07-09','2021-07-09','0000-00-00','0000-00-00','[幸福家得] 조금 좁아도 따뜻한 방처럼 “자꾸 마음이 가는 사람들” ','0','개업공인중개사가 긴 노력의 결과로서 계약서 외의 많은 부분이 특별한 경우가 아니라면 드러나지 않음을 원망할 수는 없다.  하지만 그것이 계약서 쓰는 것 외에 무슨 일을 하느냐고 매도 당한다면 분명 억울한 일이다.  개업공인중개사로서 살아가며 겪게 되는 우리의 일상을 공유하며 그 전부는 아니지만 지금보다 조금 더 우리를 보여줄 수 있기를 기대해본다. [공인중개사소식지 터]',NULL,'[기고=위브파크공인중개사사무소 | 김민주] 부동산 공인중개사무소를 운영한 지도 벌써 12년. 근래 깨달은 한 가지가 사실이 있다. 좋은 집에 살아야 행복한 사람이 되는 게 아니라, 행복한 사람이 좋은 집에 살게 된다는 것이다.\r\n\r\n요즘은 코로나 때문인지 유난히 예민한 고객들이 많다. 같은 입장에서 충분히 이해가 가지만, 때론 날이 선 목소리에 나 또한 마음이 냉랭해진다. 그래서 그럴까. 개업 시절에 만났던 참 따뜻한 신혼부부 한 쌍이 떠오른다.\r\n\r\n지난 2008년 10월 공인중개사 자격을 취득해 가까스로 사무실을 마련했다. 늦은 밤까지 구슬땀을 흘려가며 열심히 공부했고, 다행히 합격 통보를 받았다. 정말 뿌듯한 순간이었다.\r\n\r\n개업의 설렘으로 내부 인테리어를 고민하던 어느 날, 한 젊은 부부가 찾아왔다. 부부는 사무실 근처의 재래시장에서 과일가게를 하고 싶어 했다. 투박하지만 성실한 인상의 남편과 지적이고 예쁜 아내. 참 잘 어울리는 한 쌍이었다. \r\n\r\n근처 부동산에 연락해 원하는 조건과 유사한 매물을 보여주었다. 부부는 거듭 “감사하다”며  밝은 미소와 함께 원하는 위치, 예상금액, 면적을 남기고 발길을 돌렸다. 밝고 인사성 바른 두 사람의 모습에 나 또한 괜히 기분이 좋았다.\r\n\r\n며칠 후 꼭 맞는 물건이 나와서 부부에게 연락했다. 부부는 “정말 자신들이 찾던 공간”이라며 “권리금이랑 월세도 적당하고 상가 사이에 있어 공간도 넓네요. 정말 감사합니다. 이렇게 마음을 써주시다니 꼭 보답할게요”라며 인사를 건넸다. \r\n\r\n얼마 후 개업식날, 나는 부부에게 와서 떡이라도 먹고 가라고 초대했다. 부부는 당일은 시간이 되지 않아 못 왔지만 며칠 후 개업 축하 선물이라며 예쁜 시계를 선물해왔다. 너무 감사한 마음이었다. \r\n\r\n그 이후로도 나는 부부가 잘 있는지 신경이 쓰여 괜히 가게를 살펴보았다. 공동중개를 해서 인사치레가 필요할 때는 부부네 가게에서 수박을 사서 선물했고, 주변에도 “여기 과일이 참 싱싱하고 맛있다”며 소개했다. 내 속엔 부부가 진심으로 잘 됐으면 좋겠다는 마음뿐이었다. \r\n\r\n부부는 금슬이 참 좋았고 둘 다 아주 성실했다. 처음엔 가게 근처에 반지하 월세방에 살다가 2년 뒤 둘째를 가지고 지상1층 전세로 이사를 했다. 그리고 최근엔 나홀로 아파트로 옮겼다고 한다. 괜히 내가 다 뿌듯했다. 얼마 전 가게에 들르니 부부는 “아파트를 보려고 사무실에 들렀는데 내가 없었다”며 아쉬운 마음을 전했다. 나는 괜찮다며, 진심으로 축하를 건넸다. \r\n\r\n부부는 아이들이 크기 전에 돈을 좀 모아서 상가주택을 하나 사고 싶다고 했다. 나는 꼭 그렇게 될 거라고 했다. 하나하나씩 모아 성실히 가정을 이뤄나가는 모습이 요즘 젊은부부 같지 않으니 두 사람은 꼭 할 수 있을 거라고…\r\n\r\n지금도 가끔 과일을 사러 부부의 가게에 들르면, 두 사람은 여전히 따뜻한 미소로 인사를 건넨다.\r\n\r\n개업 후 첫 인연이었던 사람들. 부부는 시간이 지나도, 여전히 마음이 가는 그런 사람들이었다. 좁은 방에 있어도 늘 서로에게 따뜻함을 줄 수 있는 그런 사람. 나도 늘 그런 사람이고 싶다. \r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n \r\n\r\n\r\n \r\n',0);
INSERT INTO `article_tbl` VALUES (180942,1,31,'01022890629','2021-07-12','2021-07-12','0000-00-00','0000-00-00','[人터VIEW] 신촌 문찬호 공인중개사 대표 인터뷰','0','같은 이름이지만 같지 않은 이름이 있다. 개업공인중개사라는 이름으로 하나이지만 부동산이란 이름이 담고 있는 것은 사람이 딛고 선 모든 것이며, 결국 그 모든 것은 또한 그 위의 사람으로 인하여 의미를 가진다.  그 모든 세상과 그 위의 모든 사람을 연결하는 개업공인중개사인 그들을 향해 묻습니다.  당신이 궁금합니다. ',NULL,'<div class=\"interview_wrap\">		<p class=\"tit\"><strong>[부동산-In]</strong> #1 문찬호 공인중개사 대표 인터뷰<br></p>	<div class=\"top_img\">		<div class=\"itvw_img\"><img src=\"http://www.reuni.kr/img/interview/mch_01.jpg\" alt=\"문찬호 공인중개사\"></div>		<ul>			<li class=\"a\">문찬호 부동산, 공인중개사 문찬호 대표</li>		\r\n	<li>미래 예측 가능한 부동산 정책 시급… 변동 불안 커 </li>			<li>공실률이 30%가까운 신촌‧이대 상가</li>			<li>직방 등 IT기반 부동산 플랫폼 시장 진입에 ‘불안’ 가중 </li>		</ul>	</div>		<div class=\"itvw_img\">		<img src=\"http://www.reuni.kr/img/interview/mch_02.jpg\" alt=\"문찬호 공인중개사 \">		<span class=\"source\">사진=문찬호부동산공인중개사</span>		</div>	<p class=\"txt1\">지난해 코로나 사태 이후로 대한민국의 뜨거운 감자로 떠오른 ‘부동산 폭등’. 사상 초유의 경제난과 함께 세간에 계속 오르내렸던 ‘부동산’은 부동산 정책 실패, LH투기와 같은 키워드와 함께 국민들의 불안을 가중시켰다.</p>	<p class=\"txt1\">하늘 높은 줄 모르고 치솟은 부동산 가격에 ‘내 집 마련’은 이생에서 불가능한 일이 되어버렸고, 많은 투자자본은 주식‧가상화폐와 같은 시장으로 이동하고 있다. </p>	<p class=\"txt1\">문제는 이 순간에도 ‘부동산 폭등’은 멈추지 않고 있다는 사실이다. 이에 청년층, 빈곤층, 소상공인들의 부동산에 대한 부담은 계속 가중되고 있다. 부동산은 언제까지 오를까? 만약 언젠가 폭락하고 만다면? 그리고 이 부동산 문제는 우리의 사회를 어떻게 변화시킬까?</p>	<p class=\"txt1\">누구보다 가까이서 그 현실을 몸소 느끼는 이들이 있다. 바로 공인중개사무소를 운영하는 ‘공인중개사’분들이다. </p>	<p class=\"txt1\">본 기자는 이 나라의 다이나믹한 부동산 문제를 탐구하기 위해, 임차인과 임대인을 연결해주는 가교의 역할을 하는 ‘공인중개사무소’의 대표들을 만나 보았다.</p>	<p class=\"txt1\">첫 인터뷰는 최근 코로나19의 직격타를 받은 신촌‧이대에 위치한 ‘문찬호 공인중개사사무소(부동산법률소비조합 소속)’의 문찬호 대표님과 함께 했다. <br><br></p>		<div class=\"itvw_img\">		<img src=\"http://www.reuni.kr/img/interview/mch_03.jpg\" alt=\"문찬호 공인중개사 \">		<span class=\"source\">사진=문찬호부동산공인중개사 문찬호 대표</span>		</div>	<dl class=\"qna\">		<dt><span>Q.</span> 본인 소개 부탁드립니다. </dt>		<dd>안녕하세요. <br>저는 이대‧신촌에서 오피스텔, 원룸, 상가 등을 중개하고 있는 ‘문찬호부동산공인중개사사무소’의 문찬호 대표라고 합니다. 반갑습니다. </dd>		<dt><span>Q.</span> 부동산 공인중개사무소를 시작하게 된 계기가 있으신가요?</dt>		<dd>특별한 계기는 없었습니다. 현대건설에서 근무하다가 이른 시기에 은퇴를 하게 됐고, 한 친구의 권유로 공인중개사 자격증을 공부해서 취득하게 됐죠. <br>원래는 생각도 없었는데 몰두하다 보니까 이렇게 오랫동안 일하게 됐습니다.</dd>	</dl>		<div class=\"itvw_img\"><img src=\"http://www.reuni.kr/img/interview/mch_04.jpg\" alt=\"문찬호 공인중개사\"></div>	<dl class=\"qna\">		<dt><span>Q.</span> 공인중개사 직업의 장, 단점이 있다면?</dt>		<dd>단점은 딱히 지금은 생각이 나지 않습니다. 장점이라고 하면, 물론 모두 다르겠지만 저의 경우에는 많은 직업군의 다양한 고객과 만나면서 대화를 할 수 있다는 점이 좋다고 생각해요. 사무소에 워낙 다양한 분들이 방문하니깐요. 그래서 개인적인 삶의 지평을 좀 넓힐 수 있었다고 생각합니다. </dd>		<dd>또 다른 면에서는 우리 생활에 있어서 뗄 수 없는 부동산을 대상으로 하는 직업에 종사하다 보니 부동산에 관련된 세제개편이나 법률의 개정 및 국가정책의 변화 등을 잘 알 수 있다는 점이 있습니다. <div class=\"itvw_img\"><img src=\"http://www.reuni.kr/img/interview/mch_05.jpg\" alt=\"문찬호 공인중개사\"></div>	<dl class=\"qna\">		<dt><span>Q.</span> 현 정부의 부동산 정책의 가장 큰 문제점 or 개선해야 할 점이 뭐라고 생각하시나요?</dt>		<dd>76년도 쯤인가요? 제가 젊을 때는 부동산에 대한 개념이, 조금씩 조금씩 돈들 모아서 집을 키워나가는 수준이었어요. 그런데 지금은 부동산 정책도 자주 바뀌고, 특히 가격이 너무 큰 폭으로 오르락내리락 하니까 미래를 꿈꾸기가 쉽지가 않죠.</dd>		<dd>그래서 먼저는 부동산 정책이 적어도 50~100년을 주기로 일관성 있게 만들어져야 한다고 봅니다. 언제까지 영끌(영혼까지 끌어모아)해서 집을 살 수는 없잖아요. 너무 불안하기도 하고... </dd>		<dd>그리고 정부가 부동산을 강제적 규제로 해결할 수 있고 세금으로 해결할 수 있다는 단순한 논리로만 접근하는 것도 문제라고 생각합니다. 부동산 특히 주거문제는 인간 생활에 있어서 가장 중요한 삶의 문제잖아요! 어떻게 보면 집이 있고 없고의 차이가 너무나 심각한 개인적 삶의 행복과 질을 결정하는 척도가 되어가고 있는 슬픈현실 인거 같아 씁쓸합니다. </dd>		<dd>처음에 작은 곳에서 출발해서 조금씩 돈을 모으고, 대출도 받아서 더 큰 평수로 이사하는 선순환이 이루어 져야 하잖아요. 그런데 현실은 이러한 기대와 욕구를 산산히 조각내었다고 생각합니다. LH투기 사태도 마찬가지고요. 허탈하게 만들잖아요. 국민들을...</dd>		<dd>또 한 가지 개선할 점은, 부동산에 대해 이분법적인 잣대로 가진 자‧못가진 자, 갑‧을 등으로 나누려 하지 말고 더 큰 틀에서 접근해 부동산 시장 자체에 좀 맡겨야 할 필요도 있다고 봅니다. </dd>		<dd>급격한 규제와 잦은 법 개정은 소비자인 국민의 중장기 계획 수립을 불가하게 만들어요. 지금까지 뚝딱 만든 규제일변의 법을 폐지 또는 유예하고 좀 더 정교한 전문가의 의견이 반영된 정책설정과 진행이 필요하다고 봅니다.</dd>	</dl>		<div class=\"itvw_img\">		<img src=\"http://www.reuni.kr/img/interview/mch_06.jpg\" alt=\"문찬호 공인중개사 \">		<span class=\"source\">사진=신촌, 이대 일대 부동산 지도</span>		</div>	<dl class=\"qna\">		<dt><span>Q.</span> 지금 중개중인 ‘신촌-이대’ 지역의 부동산 이슈는? </dt>		<dd>코로나로 인한 비대면의 장기화로 신촌이대 상권이 너무 위축되어 있어요. 거의 30%가까이 공실이죠. <br>또 비대면에 따른 온라인 상권의 발달로 더욱 기존 상권이 타격을 받고 있습니다. 이 부분이 가장 걱정됩니다.</dd>		<dd>추가로 온라인 플랫폼의 시장 진입에 대한 걱정이 있어요. 배달시장과 비슷합니다. 배달의 민족 같은 기업이 시장을 장악하면서 소위 ‘갑질’이 가능해졌잖아요. 수수료 문제, 과도한 홍보 등이 그렇죠. </dd>		<dd>네이버, 카카오, 직방, 다방 등 IT기반의 거대 플랫폼이 부동산 중개업 시장을 지배할 수 있어요. 무조건적인 반대도 능사가 아니지만, 손놓고 당할수도 없는 판도라 더 그렇지요. 플랫폼에 종속돼 버리면 그때는 시키는 대로 해야할 수 밖에 없으니까요. </dd>		<dd>최근들어 점점 더 많은 온라인 플랫폼이 생기고 있어요. 그런 경우 처음에는 대다수 공격적인 자세로 영업을 해 옵니다. 우리는 수수료 받지 않거나 또는 최저 비용만 받으면서 정보를 달라고 요구하는 식이죠. 하지만 결국 나중에 자신들의 영향력이 커지면 태도를 바꾸거나 시장을 이미 지배하고 있는거죠. 영세한 중개업이 설 수 있는 자리는 점점 좁아지고 있어요. 직방이나 다방 같은 플랫폼이 중개업에 직접 뛰어든다는 기사도 봤어요. 점점 살아남기 힘들어지는 거죠. </dd>	</dl>		<div class=\"itvw_img\"><img src=\"http://www.reuni.kr/img/interview/mch_07.jpg\" alt=\"문찬호 공인중개사\"></div>	<dl class=\"qna\">		<dt><span>Q.</span> 상권이 많이 죽으면서, 신축 오피스텔이 많이 들어서고 있다고 하는데, 이로 인한 문제점이 있을까요?</dt>		<dd>이곳은 오피스텔 거주자 대부분이 젊은 학생과 젊은 직장인 위주로 이뤄져 있어요. 그러다 보니 신상품의 정보를 오프라인보다는 온라인에서 빠르게 습득합니다. 그래서 판매되는 상품의 다양성과 정보에 있어 그들의 니즈를 빨리 충족시켜주지 못하는 것이 사실입니다. </dd>		<dd>또 개인적 소비가 비대면 장기화로 온라인을 이용한 구매가 이루어지고 있는 관계로 상권의 쇠락이 더욱 가속화되고 있습니다. 이곳에 거주하지만 실제 소비는 이곳이 아닌 온라인상 또는 홍대, 연남동 등으로 옮겨간 것도 또한 상권이 활성되지 않는 이유가 될 수도 있다고 생각합니다.</dd>	</dl>		<div class=\"itvw_img\"><img src=\"http://www.reuni.kr/img/interview/mch_08.jpg\" alt=\"문찬호 공인중개사\"></div>	<dl class=\"qna\">		<dt><span>Q.</span> 부동산 가격을 낮추기 위해선 어떤 게 필요한 건가요?</dt>		<dd>장기 예측이 가능한 부동산 정책이 필요하다 봅니다. <br>그래야 실수요자 분들이 거시적으로 자금계획을 세우고 구입 계획도 검토하고 해서 적절한 시기에 취득한다는 예측 가능성이 있어야 하는데, 지금은 정책의 잦은 변경 (대출, 세제, 임대사업자 기타)으로 지금 사지 않으면 평생 못 산다라는 신호를 국가와 시장이 자꾸 주니까 영끌(영혼까지 끌어모음)해서라도 부동산에 올인하는 거죠. </dd>		<dd>악의의 투기자와 시장 교란하는 세력은 반드시 시장에서 제거해 준다라는 정책과 실제 시행도 중요하다고 생각합니다. 얼마 전 한 공직자의 부동산 이슈가 있었죠. 약 60억원 구입에 대출 54억이라면 정말 잘못된 것이죠? 대출을 내준 금융기관도 큰 문제라 봅니다.</dd>		<dd>한국의 부동산만큼 다이나믹한 곳이 없어요. 부동산 투자로 재산을 증식하는 것을 전문적으로 가르치는 학원도 있잖아요. </dd>	</dl>		<div class=\"itvw_img\"><img src=\"http://www.reuni.kr/img/interview/mch_09.jpg\" alt=\"문찬호 공인중개사\"></div>	<dl class=\"qna\">		<dt><span>Q.</span> 언론에서 부동산에 대해 다뤄주거나 취재해줬으면 하는 부분이 있다면?</dt>		<dd>최근에 대구에서 행정처분을 받은 공인중개사의 개인정보가 모두 공개된 사례가 있었습니다. <br> <br>영세한 공인중개사에 대한 과한 처분이나 법률 등은 개정과 조정이 필요하다고 봅니다. 이런 내용도 다루어 주셨으면 좋겠네요. 감사합니다. </dd>	</dl></div>',0);
INSERT INTO `article_tbl` VALUES (180944,1,31,'01039375154','2021-07-14','2021-07-14','0000-00-00','0000-00-00','[부동산 칼럼] LM=전속공인중개사? 애매한 ‘컨설팅과 중개 사이’ ','0','이번 글에서는 중개업의 새로운 위협으로 부각되고 있는 자산관리(Property Management)에 대해 알아보고 중개업과의 상생과 공존에 대해 살펴보겠습니다\r\n<br><br>\r\n▲공실 줄이기 위해 등장한 LM… PM과 다른 점은?<br> \r\n▲공인중개사법 테두리 벗어난 LM, 속 타는 공인중개사<br>  \r\n▲시장 안정 위해 ‘LM 관련  법안’ 시급…',NULL,'[기고=미소공인중개사사무소 | 대표 노상규] 오피스빌딩‧오피스텔과 같은 수익형 부동산이 대거 늘어난 후 국내에서는 CPMⓇ이라 불리는 ‘부동산자산 전문관리인’의 역할이 점점 커지고 있다. \r\n\r\n‘PM(Property Management)’이라는 개념은 외환위기(IMF) 이후 처음으로 국내에 들어왔다. 이후 2004년부터 PM 관련 제도가 본격적으로 시행됐으며, 현재는 자산관리 분야를 ▲AM(Asset Management) ▲PM(Property Management) ▲FM(Facility Management)으로 나눠서 부르고 있다. \r\n\r\n▲공실 줄이기 위해 등장한 LM… PM과 다른 점은? \r\n\r\nPM은 건물 소유자에게 권한을 위임받아 소유자와 동등한 입장에서 건물을 관리하는 전문가다. 또한 건물 소유주와 자산관리 계약을 하고, 별도로 책정된 중개보수 범위 안에서 공인중개사를 통해 건물을 관리한다. \r\n\r\nPM은 직접 ‘임대차계약’을 맺기도 하지만, 빠른 공실 해결을 위해 인근 공인중개사무소에 의뢰를 맡기기도 한다. 그리고 임대인을 통해 중개보수를 공인중개사에게 지급할 수도 있다. 즉, 공인중개사와의 상생이 가능하다. \r\n\r\n최근에는 경제난으로 공실이 늘면서 PM의 업무 중 ‘공실 리스크 관리’에 대한 중요성이 늘었다. 이에 PM을 ‘PM(Property Management)’과 ‘LM(Leasing Management)’으로 나누어 업무를 분담하는 추세로 가고 있다.\r\n\r\n▲공인중개사법 테두리 벗어난 LM, 속 타는 공인중개사  \r\n\r\n하지만 LM이 등장한 이후로 공인중개사들의 속은 타들어간다. 바로 LM이 받아가는 출처 불명의 수수료 때문이다. \r\n\r\nLM은 별도의 임대관리 수수료가 없이 계약 체결 시에만 건당 수수료를 받는다. 여기서 문제는 LM이 계약 건당 받는 수수료가 ‘컨설팅 보수’인지 ‘중개 보수’인지 명확하지 않다는 점이다. \r\n\r\nLM을 ‘전속 공인중개사’로 본다면 공인중개사법령의 규제를 받아 중개보수를 받는 게 되겠지만, ‘대형 컨설팅 법인’으로 보게 되면 수수료를 중개보수로 보기 힘든 부분이 있어 ‘컨설팅비(용역비)’로 처리해야 한다. \r\n\r\n또한 LM에게 지급되는 컨설팅 보수는 보통 공인중개사법령 및 각 시도조례에서 정한 중개보수의 범위 내에서 지급되기에 공인중개사가 받는 중개 금액과 큰 차이가 없다.\r\n\r\n하지만 LM이 받는 수수료를 컨설팅 보수라고 본다면, 공인중개사법에 적용되지 않아 혼란이 발생하는 것이다. \r\n\r\n또 한 가지, 이는 세입자의 권리 보호 측면에서도 문제다.\r\n\r\n공인중개사법 제30조에 따르면, 개업공인중개사는 중개행위를 하는 경우 고의 또는 과실로 인해 거래 당사자에게 재산상의 손해를 발생하게 한 때에는 그 손해를 배상할 책임이 있다. 또한 업무를 개시하기 전에 손해배상책임을 보장하기 위해 보증보험이나 공제에 가입해 일정 금액을 공탁해야 한다. 이를 근거로 세입자는 공인중개사의 업무상 과실 등에 따른 손해 발생 시 법적인 보호를 받을 수 있게 된다.\r\n\r\n하지만 단순 컨설팅에서는 이러한 법령 적용이 불가하다. 따라서 세입자의 입장에서는 당연히 LM이 공인중개사법의 적용을 받는 것이 더 안전하다. \r\n\r\n반면, LM의 입장은 좀 다르다. PM의 업무는 임대계약에 관련된 일만 포함된 것이 아니며 계약 건당 받는 컨설팅 수수료는 별개이기 때문에 받아도 문제가 없다는 말이다. 중개사에게는 본인의 수수료를 나눠서 지급하더라도 0.9% 이내에서 협의하는 만큼 공인중개사법 위반이 아니라는 것이다.\r\n\r\n이런 경우 공인중개사는 본인의 노력으로 계약을 성사시켜도, 무조건 LM을 통해서만 소통하고 수수료마저 나눠야 하기에, LM에 대한 의존도가 높아져 궁지에 몰릴 수 밖에 없다.\r\n\r\n이로 인해 업계에서는 “LM은 ‘대형 컨설팅 회사’들이 공인중개사의 중개보수를 빼먹기 위한 책략이 아니냐”는 비판의 목소리까지 나오고 있다. 또한 LM은 중개법인이 아닌 대형프랜차이즈 법인들이 편의로 만든 ‘전속공인중개사’라는 평가도 나온다.\r\n\r\n만약 LM이 중개사 없이 바로 세입자를 모집한다면 이는 또 공인중개사법을 위반하는 꼴이 돼 골치가 아픈 상황이다. \r\n\r\n▲시장 안정화 위해 ‘LM 관련 법안’ 시급… \r\n\r\n정리하자면, 공인중개사와 LM은 공인중개사법을 사이에 두고 계속 갈등할 수 밖에 없다. 고로 대책이 필요한 상황이다. 임차인의 보호를 위해서라도 말이다. \r\n\r\n정부는 조속히 LM 관련 법안을 재정비해야 한다. LM이 법의 둘레 안으로 들어오게 하거나, 그게 어렵다면 이들을 감독하고 소비자를 보호할 수 있는 별도의 법안을 마련해야 한다. 이렇게 가다간 공인중개사들이 모두 ‘대형 컨설팅 회사’에 잠식되는 참사가 벌어질 수도 있기 때문이다.\r\n\r\n물론 공인중개사들도 가만히 앉아서 보고만 있어서는 안된다. “LM이 하는 업무가 사실상 중개에 가까운데 왜 공인중개사 자격도 갖추지 못한 사람들에게 우리가 밀려나야 하느냐”는 불만만 표출하기 보다는, 빠르게 변화하는 부동산 시장에 대한 이해를 통해 스스로 경쟁력을 갖출 수 있게 노력해야 한다.',0);
INSERT INTO `article_tbl` VALUES (180946,1,32,'01090544679','2021-07-17','2021-07-17','2021-08-01','2021-12-31','HUG(주택도시보증공사) 코로나19로 보증료인하 2021년 12월 31일','0','HUG(주택도시보증공사)는 코로나19로 전세보증금반환보증 등의 보증료를 2021년 12월 31일까지로 연장키로 하였다. ',NULL,'보증금액의 인하 2021년 12월 31일까지!!\r\n\r\n전세보증금 2억 이하 : 80% 인하\r\n전세보증금 2억 초과 : 70% 인하\r\n\r\n①코로나19 장기화에 따른 국민 부담 경감 및 경기 위축 대응을 위해 올해 하반기 전세보증금반환보증 등 서민주거안정 지원 관련 12개 보증상품에 대한 보증료 한시 할인을 추진하고,\r\n\r\n②서민 임차인에 대한 저금리 전세대출 지원 및 전세보증금 보호를 위해 전세금안심대출보증 가입요건인 전세보증금 기준을 확대하는 한편,\r\n\r\n③공공성 강화를 위해 주택분양보증 등 12개 보증상품의 기본보증료율을 ’21.7.1.부터 인하하여 지속 적용한다고 밝혔다.\r\n\r\nㅇ 특히, 서민주거안정 지원을 위한 ‘전세보증금반환보증 보증료 할인 연장’(6월말 일몰→연말까지) 및 ‘전세금안심대출보증 가입 요건인 전세보증금 기준 확대’는 ’21년도 하반기 경제정책 방향 발표의 후속 조치로서, 이를 통해 서민의 주거비 부담을 경감하는 한편 전세시장 불안 해소 및 임대차 3법의 원활한 연착륙을 지원한다.\r\n\r\n4. 전세금안심대출보증 가입요건인 전세보증금 기준 확대\r\n\r\n□ 현행 보증가입 요건에 부합하지 않아 보증 사각지대에 노출된 서민 임차인을 보호하고자 전세금안심대출보증 가입요건인 전세보증금 기준을 수도권 7억원(5억원→7억원), 그 외 지역 5억원(4억원→5억원) 이하로 확대할 예정이다.\r\n\r\nㅇ 다만, 대출보증의 최대한도(수도권 4억원, 그 외 지역 3.2억원)는 현행 수준으로 유지하여 가계대출 총량 및 주택가격의 안정화를 목표로 하는 정부 정책을 적극 지원할 계획이다. ',0);
INSERT INTO `article_tbl` VALUES (180947,1,32,'01090544679','2021-07-21','2021-07-21','0000-00-00','0000-00-00','2. 대구 북구청 공인중개사 200명 개인정보 유출 사태, ‘사과’ 및 재발방지 촉구','0','공인중개사 소식지 터는 지난 6월 대구 북구청의 개업공인중개사에 대한 행정처분의 공표와 관련된 내용을 보도한 바 있다. 보도 이후 다양한 의견이 있었고, 본지는 취재를 통해 개인정보 유출에 대한 책임이 대구 북구청에 있음을 확인했다. ','yms.jpg','[양미숙 기자] 공인중개사 소식지 터는 지난 6월 대구 북구청의 개업공인중개사에 대한 행정처분의 공표와 관련된 내용을 보도한 바 있다. 보도 이후 다양한 의견이 있었고, 본지는 해당 대구  북구청에 이에 대한 소명을 요구했으며 이에 대한 답변을 받을 수 있었다.  \r\n\r\n이번 보도에서는 대구 북구청의 답변과 관련해 문제가 되는부분을 하나씩 살펴보고자 한다. \r\n\r\n▲개인정보보호법 무시한 대구 북구청의 ‘거짓말’\r\n\r\n먼저 대구 북구청의 답변에 대해 “정말 유감스럽다”는 말을 전하고 싶다. 대구 북구청은 공인중개사 약 200명의 개인정보를 누리집에 공표에 대한 해명요구에 행정안전부 정보공개정책과의 사전정보공표 운영 가이드를 준수했다라고 밝혔다. \r\n\r\n하지만 기자가 살펴본 바, 누리집에서 가이드를 벗어난 부분을 발견했다. 행정안전부 정보공개정책과의 사전정보공표 운영 가이드 7쪽에서는 다음과 같은 기준을 제시하고 있다. \r\n\r\n<div class=\"top_news\">○ (개인정보, 기업비밀 등 침해) 행정처분 내역 또는 각종 검사결과 중 법령에 따라 공개하도록 되어 있는 정보를 제외하고는 개인정보, 기업정보 등을 익명처리(개인정보보호지침 준수)\r\n- 다만, 개인정보, 기업정보 등을 익명 처리하더라도 개인 또는 기업 등이 특정*될 수 있는 경우는 미공표 가능\r\n※ 예) 해당 기관에서 관할 하는 지역에 업소, 기관 등이 소수로 행정처분 내역 등을 공표할 경우, 일반인이 어느 업소, 기관인지 알 수 있으면 개인정보 침해 우려가 있으므로 개인정보 보호지침에 따라 처리\r\n출처 <a href=\"https://www.mois.go.kr/frt/bbs/type001/commonSelectBoardArticle.do;jsessionid=ph6DdSYUmJ0FQF0BZPkgn7Os.node20?bbsId=BBSMSTR_000000000015&nttId=79771#none\">:사전정보공표 운영 가이드</a></div>\r\n\r\n해당 가이드는 ①행정처분 내역 또는 각종 검사결과 중 법령에 따라 공개할 수 있는 정보를 제외하고는 ②개인정보‧기업정보 등을 익명으로 처리해야 한다고 적시하고 있다. 허나 대구 북구청은 공개하도록 되어 있는 근거법령은 적시하지도 못하였고, 물론 그러한 개인정보의 공개나 공표를 위해 요구되는 비식별화 조치조차 이행하지 않았다. \r\n\r\n▲공인중개사 행정처분 내역은 ‘명백한 개인정보’ \r\n\r\n개인정보보호법 제2조는 개인정보에 대하여 다음과 같이 정의하고 있다.\r\n\r\n<blockquote> 1. “개인정보”란 살아 있는 개인에 관한 정보로서 다음 각 목의 어느 하나에 해당하는 정보를 말한다.\r\n\r\n가. 성명, 주민등록번호 및 영상 등을 통하여 개인을 알아볼 수 있는 정보\r\n\r\n나. 해당 정보만으로는 특정 개인을 알아볼 수 없더라도 다른 정보와 쉽게 결합하여 알아볼 수 있는 정보. 이 경우 쉽게 결합할 수 있는지 여부는 다른 정보의 입수 가능성 등 개인을 알아보는 데 소요되는 시간, 비용, 기술 등을 합리적으로 고려하여야 한다.\r\n\r\n다. 가목 또는 나목을 제1호의2에 따라 가명 처리함으로써 원래의 상태로 복원하기 위한 추가 정보의 사용ㆍ결합 없이는 특정 개인을 알아볼 수 없는 정보(이하 “가명정보”라 한다)</blockquote>\r\n\r\n대구 북구청 누리집이 공개한 정보는 등록번호와 업소명, 소재지, 처분내용, 처분일자 등을 포함하고 있다. 이 정보가 왜 개인정보인지를 알기 위해서는 먼저 중개업의 특성을 이해해야 한다.\r\n\r\n중개업은 등록을 요구하며 그 90%를 넘는 업소가 1인 업소이다. 즉, 등록을 하는 과정에서 같은 행정동에 대한 같은 업소명은 등록이 허용되지 않으며 등록업소별로 고유한 등록번호를 부여받는다. 따라서 등록번호는 개인고유번호임과 동시에 식별정보가 된다. 공인중개사에 대한 행정처분은 대인적 처분으로 업소명과 소재지 만으로 살아있는 개인인 공인중개사의 식별이 가능하기 때문이다. \r\n\r\n▲“개인정보 공개=공익?” 어이 없는 대구  북구청의 주장에 대해…\r\n\r\n“공개로 인해 발생할 수 있는 공익이 있다”는 대구 북구청의 주장은 물론 일리가 있다고 본다. 하지만 먼저 공개와 공표는 서로 구분돼야 하며, 공개할 수 있다고 해서 꼭 공표를 해야 하는 건 아니라고 생각한다.\r\n\r\n일례로, 무단횡단에 대한 과태료 처분 내역은 교통안전에 대한 경각심의 재고나 교통사고 예방이라는 이유로 공개 내지 공표하고 있지 않다. \r\n\r\n이는 공개‧공표에 있어서의 공익뿐 아니라 그 실행에 따른 침해 가능한 권익과의 신중한 형량이 필요하기 때문이다. 국내에서는 흉악범에 대한 신상정보를 공개할 때 조차도 엄격한 절차를 거친다. 그럼에도 불구하고, 앞선 200명의 공인중개사의 정보공개에 대해선 충분한 논의와 절차가 이뤄지지 않았다. 이는 매우 심각한 권익침해이다. \r\n\r\n이번 취재 과정에서 사견임을 전제로 관련기관의 책임자는 “공표를 통해 얻는 공익이 크다 판단되더라도 공표과정에서 개인정보의 침해 우려가 있다면 그 범위는 최소화 되어야 한다. 따라서 공인중개사의 경우 공표가 필요하다 하더라도 과태료까지 포함하는 것은 지나친 것이며, 그 범위는  업무정지의 경우에도 해당 업무정지기간으로 한정하는 것이 맞다고 본다. 해당기간이 도과하면 개인식별이 가능한 정보는 공개되지 않는 것이 타당하다”고 밝혔다.  국가공간정보포털 경우  중개업소조회를 하면 현재 행정처분 중인 내용만 조회가 가능하다  \r\n\r\n공인중개업은 해당 지역에서의 평판이 고객의 선택을 받는 데에 매우 중요한 요소로 작용한다. 고로 어떠한 이유로든 공인중개사에 대한 행정처분을 개인식별이 가능한 정보와 함께 공표하는 것은 해당 공인중개사들에게 회복불가능한 손실을 줄 수 있다.\r\n\r\n대구 북구청은 이에 대한 사과와 책임자 처벌을 실시하고, 관련 내용을 시정해야 한다. 본지는 이와 관련된 보도를 계속해서 이어갈 예정이다. ',0);
INSERT INTO `article_tbl` VALUES (180948,1,32,'01091280586','2021-07-21','0000-00-00','0000-00-00','0000-00-00','대구 북구청 민원 답변 전문 보기','0','대구광역시 북구청의 개인 정보 유출에 대한 답변의 전문입니다. ',NULL,'\r\n처리기관 대구광역시 북구 (대구광역시 북구 감사실)\r\n처리기관 접수번호 2AA-2106-1027821\r\n접수일 2021-06-25 16:39:49\r\n담당자(연락처) 한지은 (053-665-2149)\r\n처리예정일 2021-07-05 18:00:00\r\n\r\n답변 내용 \r\n답변일 2021-07-02 11:50:43\r\n처리결과\r\n(답변내용)\r\n[주관부서] : 감사실 [답변일자] : 2021-07-02 11:50:43\r\n[작성자] : 한지은 [전화번호] : 053-665-2149 [이메일] : hje1128@korea.kr\r\n[답변내용] : 1. 먼저 북구 행정발전을 위해 많은 관심을 가져주셔서 진심으로 감사드립니다.\r\n\r\n2. 국민권익위원회(국민신문고)에서 우리 구청으로 이송된 귀하의 민원 내용은 ‘공인중개사 행정처분 공개 근거 및 누리집에 공개하는 것이 정당한지’에 관한 것으로 이해됩니다.\r\n먼저 귀하께서 공인중개사 행정처분의 공개에 관하여 불편함을 느끼신 점에 대해 사과의 말씀을 드립니다.\r\n\r\n3. 귀하께서 제기하신 민원에 대하여 감사실에서 조사한 내용을 다음과 같이 답변드립니다.\r\n\r\n가. 공인중개사 행정처분의 공개는 행정안전부 정보공개정책과의 사전정보공표 운영 가이드를 준수한 사항으로,『공공기관의 정보공개에 관한 법률』 (이하 정보공개법) 제7조제1항과 제2항을 근거로 해당 내용을 공개할 수 있으며, 공개 대상 또한 행정안전부의 사전정보공표 표준모델에서 정한 바와 같이 공인중개사법 위반업소 지도점검 결과에 점검기간, 점검대상(업소명, 소재지 등), 위반사항, 조치사항(행정처분 내역 등)을 포함하였고,\r\n\r\n나. 『정보공개법』시행령 제4조제2항 “정보통신망에 게재하거나 다양한 방법으로 국민에게 공개하여야 한다”에 의거 기관 홈페이지(누리집)을 통해 공표한 것으로 확인됩니다.\r\n\r\n다. 또한,『공인중개사법 시행령』제14조(등록사항 등의 통보)제4호에 의거 국토교통부령이 정하는 바에 따라 행정처분 결과를 공인중개사협회에 통보하고 있으며, 공인중개사에게 공개사항 개별통지는 시행근거가 없어 추진되고 있지 않습니다.\r\n\r\n라. 이와 같은 내용들을 종합해 보면, 관련 공개가 개인정보보호법 등 타법령을 위반한 사항은 아닌 것으로 판단되며, 모쪼록 건전한 부동산중개업 환경조성을 위한 의미로 이해해 주시기 바랍니다.\r\n\r\n4. 만족스러운 답변이 되지 않음을 안타깝게 생각하며, 기타 궁금하신 사항이 있으시면 북구청 감사실 (☎ 665-2149) 또는 토지정보과 (☎ 665-3074)로 문의하여 주시면 성심껏 답변드리도록 하겠습니다. 감사합니다.\r\n',0);
INSERT INTO `article_tbl` VALUES (180949,1,31,'01053540675','2021-08-12','2021-08-12','0000-00-00','0000-00-00','[부동산 칼럼] 계약 1건에 중개보수 ‘몇 천’?… 하나만 알고 둘은 모른다','0','[부동산 칼럼] 계약 1건에 중개보수 ‘몇 천’?… 하나만 알고 둘은 모른다<br>\r\n-중개보수 부담 가중에 대한 현직 공인중개사의 입장<br>\r\n-중개보수 상승은 정부 규제 영향… 정액제 시행해야<br>',NULL,'<p style=\"line-height: 150%;\"><br></p><p style=\"line-height: 150%;\">[기고=양맹숙 공인중개사] 최근 주택가격이 상승함에 따라 중개보수(중개 수수료)에 대한 부담을 느끼는 이들이 점점 늘고 있다.</p><p style=\"line-height: 150%;\">지난 2015년, 집값이 상승하자 정부는 고가주택의 상한선을 6억에서 9억으로 높였다. 동시에 중개보수 규정도 조정됐다. 이후 지금까지 부동산 중개보수에 대한 사회적 논의는 계속 진행 중이다.</p><p style=\"line-height: 150%;\"><b><br></b></p><p style=\"line-height: 150%;\"><b>▲집 몇 번 보여주고 &lsquo;몇 천 만원&rsquo;&hellip; 중개보수 너무 과해?</b></p><p style=\"line-height: 150%;\"><br></p><p style=\"line-height: 150%;\"><img src=\"http:///reuni.kr/img/trans2106.jpg\" title=\"2021.06월 주택거래 통계\" alt=\"2021.06월 주택거래 통계\" style=\"vertical-align: baseline; border: 0px ;\"><p><span style=\"font-size: 11pt;\">공인중개사가 하는 일도 없이 집만 몇 번 보여준 후 계약서를 쓰고 몇 천 만원의 중개보수를 받는다는 기사가 연일 나오고 있다. 일반 직장인에 비해 너무 쉽게 큰 금액을 번다는 지적이다.</span></p><p style=\"line-height: 150%;\">하지만 이런 내용은 공인중개사가 하는 일의 전체 과정을 전혀 고려하지 않고서 한 부분만 본 것이다.</p><p style=\"line-height: 150%;\">공인중개사는 매물 분석을 시작으로 많은 발품을 팔면서 고객를 물색한다. 이 과정에서 수많은 고객을 만나 소통하고, 또 매물을 설명하는 등 많은 과정을 겪는다. 계약이 성사되는 결과만 보면 많은 수수료를 받는 것 같지만, 실제 그 중간 과정에는 무수한 수고가 들어간다.</p><p style=\"line-height: 150%;\">또한 중개보수는 개업공인중개사의 중개업소가 활동하는 지역이나 매물의 종류, 주변의 인프라 등 환경과 업무량에 따라 천차만별이다. 단순히 중개보수액을 놓고 판단했을 때는 커 보이지만, 타인의 재산을 중개한다는 리스크을 안고 거래를 하는 만큼 책임의 막중함은 매우 크다.</p><p style=\"line-height: 150%;\">지금 가장 논란이 되고 있는 고가주택의 중개보수의 경우, 2021년 6월을 기준 전체 거래의 약 6%에 지나지 않으며, 그나마 일부 지역에 집중돼 있다. 또한 집값이 9억원 이상일 때 수수료 0.9%를 다 지불하지도 않을뿐더러, 요즘처럼 정보가 노출된 상태에서는 공동중개를 하기 때문에 사실상 양쪽에서 수수료를 받는 건 어렵다.</p><p style=\"line-height: 150%;\"><br></p><p style=\"line-height: 150%;\">▲<b>중개보수 상승은 공인중개사 탓?</b></p><p style=\"line-height: 150%;\"><br></p><p style=\"line-height: 150%;\">그럼 집값 급등에 따른 중개보수의 상승은 누구의 책임일까? 부동산 가격의 상승은 전적으로 정부에게 있다. 많은 부동산 전문가들은 정부가 부동산 시장에 과도하게 개입해 지금의 폭등 현상이 벌어졌다고 설명한다. 그런데도 중개보수도 같이 많아졌다는 이유만으로 공인중개사들에게 책임을 전가하려고 한다.</p><p style=\"line-height: 150%;\">국토부 실거래시스템에 따르면, 2021년 6월 기준 전년 동월(&rsquo;20.6월, 138,578건) 대비 부동산 거래량이 35.8% 감소했다. 정부의 잇따른 부동산 규제로 인한 결과다.</p><p style=\"line-height: 150%;\">공인중개사는 집을 수차례 보여줘도 거래가 성사되지 않으면 보수를 받지 못한다. 공인중개사 법률 소비조합에서의 설문에 의하면 한 차례로 계약이 이른 경우도 있지만 하나의 계약을 위해 최고 마흔번 이상의 임장이 이루어진 경우도 있었으며 서울의 경우 평균 하나의 계약을 위해 4-6회의 임장이 이루어졌다. 그걸 \'집 한번 보여주고\'로 표현되는 건 부당하다. 전체 거래량이 줄었다는 것은 즉, 공인중개사업계도 빈익빈부익부의 양극화가 심해지고 있는 것으로 볼 수 있다.</p><p style=\"line-height: 150%;\"><b><br></b></p><p style=\"line-height: 150%;\"><b>▲중개보수 낮출 대안 없나?</b></p><p style=\"line-height: 150%;\"><br></p><p style=\"line-height: 150%;\">중개보수를 낮출 대안은 충분히 있다. 중개보수 정액제를 시행해 고가주택의 금액을 12억으로 조정한 후 요율을 정하면 된다. 항상 문제가 되는 건 고가주택이었기 때문이다.</p><p style=\"line-height: 150%;\"><br></p><p style=\"line-height: 150%;\">몇%의 한도 내에서 합의를 보고 지불하는 것은 고객과 공인중개사 간의 갈등을 일으키는 요소이다. 이런 경우 어느 한쪽은 반드시 비판을 받게 되는데 대부분 공인중개사가 그 대상이 된다.</p><p style=\"line-height: 150%;\">대다수 공인중개사는 현 정책의 중개보수 요율에 만족하지 못하고 있다. 중개보수를 낮추기 위한 합의는 정부의 일방적 대책이 아니라, 협회‧소비자단체 등과 함께 논의해 결정돼야 한다.</p>',0);
INSERT INTO `article_tbl` VALUES (180952,1,31,'01091280586','2021-08-18','2021-08-18','0000-00-00','0000-00-00','「2020년도 주거실태조사 결과」 발표','0','- 최저주거기준 미달가구(5.3%→4.6%) 감소,</br>\r\n- 1인당 주거면적 증가(32.9㎡→33.9㎡,</br>\r\n- 공공임대주택 만족도 상승(93.5%→94.4%),</br>\r\n- PIR: 5.4배→5.5배, RIR: 16.1%→16.6% 상승</br>',NULL,'국토교통부(장관 노형욱)는 국토연구원(원장 강현수)에 의뢰하여 지난해 7~12월 표본 5.1만 가구를 대상으로 실시한 2020년도 주거실태조사 결과를 발표하였다.\r\n\r\n2020년은 주거복지로드맵(’17.11, ’20,3), 신혼부부·청년 주거지원 방안(’18.7) 등 지속적인 주거복지 향상을 위해 노력한 결과, 국민 주거의 질적 측면이 개선되는 성과가 있었다.\r\n\r\n최저주거기준 미달가구의 비중이 ’19년 5.3%에서 ‘20년 4.6%로 감소하고, 1인당 주거면적은 ’19년 32.9㎡에서 ‘20년 33.9㎡로 증가하였다.\r\n\r\n공공임대주택 거주 가구의 만족도는 ’19년 93.5%에서 ’20년 94.4%로 개선되었고, 전체 가구 중 공공임대주택 입주 의향이 있는 가구도 ’19년 33.9%에서 ’20년 35.6%로 증가하였다.\r\n\r\n다만, 2020년은 코로나19 대유행이 시작된 해로, 경기 침체 대응을 위한 전세계적인 초저금리 기조* 등으로 집값과 임대료가 높아지며 PIR, RIR이 상승한 것으로 나타났다.\r\n\r\n<div class=\"note-box\">* 한은 기준금리 : (’20.1) 1.25% → (’20.3) 0.75% → (’20.5∼) 0.5%\r\n미국(연준) 기준금리 : (’20.1) 1.75% → (’20.3) 1.25% → (’20.3∼) 0.25%</div>\r\n\r\n\r\n자가가구의 PIR(연소득 대비 주택가격 배수)은 5.5배(중위수)로 ’19년 5.4배 대비 증가하고, 임차가구의 RIR(월소득 대비 월임대료 비중)도 16.6%(중위수)로 ‘19년 16.1% 대비 증가하였다.\r\n\r\n또한, 그 간 지속적인 주택 공급*에도 불구하고, 역대 최고 수준의 가구분화**로 인해 자가점유율은 57.9%로 전년(58.0%)과 유사한 수준이나, 자가보유율은 ’19년 61.2%에서 ’20년 60.6%로 감소하였다.\r\n\r\n<div class=\"note-box\">* 전체주택 입주물량 : (’19) 51.8만호, (’20) 47.1만호 (과거 10년 평균 46.9만호)\r\n** 가구수 증가분(단위: 가구) : (’18)30.5만 → (‘19)36.4만 → (’20)58.4만(인구주택총조사)</div>\r\n\r\n\r\n다만, ’21년 들어 공급 선행지표인 아파트 인허가·착공 실적* 등이 증가하고 있으며, 그 동안 발표한 공급대책(5.6, 8.4, 2.4대책 등)을 통해 충분한 물량이 추가 공급**될 예정이므로, 자가보유율이 점차 상승할 것으로 전망된다.\r\n\r\n<div class=\"note-box\">* ’21년 상반기 전국 아파트 인허가 실적 : 전국 17.1만호(과거 10년 대비 9% 증가)\r\n착공 실적 : 전국 20만호(과거 10년 대비 40% 증가)\r\n** 주택공급 전망 : (전국) ’21∼’30년 연평균 56.3만호(과거 10년 대비 20% 증가)\r\n(수도권) ’21∼’30년 연평균 31.4만호(과거 10년 대비 34.2% 증가)</div>\r\n\r\n\r\n앞으로도 정부는 무주택 서민의 주거안정을 위해 그 간 발표한 공급대책 등의 신속한 추진과 ’25년까지 장기 공공임대주택 재고 240만호 확보(재고율 10%)를 위해 지속 노력할 계획이다.\r\n\r\n공공임대주택은 중형평형(전용 60～85㎡)을 도입하고, 품질 혁신 및 맞춤형 주거서비스를 제공하여 더욱 매력적인 삶터로 조성하고, 주거급여 확대, 비주택 거주자 주거상향 사업 확대 등으로 더욱 촘촘한 주거 안전망을 구축해나갈 계획이다.\r\n\r\n[ 1. 주거 안정성 ]\r\n\r\n(자가점유율) 자가에 ‘거주’하는 가구는 전체 가구의 57.9%로 ‘19년(58.0%)과 유사한 수준을 보였다.\r\n\r\n지역별로 도지역은 소폭 상승, 수도권 및 광역시는 소폭 감소하였으나, 대체로 전년과 유사하게 나타났다.\r\n\r\n<div class=\"note-box\">* (수도권) 50.0% → 49.8% , (광역시 등) 60.4 → 60.1, (도지역) 68.8 → 69.2</div>\r\n\r\n\r\n(자가보유율) 자가를 ‘보유’한 가구는 60.6%로, 도지역에서는 상승하고, 수도권 및 광역시 등에서 감소한 것으로 나타났다.\r\n\r\n<div class=\"note-box\">* (수도권) 54.1% → 53.0%, (광역시 등) 62.8 → 62.2, (도지역) 71.2 → 71.4</div>\r\n\r\n\r\n[ 2. 주거비 부담 ]\r\n\r\n(PIR) ’20년 자가가구의 연소득 대비 주택가격 배수(Price Income Ratio)는 전국 5.5배(중위수)로, ‘19년(5.4배) 대비 상승한 것으로 나타났다.\r\n\r\n지역별로 수도권이 8.0배, 광역시 등은 6.0배, 도지역은 3.9배로, 모든 지역에서 PIR이 전년 대비 모두 상승하였다.\r\n\r\n<div class=\"note-box\">* 중위수(배) : (전국) 5.4→5.5, (수도권) 6.8→8.0, (광역시 등) 5.5→6.0, (도지역) 3.6→3.9\r\n** 평균(배) : (전국) 6.8→7.3, (수도권) 9.0→9.6, (광역시 등) 6.2→6.8, (도지역) 4.3→4.5</div>\r\n\r\n\r\n(RIR) ’20년 임차가구의 월소득 대비 월임대료 비율은 전국 16.6%(중위수)로 \'19년(16.1%)에 비해 소폭 증가했으나, 지역별(중위수)로는 수도권(18.6%), 광역시 등(15.1%)은 전년 대비 감소, 도지역(12.7%)은 전년과 동일한 것으로 나타났다.\r\n\r\n<div class=\"note-box\">* 데이터의 중간값을 의미하는 중위수 특성 상, 일정 값에 데이터가 몰려있는 경우 부분의 중위수는 감소하더라도 전체의 중위수는 증가할 수 있음\r\n** 중위수(%) : (전국) 16.1→ 16.6, (수도권) 20.0→18.6, (광역시 등) 16.3→15.1, (도지역) 12.7→12.7\r\n평균(%) : (전국) 21.3→ 20.9, (수도권) 24.6→23.7, (광역시 등) 17.7→17.9, (도지역) 14.6→14.6</div>\r\n\r\n\r\n(생애최초 주택마련 소요연수) ‘20년은 7.7년으로 ’19년(6.9년) 대비 상승하였다.\r\n\r\n[ 3. 주거이동 및 주택보유의식 ]\r\n\r\n(평균 거주기간) ’20년 전체가구의 평균 거주기간은 7.6년으로 나타났다.\r\n\r\n점유형태별로는 자가가구는 10.6년, 임차가구는 3.2년을 거주하여 전년과 유사했으며, 지역별로는 도지역(10.0년), 광역시 등(7.4년), 수도권(6.1년) 순으로 평균 거주기간이 길었다.\r\n\r\n(주거이동률) 현재주택 거주기간이 2년 이내인 가구는 전체가구 중 37.2%이며, 자가가구는 20.7%, 임차가구는 62.1%로 나타났다.\r\n\r\n지역별로 보면, 수도권(41.9%)에서 광역시 등(36.1%), 도지역(30.5%)에 비해 상대적으로 주거 이동이 잦았다.\r\n\r\n(이사이유) 이사경험이 있는 가구를 대상으로 현재주택으로 이사한 이유를 조사한 결과, ‘시설이나 설비 상향’(48.3%), ‘직주근접(29.7%)’, ‘주택마련을 위해(28.3%)’ 순으로 나타났다.\r\n\r\n[ 4. 주거수준 및 만족도 ]\r\n\r\n(최저주거기준 미달가구) 최저주거기준 미달가구는 ‘14년 이후 5%대를 유지하다, ‘20년은 4.6%로 감소하였다.\r\n\r\n(1인당 주거면적) 1인당 주거면적은 ’17년 이후로 매년 증가하여 ‘20년 33.9m2로 ’19년 32.9m2 대비 증가하였다.\r\n\r\n<div class=\"note-box\">* 주거면적은 2017년부터 공동주택에 한하여 행정자료를 활용하였으며, 기존 조사대상자의 응답에 의한 주거면적보다 작게 나타남</div>\r\n\r\n\r\n(주택 및 주거환경 만족도) 주택과 주거환경 만족도는 ‘20년 각각 3.00점, 2.97점으로 상승 추세에 있으며, 지역별로는 광역시 등에서 주택과 주거환경 만족도가 다른 지역에 비해 높게 나타났다.\r\n\r\n[ 5. 주거지원 정책수요 및 평가 ]\r\n\r\n(가장 필요한 주거지원 프로그램) 전체가구 중 주거지원 프로그램이 필요하다고 응답한 가구는 40.6%로, 필요한 주거지원 프로그램으로 ‘주택구입자금 대출지원(34.6%)’, ‘전세자금 대출지원(24.5%)’, 장기공공임대주택 공급(11.6%)‘ 등을 응답하였다.\r\n\r\n점유형태별로 보면, 자가가구는 ‘주택구입자금 대출지원(57.6%)’, 전세가구는 ‘전세자금 대출지원(37.3%)’, 월세가구는 ‘월세보조금 지원(33.8%)’을 가장 필요한 주거지원 프로그램으로 응답하였다.\r\n\r\n(공공임대주택 만족도) 공공임대주택에 거주하고 있는 가구 중 94.4%가 만족한다고 응답하여, ’19년(93.5%) 대비 만족도가 상승하였다.\r\n\r\n만족하는 이유로는 ‘저렴한 임대료(49.2%)’, ‘자주 이사를 하지 않아도 되므로(38.3%)’ 순으로 나타났다.\r\n\r\n(공공임대주택 입주의향) ’20년 전체 가구의 35.6%가 공공임대주택 입주 기회가 있으면 입주할 의향이 있다고 응답하여, 전년(33.9%) 대비 공공임대주택 입주의향이 있는 응답자가 증가하였다.\r\n\r\n점유형태별로는 월세거주 가구가 68.6%로 가장 높은 의향을 보였으며, 전세가구는 54.3%, 자가가구는 17.4%로 나타났다.\r\n\r\n[ 6. 특성가구별 주거실태 ]\r\n\r\n< ① 청년가구 >\r\n\r\n* 청년기본법에 따라 청년가구를 가구주의 연령이 만20세 이상 만 34세 이하인 가구에서 만19세에서 만34세 이하인 가구로 변경\r\n\r\n\r\n(주거안정성) 청년 가구는 1인 가구(61.9%)가 많고, 주거이동률(82.2%)이 일반가구 및 다른 특성가구에 비해 높은 것이 특징이다.\r\n\r\n<div class=\"note-box\">* (주거이동률) 청년 82.2%, 신혼부부 66.5%, 일반 37.2%, 고령 14.7%</div>\r\n\r\n\r\n청년 가구는 단독주택(38.8%)과 아파트(33.9%)에 주로 거주하며, 일반가구 및 다른 특성가구에 비해 오피스텔 등 주택이외의 거처(13.4%)에 거주하는 비율이 높은 것으로 나타났다.\r\n\r\n<div class=\"note-box\">* (주택이외 거처) 청년 13.4%, 신혼부부 1.8%, 일반 4.8%, 고령 1.7%</div>\r\n\r\n\r\n(주거비) 청년 임차가구의 RIR은 16.8%로, ’19년(17.7%) 대비 감소하였으나, 자가가구의 PIR은 5.5배로 ’19년(5.0배) 대비 증가하였다.\r\n\r\n(주거수준) 청년 최저주거기준 미달가구의 비율은 7.5%로, ’19년 9.0% 대비 감소하였으며, 1인당 주거면적도 ’19년 27.9㎡에서 ’20년 30.9㎡로 증가하여 주거 수준이 향상되었다.\r\n\r\n<div class=\"note-box\">* 지하·반지하·옥탑 거주 가구 비중은 ’20년 2.0%로 ’19년 1.9% 대비 소폭 증가</div>\r\n\r\n(정책수요) 가장 필요한 주거지원으로 ‘전세자금 대출지원(39.1%)’, ‘주택 구입자금 대출지원(23.4%)’, ‘월세보조금 지원(16.3%)’ 순으로 응답하였다.\r\n\r\n< ② 신혼부부가구 >\r\n\r\n<div class=\"note-box\">* 신혼부부가구란 혼인한지 7년 이하인 가구를 말함</div>\r\n\r\n\r\n(주거안정성) 신혼부부 가구의 46.1%는 자가에 거주하고 있으며, 신혼가구 대부분은 아파트(75.1%)에 거주하는 것으로 나타났다.\r\n\r\n<div class=\"note-box\">* (자가점유율) 신혼부부 46.1%, 청년 16.1%, 일반 57.9%, 고령 75.4%\r\n(신혼부부 주택유형) 아파트 75.1%, 단독주택 12.4%, 다세대주택 8.6%, 그 외 3.9%</div>\r\n\r\n\r\n신혼부부·생애최초 특별공급 등으로 신혼부부는 일반가구 및 다른 특성가구 대비 자가마련 방법 중 ‘신축건물 분양 및 구입’ 비율*이 29.8%로 높으며, 전년대비 증가(26.3→29.8%)하였다.\r\n\r\n<div class=\"note-box\">* (자가마련 방법 중 ‘신축건물 분양 및 구입’ 비율) 신혼부부 29.8%, 청년 24.6%, 고령 15.8%, 일반 21.7%</div>\r\n\r\n\r\n(주거비) 자가가구는 PIR이 전년 대비 상승(5.2→5.6배)하였으나, 임차가구는 월평균 소득이 월임대료보다 더 상승하여 RIR이 전년 대비 감소(20.2→18.4%)한 것으로 나타났다.\r\n\r\n(주거수준) 신혼부부의 최저주거기준 미달 가구 비율은 ’19년 3.9%에서 ’20년 1.9%로 감소하고, 1인당 주거면적도 ‘19년 24.6㎡에서 ‘20년 26.9㎡로 증가하는 등 주거수준이 전반적으로 개선되었다.\r\n\r\n<div class=\"note-box\">* 지하·반지하·옥탑 거주 가구 비중은 ’20년 0.3%로 ’19년 0.5% 대비 감소</div>\r\n\r\n\r\n(정책수요) 가장 필요한 주거지원으로 ‘주택 구입자금 대출지원(48.6%)’, ‘전세자금 대출지원(28.2%)’ 순으로 응답하였다.\r\n\r\n< ③ 고령가구 >\r\n\r\n* 고령가구란 가구주의 연령이 만65세 이상인 가구를 말함\r\n\r\n\r\n(주거안정성) 고령가구는 75.4%가 자가에 거주하고 있으며, 주거이동률은 14.7%로 낮아 다른 계층에 비해 안정적인 것으로 나타났다.\r\n\r\n<div class=\"note-box\">* (자가점유율) 고령 75.4%, 일반 57.9%, 신혼부부 46.1%, 청년 16.1%\r\n(주거이동률) 고령 14.7%, 일반 37.2%, 신혼부부 66.5%, 청년 82.2%</div>\r\n\r\n\r\n거주 주택 유형별로는 수도권에서는 아파트(50.9%)가 가장 많으나, 수도권 외에서는 단독주택(58.0%)이 가장 많아 지역별 차이를 보였다.\r\n\r\n(주거비) 고령가구는 월 평균 소득이 적어(186.8만원) 자가가구의 PIR(9.7배) 및 임차가구의 RIR(29.9%)이 일반가구 대비 높으나, 대출금 상환에 부담을 느끼는 비율은 45.8%로, 일반가구(63.9%)에 비해 낮은 것으로 나타났다.\r\n\r\n<div class=\"note-box\">* (일반가구) 월평균 소득 328.1, PIR 5.5, RIR 16.6</div>\r\n\r\n\r\n(주거수준) 고령가구의 최저주거기준 미달가구 비율은 ’19년 3.9%에서 ’20년 3.4%로 감소했으나, 1인당 주거면적은 45.2㎡로 전년(45.3㎡) 대비 소폭 감소한 것으로 나타났다.\r\n\r\n(정책수요) 가장 필요한 주거지원으로 ‘주택 구입자금 대출지원(24.7%)’, ‘개량·개보수(21.8%)’ 순으로 응답하였다.\r\n\r\n[ 7. 주거실태조사 개요 및 자료 공개 ]\r\n\r\n국토교통부는 국민들의 주거환경과 주거이동, 가구특성과 관련된 기초자료 수집을 위해 2006년부터 주거실태조사(일반가구)를 격년단위로 실시해 왔으며, 2017년부터는 보다 적시성 있는 정책수립을 위해 매년 주거실태조사를 실시하고 있다.\r\n\r\n이번 조사는 국토연구원과 한국리서치에 의뢰해 전국 5.1만 가구를 대상으로 `20년 7～12월까지 1:1 개별 면접방식으로 진행되었다.\r\n\r\n코로나19 방역지침을 준수하여 조사를 진행하였으며, 비대면조사를 희망하는 응답자에 한해 전화조사도 병행하였다.\r\n\r\n｢2020년 주거실태조사｣에 대한 연구보고서는 8.13일부터 국토교통 통계누리(www.stat.molit..go.kr)에, 마이크로데이터는 통계청 마이크로데이터 정보제공 시스템(www.mdis.go.kr)에 품질점검을 거친 후 9월 말 공개할 예정이다.',0);
INSERT INTO `article_tbl` VALUES (180953,1,31,'01053540675','2021-08-19','2021-08-19','0000-00-00','0000-00-00','부동산 중개보수 반값? 이러다 공인중개사 다 망할 판…','0','-이미 결론난 보여주기식 국토부 공청회? 보는 내내 의문 들어…<br>\r\n-서민이 중개수수료 부담? 15억 집 사는 사람이 서민?<br>',NULL,'▲국토부, 공인중개사 의견 경청할 의도 있는지 ‘의문’\r\n\r\n지난 8월 17일 오후에 국토부에서 부동산 중개수수료 요율에 대한 대국민 토론회가 열렸다.참석자들의 면면을 보니, 국토부가 국민을 의식한 흔적이 곳곳에서 보였다. 가장 먼저 든 생생각은 이 중요한 현장을 알릴 언론의 참석 정도였다. 소비자 단체는 그렇다 쳐도 언론사가 한겨레신문 한 곳만 왔다니 전혀 이해가 가지 않았다. 적어도 알려진 주요 언론사들은 참석시켜야 하는 게 상식인데 말이다.\r\n\r\n또한 한 가지 의문이 든 것은 진행자의 한 발언이었다. 국토부가 공인중개사협회에 불과 하루 전에 관련 자료를 줬으며, 그 다음날 바로 토론회에 나오라고 했다는 말이었다. 국토부가 진정 공인중개사들의 의견을 들을 준비가 되어 있는지 의심이 들었다.\r\n\r\n▲국민 달래기식 형식적 토론회에 그쳐… 공인중개사 의견 ‘묵살’까지\r\n\r\n필자의 생각에 이번 토론회는 ‘국민을 달래기 위한 국토부의 형식적인 행사’에 지나지 않았다고 본다. 또한 거기에 공인중개사협회는 들러리로 참석해달라고 한 것으로 해석이 된다.\r\n\r\n공인중개사협회가 “2시간에 걸친 토론회를 하고 내일 모레 발표를 한다는 것은 모순이다”라고 지적하자, 진행자는 그 의견을 싹둑 무시한 채 진행을 그냥 이어갔다. 이 11만 5천여명의 공인중개사들의 분노를 자아내게 한 파렴치한 행위였다.\r\n\r\n▲국토부 제공한 ‘대국민인식조사’ 자료, 표본 대표성도 없어…\r\n\r\n국토부는 ‘부동산 중개수수료 요율에 대한 일방적인 시민들의 반응’이라는 자료를 내밀었다. 하지만 이 자료는 표본을 대표할만한 어떠한 근거도 없었다. 헌데 이를 ‘대국민인식조사’라고 발표했다. 이는 국토부가 부동산 중개수수료를 가지고 국민과 공인중개사들의 편을 가르려고 한 것은 아닌가 하는 의구심을 가지게 했다.\r\n\r\n또한 ‘부동산 중개 서비스’를 계속 강조하는데, 다른 자격사들의 서비스에 대한 대국민인식 조사를 해본 적이 있는가? 예로 변호사나 법무사의 수임료를 나라가 정하지는 않는다. 그들의 서비스를 공정이라는 잣대에 놓고 대국민인식조사를 해보신 적이 있을까? 없다. 왜 공인중개사들만 서비스의 질에 대한 책임을 져야 하는지 이해가 되지 않았다.\r\n\r\n▲중개 현장 모르고 일하는 국토부?\r\n이는 마치 공인중개사들이 단순히 집 한 번 보여주고 수백만원이나 받는 나쁜 사람들로 매도하는 듯해 느껴지기도 했다. 국토부 관계자들은 실제 부동산 중개 현장에 나가본 적이 있는가? 한 집을 10번, 20번, 아니 많게는 70번까지 보여주고 계약을 하는 경우도 있다는 것을 간과한다. 계약이 성사되지 않으면 그 과정의 모든 노력들이 매몰비용이 되고 만다. \r\n\r\n또한 국토부는 공인중개사의 거래신고의무화는 당사자들과 공무원들의 편의를 위해 공인중개사들이 양심을 지키고 부담을 떠안으면서까지 이행하고 있다는 점을 인식해야 한다.\r\n\r\n세대열람과 세금완납증명등을 통해 당사자에 대한 정보 열람권을 주면 안전하게 거래할 수 있도록 모든 공인중개사는 준비가 돼 있다. 헌데 그마저도 개인정보 보호라는 형식 아래 다 막아 놓고 무슨 수로 더 이상의 정보를 원하는 지 되묻고 싶다.\r\n\r\n▲직방 등 대형 플랫폼 시장 진입이 공인중개업의 선진화?\r\n직방이나 네이버 등 대형 포털‧플랫폼이 부동산 중개업에 들어와 공인중개사들의 수수료를 반 이상 가져간다는데 이것이 중개업 선진화를 위한 길인가? 이는 시장질서를 교란시켜 대부분의 공인중개사들을 플랫폼 기업의 하수인으로 모는 결과를 가져오게 된다. 국토부 관계자들은 이에 대해 예측하며 대응 방안을 생각하고 있는지 의심스럽다.\r\n\r\n부동산 중개수수료는 현재의 요율대로도 받는 이가 드물텐데 20억짜리 아파트를 거래하면서 서민이니까 중개수수료가 비싼 것인가? 40, 50억짜리 집을 거래하는데 1%도 안되는 수수료를 받게 하는 게 국토부가 말하는 공정이고 서민을 위한 정책인가? 답해야 할 것이다.\r\n\r\n▲정부는 공인중개사들을 범죄자 취급 말라\r\n또한 국토부는 최근 집값 상승을 마치 공인중개사들의 잘못인 것처럼 연관 지어 중개사들을 범죄자 취급하고 있는데 당장 멈춰야 한다. 서울과 일부 광역시를 제외한 지방은 분리해서 생각해야 함에도 부동산 정책의 실패를 공인중개사들의 중개수수료가 너무 비싸서 그런 결과를 초래했다면 침소붕대하는 행위를 하고 있다. 이는 공인중개사들을 무시하는 행위일 뿐 아니라 손가락으로 해를 가리는 것과 같다.\r\n\r\n중개수수료보다 무자격자들의 무분별한 작업을 막는 게 먼저이다. 아무런 자격도 양심도 없이 ‘컨설팅’이라는 이름으로 중개를 하고 있음에도, 물증을 가져와야 한다는 공무원들의 대응부터 바뀌어야 한다. 분양시장에서 공인중개사를 통해서만 계약을 하는 규범이 있어야 시장 질서가 제대로 잡힐 수 있다.\r\n\r\n▲월세 전환율 인상 방안 필요… 시장 상황 고려해야\r\n빌라 수십채를 신축분양 하면서 일명 바지사장으로 매수자를 맞추고 전세를 분양가격보다 높혀 신혼부부와 젊은 청춘들을 힘들게 만드는 이들을 잡는 것도 국토부가 나서야 할일입니다.\r\n\r\n현재 월세와 보증금을 합해 전세로 전환해서 중개수수료를 받게 하고 있다. 월세를 대폭 인상하여 전세가격에 육박하는데도 전세의 중개수수료보다 현저히 낮게 책정되는데 월세 전환율을 현재의 100%에서 300~400%로 인상하는 방안이 필요하다고 본다.\r\n\r\n이는 계약갱신청구권으로 물건이 4년 동안 잠기게 되니까 지금의 100% 전환율은 엄격히 1/4내지 1/8 밖에는 되지 않는다. 앞으로 전세보다 월세가 증가할 걸로 예상이 되는데 이 또한 인상의 한 요인이라고 본다.\r\n\r\n▲짜고 치는 고스톱 ‘그만’… 공인중개사 생계도 살펴야\r\n어제 국토부가 진행한 토론회는 마치 먼저 답을 정해 놓은 채 자신들이 원하는 틀에 정책을 끼워 맞추는 ‘짜고 치는 고스톱’처럼 보였다.\r\n\r\n코로나로 인하여 소상공인들의 생계가 막막해지고 있다. 작년에 이어 올해 거래절벽이 심각하게 이어지며 생계를 위협받는 공인중개사들도 있다는 것을 알아야 한다.\r\n\r\n만약 개편이 꼭 필요하다면 이참에 의뢰인과 중개사들이 협상하게 하지 말고 고정 요율로 정해 잡음을 줄여야 한다. 의무만 강요하지 말고 공인중개사들의 입장도 신중히 살펴주기를 국토부에 간곡히 호소한다.',0);
INSERT INTO `article_tbl` VALUES (180955,1,34,'01099508943','2021-08-20','2021-08-20','0000-00-00','0000-00-00','한국공인중개사협회 남‧북부지부 ‘동맹휴업’ 결정','0','-국토부 중개보수 개편안 앞두고 공인중개사들 ‘분개’<br>\r\n-박용현 협회장 무기한 ‘단식투쟁’ 시작<br>\r\n-전 지역으로 단체행동 확산 中… 국토부 움직이나<br>',NULL,'<div class=\"news_wrap\">	<div class=\"news_img\"><img src=\"http://www.reuni.kr/img/news/210819_01.jpg\" alt=\"\"></div>	<div class=\"news_img\"><img src=\"http://www.reuni.kr/img/news/210819_02.jpg\" alt=\"\"></div>	<p class=\"txt1\">오는 8월 20일 중개보수 개편안 국토부 발표를 앞두고 한국공인중개사협회 남부지부와 북부지부는 19, 20일 이틀 동안 소등 후 동맹 휴업을 결정했다.</p>	<div class=\"news_img\"><img src=\"http://www.reuni.kr/img/news/210819_03.jpg\" alt=\"\"></div>	<div class=\"news_img\">		<img src=\"http://www.reuni.kr/img/news/210819_03a.jpg\" alt=\"\">		<span class=\"source\">동맹 휴업에 동참한 공인중개사협회</span>		</div>	<p class=\"txt1\">이들 단체는 협회장의 단식농성 및 지부장의 삭발식에도 불구하고 중개보수 개정안에 대한 공인중개사들의 의견이 받아들여지지 않자 단체행동을 의결했다. 행동에는 현직에 종사하는 대다수의 부동산이 동참할 예정이다.</p>		<div class=\"news_img\"><img src=\"http://www.reuni.kr/img/news/210819_04.jpg\" alt=\"\"></div>	<p class=\"txt1\">중개보수는 공인중개사의 생계와 직결된다. 국토부 실거래시스템에 따르면, 2020년 6월 13만 8578건이던 부동산 거래량이 2021년 6월 35.8% 감소했다. 거의 1/3이 사라진 줄어든 셈이다. 이는 중개의 완성을 통해서만 보수가 발생하는 중개업의 특성상 수입의 감소로 반영될 수 밖에 없다. 이럼에도 국토부는 부동산 정책 실패의 책임을 공인중개사에게 돌리고 있다.</p>	<p class=\"txt1\">이에 공인중개사들은 강하게 분개해 중개보수 협의가 아닌 고정요율을 요구하고 나섰다. 이는 그동안 중개보수 ‘협의’라는 단어 때문에 말이 많았기 때문이다. 또한 근래 이와 관련된 각종 소송도 늘고 있어 고정요율에 대한 주장에 힘이 실리는 추세다.</p>	<div class=\"news_img\"><img src=\"http://www.reuni.kr/img/news/210819_05.jpg\" alt=\"\"></div>	<p class=\"txt1\">어떤 매물을 중개하느냐에 따른 중개보수 구분에 대한 문제도 있다. 아파트를 중개할 때와 단독주택, 다가구주택, 상가주택을 중개할 때는 서로 다른 기준이 적용돼야 하며 시중금리의 하락에 따른 현실과 괴리된 보증금환산 요율도 중개보수의 개편논의에 반영되어야 한다고 주장한다.</p></div>',0);
INSERT INTO `article_tbl` VALUES (180956,1,34,'01000000000','2021-09-01','2021-09-01','0000-00-00','0000-00-00','[기획] 간이과세 공인중개사, 부가세 10% 법대로 받아야!','0','▲LH에 ‘부가세’ 못 받은 간이과세 공인중개사의 설움</br>\r\n▲조세법 어긴 국토부?… 이익 위해 ‘0원 세금계산서’ 발행 강요</br>',NULL,'[공인중개사소식지터 편집부] 최근 한 공인중개사가 LH(한국토지주택공사)를 상대로 간이과세 공인중개사의 부가가치세 거래징수와 관련된 소송을 제기하면서 양측의 뜨거운 공방이 예상된다.\r\n\r\n이번 소송은 국토부가 LH·SH에 보낸 공문이 “조세법에 어긋나며 부당하다”는 한 공인중개사의 반발로 시작됐다.\r\n\r\n본지 취재에 따르면, 국토부가 LH·SH에 보낸 공문에는 “간이과세 공인중개사와의 거래에서는 부가세를 계산해주지 말라”는 등의 내용이 담겨 있는 것으로 알려졌다.\r\n\r\n이번 소송을 제기한 박경윤(믿음공인중개사 대표) 공인중개사는 이에 대해 “LH·SH가 간이과세 공인중개사와의 거래에서는 부가가치세법에 따른 세금계산서를 발행할 수 없어 (자신들이) 부가세 환급을 받을 수 없다는 점을 국토부가 알고 이용한 것”이라며 “이에 어차피 환급을 받을 수 없으니 부가세를 지불하지 않고, 형식만 갖춘 0원짜리 현금영수증 발행을 간이과세 공인중개사들에게 요구해온 것”이라고 지적했다.\r\n\r\n부가가치세법에 따르면, 간이과세자는 세금납부를 간단히 하는 대신, 부가세 환급에 필요한 세금계산서 발행을 할 수 없다.\r\n\r\n취재과정의 확인결과 LH는 이에 대한 항의가 있는 경우 이전까지는 부가가치세과세표준증명 등의 서류제출을 통해 3%의 부가가치세를 인정*한 경우가 있었으며, 2021년부터는 4800만원이상 8000만원 구간의 간이 과세자에 대해서는 4%의 부가가치세를 인정해줄 것임을 확인하였다.  하지만 대다수의 공인중개사들은 관련법을 잘 몰랐기에 이런 관행은 계속 이어져 왔다. 이에 면세사업자가 아닌 간이과세 공인중개사들의 부가세 자부담에 대한 불만은 계속 커졌다.\r\n\r\n최근 참다못한 박 공인중개사가 LH를 상대로 소송을 제기했고, 법원은 ‘이행권고결정***’을 내렸다.\r\n\r\n소송을 당한 LH(한국토지주택공사)는 이행권고결정에 대한 이의신청에서 공인중개사의 부당이익을 주장하며 9명의 변호사를 선임해 반박하고 나섰고, 곧 재판 절차가 진행될 것으로 보인다.\r\n\r\n박 공인중개사는 “이(부가세)를 인정받지 못하는 것은 부당한 일”이라며 “국토부와 LH·SH 등이 자신들의 손해를 피하기 위해 법을 어기고 부가세를 계산해주지 않은 것”이라고 비판했다.\r\n\r\n이어 “하지만 간이과세 공인중개사들은 그 부가세에 대한 부담을 고스란히 짊어져야만 한다”며 “이는 말이 되지 않는다”고 호소했다.\r\n\r\n\r\n<div class=\"note-box\">\r\n* 부동산중개업의 경우 업종별부가가치세율(30%) × 부가가치세율(10%) = 3%\r\n** 2021년 이전 간이과세자는 공급대가에 업종별 부가가치율 및 세율만 적용해 납세 의무를 간편하게 이행할 수 있다. 하지만 납부세액을 계산할 때 매입 세액은 공제받을 수 없으며 세금계산서를 발급할 수도 없다.\r\n*** 이행권고결정이라 함은 소액사건의 소가 제기된 때에 법원이 결정으로 피고에게 청구 취지대로 이행할 것을 권고하는 결정을 말한다. 이에 이의 신청을 하는 경우 정식재판절차가 진행되게 된다. </div>\r\n\r\n본지가 이번 소송을 제기한 박경윤 공인중개사를 인터뷰한 결과, 그는 이같이 주장했다.\r\n\r\n<박경윤 믿음공인중개사 대표 인터뷰 내용>\r\n\r\nQ. 안녕하세요. 소개 부탁드립니다.\r\n\r\n안녕하세요. 저는 믿음공인중개사무소 대표 박경윤이라고 합니다. 반갑습니다.\r\n\r\nQ. 최근 국토부 산하 LH‧SH 등 공기업과의 거래에서 부가가치세(10%)를 인정받지 못했다는 것으로 소송을 시작하셨다고 들었는데요.\r\n\r\n네, 그렇습니다. 조세는 헌법 제59조에 따라 국회가 정한 법률에 따라야 합니다. 그런데 국토부는 아무런 법적인 근거도 없이 일방적인 공문을 ‘한국공인중개사협회’ 측에 내려 간이과세 공인중개사들의 권리를 빼앗아 갔습니다.\r\n\r\n내용은 이렇습니다. 간이과세자 공인중개사에게 부가가치세를 지난 7월 1일 이전까지는 0~3%, 그 이후부터는 0~4%만 받을 수 있다며 기존의 법률 (부가가치세법 제31조)를 전혀 무시해 온 것입니다.\r\n\r\n법률대로 10%를 받으면 ‘초과중개보수’라고 하면서 “자격정지‧등록취소‧1년 이하의 징역 또는 1천만원 이하의 벌금에 처한다”고 했습니다.\r\n\r\n이는 지금껏 공인중개사들이 부가세에 대한 법을 잘 몰랐기 때문입니다. 그래서 이번에 권리를 되찾고자 용기를 내 소송을 시작하게 됐습니다.\r\n\r\nQ. 공기업과의 부동산 거래에선 부가가치세가 없는 특별한 이유가 있나요? 법률이 있는 건지, 관행적으로 그렇게 해온 것인지?\r\n\r\n특별한 이유는 위와 같은 국토부의 말이 되지 않는 공문 때문이지요. 자신들의 ‘이익’과 ‘편의’를 우선한 나머지, 법을 망각한 것입니다. 이 때문에 공인중개사들이 일반 소비자들에게도 부가세를 받지 못했습니다. 이는 분명 억울한 일입니다. 바로 잡아야죠.\r\n\r\nQ. ‘한국공인중개사협회’도 국토부의 공문에 협조하고 있었다고요?\r\n\r\n네, 그렇습니다. 공인중개사들의 권리를 되찾아주고 지켜줘야 할 한국공인중개사협회가 도리어 간이과세 공인중개사들에게 부가세를 받지 말라고 했죠. 그래서 협회 측에도 “이 문제를 당장 시정조치 하라”고 요구한 상황입니다.\r\n\r\nQ. 마지막으로 동료 공인중개사분들에게 당부하고 싶으신 말씀은?\r\n\r\n공인중개사 여러분, 국토부의 교묘한 횡포에 기죽지 말고, 부가가치세는 부가가치세법에 정한대로 당당하게 받으시길 바랍니다. 그리고 공인중개사로서 부동산 관련 부가가치세에 대한 공부도 하셔서, 나의 정당한 권리와 이익을 되찾았으면 좋겠습니다. 모두 힘냅시다. 감사합니다.\r\n\r\n한편, 이번 소송의 결과에 따라 LH와 SH, 그리고 간이과세 공인중개사 등 모두에게 큰 영향을 줄 것으로 예상된다.',0);
INSERT INTO `article_tbl` VALUES (180957,1,35,'01091280586','0000-00-00','2021-09-22','0000-00-00','0000-00-00','[알아두면 유익한 부동산 상식]계약해지와 보증금의 반환','0','서울시 글로벌 센타에서 외국인 관련상담을 하다보면 가장 많은 상담이 임대차 계약의 해지와 보증금 반환과 관련된 상담이다.  하지만 관행이라는 이름으로 묻혀서 그렇지 잘 드러나지 않아도 임차인의 임장에 이는 내외국인은 가리지 않고 가장 많은 갈등 내지 스트레스의 원인이고 이를 위한 필요한 요건들과 소요될 시간들에 대해 알아두는 것은 매우 유익한 일이 될 것이다. ',NULL,'1. 계약해지와 보증금의 반환\r\n\r\nQ. 저는 한국에서 취업을 위해 입국한 외국인입니다. 직장의 변동으로 해외로 출국해야 하는데 보증금을 반환 받기 위해서는 어떻게 해야 하나요?\r\n\r\nA. 많은 외국인들이 고민하는 질문이다. 외국인 상담의 상당한 부분이 계약의 해지와 보증금 반환과 관련된 상담이다.\r\n\r\n먼저 알아야 할 것은 \'보증금 반환은 계약의 해지와 연관돼 있고, 계약의 해지나 보증금의 반환이 한국은 다른 국가의 관행과 다른 경우가 많다는 점\'이다. 그럼 외국인이 계약을 해지하고 보증금을 반환하기 위해 단계별로 알아야 할 점을 살펴보자.\r\n\r\n1. 임대차 계약-계약 해지시 미리 알아둬야 할 점\r\n(1) 해지권 유보의 특약\r\n임차인 또는 임대인은 임대차 계약을 체결하면서 그 계약서에 예를 들어 “전근, 취학, 비자의 연장 불가 등 부득이한 사유가 생기면 임차인이 통보한 날부터 1개월 후에 계약이 해지된 것으로 보며 이때 임차인은 월차임 3개월분의 위약금을 지불하기로 한다”라는 해지권 유보의 특약을 약정한 경우에는 임대차 기간이 남았어도 중도에 임대차계약을 해지할 수 있다.\r\n\r\n이 경우 임대인이 해지통고를 받은 날부터 1개월이 지나면 임대차는 해지된다(「민법」 제635조 및 제636조).\r\n\r\n하지만 실질적으로는 특약을 조건으로 하는 임대인의 동의를 구하기가 쉽지 않다. 그래서 그에 따른 3개월의 차임 등을 위약금으로 약정하는 것도 현명한 방법이다.\r\n\r\n해지권 유보의 특약이 없다면, 대다수의 계약에서 임차인이 임대차 계약을 해지하기는 힘들다(임대인의 ‘계약 불이행’이 있는 경우는 제외).\r\n\r\n(2) 임대차보증금의 최소화\r\n한국에서의 임대차 보증금은 다른 국가에 비해 상당히 크다. 따라서 외국인 입장에서는 임대차 보증금을 최소화하는 것도 하나의 방법이다. 이는 임차인과 임대인 모두에게 보증금에 대한 부담을 줄일 수 있는 방법이기도 하다.\r\n\r\n만약 앞의 두 방법으로 준비가 어렵다면, 다음으로 선택할 수 있는 방법은 아래와 같다.\r\n\r\nⓛ 임대차 만기 전\r\n임대차 만기 전이라면 계약해지의 준비를 미리 하는 것이 중요하다. 무엇보다 먼저 충분한 시간을 가지고 계획하는 것이 좋다. 한국에서 임대인은 만기 전 임차인이 계약해지 의사를 표시하는 경우, 임차인이 새로운 임차인을 구하고서 나갈 것으로 기대한다. 보통 이 기간은 3개월 정도로 본다.\r\n\r\n따라서 임대인과의 협상을 위해서는 충분한 시간을 가지고 보증금의 반환을 준비해야 한다. 임대인과 충분히 상의가 되면 바로 공인중개사사무소에 중개를 의뢰하고, 새로운 세입자를 구하는데 최대한 협조해 이삿날을 조정하는 것이 좋다.\r\n\r\nⓛ-2 임대차 만기 전 : 갱신 거절의 의사 표시를 한 경우\r\n임대인 또는 임차인이 임대차 기간이 끝나기 6개월 전부터 2개월 전까지 갱신 거절의 통지를 하지 않거나, 계약조건을 변경하지 않거나, 갱신하지 않는다는 뜻을 밝히지 않으면 임대차 기간이 끝나는 시점부터 전 임대차와 동일한 조건으로 다시 임대차한 것으로 본다(주택임대차보호법 제6조[계약의 갱신]].\r\n\r\n따라서 이러한 갱신 거절의 의사를 밝히지 않으면, 계약의 해지 및 임대차 보증금의 반환은 더 오랜 시간이 소요될 수 있다. 따라서 갱신 거절의 표시는 내용증명의 방법으로 하는 것이 좋으며, 이는 추후 법적인 분쟁 발생 시 증거로 사용될 수 있다.\r\n\r\n② 임대차 만기 후\r\n임대차 기간이 만기된 경우 보증금 반환은 받지 못하고 귀국 등의 사유로 해외로 나가게 된다면, ‘임차권등기명령신청’을 고려할 수 있다. 하지만 이 또한 충분한 준비기간이 필요하다.\r\n\r\n\'임차권등기명령신청’을 위해서는 먼저 임대차 기간이 만료됐는지 확인하고 만기가 경과하였다면 \'임대차등기명령신청’이 가능하다. 이후 \'등기사항증명서\'를 통해 \'임차권등기경료\'를 확인한 후 임대차 목적물 반환이 이루어져야 한다. 그래야 \'임차인의 권리, 대항력 우선변제권\'를 유지한 채 이사할 수 있으며 반환일로부터의 차임 지급의 의무도 사라지게 된다.  임차권등기명령 신청에는 통상 2주정도의 시간이 소요된다. \r\n\r\n③ 만기 후 임대차 계약의 묵시의 갱신 또는 갱신청구가 된 경우\r\n임차인은 임대차계약이 묵시적으로 갱신된 경우에는 언제든지 그 계약을 해지할 수 있다. 이 경우 임차인이 계약해지를 통지하는 경우에는 임대인이 그 통지를 받은 날부터 3개월이 지나면 임대차는 종료되게 된다(「주택임대차보호법」 제4조제1항 및 제6조의2).\r\n\r\n따라서 원활한 해지를 위해서 세입자는 4개월 정도(해지[3개월], 임차권 등기명령신청[2주])의 시간을 고려해서 계약의 해지 및 보증금 반환을 준비하면 된다.',0);
INSERT INTO `article_tbl` VALUES (180958,1,34,'01090544679','2021-10-02','2021-10-02','0000-00-00','0000-00-00','[부동산 이슈] 중개보수와 헌법소원의 이해','0','지난 9월 16일 새로운 중개보수 안이 입법예고 되었으며 이에 대해 공인중개사협회는 헌법소원을 예고하여 이전보다 더욱 치열한 싸움이 새로운 국면으로 벌어질 전망이다.  이에 따라 공인중개사 소식지 터는 앞으로 예상되어지는 과정에 대해 이해하고, 이를 계기로 이러한 중개보수에 대한 논란이 단순히 중개보수인하저지를 위한 싸움이 아니고 많은 개업공인중개사들의 바램대로 여러 문제를 안고 있는 우리의 부동산 거래관행에 대한 발전적 논의를 위한 동기가 되길 바라본다.',NULL,'[공인중개사소식지터] 최근 정부의 중개보수 인하 입장으로 촉발된 논쟁이 뜨겁다.\r\n\r\n현재 공인중개사의 중개보수에 대해서는 ‘공인중개사법 제32조(중개보수 등)’를 통해 각각 주택과 주택 외로 나누어 조례와 국토교통부령으로 정하고 있다.\r\n\r\n<blockquote>* 제32조(중개보수 등) <생략>\r\n④주택(부속토지를 포함한다. 이하 이 항에서 같다)의 중개에 대한 보수와 제2항에 따른 실비의 한도 등에 관해 필요한 사항은 국토교통부령으로 정하는 범위 안에서 특별시ㆍ광역시ㆍ도 또는 특별자치도(이하 ‘시ㆍ도’라 한다)의 조례로 정하고, 주택 외의 중개대상물의 중개에 대한 보수는 국토교통부령으로 정한다. <개정 2008.2.29, 2008.6.13, 2013.3.23, 2014.1.28, 2020.6.9></blockquote>\r\n\r\n국토교통부가 지난 8월 20일 확정 발표한 ‘부동산 중개보수 및 중개서비스 개선방안’ 의 일부인 ‘공인중개사법 시행규칙 개정안’이 9월 16일 입법예고 되었으며 앞으로 규제심사 법제처 심사 공포를 거처 시행되게 된다. \r\n\r\n*<b><a href=\"https://opinion.lawmaking.go.kr/gcom/ogLmPp/65190\" target=\"_blank\">공인중개사법 시행규칙 일부개정령안 입법예고</a></b>\r\n*<b><a href=\"https://www.lawmaking.go.kr/lmGde/govLm\" target=\"_blank\">입법과정안내</a></b>\r\n\r\n▲한국공인중개사협회, 중개보수 개편안 헌법소원제기 만장일치로 ‘가결’\r\n-업계 협의 없는 일방적 개편안… 수용할 수 없다 ‘반박’\r\n\r\n이에 한국공인중개사협회는 최근 열린 중앙투쟁위원회 회의에서 ‘중개보수 개편안’에 대한 헌법소원제기를 만장일치로 가결했다고 지난 26일 밝혔다.\r\n\r\n이러한 법률의 위헌 확인을 구하는 헌법소원심판의 결의 배경에는 중앙투쟁위원회 측의 “업계와 충분한 협의 없이 일방적으로 추진된 중개보수 개편안 입법은 받아들일 수 없다”는 입장이 포함돼 있다.\r\n\r\n한국공인중개사협회는 지난 24일 세종시 국토교통부 청사 앞에서 집회를 열고, 23일부터 25일까지 회원 공인중개사사무소 소등행사를 진행했다.\r\n\r\n이에 헌법소원심판과 함께 쟁점이 되는 시행규칙의 효력정지 가처분 신청이 이뤄질 것으로 보인다. 효력정지 가처분 신청은 헌법소원심판의 결정 될 때까지 쟁점이 되는 법률의 효력을 정지시키는 것으로, 가처분의 허용기준은 다음과 같다.\r\n\r\n*헌법소원심판에서 가처분 결정은 다투어지는 ‘공권력 행사 또는 불행사’의 현상을 그대로 유지시킴으로 인하여 생길 회복하기 어려운 손해를 예방할 필요가 있어야 하고, 그 효력을 정지시켜야 할 긴급한 필요가 있어야 한다는 것 등이 그 요건이므로, 본안심판이 부적법하거나 이유 없음이 명백하지 않는 한, 위와 같은 가처분의 요건을 갖춘 것으로 인정되고, 이에 덧붙여 가처분을 인용한 뒤 종국 결정에서 청구가 기각되었을 때 발생하게 될 불이익과 가처분을 기각한 뒤 청구가 인용되었을 때 발생하게 될 불이익에 대한 비교형량을 하여 후자의 불이익이 전자의 불이익보다 크다면 가처분을 인용할 수 있다. [2005헌사754]\r\n\r\n▲‘중개보수 개편안’ 헌법소원심판 가처분 인용 시, 재논의 필요…\r\n-공인중개사법률소비조합, 향후 정책 개편 시 중개사 영향력 키워야\r\n\r\n기대하는 결과가 나올지는 모르지만, 가처분 신청의 인용은 중개보수 관련 정책에 대한 정부의 인식을 바꿀 수 있는 중요한 계기가 될 것이라고 본다. 중개보수 관련 법안은 현직에 있는 개업공인중개사와의 충분한 논의를 해야한다는 점이다.\r\n\r\n이번 가처분이 인용되면 급한대로 관련 사안에 대해 논의할 시간을 벌 수 있고, 이를 계기로 중개 거래 문화의 발전을 모색하며 ,그를 위한 제도적 초석을 마련할 수 있을 것으로 보인다.\r\n\r\n공인중개사법률소비조합은 이번 논의에 대해 “앞으로의 중개보수 관련 정책의 개편 과정에서 개업공인중개사가 그 주체로서 자리할 수 있게 만들어 가겠다”고 말했다.',0);
INSERT INTO `article_tbl` VALUES (180959,1,NULL,'01000000000','2021-10-08','2021-10-08','0000-00-00','0000-00-00','★한 공인중개사의 죽음 매도한 \'거짓 언론\'… 최소한의 양심은 지켜야','0','[공인중개사소식지터 편집부]  성급한 보도 앞에 드러난 언론의 자화상과 그에 무방비하게 노출된 대중, 그리고 최소한의 존엄조차 지켜지지 못한 죽음과 매도된 우리의 직업을 바라보며 스스로에게 묻게 된다.  과연 어디서부터 무엇이 문제였던가? ',NULL,'▲한 공인중개사의 죽음… 원인은 보증금? 결로? \'카더라\' 거짓 뉴스 쏟아져\r\n\r\n지난 10월 4일 서울 은평구에 위치한 한 공인중개사사무소에서 끔찍한 사건이 일어났다. 이 사건의 최초 언론 보도 타이틀은 \'전세자금 돌려줘, 30대 남성(이) 공인중개사 사장 살해 후 극단선택\'이었다.\r\n\r\n첫 보도 후 수많은 언론은 물밀 듯 관련 기사를 쏟아냈고, 언론이 보도한 사건의 발생 원인은 하나 같이 ‘보증금 분쟁’이었다. 일부 언론에서는 사건의 원인으로 ‘결로에 의한 분쟁’을 꼽기도 했으나, 조사 결과 언론이 보도한 사건의 원인은 모두 사실 무근의 허위 정보였다.\r\n\r\n본지가 인근 중개업소들을 취재하는 과정에서 ‘보증금 분쟁’과 ‘결로’ 등의 이야기들이 나온 건 사실이나, 떠도는 구설일 뿐 이를 뒷받침해줄 수 있는 명확한 근거는 없었다.\r\n\r\n보도 이후 언론이 쏟아낸 거짓뉴스로 인한 화살은 사망한 공인중개사에게로 향했다. 관련 기사들에는 사망한 공인중개사를 비하하고 혐오하는 발언의 댓글들이 다량 달렸다.\r\n\r\n충격이었다. 그의 직업이 공인중개사이고, 범행 현장이 공인중개사 사무실이었다는 정황만으로 죽음의 이유를 예단하고, 직업을 비하하고 심지어는 혐오성 발언까지 서슴치 않는 반응들은 마치 먹잇감을 향해 달려오는 좀비떼 같았다.\r\n\r\n당일 오후 범행의 동기가 인터넷 방송에서 비롯됐다는 보도가 나왔다. 하지만 오보를 인정하는 언론사도, 망자에 대한 모욕을 사과하는 사람도 하나 없었다. 현 대한민국 언론의 처참한 실태였다.\r\n\r\n▲정정보도 책임 않는 한국 언론… \'기레기’ 양성소라 불려\r\n\'사망한 여성의 직업이 공인중개사였으니 당연히 이렇게 했을 것이다\'라는 추측은 누가 만드는가? 언론은 보도한 기사에 대해 오보 여부가 밝혀지면 정정 보도를 해야 한다.\r\n\r\n더구나 확인하지 못한 기사에 대해서는 더 막중한 책임을 져야 하고 최소한의 사실 확인 후 보도를 해야 한다. 거짓 뉴스는 이미 억울하게 떠난 사람을 두 번 죽이는 것이고, 그 죽음을 애도하게 하기보다 조롱과 비난으로 변모시키는 잔인함을 양성한다.\r\n\r\n\'아니면 말고\'식의 책임감 없는 보도는 기사를 보고 댓글을 다는 국민을 바보로 만드는 파렴치한 행위다.\r\n\r\n언젠가부터 일부 기사들을 보며 그들을 기레기라 부르는 걸 보면 안타깝기도 하지만, 분명 문제가 있기 때문이라고 본다. 자유로운 취재는 언론 자유의 핵심이지만, 보도는 그만큼 신중해야 한다. 통화 몇 번만으로도 확인할 수 있었던 이유에 대해 최소한의 확인도 거치지 않았다면, 언론인으로서 부끄러움을 느껴야 한다.\r\n\r\n▲언론 책임 완수는 필수… 거짓 뉴스 양산 \'사과해야\'\r\n언론 규제를 강화하는 언론중재법도 도마에 올랐지만, 법의 제정 여부를 떠나 언론은 최소한의 양심과 윤리의식을 가지고 보도를 해야 한다. ‘말 한 마디에 천냥 빚을 갚는다’는 말도 있지만, 지금 언론의 태세는 ‘말 한 마디에 천명의 목숨을 앗아간다’와 같은 경우가 많기 때문이다.\r\n\r\n미래를 예측할 수 없는 요즘, 이런 거짓 뉴스의 피해자는 내가 될 수도 있고 내 가족이 될 수도 있다. 그러니 어떤 일이 일어나도 우리는 모든 목숨에 대한 최소한의 예의를 지켜야 한다.\r\n\r\n거짓 뉴스를 양산한 언론은 이번 사건에 대해 유족 앞에 진지한 사과를 해야 한다.\r\n\r\n또한 본지는 이번 사건을 계기로 언론으로서의 사명과 최소한의 예의를 지키기 위해 더 노력하고, 만약 오보가 발생한다면 진정한 사과와 책임 완수를 피하지 않겠다고 깊게 다짐한다.\r\n\r\n마지막으로, 삼가고인의 명복을 빕니다. ',0);
INSERT INTO `article_tbl` VALUES (180960,1,32,'01091280586','2021-10-16','2021-10-18','0000-00-00','0000-00-00','유사 부동산중개업 활개… 허울뿐인 법, 구청 \'나몰라라\'','0','-이런 법(法)이 어디있나요? 잡혀야 \'위반\' 안 잡히면 \'그만\'',NULL,'[공인중개사소식지터] 법은 모든 국민 앞에 공정해야 한다. 또한 공공은 법을 기준으로 공정한 사회를 만들어야 한다. 허나 법의 사각지대는 늘 존재하고, 이 사각지대를 틈타 불법은 성행한다.\r\n\r\n법의 이런 사각지대가 발견될 경우, 공공은 이 점을 개선하기 위해 노력해야 한다. 만약 그러한 노력이 없다면 법도 결국은 형식에 지나지 않는 허상에 불과하기 때문이다.\r\n\r\n법 이야기를 꺼낸 이유는 최근 만연하는 유사 부동산중개업들 때문이다. 이들은 법의 사각지대를 이용해 정당한 자격을 가지고 일하는 공인중개사들을 위협한다.\r\n\r\n▲유사 부동산중개업, 잡혀야 \'위반\', 안 잡히면 \'상관없다?\'\r\n\r\n<blockquote>\r\n<p>공인중개사법 제8조(유사명칭의 사용금지) 공인중개사가 아닌 자는 공인중개사 또는 이와 유사한 명칭을 사용하지 못한다.</p>\r\n\r\n<p>제49조(벌칙) &#9312;다음 각 호의 어느 하나에 해당하는 자는 1년 이하의 징역 또는 1천만원 이하의 벌금에 처한다. &lt;개정 2013. 6. 4., 2014. 1. 28., 2019. 8. 20., 2020. 6. 9.&gt;</p>\r\n<p>&lt;생략&gt;</p>\r\n<p>2. 제8조의 규정을 위반하여 공인중개사가 아닌 자로서 공인중개사 또는 이와 유사한 명칭을 사용한 자</p>\r\n</blockquote>\r\n<p><img src=\"http://www.reuni.kr/img/illegal22.jpg\" title=\"\" alt=\"\" style=\"vertical-align:baseline; border:0px solid #000000\"></p>\r\n위 사진은 서대문구에 위치한 한 유사 부동산중개사무소이다. 본지는 취재를 통해 해당 업소가 실제 중개 매물 접수를 받고 있음을 확인하고, 관할 기관인 서대문구청에 민원을 제기하였다.\r\n\r\n하지만 서대문구청은 이에 대해 “이는 유사명칭 사용이 아니”라며 “단속을 위해서는 실제로 계약 등이 이루어진 계약서가 있어야 처분할 수 있다”고 말한다.\r\n\r\n물론 법의 집행은 증거가 있어야 할 수 있는 것이 맞다. 하지만 법의 사각지대를 발견하고 그 안에서 불법이 확인됐다면, 공공은 이를 개선하기 위해 나서야 한다고 본다. 존재만 하고 실효성이 없다면 살아있는 법이 아니지 않은가.\r\n\r\n<p><b>서대문구청	지적과 	02-330-1450,1452</b></p>\r\n\r\n<p>▲아무런 표기 없이 광고… ‘표시광고물 위반’ 아니다?</b>\'</p>\r\n<p><img src=\"http://www.reuni.kr/img/illegal11.jpg\" title=\"\" alt=\"\" style=\"vertical-align:baseline; border:0px solid #000000\"></p>\r\n\r\n위 광고물은 공인중개사무소 소재지도 공인중개사의 이름도 없이 버젓이 공인중개사인양 영업를 하고 있는 불법의 행태를 고스란히 보여준다.\r\n\r\n하지만 앞선 사례와 마찬가지로, 관할구청인 마포구청은 “중개대상물에 대한 광고가 아니기 때문에 표시 광고물 위반이 아니다”라고 말한다.\r\n<b><a href=\"http://www.kar.or.kr/pnews/noticeview.asp?notice=2059\" target=\"_blank\">중개대상물 표시․광고 규정 가이드라인(문답풀이)</a></b>\r\n<b>마포구청 부동산 관리팀 02-3153-9532</b>\r\n\r\n보통 광고에는 해당 제품이나 서비스를 판매하는 주체가 누구인지 표기하는 것이 상식이다. 하지만 유사 부동산중개업에 대해 이렇게 무딘 것이 관련 법에 대한 공공의 인식이다.\r\n\r\n▲불법에는 \'관대\' 적법에는 \'엄격\'… 이게 맞나요?\r\n\r\n하지만 진짜 문제는 이렇게 무딘 법이 실제 개업공인중개사들에게는 도리어 날카롭다는 것이다. 몇 가지 사례만 살펴보고자 한다.\r\n\r\n첫 번째는 ‘소속공인중개사 소유의 매물을   중개의뢰받아 공동중개한 사안을 직접거래로 경찰에 고발한 사례’이다.\r\n\r\n경기도의 한 시청은 소속공인중개사의 소유의 매물을  중개의뢰받아 공동중개한 것을 중개의뢰인과의 직접거래로 경찰에 고발조치 했고, 해당 공인중개사는 경찰의 조사를 받고서야 무혐의 처분을 받았다.\r\n\r\n당시 부동산 업무를 담당하는 공무원이 “중개의뢰인에 대한 판단도 제대로 하지 못한다는 사실에 수사 담당 경찰도 어이가 없다”고 했다.\r\n\r\n두 번째는 ‘아파트 매매 거래에서 지적도 미첨부를 이유로 한 업무정지 사례’이다.\r\n\r\n서울의 모 구청은 아파트 매매에서 지적도를 교부하지 않았다고 행정처분을 강행했고, 오랜 공방 끝에 행정소송에서 승소해 행정처분은 취소됐다.\r\n\r\n담당 공무원은 지분에 대한 이해조차 없었고 물리적 토지의 표시를 하는 지적도 제시와 교부의 구분도 하지 못한 것으로 파악됐다. 담당 공무원의 무지로 인해 공인중개사가 피해를 당한 사례로 볼 수 있다.\r\n\r\n<b>관련기사 : <a href=\"http://www.reuni.kr/index.html?article_id=135&authorid=01080073279\" target=\"_blank\">집합건물을 중개함에 있어서의 확인설명의무</a></b>\r\n\r\n공인중개사법은 \'성실‧정확하게 중개대상물의 확인‧설명을 하지 아니하거나 설명의 근거자료를 제시하지 아니한 자\'로 적시하고 있다. 또한 \'제시\'와 \'교부(交付)\'는 분명히 구분되기에 이를 잘 파악해야 한다.\r\n\r\n법은 모두에게 공정해야 한다. 또한 공무원은 그 공정을 집행할 능력을 갖추어야 한다. 만약 공무원의 무지, 능력 부족, 나태로 공정의 선을 벗어난다면 분명 그 책임을 져야 한다. 그럼에도 불구하고 법의 사각지대에서 성행하는 불법 영업에 대해서는 ‘나몰라라’ 하고 있는 공공은 다시 한번 공공의 역할에 대해서 생각해봐야 할 것이다.',0);
INSERT INTO `article_tbl` VALUES (180961,1,35,'01090544679','2021-10-23','2021-10-27','0000-00-00','0000-00-00','묵시적 갱신거절의 행사기간','0','실제 현장에서의 임대인과 임차인 사이 상담사례를 통해 부동산 거래 과정에서의 문제들을 확인해 보도록 하겠습니다.  이번에는 묵시적 갱신의 거절 행사기간에 대해 확인해 보았습니다. ',NULL,'<blockquote>주택임대차보호법 제6조(계약의 갱신) ① 임대인이 임대차기간이 끝나기 6개월 전부터 2개월 전까지의 기간에 임차인에게 갱신거절(更新拒絶)의 통지를 하지 아니하거나 계약조건을 변경하지 아니하면 갱신하지 아니한다는 뜻의 통지를 하지 아니한 경우에는 그 기간이 끝난 때에 전 임대차와 동일한 조건으로 다시 임대차한 것으로 본다. 임차인이 임대차기간이 끝나기 2개월 전까지 통지하지 아니한 경우에도 또한 같다.  <개정 2020. 6. 9.>\r\n\r\n② 제1항의 경우 임대차의 존속기간은 2년으로 본다.  <개정 2009. 5. 8.>\r\n\r\n③ 2기(期)의 차임액(借賃額)에 달하도록 연체하거나 그 밖에 임차인으로서의 의무를 현저히 위반한 임차인에 대하여는 제1항을 적용하지 아니한다.</blockquote>\r\n\r\n상담자 :  무서운 세입자가 있네요.  만기가 1개월 반 남았는데 묵시적갱신됐다고 하네요. 6~2개월 사이에 계약 해지 요구를 안했다고요\r\n\r\n양미숙 부동산연구소 :  계약은 언제 체결했나요? \r\n상담자 :  계약은 <b>2019년 11월14일</b>입니다.\r\n양미숙 부동산연구소 :  6개월~2개월은 2020년 12월 10일 이후 임대차계약부터 해당이 됩니다.  따라서 2019년 11월 14일 체결된 계약의 묵시적갱신은 6개월~1개월이 적용됩니다.\r\n양미숙 부동산연구소 :  1년 계약한게 아니라면요 \r\n<img src=\"/img/renewal.jpg\" alt=\"주택임대차보호해설집\">\r\n출처 : <a href=\"http://www.moj.go.kr/bbs/moj/118/530043/artclView.do\">주택임대차보호해설집(법무부-국토교통부)</a>\r\n\r\n상담의뢰 : <a href=\"https://m.expert.naver.com/expert/profile/home?storeId=100010578\" target=\"_blank\">양미숙부동산연구소 네이버엑스퍼트 상담</a>',0);
INSERT INTO `article_tbl` VALUES (180962,1,31,'01063060523','0000-00-00','2021-11-03','0000-00-00','0000-00-00','부동산 ‘갭 투자’ 속 전세 보증금… 돌려받을 수 있을까?','0','공인중개사도 고객도 중개실무에서 법률의 세부적인 사항까지 잘 살피지 못하는 부분들을 시리즈로 살펴보도록 하겠습니다. 먼저 임대차 잔금과 매매잔금이 동시에 치루어 지는 경우의 법리적인 부분과 실무적으로 조심해야 할 부분을 살펴보도록 하겠습니다. ','','[공인중개사소식지터] 부동산을 취득하는 방법 중 하나로 전 세입자가 살고 있는 집을 매수하는 방식으로 소액을 투자하는 ‘갭메우기 투자’가 있다.\r\n\r\n‘갭메우기 투자(갭 투자)’는 당장 입주할 필요가 없고 주택 가격이 상승할 경우 시세차익을 남길 수 있다는 장점이 있어, 예전부터 많이 성행해왔다. 하지만 근래에는 부동산 가격이 급등하면서 실거주 목적이 아닌 단순 수익을 위한 투기성으로 전락해버린 것이 현실이다.\r\n\r\n사실, 매매계약을 체결하고 소유권 이전 등기를 마치기 전에 제3자와 임대차계약을 체결해 임차인의 보증금으로 매매 잔금을 지급하는 것은 중개 실무에서는 흔히 있는 일이다.\r\n\r\n다만 이 경우, 첫째 ‘임대인을 누구로 특정할 것인가’ ‘둘째는 이미 체결된 매매계약이 해제될 경우 어떻게 할 것인가’ 하는 두 가지 문제가 발생할 수 있다.\r\n\r\n또한 갭투자는 보통 매매 잔금일과 전세 잔금일을 같은 날에 하게 된다. 이때 전세계약을 한 임차인은 전세보증금을 안전하게 보장받을 수 있을까? 각종 대법원 판례를 통해 주의할 점을 한번 알아보고자 한다.\r\n\r\n▲상황별 판례 살펴보기\r\n1. 매도인을 임대인으로 한 경우\r\n소유권 이전과 대항요건을 같은 날 동시에 한다고 해도 소유권 이전등기는 접수 한 때 효력이 발생하고, 임차인의 대항요건 효력은 다음날 \'0\'시에 발생하므로 임차권이 매수인에게 승계되지 않는다. 그러므로 임차인은 소유권 이전 후 매수인과 다시 임대차계약을 체결해야 하는 번거로움이 따른다.(대법원 1993.7.16 선고 93다17324판결)\r\n\r\n2. 매수인을 임대인으로 한 경우\r\n매매계약의 이행(분양아파트로 계약금+중도금+입주금은 지급하였으나 국민주택기금의 명의변경과 소유권이전등기 하기전)으로 매수인이 매도인으로부터 주택의 임대 권한을 부여받은 후 매매계약 해제 전 임차인이 대항력(확정일자+전입신고)을 갖추었다면 그 후 매매계약이 해제된다 하더라도 대항력을 유지하게 된다. (<a href=\"https://law.go.kr/precInfoP.do?mode=0&precSeq=133437\" target=\"_blank\">대법원 2009.1.30 선고 2008다65617 판결)</a>\r\n\r\n그러나 계약금만 지급한 상태에서 매매계약이 해제된 경우 대법원은 매매계약의 해제조건부를 두고 있다. 판결 내용은 다음과 같다. \'매도인은 매수인이 잔금 지급하기 전에 임대하는 것은 동의하나, 매매계약이 해제되면 임대차계약도 무효가 된다. 전세 권한을 부여받은 매수인이 주택을 임대한 후 매도인과 매수인 사이의 매매계약이 해제됨으로써 해제조건이 성취되어 그때부터 매수인이 주택을 전세 놓을 권한을 상실하게 된다. 이때 임차인은 전세계약을 체결할 권한이 없는 자와 전세계약을 체결한 것과 마찬가지로, 매도인의 명도청구에 대항할 수 없다‘ (<a href=\"https://www.law.go.kr/%ED%8C%90%EB%A1%80/(95%EB%8B%A432037)\" target=\"_blank\">대법원 1995.12.12 선고 95다32037 판결</a>)\r\n\r\n임차인은 등기부상 소유자인 매도인과 임대차 계약을 체결하려고 하지만, 팔고 나가는 매도인 입장에서는 새로운 계약의 당사자가 되는 것을 원하지 않는 경우가 많고, 매수인을 임대인으로 특정하면 매매계약이 해제될 때 문제가 된다. 그렇다면 중개 실무에서는 어떻게 적용하는 것이 좋을까?\r\n\r\n▲손해 발생 시 매수‧매도인 연대책임 必 기재\r\n계약의 사실관계를 특약으로 기재하고, 덧붙여서 임차인에게 손해가 발생할 경우 매도인과 매수인이 연대해서 손해배상을 부담한다는 내용을 반드시 기재해야 한다. 그래야 매도인 매수인 모두가 책임감을 갖게 되고, 유사 상황 발생 시 임차인의 손해를 막을 수 있다.',0);
INSERT INTO `article_tbl` VALUES (180963,1,35,'01032382196','2021-11-26','2021-11-26','0000-00-00','0000-00-00','[IT]내 윈도우의 버전과 32/64비트 확인하기 ','0','컴퓨터 A/S 또는 어플리케이션의 설치나 업그레이드시 필요하게 되는 윈도우즈 버전이나 64/32 bit 인지 여부를 윈도우즈 10에서 확인하는 방법입니다. ',NULL,'<P CLASS=HStyle0>* <SPAN STYLE=\'font-weight:bold\'>내 윈도우의 버전과, 윈도우가 32bit인지, 64bit인지 확인하기</SPAN></P>\r\n\r\n<P CLASS=HStyle0>&nbsp;</P>\r\n\r\n<P CLASS=HStyle0>1) 왼쪽 하단의 시작메뉴를 클릭하여 설정을 선택한다.</P>\r\n\r\n<P CLASS=HStyle0><IMG src=\"img/KKH/image002.jpg\" width=\"153\" height=\"353\" vspace=\"0\" hspace=\"0\" border=\"0\"></P>\r\n\r\n<P CLASS=HStyle0>[그림1] 시작메뉴에서 설정 선택</P>\r\n\r\n<P CLASS=HStyle0>&nbsp;</P>\r\n\r\n<P CLASS=HStyle0>2) 설정창에서 <SPAN STYLE=\'font-family:\"굴림\"\'>‘</SPAN>시스템<SPAN STYLE=\'font-family:\"굴림\"\'>’</SPAN>을 선택한다.</P>\r\n\r\n<P CLASS=HStyle0><IMG src=\"img/KKH/image004.jpg\" alt=\"그림입니다.\r\n원본 그림의 이름: DRW000027084d4e.bmp\r\n원본 그림의 크기: 가로 559pixel, 세로 291pixel\" width=\"559\" height=\"291\" vspace=\"0\" hspace=\"0\" border=\"0\"></P>\r\n\r\n<P CLASS=HStyle0>[그림1] 설정창에서 <SPAN STYLE=\'font-family:\"굴림\"\'>‘</SPAN>시스템<SPAN STYLE=\'font-family:\"굴림\"\'>’</SPAN>선택</P>\r\n\r\n<P CLASS=HStyle0>&nbsp;</P>\r\n\r\n<P CLASS=HStyle0>3) 시스템 정보 확인하기</P>\r\n\r\n<P CLASS=HStyle0>&nbsp;</P>\r\n\r\n<P CLASS=HStyle0><IMG src=\"img/KKH/image006.jpg\" alt=\"그림입니다.\r\n원본 그림의 이름: DRW000027084d50.bmp\r\n원본 그림의 크기: 가로 492pixel, 세로 526pixel\" width=\"492\" height=\"526\" vspace=\"0\" hspace=\"0\" border=\"0\"></P>\r\n\r\n<P CLASS=HStyle0>[그림3] 시스템 정보</P>\r\n\r\n<P CLASS=HStyle0>&nbsp;</P>',0);
INSERT INTO `article_tbl` VALUES (180964,1,31,'01054326254','2021-11-29','2021-11-29','0000-00-00','0000-00-00','[칼럼] 한국공인중개사협회 회장 선거의 현실과 나아갈 길','0','지난 11월 25일, 한국공인중개사협회 13대 회장 선거가 역대 최저 투표율 35.9%를 기록하며 이종혁 후보의 당선으로 막을 내렸다.  하지만 당선자만을 주목하게 되는 것이 선거라고 하지만, 그 속의 의미있는 도전과 실패로 다음이라는 희망을 기대하게 된다.  발전된 미래를 위한 실패의 의미와 그 도전의 의미를 되새겨 본다. ',NULL,'[공인중개사소식지터] 지난 11월 25일, 한국공인중개사협회 13대 회장 선거가 역대 최저 투표율 35.9%를 기록하며 이종혁 후보의 당선으로 막을 내렸다.\r\n\r\n▲금권‧조직 선거의 벽… 이변 없는 선거판\r\n그간의 회장선거와 같이 이변은 없었다. 조직선거와 금권선거의 관행은 여전히 깨지지 않았다. 이 악습을 끊어내지 않는 한 공명선거의 실천은 요원(遙遠)하다.\r\n\r\n특히 이번 선거는 공정성을 넘어 돈의 영향력이 다분한 금권선거였다고 봐도 과언이 아니다. 입후보자의 선거등록금을 3,000만원에서 5,000만원으로 인상해 회원의 피선거권 제한을 강화하는 선거제도의 개악과 함께 치러졌기 때문이다. 입후보자의 등록금과 법정 선거비용을 일정 득표율에 따라 보전하는 공직선거제도와 달리, 협회의 선거규정은 등록비와 선거에 필요한 일체의 비용을 모두 후보에게 부담한다.\r\n\r\n이로 인해 그동안 금권선거를 조장한다는 비판을 받아 왔지만, 현재까지도 아무런 개선이 없는 실정이다. 실제로 5억을 쓰면 낙선하고 6억을 쓰면 당선된다는 ‘5낙 6당’이라는 말까지 나오고 있다.\r\n\r\n공정(公定)과 선(善)의 마음으로 3년을 봉사해야 할 자리에 돈 5~6억의 금권으로 당선된 사람이 앉는다면 어떻게 되겠는가? 각종 이권이 걸린 사업들로부터 공정한 집행이 이뤄지지 않을 것이라는 합리적 의심이 든다.\r\n\r\n▲협회장 선거 개선 必… 선거 비용 폐지‧최소화 해야\r\n고로 한국공인중개사협회장 선거는 바뀌어야 한다. 선거제도와 규정을 개정해 각 급 단위의 선거를 할 때는 선거에 필요한 일체의 비용을 협회 예산으로 확보해야 한다. 입후보자의 선거등록금은 폐지하거나 최소화해 소신과 열정이 있는 회원이라면 후보로 나설 수 있게 해야 한다.\r\n\r\n봉사하고자 나선 회원에게 수억원의 비용을 지출하게 하거나, 선거비용이 없어 능력을 두고도 나서지 못하는 회원이 있어서 되겠는가? 기회의 균등을 넘어서 협회의 발전을 위해서라도 반드시 개선돼야 한다고 본다.\r\n\r\n▲구시대적 선거문화 답습… 표몰이 ‘조직선거\r\n\r\n조직선거 또한 금권선거와 함께 사라져야 할 구태(舊態)이다.\r\n\r\n조직선거는 영향력 있는 사람의 지지성향에 따라 특정 후보에게 조직적으로 표를 몰아주는 투표를 말한다. 30%중반의 투표율이 말해주듯, 다수의 회원들은 협회 선거에 관심이 없다. 무관심한 회원에게 후보자의 정보는 제한된다.\r\n\r\n제한된 정보는 합리적 선택을 어렵게 만들고 이는 지역 조직장에 대한 높은 의존도로 이어진다. 유권자가 속한 지역의 지부장, 지회장, 대의원이 어느 후보를 지지하느냐에 따라 조직적인 투표가 이뤄진다는 것이다.\r\n\r\n이런 현상은 이번 13대 회장 선거도 예외가 아니었다. 각 지역별 득표 현황을 살펴보면 바로 확인될 것이다. 각 단위의 조직장, 또는 대의원이 ‘표몰이’를 할 수 있다는 것은 한 표라도 아쉬운 후보자들에게는 엄청난 유혹으로 다가올 것이다.\r\n\r\n이것이 바로 조직투표와 금권선거가 결코 무관할 수 없는 이유이다. 그동안의 협회 선거를 보아도 실제로 지부장 출신의 후보가 회장에 당선돼왔다.\r\n\r\n▲이을재 후보의 ‘클린 선거, 중간평가 공약’… 새 선거의 불씨 지펴\r\n하지만 거센 눈보라에도 우뚝 선 나무는 있듯, 이번 선거에서도 분명 주목할 점은 있었다.\r\n\r\n바로 이을재 후보의 선거운동이 그 실상이다. 이 후보는 구습(舊習)을 깨는 새로운 형태의 선거운동을 일으켰다.\r\n\r\n이 후보를 지지하는 회원들이 자발적으로 선거기금을 모금하고, 더 나아가 자원봉사의 형태로 선거운동에 참여하는 것이다. 선거기금도 다양해서 적게는 1만원에서부터 많게는 100만원에 이르기까지 후원금을 냈다.\r\n\r\n무보수 자원봉사로 선거운동원에 등록해 지역에서 지지후보를 알리며 선거운동을 한 것이다. 그간의 회장 선거에서는 경험하지 못한 참신한 시도였다.\r\n\r\n또한 이을재 후보 선거대책본부에서는 ‘클린선거’와 ‘중간평가 서약’을 공약으로 제시했다. 스스로 깨끗한 선거풍토 조성에 앞장서 임기 중에 중간평가를 받아 회원의 신임을 확인하겠다는 파격적인 발언이었다.\r\n\r\n‘클린선거 서약’은 선거기간 부정한 선거비용을 수수한 사실이 확인되면 당선 뒤에라도 사임하겠다는 약속이다. ‘중간평가 서약’은 임기 중반에 중간평가를 위한 대의원총회를 소집해 공약이행 검증 등 업무평가를 받고 대의원 반수 이상의 신임을 받지 못하면 사임하겠다는 것이다. 정관의 규정에도 불구하고 회원의 의사에 반해 임기에 연연하지 않겠다는 선언이다.\r\n\r\n아쉽게도 이을재 후보 외에 다른 후보들의 동참은 없었다. 하지만 이을재 후보 캠프의 선거운동은 선거의 한 획을 긋는 혁명으로 남을 것으로 보인다.\r\n\r\n자발적인 선거후원금 모금과 자원봉사자로 구성된 선거운동은 협회의 선거역사에서 전무한 시도였다. 나아가 후보 자신의 ‘클린선거’와 ‘중간평가 서약’은 공명선거를 실천하고 회원을 섬기는 협회장이 되겠다는 의지의 구체적 표현이기도 했다.\r\n\r\n회원이 주체가 된 새로운 선거운동의 시도, 금권선거의 악습을 끊는 ‘클린선거’와 ‘중간평가 서약’은 선거운동 방식의 변화를 넘어 우리가 나아가야 할 새로운 선거 문화라고 생각한다.\r\n\r\n이는 득표율과 무관하게 이번 선거의 또 다른 승자로 이을재 후보를 지목하는 이유이기도 하다. 그의 용기있는 도전에 박수를 보낸다.',0);
INSERT INTO `article_tbl` VALUES (180966,1,18,'01091280586','2021-12-01','2021-12-01','2021-12-20','0000-00-00','[국토교통부|표시광고]인터넷 허위매물에 대한 단속강화 예고','0','',NULL,'<TABLE border=\"1\" cellspacing=\"0\" cellpadding=\"0\" style=\'border-collapse:collapse;border:none;\'>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:635;height:42;border-left:none;border-right:none;border-top:none;border-bottom:double #000000 2.0pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;line-height:140%;\'>인터넷 허위매물에 대한 단속강화 예고</P>\r\n	</TD>\r\n</TR>\r\n</TABLE>\r\n<P CLASS=HStyle0 STYLE=\'text-align:center;\'>- 30일부터 &#65378;표시·광고 업무 위탁기관 지정&#65379; 등 행정예고 -</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:23.6pt;text-indent:-23.6pt;\'>□ 국토교통부(장관 노형욱)는 부동산 시장의 건전하고 투명한 온라인 광고를 위해 &#65378;표시·광고 업무 위탁기관 지정 일부 개정안&#65379; 등에 대한 행정예고를 실시(‘21.11.30~12.20)한다고 밝혔다.</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:30.1pt;text-indent:-30.1pt;\'>&nbsp;ㅇ 이번 개정은 <SUP>①</SUP>실거래신고 자료를 활용한 온라인 모니터링 도입, <SUP>②</SUP>소재지 및 입주가능일 명시 기준 개선 등을 주요 내용으로 한다.</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:31.8pt;text-indent:-31.8pt;\'>&#10102; 실거래신고 자료를 활용한 온라인 모니터링 도입</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:23.7pt;text-indent:-23.7pt;\'>□ ‘20년 8월 부동산 허위·과장광고 등에 대한 모니터링 시행 이후, 소비자 발길을 유도하기 위한 소위 “낚시성 매물” 등 허위매물에 대한 단속 강화 필요성이 지속적으로 제기됐다.</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:31.8pt;text-indent:-31.8pt;\'>&nbsp;ㅇ 이에 따라 국토부는 부동산 실거래정보를 보유하고 있는 한국부동산원을 모니터링 업무 위탁 기관으로 추가 지정하고, 부동산 광고 플랫폼(네이버 부동산)과 시스템을 연계하여,</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:33.1pt;text-indent:-33.1pt;\'>&nbsp;ㅇ 거래완료 후에도 온라인에 방치되는 허위매물에 대한 단속과 부동산 광고플랫폼의 자율시정 역량을 강화하기 위해 이번 개정을 추진한다고 밝혔다.</P>\r\n<P CLASS=HStyle0 STYLE=\'margin-left:23.6pt;text-indent:-23.6pt;\'>□ 모니터링은 플랫폼 상에 노출된 광고와 실거래 정보를 비교하여 거래완료 여부를 확인하고, 거래가 완료된 부동산 광고는 삭제하도록 하기 위한 것이며,</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:32.8pt;text-indent:-32.8pt;\'>&nbsp;ㅇ 제도의 원활한 정착을 위해 3개월의 유예기간을 거쳐 거래를 성사시킨 공인중개사가 해당 물건에 대한 부동산 광고를 삭제하지 않는 경우에는 과태료를 부과(500만원 이하)할 계획이다.</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:30.3pt;text-indent:-30.3pt;\'>&nbsp;&nbsp;&nbsp;* 거래가 완료된 부동산 광고는 플랫폼 업체가 자진 삭제하되, 광고를 게재했으나 거래를 성사시키지 않은 공인중개사에 대해서는 과태료 미부과 예정</P>\r\n\r\n<TABLE border=\"1\" cellspacing=\"0\" cellpadding=\"0\" style=\'border-collapse:collapse;border:none;\'>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:597;height:31;border-left:none;border-right:none;border-top:none;border-bottom:dotted #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'>&lt;&nbsp;실거래기반 모니터링 절차 &gt;</P>\r\n	</TD>\r\n</TR>\r\n<TR>\r\n	<TD valign=\"middle\" style=\'width:597;height:248;border-left:dotted #000000 0.4pt;border-right:dotted #000000 0.4pt;border-top:dotted #000000 0.4pt;border-bottom:dotted #000000 0.4pt;padding:1.4pt 5.1pt 1.4pt 5.1pt\'>\r\n	<P CLASS=HStyle0 STYLE=\'text-align:center;\'><IMG src=\"img/PICB63D.jpg\" alt=\"그림입니다.\r\n원본 그림의 이름: PIC7BB3.jpg\r\n원본 그림의 크기: 가로 593pixel, 세로 236pixel\" width=\"593\" height=\"236\" vspace=\"0\" hspace=\"0\" border=\"0\"></P>\r\n	</TD>\r\n</TR>\r\n</TABLE>\r\n<P CLASS=HStyle0 STYLE=\'margin-left:31.3pt;text-indent:-31.3pt;\'>&#10103; 소재지 및 입주가능일 명시 기준 개선</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:35.5pt;text-indent:-35.5pt;\'><BR></P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:24.2pt;text-indent:-24.2pt;\'>□ 현행 &#65378;중개대상물의 표시·광고 명시사항 세부기준&#65379;에서는 중개대상물 소재지 명시방법을 <SUP>①</SUP>단독주택 <SUP>②</SUP>공동주택 <SUP>③</SUP>근린생활시설 중 상가건물로만 구분하여 규정하고 있어,</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:31.0pt;text-indent:-31.0pt;\'>&nbsp;ㅇ 그 외 건축물에 대해서는 소재지 명시에 대한 규정이 명확하지 않으며, 이번 개정을 통해 주택 외 건축물에 대해 읍·면·동·리 및 층수를 명시하도록 하는 등 개선을 추진한다고 밝혔다.</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:24.9pt;text-indent:-24.9pt;\'>□ 또한, 입주가능일을 ‘실제 입주일’ 또는 ‘즉시 입주’로만 표시하도록 정하고 있는 규정도 개선할 예정이다.</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:29.5pt;text-indent:-29.5pt;\'>&nbsp;ㅇ 현행 규정은 부동산 계약 이후 대출 등의 준비절차가 필요함에도 입주가능일을 특정하여 광고하도록 하는 등 실제 거래 현황과 다소 맞지 않는 부분이 있으며,</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:30.7pt;text-indent:-30.7pt;\'>&nbsp;ㅇ 이번 개정안은 이러한 규정과 현장의 간극을 좁히기 위해 거래당사자 간 합의에 따라 입주날짜를 조정할 수 있는 경우, 입주가가능한 월의 초순·중순·하순으로 입주가능일을 표시할 수 있도록 하는 내용을 담고 있다.</P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:23.5pt;text-indent:-23.5pt;\'>□ 국토교통부 부동산산업과 한정희 과장은 “이번 개정을 통해 허위매물에 대한 차단 효과가 매우 클 것으로 예상하며 이와 함께 민간플랫폼의 자율시정 역량이 한층 더 향상될 것으로 기대”한다면서, </P>\r\n\r\n<P CLASS=HStyle0 STYLE=\'margin-left:30.9pt;text-indent:-30.9pt;\'>&nbsp;ㅇ 아울러 “향후 모니터링 강화와 민간과 협업 확대를 지속적으로 추진하는 등 건전한 부동산 시장 질서를 확립에 최선의 노력을 다할 것”이라고 밝혔다.</P>\r\n',0);
INSERT INTO `article_tbl` VALUES (180967,1,31,'01022943342','2021-12-06','2021-12-06','0000-00-00','0000-00-00','1. 서울, 백년을 걷다 ','0','','news/photo_211201_10.jpg','	<div class=\"photo_type_01\">\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_10.jpg\" alt=\"\" />\r\n		<p class=\"photo_info\">서울, 백 년을 걷다</p>\r\n	</div>\r\n\r\n	<p>[서소영 세왕 부동산 글로벌 공인중개사무소 대표] 지난 2021년 11월 14일, 서울 회현‧후암‧동자동 일대에서 서울의 백 년을 기념하는 ‘캐치프레이즈’로 공인중개사의 지역 탐방 행사가 열렸다.</p>\r\n	<p>이번 행사는 공인중개사 법률소비조합의 주체로 ‘서울, 백 년을 걷다’라는 이름으로 진행됐다.</p>\r\n	<p>이번 탐방은 “서울이라는 도시를 공인중개사들이 탐방해보면 어떨까” 하는 아이디어에서 시작됐다. 세계의 많은 관광지에는 구도심 여행이 있는데, 서울은 그렇지 않으니 우리가 한번 새롭게 서울을 여행해보자는 취지였다. </p>\r\n	<p>주최 측은 코로나 시국에 맞게 인원을 최소화해 20명을 선착순으로 선발했다. </p>\r\n\r\n\r\n	<div class=\"photo_type_02\">\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_03.jpg\" alt=\"\" />		\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_07.jpg\" alt=\"\" />\r\n		<p class=\"photo_info\">▲ ‘20명의 공인중개사’ 서울 구도심 여행을 떠나다 </p>\r\n	</div>\r\n	\r\n	<p>한국의 수도 서울은 국내에서도 손꼽히는 아름다운 도시다. 한강을 기준으로 강남과 강북으로 나뉘어, 공간의 활용성도 다양하다. 또한 유수한 기업들이 터를 잡고 성장을 이뤄낸 경제의 중심지이기도 하다. </p>\r\n\r\n	<div class=\"photo_type_02\">\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_06.jpg\" alt=\"\" />\r\n		<p class=\"photo_info\">▲ ‘100년 전부터 현재까지’ 다양한 건축을 입은 서울 </p>\r\n	</div>\r\n\r\n\r\n	<p>또한 서울에는 각 지방에서 모인 사람들이 만들어낸 다양한 ‘건축양식’이 존재한다. 과거 100년 전의 양식부터 현재에 이르기까지 작은 지역 안에서 다양한 건축양식을 만날 수 있다. </p>\r\n	<p>공인중개사 법률소비조합 측은 “이번 기회를 통해 다른 지역에 대한 호기심을 채울 좋은 기회가 될 수 있다”고 설명했다. </p>\r\n	<p>이어 “100년전부터 현재까지 다양한 건축물이 어우러져 과거와 현재를 함께 담은 서울은, 기와지붕의 구옥과 고층 빌딩의 조화가 그리 어색하지 않은 매력적인 도시”라고 감상했다. </p>\r\n	\r\n	<div class=\"photo_type_02\">\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_01.jpg\" alt=\"\" />\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_02.jpg\" alt=\"\" />\r\n		<p class=\"photo_info\">▲ 탐방 지역은 서울의 성장 과정 담은 ‘회현동 후암동 동자동 일대’ 선정</p>\r\n	</div>\r\n	\r\n	<p>이번 탐방의 지역 선정은 청계천이 사이에 두고 조선시대부터 우리나라의 전통적인 상권을 형성한 종로와 구도심의 상권을 양분하던 서울 구도심의 대표지역인 회현동과 후암동, 동자동이 선정됐다. </p>\r\n\r\n	<div class=\"photo_type_02\">\r\n		<div class=\"img_half\">\r\n			<img src=\"http://www.reuni.kr/img/news/photo_211201_08.jpg\" alt=\"\" />\r\n			<img src=\"http://www.reuni.kr/img/news/photo_211201_09.jpg\" alt=\"\" />\r\n		</div>\r\n		<p class=\"photo_info\">▲ 회현동과 후암동, 회현동 일대</p>\r\n	</div>\r\n\r\n	<p>회현동과 후암동, 회현동 일대는 일제시대 조선인들이 모여사는 남촌과 대비되어 도성에 머무는 것이 금지된 일본인들이 남산기슭으로 내려오면서 형성된 지역이며 동자동 일대는 70년대 급격한 개발시기 서울의 관문 역활을 하던 서울역인근으로서의 입지로 자연스래 형성된 지역이며 최근 개발이슈들이 부각되어 지고 있는 지역이다.  그런 의미에서 이곳들은 서울의 미래까지 가늠해 볼 수 있는 지역이다. </p>\r\n	<p>그러한 이유로 해당 지역에는 ‘적산가옥’이라 하는 광복 전 일본인들이 소유했던 집이 리모델링을 거쳐 여전히 자리하고 있다. 이들은 서울역에 인접해 사창가와 같은 도시의 그늘로서 운집돼 명맥을 유지해오기도 했다. </p>\r\n\r\n\r\n	<div class=\"photo_type_02\">\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_04.jpg\" alt=\"\" />\r\n		<img src=\"http://www.reuni.kr/img/news/photo_211201_05.jpg\" alt=\"\" />\r\n	</div>\r\n\r\n	<p>다만 현재는 용산의 가장 뜨거운 개발 이슈로 떠오른 지역이기도 하다. </p>\r\n	<p>회현동 지역은 옛 서울 대표인 강한정 공인중개사 대표님이, 후암동‧동자동 일대는 이정희 용산 후암동 센트레빌 공인중개사님이 맡아 탐방을 진행했다.  </p>\r\n',0);
INSERT INTO `article_tbl` VALUES (180968,1,31,'01053540675','2021-12-13','2021-12-13','0000-00-00','0000-00-00','[칼럼] 두 얼굴의 세입자, 사람 사는 세상 맞나요?...','0','',NULL,'[칼럼=김일숙 공인중개사] 찬바람이 새차게 불던 지난 11월의 어느 날, 간만에 동네에서 알고 지내던 임대인 A씨를 만났다.\r\n\r\n그는 “요즘은 코로나보다 사람이 더 무섭다”며 깊은 한숨을 내쉬었다. 하얗게 질린 얼굴에 “무슨 일이 있었냐”고 물었지만, 그는 고개를 절레절레하며 더 이야기하고 싶지 않다고만 말했다. 계속된 대화 끝에 겨우 그의 사연을 들을 수 있었다.\r\n\r\n한 세입자와 있었던 일이었다. 선량하게 생긴 세입자에게서 낯설고 무서운 경험을 한 것이다.\r\n\r\n▲태도 확 바꾼 세입자, 대화 통하지 않아…\r\nA씨는 세입자가 신사답고 좋은 사람처럼 보여서 입주 시 집을 깔끔하게 수리해 주었다. 또한 6년 동안 불평 한마디 없이 조용히 살아줘서 정말 고맙게 생각했다.\r\n\r\n그런데 어느 순간부터 세입자의 태도가 확 바뀌었다. 근간은 A씨가 개인 사정으로 집을 팔아야 하니, 부동산에 집을 좀 보여달라고 한 때부터였다.\r\n\r\n세입자는 A씨에게 “요즘 같이 코로나19로 엄중한 시기에 어디 낯선 사람에게 집을 개방하라 하냐, 그렇게는 못한다”며 어름장을 놓았다. A씨는 그럼 사진이나 동영상이라도 보내 달라고 부탁했지만 통하지 않았다. 세입자는 “부동산을 통해서는 집을 보여줄 수 없으니, 전화하지 마라”며 통보했다. 이후 세입자는 A씨의 연락을 받지 않았다.\r\n\r\n발만 동동 구르던 중, 다행이 집을 보지 않고 집을 사겠다는 사람이 나타났다. 듣던 중 다행이었다. A씨는 매매계약을 하고 전세 만기가 되면 더 거주해도 된다는 요건을 제시하면서 5%인상을 합의했다. 그렇게 일은 잘 마무리되는 듯했다.\r\n\r\n그런데 전세 만기 2달을 두 달 남겨놓고 세입자에게서 연락이 왔다. 이사를 갈 것이니 보증금을 반환해달라는 것이었다. A씨는 “무슨 말이냐, 계속 거주할 것이라고 집을 계약했다”고 하니 세입자는 “왜 자신(세입자)에게 의사를 묻지도 않고 집을 팔았느냐, 기분이 나쁘다”며 “만기 날짜에 보증금을 반환하지 않으면 법적인 조치를 취하겠다”는 답변만 내놓았다.\r\n\r\nA씨가 사정했지만 돌아오는 대답은 험악한 말뿐이었다. 이에 A씨는 “나가려면 새로운 세입자를 들여놓고 보증금을 받아서 나가라”고 말했다. 만기일까지는 약 2달의 시간이 남아있었다. A씨는 “별일은 없겠지”하면서 부동산에 새로운 전세 계약자를 찾아달라고 했다.\r\n\r\n이후 부동산에서 연락이 왔다. 청천벽력 같은 소리였다. “세입자 변호인이 연락이 왔는데 등기부 등본을 가압류시켜 놓았으니 전달해주고, 그리고 1주일의 시간을 줄 테니 만기일에 보증금을 내놓으라는 확답을 받아달라”는 통보였다.\r\n\r\n순간 A씨는 어이가 없어 화가 치밀어 올랐다.\r\n\r\n\r\n▲각박한 사회, ‘인정’은 어디에…\r\n“이렇게 이런 인정머리 없는 사람이 있을 수 있나? 그동안 한 번도 보증금을 올리지 않고 싸게 살았는데, 어떻게 이럴수가...”\r\n\r\nA씨는 배신감과 함께 인간에 대한 회의까지 들었다. 세입자 변호인에게 “전세 만기가 남아 있는데 어떻게 가압류를 할 수가 있냐, 나가려면 집을 보여주고 새로운 세입자와 계약을 해서 보증금을 받아 가는 것이 관례 아니냐”고 사정했지만, 변호인은 정색하면서 그런 얘긴 할 필요가 없고 돈을 그 날짜에 줄 것인지 아닌지만 대답하라고 다그쳤다.\r\n\r\nA씨는 매수자한테 사정을 설명하고 전세보증금 대위변제가 가능한지 물었지만, 매수인도 전세입자가 있는 상태에서 나머지 돈만 준비된 상태라 힘들다고 답했다.\r\n\r\n답답한 A씨는 피가 마르는 듯한 심정으로 지내고 있어다. 다행히 수소문 끝에 한 지인의 도움으로 보증금반환소송까지는 가지 않고 보증금을 반환할 수 있었다.\r\n\r\nA씨는 이번 사태에서 느낀 게 크다며 “그동안 우리는 임대인과 임차인이 적당한 선에서 협의를 통해 계약 기간을 연장할 것인지, 보증금을 인상할 것인지 등을 결정해 온 것이 상식이었는데, ‘임대차 3법’이 생기면서 임차인은 보호받아야 할 약자로 구분되고, 임차인에게 손해가 되는 규정은 합의했더라도 무효라는 점이 임대인들을 참 씁쓸하게 만든다”고 말했다.\r\n\r\n이어 그는 “계약 안에서도 사람이 함께 살아가는 세상인데, 인정 하나 없이 저렇게 해 버리는 것이 정말 맞는 걸까”하는 회의감도 든다고 했다.',0);
INSERT INTO `article_tbl` VALUES (180969,1,35,'01032382196','2021-12-17','2021-12-17','0000-00-00','0000-00-00','[IT]인터넷 통신 하나가 죽었을 때 HOT SPOT 이용하기','0','',NULL,'<b>핫스팟이란?\r\n\'핫 스폿(Hot Spot)\'의 비표준어로, 핸드폰 등의 이동 단말기를 사용하여 액세스포인트가 설치된 주변 지역에서 무선으로 네트워크에 접속하여 이용할 수 있는 서비스 가능 지역을 말합니다. \r\n\r\n즉 핸드폰에서 핫스팟을 설정하고 실행하면, 그 핸드폰이 와이파이 서버로 작동할 수 있습니다. 이 와이파이 서버를 다른 와이파이 설정하듯 선택하여 PC 혹은 다른 핸드폰에서 와이파이를 이용할 수 있습니다. \r\n\r\n본인의 핸드폰, 혹은 노트북을 와이파이에 연결하고자 할\r\n때, 주변의 다른 핸드폰으로 핫스팟을 설정 실행하면 와이파이 서버로 작동하고, 이 핸드폰을 와이파이 서버로 설정하여 인터넷을 이용할 수 있습니다.\r\n\r\n가장 쉬운 예로 전에 처럼 KT가 인터넷이 죽어서 노트북에서 인터넷 뱅킹을 사용하지 못하거나 기기가 wifi 전용인 경우 스마트폰이 SKT나 LG라면 아래의 방법으로 HOT SPOT을 이용하여 노트북 등 기기에서 인터넷뱅킹 등을 이용할 수 있다.  \r\n\r\n* 아이폰에서 핫스팟 설정하기\r\n\r\n1) ‘설정’ 화면을 켜고, ‘개인용 핫스팟‘ 을 선택합니다.\r\n\r\n <img src=\"/img/hotspot/image001.jpg\" >\r\n<img width=187 height=387 src=\"/img/hotspot/image002.jpg\">[그림1] 설정 화면\r\n\r\n2) ’다른 사람의 연결 허용‘을 선택하고, ’Wi-Fi 암호‘를 선택합니다.\r\n\r\n<img src=\"/img/hotspot/image003.jpg\">\r\n<img width=187 height=391 img src=\"img/hotspot/image004.jpg\" >[그림2] 핫스팟 설정화면\r\n\r\n3) \'Wi-Fi 암호’를 설정합니다.\r\n\r\n암호는 핸드폰에서 자동으로 추천암호를 보여주기도 하고, 본인이 직접 만들어서 입력할 수도 있습니다.\r\n\r\n <img src=\"img/hotspot/image005.jpg\" >\r\n[그림3] Wi-Fi 암호 설정화면\r\n\r\n암호 설정을 마치면 그림2의 화면에 설정된 암호가 보이고, 다른사람의 연결 허용이 초록색으로 켜져 있습니다.\r\n이후 노트북이나 PC에서 와이파이를 설정한 핸드폰 이름을\r\n찾아 선택하면 됩니다.\r\n\r\n\r\n\r\n\r\n\r\n* 안드로이드 폰에서 핫스팟 설정하기\r\n\r\n\r\n\r\n\r\n\r\n1) 설정창을 열고 ‘무선 및 네트워크 설정’을 선택한다.\r\n\r\n <img src=\"img/hotspot/image007.jpg\" ><img width=180 height=360 img src=\"img/hotspot/image008.jpg\">[그림4] 안드로이드 \r\n\r\n2) ‘테더링 및 휴대용 핫스팟’을 선택한다.\r\n\r\n <img src=\"img/hotspot/image009.jpg\" >\r\n<img width=180 height=360 src=\"img/hotspot/image010.jpg\">[그림5] 테더링 및 휴대용 핫스팟 선택\r\n\r\n\r\n\r\n3) ‘휴대용 Wi-Fi 핫스팟’을 선택한다.\r\n <img src=\"img/hotspot/image011.jpg\" >\r\n[그림6] 휴대용 Wi-Fi 핫스팟을 선택한다.\r\n\r\n\r\n\r\n4) 핫스팟을 켜고, ‘WIFI 핫스팟 설정’을 선택한다.\r\n\r\n<img src=\"img/hotspot/image013.jpg\" ><img width=180 height=360 img src=\"img/hotspot/image014.jpg\" \r\n[그림7] 상단의 1번 스위치를 켜면 핫스팟이 켜진다. 이후 2번의 WIFI 핫스팟 설정을 선택한다.\r\n\r\n\r\n\r\n5) WIFI 핫스팟 설정 화면에서 비밀번호를 입력하고, 저장한다.\r\n\r\n\r\n <img src=\"img/hotspot/image015.jpg\" ><img width=180 height=360 img src=\"img/hotspot/image016.jpg\" >[그림8] 비밀번호를 정한다.\r\n\r\n\r\n* PC에서 설정된 핫스팟 이용하기\r\n\r\n1) 설정창을 엽니다.\r\n\r\n설정창은 화면 왼쪽 하단의 시작메뉴 아이콘을 클릭하면 톱니모양의 설정 아이콘이 있습니다.\r\n\r\n\r\n <img src=\"img/hotspot/image017.jpg\" >\r\n<img width=153 height=353 src=\"/img/hotspot/image018.jpg\" >&nbsp;\r\n[그림9] 화면 왼쪽 하단의 시작메뉴에서 설정을 선택한다.\r\n\r\n2) 설정창에서 ‘네트워크 및 인터넷’을 선택한다.\r\n\r\n<img src=\"/img/hotspot/image019.jpg\" >\r\n<img width=557 height=290 src=\"/img/hotspot/image020.jpg\" >\r\n[그림10] 설정창\r\n\r\n\r\n\r\n3) 네트워크 설정창에서 Wi-Fi를 선택하고, ‘사용 가능한 네트워크 표시’를 선택한다.\r\n\r\n\r\n <img src=\"/img/hotspot/image021.jpg\" >\r\n<img width=479 height=255 img src=\"/img/hotspot/image022.jpg\" alt=EMB00004ef06614 >\r\n\r\n[그림11] 네트워크 \r\n\r\n\r\n4) 이후 그림11과 같은 화면이 오른쪽 하단에 등장한다. 이곳에서 핫스팟으로 설정한 핸드폰의 이름을\r\n찾아 선택하여 Wi-Fi를 연결한다.\r\n\r\n <img src=\"/img/hotspot/image023.jpg\" >\r\n<img width=294 height=389 img src=\"/img/hotspot/image024.jpg\" \">[그림11] 사용가능한 네트워크',0);
INSERT INTO `article_tbl` VALUES (180970,1,31,'01063060523','2021-12-24','0000-00-00','0000-00-00','0000-00-00','[매물 정보] 즉시입주 가능한 목동센트럴아이파크워브 ‘숲‧공원‧학교’ 최적 입지','0','','room/room_211221_03.jpg','\r\n<script src=\"http://reuni.kr/js/jquery-1.9.1.min.js\"></script>\r\n<script src=\"http://reuni.kr/js/jquery.bxslider.js\"></script>\r\n<script type=\"text/javascript\">\r\n	$(document).ready(function(){\r\n		//매불 둘러보기 슬라이더\r\n		$(\'.room_slider\').bxSlider({\r\n			mode:\'fade\',\r\n			pagerCustom: \'.bx-pager\',\r\n			auto:true,\r\n			speed:500\r\n		});\r\n\r\n		// 우측 매물보기 플로팅 버튼 \r\n		var offset = 500;  \r\n		var duration = 500; \r\n		 var footer_h = $(\'footer\').outerHeight();\r\n		$(window).scroll(function() {\r\n			var val = $(document).height() - $(window).height() - footer_h +100;\r\n			\r\n				if($(this).scrollTop() >= val){\r\n					$(\'.floating\').addClass(\'ab\');\r\n				} else {\r\n					$(\'.floating\').removeClass(\'ab\');\r\n				}\r\n			\r\n		});\r\n	});\r\n</script>\r\n\r\n<div class=\"room_info\">\r\n\r\n	<div class=\"floating\">\r\n		<span class=\"btn_close\" onclick=\"$(\'.floating\').hide();\">닫기</span>\r\n		<a href=\"https://new.land.naver.com/rooms?ms=37.5680339,126.9068713,16&a=APT:OPST:ABYG:OBYG:GM:OR:VL:DDDGG:JWJT:SGJT:HOJT&b=B1&e=RETAIL&aa=SMALLSPCRENT&articleNo=2133361529\" target=\"_blank\"><p>상세정보보기</p></a>\r\n	</div>\r\n\r\n</br>\r\n	<div class=\"room_txt\">\r\n		▲<strong class=\"color1\">‘숲‧공원‧학교’ 최적의 입지</strong> 자랑하는 목동센트럴아이파크워브 매물<br />\r\n		▲방 분리로 ‘독립성’ 확보… <strong class=\"color1\">‘탁 트인’ 정남향 조망권</strong><br />\r\n		▲흠잡을 곳 없는 매물… 집주인 “금방 나갈 것 예상”<br /><br />\r\n\r\n		[위브파크부동산=김민주 공인중개사] 즉시 입주가 가능한 목동센트럴아이파크위브(59㎡) 매물이 나와 소개하고자 한다.\r\n	</div>\r\n\r\n	\r\n\r\n\r\n	<div class=\"tit_room\"><h3>매물 둘러보기</h3></div>\r\n	<div class=\"room_slider_wrap\">\r\n		<div class=\"room_slider\">\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_01.jpg\" alt=\"\" /></div>\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_02.jpg\" alt=\"\" /></div>\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_03.jpg\" alt=\"\" /></div>\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_04.jpg\" alt=\"\" /></div>\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_06.jpg\" alt=\"\" /></div>\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_07.jpg\" alt=\"\" /></div>\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_08.jpg\" alt=\"\" /></div>\r\n			<div class=\"slide\"><img src=\"http://reuni.kr/img/room/room_211221_09.jpg\" alt=\"\" /></div>\r\n		</div>\r\n\r\n		<div class=\"bx-pager clfix\">\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"0\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_01.jpg\" alt=\"\" /></a></div>\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"1\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_02.jpg\" alt=\"\" /></a></div>\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"2\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_03.jpg\" alt=\"\" /></a></div>\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"3\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_04.jpg\" alt=\"\" /></a></div>\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"4\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_06.jpg\" alt=\"\" /></a></div>\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"5\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_07.jpg\" alt=\"\" /></a></div>\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"6\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_08.jpg\" alt=\"\" /></a></div>\r\n			<div class=\"bx-pager-item\"><a href=\"\" data-slide-index=\"7\" class=\"bx-pager-link\"><img src=\"http://reuni.kr/img/room/room_211221_09.jpg\" alt=\"\" /></a></div>\r\n		</div>\r\n	</div>\r\n\r\n	<div class=\"room_txt\">\r\n		▲‘숲‧공원‧학교’ 최적의 입지 자랑하는 목동센트럴아이파크워브 매물<br />\r\n		‘목동센트럴아이파크위브’는 서울 양천구 신월동에 위치한 단지로, 신남초등학교‧신남중학교‧강신중학교 등이 가까이 자리하고 있다. 남쪽으로는 서울 유아숲체험장 및 계남공원을 이용할 수 있어 쾌적한 여유도 즐길 수 있다. 학권과 숲세권을 한 번에 누릴 수 있는 최적의 입지다.<br /><br /><br />\r\n\r\n\r\n		이번 매물은 현재 소유자가 입주해 새집처럼 살고 있는 집으로, ‘H타입’에 타워형이다.<br />\r\n\r\n		가장 큰 장점은 침실이 2개라서 활용도가 높다는 것이다. 도면을 보면 ‘침실1’이 넓어서 옷방으로도 사용이 가능하다. 장롱이나 큰 옷장은 이 방에 배치하면 여유가 있을 것으로 보인다.<br />\r\n	</div>\r\n\r\n\r\n	<div class=\"img_wrap\">\r\n		<div class=\"img_two clfix\">\r\n			<img src=\"http://reuni.kr/img/room/room_211221_04.jpg\" alt=\"\" />\r\n			<img src=\"http://reuni.kr/img/room/room_211221_08.jpg\" alt=\"\" />\r\n		</div>\r\n		<p class=\"img_txt\">▲방 분리로 ‘독립성’ 확보… ‘탁 트인’ 정남향 조망권</p>\r\n	</div>\r\n	\r\n\r\n	<div class=\"room_txt\">\r\n		집을 선택할 때는 라이프스타일에 따른 교통과 편의시설의 동선, 가족 구성원에 따른 방 배치 등이 중요하다.<br />\r\n		이번 ‘59타입’은 대부분 단일 가족이므로 방의 위치는 크게 상관이 없지만, 안방과 작은방이 붙어 있지 않아 독립적인 생활이 가능하다.<br /><br />\r\n		또 하나 중요한 점은 조망권이다. 거실에서 보이는 창밖이 탁 트였는지, 햇볕이 잘 들어오는 지가 중요한 요소다. 보통 남향을 선호하지만 앞에 건물이 가려져서 답답한 남향이라면, 조망이 트인 동향이 훨씬 좋다.<br />\r\n		이번 매물은 정남향으로 일조권이 좋고 앞이 시원하게 트인 최고의 조망을 가지고 있다.<br /><br />\r\n		위 사진은 이번 매물의 거실에 서서 하늘을 올려다본 풍경이다. 날씨가 맑은 맑은 가을이라면 정말 아름다운 퐁경이 예상된다. 앞에 보이는 산은 신정산으로 잘 정비된 산책로가 있는 계남근린공원이 위치하고 있다.<br /><br />\r\n		다음 사진은 거실에서 아래로 보이는 신남초등학교다. 거실에서 학교와 산이 모두 보이고, 외부에서는 아무도 집 내부를 볼 수 없는 구조로 보안에도 강하다.<br /><br />\r\n	</div>\r\n\r\n	<div class=\"img_wrap\">\r\n		<img src=\"http://reuni.kr/img/room/room_211221_02.jpg\" alt=\"\" />\r\n		<p class=\"img_txt\">▲세련된 아일랜드 식탁과 함께 환풍을 위한 커다란 창문이 있는 주방</p>\r\n	</div>\r\n\r\n	<div class=\"room_txt\">\r\n		이번 매물의 주방의 모습이다. 세련된 아일랜드 식탁과 함께 환풍을 위한 커다란 창문이 있다. 발코니에는 세탁기와 건조기를 놓을 수 있는 넉넉한 공간이 있다. 또한 안전을 위해 가스레인지 대신 인덕션‧오븐렌지‧도마살균기 등이 구비돼 있다.<br /><br />\r\n	</div>\r\n\r\n	\r\n	<div class=\"img_wrap\">\r\n		<img src=\"http://reuni.kr/img/room/room_211221_04.jpg\" alt=\"\" />\r\n		<p class=\"img_txt\">▲거실에서 현관으로 가는 통로의 모습</p>\r\n	</div>\r\n\r\n\r\n	<div class=\"room_txt\">\r\n		위 사진은 거실에서 현관으로 가는 통로의 모습이다. 방문과 문틀은 깔끔한 흰색으로 산뜻함이 돋보인다. 왼쪽으로는 안방과 공용화장실 현관이 위치하고, 정면 끝에 ‘침실1’이, 그 오른쪽에 ‘침실2’이 위치한다.<br /><br />\r\n		이번 매물을 답사한 공인중개사들은 하나 같이 “‘목동센트럴아이파크위브 59㎡’는 흠잡을 데가 없으며, 특히 이 매물은 집주인이 살아서 그런지 관리가 잘 돼 있어 입주 및 투자로 추천할 만하다”고 감탄했다.<br />\r\n		이번 매물의 소유자는 아래의 점을 강조하며, 어서 집이 나가기 전에 연락을 달라고 강조했다.<br /><br />\r\n\r\n\r\n		▲현재 집주인 거주, 입주일 협의 가능 (잔금 대출 가능)<br />\r\n		▲젊은층이 선호하는 평면<br />\r\n		▲탁 트인 조망권, 신정산 조망<br />\r\n		▲확장‧시스템에어컨 3대 배치, 침실2 붙박이장 설치. 전체 화이트톤 필름 작업<br /><br />\r\n\r\n		이번 매물과 관련한 자세한 사항을 알고 싶거나 답사를 희망한다면, 목동센트럴아이파크위브 2단지 상가에 위치한 위브파크부동산으로 문의하면 된다.\r\n\r\n	</div>\r\n\r\n</div>\r\n\r\n\r\n',1);
INSERT INTO `article_tbl` VALUES (180971,1,31,'01091280586','2022-01-22','2022-01-22','0000-00-00','0000-00-00','[부동산 칼럼] 벼랑끝의 ‘전세’… 없어진다면? ','0','-한국에만 있는 ‘전세’… 무조건 좋을까?</br> \r\n-전세난의 시작… ‘저금리’와 ‘전세자금대출’</br>\r\n-부작용만 남은 전세… ’월세전환‘의 장점은?  </br>\r\n-월세전환 함께 ‘중개보수 개편’ 논의도 필요해…</br>',NULL,'최근 전세가 줄고 월세가 늘고 있다. 일부 언론은 이를 ‘월세지옥’이라고까지 표현하지만, 다른 시각에서의 고민도 필요하다고 생각한다. 왜 그렇게 생각하는지, 아래에서 살펴보자. \r\n\r\n◆한국에만 있는 ‘전세’… 무조건 좋을까? \r\n한국에만 있는 부동산 문화 3가지는 ▲권리금 ▲선분양 ▲전세이다. 그중 전세는 부동산 거래의 한 형태이다. 최근 전세 매물이 귀해지자, 곳곳에서는 “부동산 정책의 실패 때문이다” “서민들의 내 집 마련의 꿈이 사라졌다”는 등 하소연의 목소리가 터져 나왔다. 심지어 언론은 이를 ’재앙‘이라고까지 비판했다.\r\n\r\n그렇다면, 전세가 없는 한국을 제외한 모든 나라가 부동산 지옥에서 사는 걸까? 아니다. 전세가 없다고 해서 다른 나라를 \'지옥\'이라고 할 수는 없다. 전세가 있음에도, 한국이 어느 나라보다 심각한 주거난과 부동산 문제를 겪고 있는 걸 보면 알 수 있다. \r\n\r\n이쯤에서 우리는 ’전세 제도의 한계‘와 ’전세가 가져온 부동산 문제‘에 대해 깊이 고민해봐야 한다. \r\n\r\n◆전세난의 시작… ‘저금리’와 ‘전세자금대출’\r\n‘전세’는 어떻게 시작됐을까? 과거 금융기관이 발달하기 전, 집의 일부를 빌려주는 것은 서민이 가장 쉽게 목돈을 마련하는 방법 중 하나였다. \r\n\r\n세입자는 저임금 정책으로 인한 생활비 부담을 줄일 수 있고, 임대인은 금융기관을 통해 조달하기 힘든 목돈을 손에 쥘 수 있었기 때문이다. \r\n\r\n하지만 2000년대 이후 지금까지 금리는 거의 ’제로(0)‘에 가깝게 떨어졌고, 같은 기회비용을 얻기 위한 보증금의 액수는 점점 커져갔다. \r\n\r\n전세난은 관련 정책이 등장하면서 더욱 극대화됐다. 이에 가장 큰 역할을 한 것이 바로 ’전세자금대출‘이다. 대학생을 대상으로 시작된 이 제도는, 당시 계약 현장에서 보증금 1~2천만원이 올라가는 기이한 광경을 보여주기도 했다. 보증금 1~2천만원을 늘여도, 대출 이자는 월 1~2만원에 지나지 않기 때문이었다.\r\n\r\n점점 시중의 유동자금이 지나치게 늘자, 매매가 대비 60-70% 정도였던 전세보증금이 매매가의 90%까지 육박했고, 이로 인해 ’갭투자‘라 불리는 투기가 성행하게 됐다.\r\n\r\n\r\n◆부작용만 남은 전세… ’월세전환‘의 장점은?  \r\n전세보증금은 사실상 증여임에도 과세권은 행사할 수 없었다. 이에 보증금을 부담할 경제력에 따라 부의 세습이 이뤄졌고, 소득 양극화는 점점 심해졌다.\r\n\r\n이러한 문제는 기존의 전세를 가능케 했던 ▲고금리 ▲금융기관의 높은 문턱 ▲저임금 정책 등이 무너지면서 이미 발생하고 있었다. 사실상, 부작용만 남은 것이다. \r\n\r\n그럼 만약, ‘전세’가 사라진다면 어떻게 될까?\r\n\r\n첫째, 부모세대(5~60대)의 부담이 줄어들 것이다. 분가를 할 자녀의 전세보증금 마련을 위해 본인의 집을 팔거나 줄이지 않아도 되기 때문이다. \r\n\r\n둘째, 갭투자의 기반이 사라지면서 부동산 시장이 매매차익보다 수익률 중심으로 바뀔 것이다. 현재 부동산 수익율은 은행의 이자율에 가까워지고 있다. 이런 경우, 은행에 비해 상대적 위험한 부동산에 투자할 이유가 없어진다. 부동산 투자가 늘어난 이유는 갭투자에서 얻는 매매차익 때문이었다.\r\n\r\n셋째, 보증금 반환에 대한 세입자의 부담이 줄어들 것이다. 특히 요즘과 같이 부동산 가격이 하락하는 시기에는 더욱 그렇다. 전세보증금이 90%를 육박하면서 매매가가 전세가를 담보하지 못하는 ‘깡통전세’만 봐도 그렇다. \r\n\r\n◆월세전환 함께 ‘중개보수 개편’ 논의도 필요해…\r\n월세로의 전환이 이뤄지면, 중개보수에 대한 새로운 논의도 이뤄질 것으로 본다.\r\n\r\n현재 월세의 경우, 중개보수를 ‘보증금+(월차임액 X 100)’으로 하고 있으나, 지금처럼 전월세 전환율을 4.0%에서 2.5%로 낮춘 상태에서는 분명 개편이 시급하다. 중개보수 요율의 인하와 전월세 전환율의 하락이 공인중개사의 소득을 이중으로 감소하게 했기 때문이다. \r\n\r\n살펴보니 어떠한가? 지금의 전세 제도는 현실에 맞지 않는 부분이 정말 많다. 월세 전환를 통해 오히려 부동산 시장이 새로운 기회를 맞게 될 수도 있지 않겠는가? 이 땅에 사는 모두가 한 번 생각해볼 문제이다. ',0);
INSERT INTO `article_tbl` VALUES (180972,1,18,'01091280586','0000-00-00','2022-03-02','0000-00-00','0000-00-00','토지 취득 시 ’자금조달계획서‘ 제출 의무화','0','-국토부, 부동산거래신고법 시행령 개정안 통과</br>\r\n-토지거래허가구역 내 용도지역별 허가 기준면적 강화</br>',NULL,'‘22.2.28 이후 일정 면적 이상의 토지 및 지분거래 등으로 토지를 취득하는 경우 자금조달서계획서를 의무적으로 제출해야 한다. \r\n\r\n국토교통부는 국무회의에서 위 같은 내용의 ’부동산 거래신고 등에 관한 법률‘ 시행령 및 시행규칙 일부 개정안이 의결됐다고 2월 22일 밝혔다. \r\n\r\n이에 따라 도심 내 주거지역은 현행 180㎡에서 60㎡로, 상업지역은 200㎡에서 150㎡로, 공업지역은 660㎡에서 150㎡ 등으로 각각 조정된다. \r\n\r\n단, 지자체에서 기준면적의 10%로 허가대상 면적 기준을 따로 정해서 공고할 시, 주거지역의 경우 현행 18㎡에서 6㎡ 초과 토지까지 허가대상에 포함된다. \r\n\r\n이번 개정은 토지 취득 시 편법적인 증여, 대출금을 정해진 용도 외로 활용하는 등 투기 자금이 유입되는지를 확인하기 위함이다.\r\n\r\n수도권‧광역시‧세종특별자치시의 경우, 기획부동산 피해를 최소화하기 위해 지분거래 시에는 금액과 무관하게 자금조달계획서를 제출해야 한다. 지분거래가 아니라면 1억 원 이상의 토지를 취득할 때만 자금조달계획서를 제출하도록 한다.\r\n\r\n자금조달계획서 제출을 회피하기 위해 계약을 수차례 나누어 체결하는 경우를 방지하기 위해 1년 이내 서로 맞닿은 토지를 추가 취득한 경우는 합산해 계산한다.\r\n\r\n그 외 기타지역은 상대적으로 개발 호재에 편승한 투기성 자금 유입 우려가 낮아 6억 원 이상의 토지를 취득하는 경우에만 자금조달계획서를 제출하면 된다.\r\n\r\n\r\n 토지 자금조달계획서 제출 방법은 부동산 소재지 관할 시군구청 방문 또는 인터넷(rtms.molit.go.kr)을 통해 제출이 가능하며, 공인중개사를 통해 제출하는 경우, 매수인은 25일 이내 관련 자금조달계획서를 공인중개사에게 제출해야 하며, 기간 내 제출하지 않는 경우 매수인이 별도로 제출해야 한다.\r\n\r\n이때 자금조달계획서를 부동산거래계약신고서와 별도 제출할 수 있으나, 부동산거래계약신고서만 제출되고 자금조달계획서가 제출되지 않는 경우에는 소유권 이전등기신청시 필수 제출 서류인 신고필증*이 발급되지 않는다.  \r\n\r\n김형석 국토교통부 토지정책관은 “이번 개정으로 실수요 중심의 부동산 거래 시장을 조성하고, 투기수요 유입을 차단할 것으로 기대한다”라며 “주택과 더불어 토지에 대한 투기도 근절하기 위해 지속적인 감시하고, 이상 거래에 대한 조사를 계속할 것”이라고 말했다.\r\n\r\n한편 이번에 시행되는 시행령·시행규칙 개정안은 시행일 이후 법제처 국가법령정보센터에서 확인할 수 있다.',0);
INSERT INTO `article_tbl` VALUES (180975,1,34,'01091280586','2022-03-22','2022-03-22','0000-00-00','0000-00-00','[법소조]대형 산불 피해 지역주민들을 지원 성금전달','0','','sunggum.jpg','<p>공인중개사법률소비조합(이하 \'법률소비조합\')은 2022년 3월 18일 조합원의 뜻을 모아 한국공인중개사협회(협회장 이종혁)에서 진행하는 울진·삼척 대형산불 피해 지역주민들을 지원하기 위해 범회원 『성금모금 운동』에 1,500,000원의 성금을 전달하였다.</p>\r\n\r\n<p>이날 한국공인중개사협회 이종혁 협회장과의 자리에서 성금전달에 함께한 조합원들은 공인중개사의 권리보호와 권익보호라는 법률소비조합의 취지를 설명하고, 사회적 봉사활동을 통해 공인중개사들의 사회적 참여확대와 이미지를 제고하는 계기가 되기 바라는 뜻을 전달하였다.</p>\r\n\r\n<img src=\"img/sunggum.jpg\" alt=\"성금전 달\" style=\"max-width: 100%; height: auto;\">',0);
INSERT INTO `article_tbl` VALUES (180978,1,34,'01091280586','2022-03-28','2022-03-28','0000-00-00','0000-00-00','[경기|안성] 330만원의 과태료 예고처분과 공인중개사의 분노','0','가계약 후 본계약으로 진행된 경우 부동산 거래신고를 위한 기산점에 대한 논쟁이 뜨겁다. ','ansung3.jpg','「부동산 거래신고 등에 관한 법률(법률 제17483호)」제3조는 공인중개사에게 부동산 매매거래시 거래당사자 그 실제 거래가격 등을 계약체결일부터 30일 이내에 해당 부동산 소재지를 관할하는 시군구청(신고관청)에 신고할 의무를 부과하고 있고, 이를 이행하지 않거나 거짓으로 신고한 경우 제28조에 따른 과태료 부과 대상으로 규정하고 있다. \r\n\r\n최근 한 사건으로 동조의 부동산 「계약체결일」에 대한 논란이 뜨겁다.  사건은 한 공인중개사가 공동중개를 통해 2021년 6월 14일 가계약금 200만 원을 매도인 계좌로 입금과 계약내용을 문자로 통지하였고, 매수인의 사정으로 바로 계약서 작성을 할 수 없어 2021년 7월 1일 정식 매매계약서 작성과 계약금 입금이 이루어졌다. 해당 공인중개사들은 2021년 7월 **일 이에 대한 부동산거래신고를 마쳤다. 이에 대해 경기도 안성시는 가계약일을 계약체결일로 판단하여 「부동산 거래신고 등에 관한 법률」 위반을 이유로 330만 원의 과태료 처분을 공인중개사들에게 예고하고 있다. \r\n\r\n<!--<img src=\"img/ansung1.jpg\" alt=\"과태료예고처분\" style=\"max-width: 100%; height: auto;\">-->\r\n<img src=\"img/ansung3.jpg\" alt=\"과태료예고처분\" style=\"max-width: 100%; height: auto;\">\r\n하지만 취재과정에서 안성시청(토지민원과 주소부동산팀 031-678-2891)은 관련 유권해석 및 타 시도의 처분 사례를 참조하였고, 중개사와 거래당사자간에 주고 받은 문자에 근거하여 판단을 하였다고 주장하고 있으나, 이러한 행정청의 처분에서 여러 문제점을 확인할 수 있었다. \r\n\r\n첫째, 「부동산 거래신고 등에 관한 법률」 제3조 제3항은 \"「공인중개사법(법률 제17799호)」 제2조 제4호에 따른 개업공인중개사(이하 “개업공인중개사”라 한다)가 같은 법 제26조 제1항에 따라 거래계약서를 작성ㆍ교부한 경우에는 제1항에도 불구하고 해당 개업공인중개사가 같은 항에 따른 신고를 하여야 한다. 이 경우 공동으로 중개를 한 경우에는 해당 개업공인중개사가 공동으로 신고하여야 한다.\"라고 명시하고 있다. 법률에서는 공인중개사의 신고시점을 \"거래계약서를 작성 교부\"했을 때로 그 시점을 명확히 하고 있으나 안성시청이 주장하는 유권해석은 최소한 취재과정에서는 관련민원 답변 말고 그 존재를 확인할 수 없었으며 관련 민원 답변이 행정처분의 근거가 될 수 있는가 또한 의문이다. \r\n\r\n둘째, 「공인중개사법」 제26조 제2항의 공인중개사의 거래계약서 작성은 개업공인중개사의 서명ㆍ날인을 요구하기 때문에 가계약금 입금일을 공인중개사를 처분할 수 있는 근거로 판단해서도 안된다.\r\n(가계약금 입금일에 거래신고를 할 수 있는 매도인, 매수인 인적사항, 대금 지급일, 잔금일 등이 특정되지 않는다.)\r\n\r\n셋째, 계약의 성립을 행정기관이 판단할 수 있는가의 문제이다. 계약의 성립 불성립은 사법적 판단이 필요한 문제로 행정기관이 그를 판단할수 있는 근거도 법익도 존재하지 않는다. \r\n\r\n마지막으로, 현장에서 가계약까지의 과정에서 최종적으로 부동산 서면에 표시된 이상의 내용들이 논의되어지고 결정되어지며 이에 따라 계약내용의 변경 심지어는 본계약에 이르지 못하는 경우도 다반사로 발생한다. 따라서 단순히 금전(가계약금)의 교부에 근거하여 계약의 성립을 판단하다는 것은 행정적 편의주의로 보일 뿐이며, 심지어 많은 경우 가계약금에 대한 법원의 판단 또한 그 반환에 있어 계약의 구속력 없이 부당이득으로 판단하는 경우가 부지기 수이다. \r\n\r\n이에 대한 현업에 있는 개업공인중개사의 분노는 안성시청의 처분뿐만 아니라 이에 대한 협회에 대응에까지 미치고 있다. 즉, 회원들은 협회가 일선 행정기관의 부당한 해석에 대항하지 못하고, 오히려 그에 승복하고 부당한 행정처분을 수긍하는 식의 대응을 하고 있다고 분노하고 있다. 이에 따라 공인중개사법률소비조합은 유사사례를 찾아 법적인 판단을 구해 볼 계획이다. (담당 조항준 010-9128-0586) ',0);
INSERT INTO `article_tbl` VALUES (180979,1,35,'01022943342','2022-03-31','2022-03-31','0000-00-00','0000-00-00','축척자(scale ruler)를 이용한 도면 읽기','0','토지 등의 중개실무에서 종종 필요하게 되는 스케일 자 (축척자)를 이용한 도면 읽는 법에 대해 알아보도록 하겠습니다. ','scale/5.jpg','<p style=\"text-align: left;\">중개과정에서 도면을 읽는 읽이 필요할 때가 있습니다.</p>\r\n<p style=\"text-align: left;\">예를 들어서,,</p>\r\n<p style=\"text-align: left;\">공장 중개를 할 때 고객들이 가장 많이 묻는 것이</p>\r\n<p style=\"text-align: left;\">전면 도로의 너비와 폭입니다. 컨테이너, 트럭 등의 진입이 용이한지 알아보고자 하는 것인데요,</p>\r\n<p style=\"text-align: left;\">지번만 알면 축척자를 이용하여 쉽게 도로의 너비를 알 수 있어요.</p>\r\n<p style=\"text-align: left;\">지적도 또는 토지이용계획원의 도면을 원하는 축척으로 출력하여 삼각 축척자를 이용해 거리를 환산하여 재어 볼 수 있습니다. 축척이란 일정한 비율로 축소 또는 확대되어 표현되었다는 표시입니다.</p>\r\n<img src=\"img/scale/2.jpg\" alt=\"2\" style=\"max-width: 100%; height: auto;\">\r\n<p style=\"text-align: left;\">삼각 축척자 또는 스케일 자 (scale ruler)라고 불러요.</p>\r\n<img src=\"img/scale/1.jpg\" alt=\"1\" style=\"max-width: 100%; height: auto;\">\r\n\r\n<p style=\"text-align: left;\">스케일 자는 위와 같은 모양이고 길이는 시중에 다양하게 나와있습니다.</p>\r\n<p style=\"text-align: left;\">단면이 삼각형으로 6개의 축척이 그려져있는데요, 위 사진에서 1/500 이 축척 표시입니다.</p>\r\n<img src=\"img/scale/3.gif\" alt=\"3\" style=\"max-width: 100%; height: auto;\"><p style=\"text-align: left;\">보시면, 1/500 뒤에 1/50 보이나요?</p>\r\n<img src=\"img/scale/4.gif\" alt=\"4\" style=\"max-width: 100%; height: auto;\"><p style=\"text-align: left;\">1/50, 1/300</p>\r\n<p style=\"text-align: left;\">지도의 축척과 스케일 자의 축척을 일치시켜 수치를 읽습니다. 수치는 미터(m) 단위로 표시되어 있어요.</p>\r\n<img src=\"img/scale/5.jpg\" alt=\"5\" style=\"max-width: 100%; height: auto;\">\r\n<p style=\"text-align: left;\">숫자 1 원은 1/500 축척이라는 뜻이고</p>\r\n<p style=\"text-align: left;\">숫자 2 원은</p>\r\n<p style=\"text-align: left;\">숫자 1에서 숫자 2까지 가 10미터라는 뜻입니다.</p>\r\n<p style=\"text-align: left;\">아래 사진에</p>\r\n<p style=\"text-align: left;\">토지이용계획확인원의 도면에서 확인해 보면</p>\r\n<p style=\"text-align: left;\">(저는 보기 편하려고 일부러 500 축척으로 도면을 출력했어요. )</p>\r\n<p style=\"text-align: left;\">영도 남항동 1가의 주민센터를 표본으로 설명해 볼게요.</p>\r\n<p style=\"text-align: left;\">아래 도면상의 노란색 네모가 남항동 주민센터인데요,</p>\r\n<p style=\"text-align: left;\">아래 빨간색 줄이 도로에 닿는 면이에요.</p>\r\n\r\n<img src=\"img/scale/6.jpg\" alt=\"6\" style=\"max-width: 100%; height: auto;\">\r\n\r\n<p style=\"text-align: left;\">실제 로드뷰를 보면 아래와 같은 모습입니다.</p>\r\n<img src=\"img/scale/7.png\" alt=\"7\" style=\"max-width: 100%; height: auto;\"><p style=\"text-align: left;\">빨간 선 표시의 거리를 도면상에서</p>\r\n<p style=\"text-align: left;\">스케일 자로 재어 보면,</p>\r\n<img src=\"img/scale/8.jpg\" alt=\"8\" style=\"max-width: 100%; height: auto;\">\r\n<p style=\"text-align: left;\">1/500 축척 도면에</p>\r\n<p style=\"text-align: left;\">1/500 축척 스케일 자로 15미터 확인할 수 있습니다.</p>\r\n<p style=\"text-align: left;\">스케일 자의 눈금은 미터(m) 단위입니다.</p>\r\n<p style=\"text-align: left;\">어렵지 않죠?</p>\r\n<p style=\"text-align: left;\">예를 들어</p>\r\n<p style=\"text-align: left;\">스케일 자에 없는 축척의 도면을 봐야 하는 경우가 생길 경우에는 아주 약간만 생각을 바꾸면 됩니다.</p>\r\n<p style=\"text-align: left;\">스케일 자에 표기된 축척이 아닐 경우 곱하기 쉬운 배수로 판독할 수 있어요.</p>\r\n<p style=\"text-align: left;\">1/2400 축척의 도면을 재야할 경우,</p>\r\n<p style=\"text-align: left;\">1/600 또는 1/400, 1/300, 1/200 스케일을 사용할 수 있어요.</p>\r\n<p style=\"text-align: left;\">ex)</p>\r\n<p style=\"text-align: left;\">1/2400 도면일 경우,</p>\r\n<p style=\"text-align: left;\">1/600 스케일 사용 후</p>\r\n<p style=\"text-align: left;\">수치 눈금( m) 곱하기 4로 계산하면 됩니다.</p>\r\n<p style=\"text-align: left;\">ex)</p>\r\n<p style=\"text-align: left;\">1/4500도면 일 경우,</p>\r\n<p style=\"text-align: left;\">1/500 스케일 사용 후,</p>\r\n<p style=\"text-align: left;\">수치 눈금( m) 곱하기 9로 계산하면 됩니다.</p>\r\n<p style=\"text-align: left;\">1/500축척으로 2m로 확인이 되었다면,</p>\r\n<p style=\"text-align: left;\">1/4500 도면의 실제 거리는</p>\r\n<p style=\"text-align: left;\">2m 곱하기 9 = 18m입니다.</p>\r\n<p style=\"text-align: left;\">쉬운 산수인데,</p>\r\n<p style=\"text-align: left;\">헷갈리는 건 저뿐이겠죠?</p>\r\n<p style=\"text-align: left;\">왜 눈물이..</p>',1);
INSERT INTO `article_tbl` VALUES (180980,1,32,'01091280586','2022-04-03','2022-04-12','0000-00-00','0000-00-00','부동산거래신고 2. 국토교통부에 공개질의 하였습니다. ','0','해당질의에 관하여 국토교통부 (국토교통부 주택토지실 토지정책관 토지정책과)는 관련 법령 확인 및 검토에 추가 시간 본 민원 질의에 대한 2022-04-21로 연기하였습니다. ',NULL,'인터넷매체 공인중개사 소식지 터의 발행인 조항준입니다.  취근 개업공인중개사 사이에 이슈가 되고 있는 공인중개사의 거래시점 관련하여 취재목적 질의드립니다. \r\n\r\n*관련법규*\r\n「부동산 거래신고 등에 관한 법률」제3조(부동산 거래의 신고) ① 거래당사자는 다음 각 호의 어느 하나에 해당하는 계약을 체결한 경우 그 실제 거래가격 등 대통령령으로 정하는 사항을 거래계약의 체결일부터 30일 이내에 그 권리의 대상인 부동산등(권리에 관한 계약의 경우에는 그 권리의 대상인 부동산을 말한다)의 소재지를 관할하는 시장(구가 설치되지 아니한 시의 시장 및 특별자치시장과 특별자치도 행정시의 시장을 말한다)ㆍ군수 또는 구청장(이하 “신고관청”이라 한다)에게 공동으로 신고하여야 한다. 다만, 거래당사자 중 일방이 국가, 지방자치단체, 대통령령으로 정하는 자의 경우(이하 “국가등”이라 한다)에는 국가등이 신고를 하여야 한다. <개정 2017. 2. 8., 2019. 8. 20.>\r\n<생략>\r\n③ 「공인중개사법」 제2조제4호에 따른 개업공인중개사(이하 “개업공인중개사”라 한다)가 같은 법 제26조제1항에 따라 거래계약서를 작성ㆍ교부한 경우에는 제1항에도 불구하고 해당 개업공인중개사가 같은 항에 따른 신고를 하여야 한다. 이 경우 공동으로 중개를 한 경우에는 해당 개업공인중개사가 공동으로 신고하여야 한다.\r\n\r\n「공인중개사법」 제26조(거래계약서의 작성 등) ①개업공인중개사는 중개대상물에 관하여 중개가 완성된 때에는 대통령령으로 정하는 바에 따라 거래계약서를 작성하여 거래당사자에게 교부하고 대통령령으로 정하는 기간 동안 그 원본, 사본 또는 전자문서를 보존하여야 한다. \r\n\r\n라고 하고 있습니다. 이와 관련하여\r\n\r\n1.「부동산 거래신고 등에 관한 법률」 제3조 제1항 동조 제3항은 부동산 거래신고에 관하여 거래당사자는 계약을 체결한 경우 제3항은 공인중개사는 중개가 완성되어 개업공인중개사가 거래계약서의 작성 교부한 경우로 달리 구분하고 있습니다.  이때 공인중개사 중개완성전(거래계약서의 작성ㆍ교부 이전)에 예약금(가계약금)의 교부가 이루어진 경우 신고의무기간인 30일의 기산점은 언제입니까? \r\n\r\n즉, 중개완성(거래계약서의 작성ㆍ교부이전) 개업공인중개사의 부동산거래신고의무가 발생합니까? \r\n\r\n2. 이의 판단과 관련하여 사법의 존재에 불구하고 구청(시청) 공무원이 민사로서의 계약의 성립ㆍ 불성립을 판단 및 교부된 금전의 성격에 대한 민사적 판단의 권한을 가집니까?\r\n\r\n참고로 법은 계약의 완성과 중개의 완성을  구분하고 있으며, 국토교통부 또한 일관되게 계약의 완성과 중개의 완성을 구분하여 왔습니다. ',0);
INSERT INTO `article_tbl` VALUES (180986,1,31,'01049544595','2022-04-08','2022-04-08','0000-00-00','0000-00-00','코로나 와중의 전세계약, 그 아찔함에 관하여 ','0','코로나는 모두에게 가혹했다.  요즘같이 힘든때 코로나 사망자가 발생한 중개대상물로 인한 공인중개사의 고난','ybw1.jpg','A: 지인, B: 기존 임차인, C: 임대인, D: 새로운 임차인\r\n\r\n2022년 2월 말에 아는 분(A)이 찾아와 전세를 의뢰하면서, 가능하면 빨리 세입자를 찾아 달라고 부탁했다. A의 지인이 사는 집인데 만기 전에 지방으로 급히 가야 할 사정이 생겼다는 것이다. 해당 주택의 계약을 했던 경험도 있고 하여 별 의심 없이 물건을 접수받았다. 전세 계약을 하게 되었고, 계약 후 A에게 연락이 와서 기존 임차인(B)이 지방으로 이사하는 집을 계약하는데, 자금이 필요하다며 잔금을 독촉하였다. ‘왜 이렇게 급하게 서두르지?’하는 생각이 잠깐 스치긴 했지만 ‘설마, 별일이야 있겠어?’라고 대수롭지 않게 지나쳤다. 새로운 임차인(C)이 잔금의 일부를 중도금으로 지급하고 계약은 순조롭게 진행되는 듯 보였다.\r\n\r\n잔금을 3일 앞두고 A가 부동산에 찾아와 B가 그 집에서 코로나로 인해 사망했다는 사실을 전했다. 나는 순간 망치로 머리를 한 방 맞은 듯했다. 전세를 의뢰할 때 얘기를 하지 않고 왜 이제야 말하냐고 했더니, 벌써 작년 일이고, 100일이나 지났는데 그게 무슨 문제가 되냐고 하며 대수롭지 않은 듯 가버렸다. \r\n\r\n미리 알았으면 고지를 하고 임차인을 맞췄을 텐데, 이런 내용을 모르고 계약을 했으니 C가 어떻게 받아들일지 난감하였다. B의 상속자들은 ’B의 사망 얘기를 왜 지금 해서 긁어 부스럼을 만드느냐‘며 되레 큰소리를 쳤다.\r\n\r\n고민하다가 내가 속해 있는 「공인중개사 법률소비조합」 회원들께 조언을 구해 보았다.\r\n의견은 크게 두 가지로 나뉘었다. “사람 사는데 사망 사건 있을 수 있고, 이미 계약한 상태이니 굳이 말할 필요성이 있을까~”, “사실을 알게 되었으니 지금이라도 고지해야 한다”는 것이었다. 고민 끝에 후자를 선택했다. 그게 사람의 도리라고 생각했기 때문이다. \r\n\r\n예상대로 C는 무척 놀라며 당장 계약을 파기하거나 손해배상을 청구하겠다고 했다. 누구라도 그랬을 거라는 생각에 미안하다는 말 밖에는 할 수 있는 것이 없었다. 그렇게 하루가 지나고 C가 뜻밖의 제안을 했다. 도배와 장판을 좋은 것으로 교체해 주고, 단열재 보강을 해 주면 입주해서 살겠다는 것이다. B의 상속인과 임대인(D)은 내가 그걸 왜 해 줘야 하느냐고 거절했고, 종일 두 사람을 설득하느라 진이 다 빠질 정도였지만 두 사람 모두 꿈쩍도 하지 않았다. \r\n\r\n그러던 중 한 줄기 빛 같은 판례(부산지방법원 2010. 11. 23 선고 2010가소219998 판결)를 알게 되었다. 「공인중개사 법률소비조합」 회원 중에 양미숙 박사가 이번 사건과 비슷한 판례를 찾아서 알려준 것이다. 판례를 읽는 순간 머리가 번쩍였다. B의 상속인과 D에게 판례를 전달했더니 C의 제안대로 도배, 장판, 단열재까지 해 주겠다고 했다.\r\n\r\n전쟁 같은 일을 겪고 보니 많은 생각이 들었다. 중개보수에 비해 받은 스트레스가 엄청나게 컸지만 일을 해결했다는 보람도 있고, 공인중개사들이 새삼 위대하다는 생각도 든다. 중개업을 하면서 인생 공부가 저절로 되는 것만 같고, 앞으로 어떤 고객을 만나 또 얼마나 쓰디쓴 인생 공부를 하게 될지 은근 기대(?)가 되기도 한다.\r\n모든 공인중개사들께서는 지금 대단한 일을 하고 있고, 오늘도 파이팅하시길~',0);
INSERT INTO `article_tbl` VALUES (180987,1,32,'01091280586','2022-04-12','2022-04-18','0000-00-00','0000-00-00','정부, 코로나19 피해 소상공인 임대료 감액 기준 마련 ','0','임대차분쟁조정위원회 차임증감청구권 가이드라인 마련 예정',NULL,'2020년 9월 상가임대차보호법이 개정돼 현재 임차인인 소상공인은 ‘감염병 등에 의한 경제사정의 변동’을 이유로 임대인에게 장래의 차임 또는 보증금에 대해 증감을 청구할 수 있게 됐다.\r\n\r\n하지만 그 요건이나 조정폭이 불분명해 소상공인이 차임 등의 증감청구권을 제대로 활용하기 어려운 상황이었다.\r\n\r\n이에 상가건물 임대차분쟁조정위원회(조정위원회)차임 증감 조정의 활성화를 위해 상가건물 임대차보호법 개정을 통한 구체적인 기준을 마련할 필요에 따라, 시일이 소요되는 법률 개정 전 조정위원회에서 내부 기준으로 사용할 가이드라인을 마련하려는데 의미가 있다.\r\n\r\n감염병 등에 의한 경제사정의 변동 판단 기준\r\n▲감액 협의를 요청할 수 있는 기준\r\n① 임대차계약일 이후에 감염병 등에 의한 방역 또는 예방 조치가 강화되고, ② 방역 또는 예방 조치 강화 전·후 평균 매출액이 30% 이상 감소한 경우, ‘감염병 등에 의한 경제사정의 변동’이 있는 것으로 보아 차임을 감액해 줄 것을 요청할 수 있습니다.\r\n\r\n 다만 ①방역 또는 예방 조치가 없어지고 ② 매출액이 방역 또는 예방 조치 강화 이전으로 회복되면, 임대인은 다시 차임 증액을 요청할 수 있습니다.\r\n\r\n▲차임감액 범위에 관한 기준\r\n위 기준에 의해 감염병 등에 의한 경제사정의 변동이 있다고 서로 협의가 된 경우, 아래와 같은 기준을 참조하여 임대인과 소상공인이 감액 범위를 정할 수 있도록 했다. 원칙적으로 방역 또는 예방 조치가 강화되기 전·후 평균 매출액이 감소되는 비율 만큼을 기준으로 하여 감액의 구체적인 범위를 협의할 수 있다. \r\n▲감액 기준금액 = 현재 임대료 × 방역 또는 예방 조치 강화 전·후 평균 매출액 감소율\r\n\r\n다만, 차임의 구체적인 범위를 협의하는 데 있어 금융비용 및 제세공과금을 고려해 임대인이 감내할 수 있는 범위를 넘지 않도록 해야 한다.\r\n\r\n이러한 가이드라인의 마련으로 조정위원회는 조정성립률이 높아져 소송비용 등 불필요한 부담이 줄어들 것으로 예상하고 있다. 또한 당사자 사이에 자율적 분쟁해결의 기준으로 활용될 수도 있어 차임 증감에 대한 협의가 쉬워질 것으로 보고있다.  \r\n',0);
INSERT INTO `article_tbl` VALUES (180989,1,31,'01091280586','2022-06-12','2022-06-12','0000-00-00','0000-00-00','기자가 부동산을 잘 모르거나 공부하지 않으면 ','0','부동산 거래를 모르는 신문기사에 공인중개사로서의 조언을 더해보았습니다. ',NULL,'다음은 중앙일보 2022.06.12 06:00에 입력된 전입신고날 근저당 건 집주인…\'이 특약\' 한 줄이면 안 당한다 라는 기사이다. </br></br>\r\n\r\n이걸 분석해보면 </br>\r\n<div class=\"txc-textbox\" style=\"background-color: #eeeeee; border:#c1c1c1 1px solid; padding: 10px>\r\n<p data-ke-size=\"size16\">회사원 A씨(29)는 지난해 말 서울 관악구의 한 신축 빌라에 전세보증금 2억3000만원을 주고 입주하기로 계약했다. 하지만 잔금을 치르고 입주한 뒤인 지난 2월, 은행에서 청천벽력 같은 얘기를 들었다. 빌라가 경매에 넘어갔다는 것이다. 집을 소유한 임대사업자 대표가 회사를 부도처리를 하고 잠적한 것이다.\r\n</p></div></br>\r\n\r\n\r\n일단 여기서 말하는 임대사업자가 주택임대사업자인지는 불분명하지만 주택임대사업자라면 2020년 8월 18일부터 법개정으로 소액 임대보증금등이 예외를 제외하면 임차인에게 임대보증금 가입을 책임지는 보험이 의무가입이다.  </br></br>\r\n\r\n<div class=\"txc-textbox\" style=\"background-color: #eeeeee; border:#c1c1c1 1px solid; padding: 10px>\r\n<p data-ke-size=\"size16\">\r\n“전세가, 매매가 70~80% 넘지 말아야”\r\n전세 사기를 예방하는 첫 번째 방법은 임대차 계약 전후로 등기부 등본을 꼼꼼하게 살피는 것이다. 등기사항 증명서에 집을 소유한 사람의 이름과 전세계약을 하러 나온 사람이 동일인인지를 확인하는 것이 시작이다. 만약 전세계약을 하러 나온 사람이 부동산 소유주의 대리인일 경우 반드시 위임장과 인감증명서를 확인하고 인감도장이 날인됐는지 살펴봐야 한다.\r\n\r\n</p></div></br>\r\n일단 이 부분에서 임대차거래에서 거래 당사자에게 인감도장이 요구되지도 않고 그렇게 진행하는 경우도 거의 없다.  더군다가 오히려 사기사건에서 인감증명 위임장이 없는 경우는 없다.  속여야 하니까 서류가 뭐가 필요한지는 사기꾼들이 더 잘 알고 있으며 공인중개사가 대리계약임에도 불구하고 계약을 진행한다면 그만한 충분한 이유를 가지고 결정하게 된다.  임대인이 본인임을 확인하는데는 다양한 방법이 있다.  오랜 반복적인 거래나 인간관계 등의 정말 여러 방법을 통해 공인중개사는 하나의 계약에 책임을 지기 위한 다양한 방법을 고민하고 실행한다.  또한 임대차 계약에서 엄밀한 의미의 대리계약보다는 본인의 의사결정에 의하 사자의 행위로서의 계약이 많다.  즉, 임대인의 배후자거나 가족인 경우는 매우 흔하다.  이런 경우는 심지어 대리인 표시도 하지 않는다.  그렇다고 계약에 문제가 발생하지는 않는다.  \r\n</p></div></br>\r\n<div class=\"txc-textbox\" style=\"background-color: #eeeeee; border:#c1c1c1 1px solid; padding: 10px>\r\n<p data-ke-size=\"size16\">\r\n박원갑 KB국민은행 부동산수석전문위원은 “전셋값과 해당 부동산을 담보로 받은 대출금이 매매가의 70~80%를 넘게 되면 ‘깡통전세’로 의심할 수 있는 만큼 임대차 계약할지를 다시 생각해봐야 한다”고 조언했다.\r\n</p></div></br>\r\n아주 교과서 적인 얘기이다. 이의 판단은 공인중개사가 시장상황에 따라 공격적으로 요즘같은 경우에는 보수적인 판단의 기준을 가지게 된다. </br></br>\r\n\r\n<div class=\"txc-textbox\" style=\"background-color: #eeeeee; border:#c1c1c1 1px solid; padding: 10px>\r\n<p data-ke-size=\"size16\">\r\n임대인의 세금 체납 여부 확인도 중요하다. 해당 부동산에 부과된 재산세나 상속세, 증여세, 종부세 등은 전세보증금보다 우선 환수할 수 있다. 부동산을 압류해 경매로 넘겨 환수한 돈을 조세 당국이 세입자보다 먼저 가져간다는 뜻이다. 임대차 계약 전 국세청 \'미납국세 열람제도\'를 통해 임대인의 미납국세를 미리 확인하거나 임대인에게 세급납부증명서 등을 요구해야 한다.\r\n</p></div>\r\n실무에서 10년을 훨씬 넘게 있지만 이런 경우가 손가락을 합쳐서가 아니고 한손가락으로도 충분할 만치 아니면 기억이 안날 정도로 드물다.  거의 계약안하겠다는 얘기로 들릴수 있다는 걸로 생각하면 된다. </br></br>\r\n\r\n<div class=\"txc-textbox\" style=\"background-color: #eeeeee; border:#c1c1c1 1px solid; padding: 10px>\r\n<p data-ke-size=\"size16\">\r\n전입신고는 다음날부터 효력…특약 적극 활용해야\r\n\r\n부동산의 근저당권이 전입신고와 같은 날에 진행되면 대항력을 인정받지 못한다는 것도 주의해야 한다. 대항력은 집의 주인이 바뀌더라도 계약 기간까지 살 수 있고 보증금을 모두 돌려받을 권리다. 임차인의 대항력은 주택을 점유하고 동사무소에 전입 신고한 다음 날부터 생긴다. 부동산을 담보로 대출을 빌리는 근저당권설정등기는 등기신청일부터 효력이 발생한다.\r\n\r\n문제는 임대인이 전세계약을 맺은 당일에 해당 매물을 담보로 대출을 받은 뒤 돈을 갚지 못해 집이 경매로 넘어가면, 임차인이 전세금을 모두 돌려받지 못할 수 있다. 전입신고와 근저당권 설정을 같은 날에 했더라도, 근저당권이 전입신고에 따른 대항력보다 선순위인 만큼 경매 등으로 회수한 돈을 대출 기관이 먼저 가져가기 때문이다.\r\n\r\n이런 일을 피하려면 전세계약서의 특약을 적극적으로 활용해야 한다. 계약서의 특약에 ‘전입신고의 효력이 발생하는 계약일 다음 날까지 계약 당시 상태로 유지한다’는 특약사항을 기재하면 이러한 피해를 줄일 수 있다.\r\n\r\n또한 이러한 특약을 포함한 계약서를 작성한 뒤 동사무소에서 확정일자를 받고, 해당 주택에 거주자가 없으면 잔금을 치르기 전 미리 전입신고를 해 우선변제권(전셋집이 경매로 넘어갈 경우 우선해 돈을 돌려받을 수 있는 권리)을 빠르게 확보하고 대항력이 생기도록 해야 한다.</br>\r\n\r\n</p></div></br>\r\n\r\n대부분의 공인중개사들이 이미 관련특약을 현장에서 사용하고 있는 것으로 알고 있다.  하지만 실무에서 분양빌라가 아니라면 전세가 공실인 상태로 임대차 목적물이 인도되는 경우는 없어 별 도움되지 않는 조언으로 보이나 현장에서는 \'이삿짐은 좀 못넣더라도 확정일자와 전입신고는 반드시 챙기셔야 합니다.\' 라고 안내하고있다. ',1);
INSERT INTO `article_tbl` VALUES (180991,1,35,'01091280586','2022-07-27','2022-07-27','0000-00-00','0000-00-00','Q.모아타운이 뭔가요?','0','',NULL,'A.  모아타운 지정 근거는 ｢빈집 및 소규모주택 정비에 관한 특례법｣ 따른 ‘소규모주택정비 관리지역’ 방식을 활용해 노후도 50% 이상, 면적 10만㎡ 이내 지역을 ‘모아타운’(소규모주택정비관리지역)으로 지정한다. 이는  대규모 재개발이 어려운 노후 저층주거지의 새로운 정비모델인 \'모아주택\'을 묶어 하나의 대단지 아파트처럼 관리하는 것으로, 모아주택은 이웃한 다가구·다세대주택 필지 소유자들을 모아서 블록 단위로 공동 개발하는 소규모 정비모델로 아파트 단지처럼 체계적으로 관리할 수 있으며 다양한 편의시설도 함께 조성됩니다. 모아타운에는 건축규제 완화와 공영주차장, 공원 등 기반시설 조성을 위한 국비지원 등의 특례가 제공된다.\r\n\r\n\r\n빈집 및 소규모주택 정비에 관한 특례법 제 2 조 9. “소규모주택정비 관리지역”(이하 “관리지역”이라 한다)이란 노후ㆍ불량건축물에 해당하는 단독주택 및 공동주택과 신축 건축물이 혼재하여 광역적 개발이 곤란한 지역에서 정비기반시설과 공동이용시설의 확충을 통하여 소규모주택정비사업을 계획적ㆍ효율적으로 추진하기 위하여 제43조의2에 따라 소규모주택정비 관리계획이 승인ㆍ고시된 지역을 말한다.',0);
INSERT INTO `article_tbl` VALUES (180992,1,32,'01091280586','2022-08-02','2022-08-03','0000-00-00','0000-00-00','삼쩜삼 한번이라도 이용했다면 ','0','세무회계 플랫폼인 삼쩜삼이 최근 조회과정에서 사용자에 대한 세무대리인 선임에 대한 불충분한 고지와 그에 따른 개인정보유출 우려로 시끄럽다. ',NULL,'삼쩜삼은 복잡한 세금 신고 및 환급을 앱을 통해 손쉽게 처리해주는 세무·회계 대리 플랫폼을 표방하면서 출범했다. 하지만 최근들어 삼쩜삼에 대한 논란이 뜨겁다.  이유는 간편하게 환급액 조회를 할 수 있다고 해서 삼쩜삼을 이용했는데, 나도 모르는 세무대리인이 등록된다는 사실 때문이고 이에 대해 제대로 된 고지가 없었다는 사실 때문이다. \r\n\r\n또한 당사자가 인지하지 못한 세무대리인 등록이 문제가 되는 이유는 등록된 세무대리인이 납세사실증명, 소득증명원, 과세표준증명원 등 납세사실뿐만 아니라 납세자의 주민등록번호등 납세자의 납세 관련 정보를 임의로 볼 수 있다는 것 때문이다. 취재결과 삼쩜삼과 연관된 세무법인은 \'한결세무법인\' \'세무법인 스타밸류\' 2곳으로 확인됐다. \r\n\r\n세무대리인 해지 방법\r\n\r\n1. 먼저 <a href=\"http://www.hometax.go.kr\" width=\"750\">HOMETAX</a>에 접속하여 전체메뉴를 선택합니다. \r\n\r\n<img src=\"../img/331.jpg\" width=\"750\">\r\n\r\n2. 세무대리인 선임여부 조회</br>\r\n\r\n전체메뉴>세무대리정보>나의 세무대리인조회를 순서대로 클릭합니다.\r\n<img src=\"../img/3321.jpg\" width=\"750\">\r\n\r\n2. 그럼 아래 그림과 같이 세무대리인의 선임여부를 확인할 수 있습니다.  저의 경우 스타밸류가 저도 모르는 사이에 선임되어 있음을 알 수 있습니다. \r\n<img src=\"../img/333.jpg\" width=\"750\">\r\n\r\n3.만약 본인의 의사가 아니었다면 해임가능합니다. 이번에는 그림과 같이 전체메뉴>세무대리정보>나의세무대리인해임을 선택합니다. \r\n<img src=\"../img/3322.jpg\" width=\"750\">\r\n\r\n4. 아래 그리과 같이 해지를 위한 화면에서 세무대리인 해지를 하시면 됩니다. \r\n<img src=\"../img/336.jpg\" width=\"750\">\r\n\r\n',0);
INSERT INTO `article_tbl` VALUES (180993,1,32,'01090544679','2022-08-16','2022-08-16','0000-00-00','0000-00-00','[속보]  2022년 8월 12일 발표한「2022년 광복절 특별사면」중 공인중개업에 대한 행정제재의 해제범위','0','공고 제2022-1083호\r\n\r\n◉ 국토교통부 공고 제2022-1083 호\r\n\r\n공인중개업에 대한 제재조치의 해제범위 공고\r\n\r\n2022년 8월 12일 발표한「2022년 광복절 특별사면」중 공인중개업에 대한 행정제재의 해제범위에 관한 구체적 지침을 다음과 같이 공고 합니다.\r\n\r\n2022년 8월 16일  \r\n국토교통부장관',NULL,'◉ 국토교통부 공고 제2022-1083호\r\n\r\n \r\n\r\n \r\n\r\n공인중개업에 대한 제재조치의 해제범위 공고(안)\r\n\r\n \r\n\r\n  2022년 8월 12일 발표한「2022년 광복절 특별사면」중 공인중개업에 대한 행정제재의 해제범위에 관한 구체적 지침을 다음과 같이 공고 합니다.\r\n\r\n \r\n\r\n2022년 8월 16일  \r\n\r\n국토교통부장관\r\n\r\n \r\n\r\n \r\n\r\n1. 특별감면 조치의 취지\r\n\r\n \r\n\r\n ㅇ 국민생활에 밀접한 공인중개업에 대한 업무정지 처분을 감면하여 생업에 조속히 복귀할 수 있도록 지원\r\n\r\n \r\n\r\n2. 제재조치의 해제범위\r\n\r\n \r\n\r\n ㅇ 공인중개사법을 위반하여 2022. 8. 14. 이전 업무정지처분을 받고 2022. 8. 15. 현재 업무정지 중에 있거나 폐업신고 한 자로서 업무정지기간이 지나지 아니한 개업공인중개사\r\n\r\n \r\n\r\n ㅇ 다만, 공인중개사법 위반으로 최근 1년 이내 2회 이상 업무정지처분을 받은 경우는 제외\r\n\r\n \r\n\r\n3. 제재조치 해제의 효과\r\n\r\n \r\n\r\n ㅇ 2022. 8. 15.자 이후 잔여 업무정지기간을 감면\r\n\r\n \r\n\r\n4. 특별감면 조치의 시행방법 등\r\n\r\n \r\n\r\n ㅇ 금번 특별조치에 의하여 해제되는 공인중개업에 업무정지 처분을부과한 처분청은 대상자에 중개사무소등록증을 반환하여 영업을 재개할 수 있도록 조치\r\n\r\n \r\n\r\n ㅇ 금번 특별조치 해제 여부에 관한 문의는 관할 등록관청에 문의\r\n\r\n출처 : <a href=\"http://www.molit.go.kr/USR/BORD0201/m_69/DTL.jsp?id=N01_B&cate=&mode=view&idx=250095&key=&search=&search_regdate_s=2021-08-16&search_regdate_e=2022-08-16&order=&desc=asc&srch_prc_stts=&item_num=0&search_dept_id=&search_dept_nm=&srch_usr_nm=N&srch_usr_titl=N&srch_usr_ctnt=N&srch_mng_nm=N&old_dept_nm=&search_gbn=&search_section=&source=&search1=&lcmspage=1\">국토교통부</a>',0);
INSERT INTO `article_tbl` VALUES (180994,1,34,'01091280586','2022-08-18','2022-08-18','2022-08-17','0000-00-00','한공 산불모금성금의 반환 결정','0','',NULL,'한국공인중개사협회는 지난 3월 11일부터 24일까지 산불피해 이재민돕기 성금모금을 추진한 바 있습니다. 모금에 1,259명의 회원과 단체가 참여하여 92,241,590원을 모금했습니다. 이는 한국공인중개사협회 역사상 최대 모금액이었으며 이러한 적극적인 동참에는 첫째, 이재민을 돕겠다는 순수한 동기와 둘째, 이재민 돕기를 통해 공인중개사의 사회적 위상을 높이자는 마음에서 참여한 것으로 알려지고 있다. \r\n\r\n이러한 이러한 회원들의 뜻에 불구하고 수탁기관변경과정에서의 여러 이유로 협회는 의견 조율 부족으로 제때에 성금을 전달되지 못하였다.  협회는 이에 따른 사과와 함께 그 환불을 진행하고 있는 것으로 알려지고 있다. \r\n\r\n성금의 반환을 원하는 경우 8월 25일까지 회원지원부 (02-2015-9862∼4)로 전화하면 반환를 진행할 예정이며 환불예정일은 8월 26일로 전해지고 있다. ',0);
INSERT INTO `article_tbl` VALUES (180995,1,34,'01091280586','2022-11-24','2022-11-24','2022-11-24','2022-12-18','제4회 공인중개사법률소비조합컨퍼런스 개최 ','0','코로나로 그동안 개최되지 못했던 공인중개사법률소비조합 제4회 컨퍼런스 개최예정입니다. ','confer_i.jpg','<img src=\"http://reuni.kr/img/confer_last630.jpg\"  style=\"max-width: 100%; height: auto;\" alt=\"초청장\">\r\n\r\n<a href=\"https://forms.gle/zPa5mDp5FyHA3Xa99\" target=\"_blank\">*참가신청하기*</a>\r\n\r\n공인중개사법률소비조합은 2019년 12월 8일 제 3회 컨퍼런스 개최 후 코로나로 인해 미루어 오던 정기 컨퍼런스를 오는 12월 18일(일) 한국공인중개사협회 북부지부 교육장에서 오전 11부터 오후 5까지 개최할 예정이다.  \r\n\r\n이번 컨퍼런스는 가계약과 표시광고 관련하여 공인중개사에 대한 과도한 과태료 부과로 인해 생계의 위협을 토로하는 가운데 조직적인 대응을 위한 대안과 중개 현장에서의 다양한 주제들에 대해 논의할 예정이다. \r\n\r\n일정 : \r\n<img src=\"http://reuni.kr/img/TimeTlast630.jpg\"  style=\"max-width: 100%; height: auto;\" alt=\"초청장\" >\r\n\r\n오시는 길 : \r\n<img src=\"http://seoul-n.kar.or.kr/share/upload/template/map/%EC%84%9C%EC%9A%B8%EB%B6%81%EB%B6%80%EC%A7%80%EB%B6%80%EC%95%BD%EB%8F%84%EC%9D%B4%EC%A0%8402_web.jpg\"  style=\"max-width: 100%; height: auto;\" alt=\"북부지부오시는 길\">',0);
INSERT INTO `article_tbl` VALUES (190000,1,32,'01091280586','2023-04-28','2023-04-28','2023-04-28','2023-12-30','공인중개사 과태료 대응방안','0','최근 과태료 부가의 증가로 중개업계에서 어떻게 과태료 대응을 하여야 하는가에 대해 궁금해하고 있다. ',NULL,'왜 이의제기[1]인가? (이의 신청의 의의)\n\n\n\n과태료 처분이 앞에서 설명한 대로 사전처분 과태료 처분을 통해 이루어진 경우 처분하는 부과권자가 할 수\n 있는 재량권의 범위는 공인중개사법 시행령 제38조(과태료의 부과ㆍ징수) 별표 2[2]의 제2호의 개별기준\n에 따라 과태료 금액의 2분의 1범위에서 금액을 줄일 수 있을 뿐이다.\n\n\n\n즉, 공인중개사법 제18조의2제4항[3]에 위반한 광고삭제지연의 경우 만약 사전통지단계에서 250만원의 과\n태료예고가 된 경우 사실 부과권자로서의 최선의 배려인 것이다. 따라서 이미 250만원의 사전통지가 된 경\n우 과태료 당사자의 입장에서 사실상 의견제출로 인해 기대할 이익은 없는 것이다.\n\n\n\n따라서 250만원의 과태료 처분에도 내가 동의할 수 없다는 과태료 처분에 대한 이의제기만이 남게되는 것이\n다.\n\n\n\n하지만 이의신청은 단순히 과태료를 가지고 다툰다는 의미만을 가지지 않는다. 즉, 이의제기를 하는 경우 \n부과된 과태료 처분은 이의제기로 인하여 그 효력을 상실하게 된다.[4] 이것이 얼마나 강력한지는 이번 과\n태료 부과처분의 특징을 살펴보면 더욱 분명해 진다. 현재 가장 많은 비중을 차지하는 표시광고위반의 경우\n 분기별로 정기 모니터닝이 이루어지고 필요에 의해 수시모니터링이 이루어진다. 그리고 그 결과를 가지고 \n각 지자체로 그 결과가 통보되게 된다.\n\n\n\n결국 지금 과태료가 부과되는 건 2023년도의 위반행위가 아니다. 대부분의 경우 22년도의 분기 또는 수시\n 모니터링을 통해 적발된 사항이 현재 조치가 이루어지고 있으며 자치단체에 따라 2개분기의 것이 합쳐저서\n도 나오는 경우도 있다. 따라서 현재의 과태료가 마지막이 아닐 수도 있다.\n\n\n\n근데 이 경우 이의제기를 질서위반행위규제법 제20조에 의해 과태료 부과처분은 그 효력을 상실하게 된며 \n따라서 법원의 판결시까지는 공인중개사법 제39조 1항 12호[5]에 의한 업무정지 및 공인중개사법 제 38조\n 1항 10호[6]에 의한 등록취소의 사유로서의 카운팅이 멈추게 된다.\n\n\n\n또한 ｢질서위반행위규제법｣ 제3조[7]는 질서위반행위의 성립과 과태료 처분은 원칙적으로 행위 시 법률에 \n따르되(제1항) 질서위반행위 후 법률의 변경으로 과태료 액수가 감경되거나 부과 대상에서 제외된 경우에는\n 법률에 특별한 규정이 없는 한 신법을 적용하도록하였다(제2항) 또한 현재 국회의 법개정이 임박한 상황에\n서는 이에 대한 고려 또한 중요한 사항이 될 것이다.\n\n​\n\n\n\n*각주*\n\n[1]질서위반행위규제법 제20조(이의제기) ① 행정청의 과태료 부과에 불복하는 당사자는 제17조제1항에 따\n른 과태료 부과 통지를 받은 날부터 60일 이내에 해당 행정청에 서면으로 이의제기를 할 수 있다.\n\n② 제1항에 따른 이의제기가 있는 경우에는 행정청의 과태료 부과처분은 그 효력을 상실한다.\n\n③ 당사자는 행정청으로부터 제21조제3항에 따른 통지를 받기 전까지는 행정청에 대하여 서면으로 이의제기\n를 철회할 수 있다.\n\n\n\n[2] 가. 부과권자는 다음의 어느 하나에 해당하는 경우에는 제2호의 개별기준에 따른 과태료 금액의 2분의\n 1 범위에서 그 금액을 줄일 수 있다. 다만, 과태료를 체납하고 있는 위반행위자의 경우에는 그렇지 않다.\n\n1) 위반행위가 사소한 부주의나 오류 등 과실로 인한 것으로 인정되는 경우\n\n2) 위반행위자가 법 위반행위를 시정하거나 해소하기 위하여 노력한 사실이 인정되는 경우\n\n3) 그 밖에 위반행위의 정도, 동기와 그 결과 등을 고려하여 과태료 금액을 줄일 필요가 있다고 인정되는 \n경우\n\n\n\n[3]공인중개사법 제18조의2(중개대상물의 표시ㆍ광고) ① 개업공인중개사가 의뢰받은 중개대상물에 대하여 \n표시ㆍ광고(「표시ㆍ광고의 공정화에 관한 법률」 제2조에 따른 표시ㆍ광고를 말한다. 이하 같다)를 하려\n면 중개사무소, 개업공인중개사에 관한 사항으로서 대통령령으로 정하는 사항을 명시하여야 하며, 중개보조\n원에 관한 사항은 명시해서는 아니 된다. <개정 2014. 1. 28., 2019. 8. 20.>\n\n② 개업공인중개사가 인터넷을 이용하여 중개대상물에 대한 표시ㆍ광고를 하는 때에는 제1항에서 정하는 사항\n 외에 중개대상물의 종류별로 대통령령으로 정하는 소재지, 면적, 가격 등의 사항을 명시하여야 한다. <신\n설 2019. 8. 20.>\n\n③ 개업공인중개사가 아닌 자는 중개대상물에 대한 표시ㆍ광고를 하여서는 아니 된다. <개정\n 2014. 1. 28., 2019. 8. 20.>\n\n④ 개업공인중개사는 중개대상물에 대하여 다음 각 호의 어느 하나에 해당하는 부당한 표시ㆍ광고를 하여서는\n 아니 된다. <신설 2019. 8. 20.>\n\n1. 중개대상물이 존재하지 않아서 실제로 거래를 할 수 없는 중개대상물에 대한 표시ㆍ광고\n\n2. 중개대상물의 가격 등 내용을 사실과 다르게 거짓으로 표시ㆍ광고하거나 사실을 과장되게 하는 표시ㆍ광\n고\n\n3. 그 밖에 표시ㆍ광고의 내용이 부동산거래질서를 해치거나 중개의뢰인에게 피해를 줄 우려가 있는 것으로\n서 대통령령으로 정하는 내용의 표시ㆍ광고\n\n⑤ 제4항에 따른 부당한 표시ㆍ광고의 세부적인 유형 및 기준 등에 관한 사항은 국토교통부장관이 정하여 고\n시한다. <신설 2019. 8. 20.>\n\n[본조신설 2013. 6. 4.]\n\n\n\n[4]질서위반행위규제법 제20조(이의제기) ① 행정청의 과태료 부과에 불복하는 당사자는 제17조제1항에 따\n른 과태료 부과 통지를 받은 날부터 60일 이내에 해당 행정청에 서면으로 이의제기를 할 수 있다.\n\n② 제1항에 따른 이의제기가 있는 경우에는 행정청의 과태료 부과처분은 그 효력을 상실한다.\n\n③ 당사자는 행정청으로부터 제21조제3항에 따른 통지를 받기 전까지는 행정청에 대하여 서면으로 이의제기\n를 철회할 수 있다.\n\n\n\n[5] 12. 법에 의하여 2회 이상 업무정지 또는 과태료의 처분을 받고 다시 과태료의 처분에 해당하는 행위\n를 한 경우\n\n\n\n[6] 10. 최근 1년 이내에 이 법에 의하여 3회 이상 업무정지 또는 과태료의 처분을 받고 다시 업무정지 \n또는 과태료의 처분에 해당하는 행위를 한 경우(제1항제8호에 해당하는 경우는 제외한다)\n\n\n\n[7] 질서위반행위규제법 제3조(법 적용의 시간적 범위) ① 질서위반행위의 성립과 과태료 처분은 행위 시의\n 법률에 따른다.\n\n② 질서위반행위 후 법률이 변경되어 그 행위가 질서위반행위에 해당하지 아니하게 되거나 과태료가 변경되기\n 전의 법률보다 가볍게 된 때에는 법률에 특별한 규정이 없는 한 변경된 법률을 적용한다.\n\n③ 행정청의 과태료 처분이나 법원의 과태료 재판이 확정된 후 법률이 변경되어 그 행위가 질서위반행위에 \n해당하지 아니하게 된 때에는 변경된 법률에 특별한 규정이 없는 한 과태료의 징수 또는 집행을 면제한다.\n\n\n\n #중개실무 #이의제기 #과태료  #상담실\n\n',0);
